/**
 * scripts/seed-artigos.ts
 * Popula a topografia completa da CF/88 no Supabase
 * Dados extraídos do documento oficial com filtro de redações antigas (strikethrough)
 * Apenas redação ATUAL de cada dispositivo.
 *
 * Execute: npx tsx scripts/seed-artigos.ts
 */
import { createClient } from '@supabase/supabase-js'
import * as dotenv from 'dotenv'
dotenv.config({ path: '.env.local' })

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.SUPABASE_SERVICE_ROLE_KEY!
)

async function insertBatch(table: string, rows: any[], batchSize = 200) {
  for (let i = 0; i < rows.length; i += batchSize) {
    const batch = rows.slice(i, i + batchSize)
    const { error } = await supabase.from(table).upsert(batch, { onConflict: 'id' })
    if (error) throw new Error(`${table} lote ${i}: ${error.message}`)
    process.stdout.write(`\r  ${table}: ${Math.min(i+batchSize, rows.length)}/${rows.length}`)
  }
  console.log()
}

