  const ARTIGOS = [{"id": 1, "numero": 1, "numero_texto": "1º", "caput": "Art. 1º A República Federativa do Brasil, formada pela união indissolúvel dos Estados e Municípios e do Distrito Federal, constitui-se em Estado Democrático de Direito e tem como fundamentos:", "tipo": "CF", "titulo_id": 1, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 1, "vigente": true}, {"id": 2, "numero": 2, "numero_texto": "2º", "caput": "Art. 2º São Poderes da União, independentes e harmônicos entre si, o Legislativo, o Executivo e o Judiciário.", "tipo": "CF", "titulo_id": 1, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 2, "vigente": true}, {"id": 3, "numero": 3, "numero_texto": "3º", "caput": "Art. 3º Constituem objetivos fundamentais da República Federativa do Brasil:", "tipo": "CF", "titulo_id": 1, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 3, "vigente": true}, {"id": 4, "numero": 4, "numero_texto": "4º", "caput": "Art. 4º A República Federativa do Brasil rege-se nas suas relações internacionais pelos seguintes princípios:", "tipo": "CF", "titulo_id": 1, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 4, "vigente": true}, {"id": 5, "numero": 5, "numero_texto": "5º", "caput": "Art. 5º Todos são iguais perante a lei, sem distinção de qualquer natureza, garantindo-se aos brasileiros e aos estrangeiros residentes no País a inviolabilidade do direito à vida, à liberdade, à igualdade, à segurança e à propriedade, nos termos seguintes:", "tipo": "CF", "titulo_id": 2, "capitulo_id": 1, "secao_id": null, "subsecao_id": null, "ordem": 5, "vigente": true}, {"id": 6, "numero": 6, "numero_texto": "6º", "caput": "Art. 6º São direitos sociais a educação, a saúde, a alimentação, o trabalho, a moradia, o transporte, o lazer, a segurança, a previdência social, a proteção à maternidade e à infância, a assistência aos desamparados, na forma desta Constituição.", "tipo": "CF", "titulo_id": 2, "capitulo_id": 2, "secao_id": null, "subsecao_id": null, "ordem": 6, "vigente": true}, {"id": 7, "numero": 7, "numero_texto": "7º", "caput": "Art. 7º São direitos dos trabalhadores urbanos e rurais, além de outros que visem à melhoria de sua condição social:", "tipo": "CF", "titulo_id": 2, "capitulo_id": 2, "secao_id": null, "subsecao_id": null, "ordem": 7, "vigente": true}, {"id": 8, "numero": 8, "numero_texto": "8º", "caput": "Art. 8º É livre a associação profissional ou sindical, observado o seguinte:", "tipo": "CF", "titulo_id": 2, "capitulo_id": 2, "secao_id": null, "subsecao_id": null, "ordem": 8, "vigente": true}, {"id": 9, "numero": 9, "numero_texto": "9º", "caput": "Art. 9º É assegurado o direito de greve, competindo aos trabalhadores decidir sobre a oportunidade de exercê-lo e sobre os interesses que devam por meio dele defender.", "tipo": "CF", "titulo_id": 2, "capitulo_id": 2, "secao_id": null, "subsecao_id": null, "ordem": 9, "vigente": true}, {"id": 10, "numero": 10, "numero_texto": "10", "caput": "Art. 10. É assegurada a participação dos trabalhadores e empregadores nos colegiados dos órgãos públicos em que seus interesses profissionais ou previdenciários sejam objeto de discussão e deliberação.", "tipo": "CF", "titulo_id": 2, "capitulo_id": 2, "secao_id": null, "subsecao_id": null, "ordem": 10, "vigente": true}, {"id": 11, "numero": 11, "numero_texto": "11", "caput": "Art. 11. Nas empresas de mais de duzentos empregados, é assegurada a eleição de um representante destes com a finalidade exclusiva de promover-lhes o entendimento direto com os empregadores.", "tipo": "CF", "titulo_id": 2, "capitulo_id": 2, "secao_id": null, "subsecao_id": null, "ordem": 11, "vigente": true}, {"id": 12, "numero": 12, "numero_texto": "12", "caput": "Art. 12. São brasileiros:", "tipo": "CF", "titulo_id": 2, "capitulo_id": 3, "secao_id": null, "subsecao_id": null, "ordem": 12, "vigente": true}, {"id": 13, "numero": 13, "numero_texto": "13", "caput": "Art. 13. A língua portuguesa é o idioma oficial da República Federativa do Brasil.", "tipo": "CF", "titulo_id": 2, "capitulo_id": 3, "secao_id": null, "subsecao_id": null, "ordem": 13, "vigente": true}, {"id": 14, "numero": 14, "numero_texto": "14", "caput": "Art. 14. A soberania popular será exercida pelo sufrágio universal e pelo voto direto e secreto, com valor igual para todos, e, nos termos da lei, mediante:", "tipo": "CF", "titulo_id": 2, "capitulo_id": 4, "secao_id": null, "subsecao_id": null, "ordem": 14, "vigente": true}, {"id": 15, "numero": 15, "numero_texto": "15", "caput": "Art. 15. É vedada a cassação de direitos políticos, cuja perda ou suspensão só se dará nos casos de:", "tipo": "CF", "titulo_id": 2, "capitulo_id": 4, "secao_id": null, "subsecao_id": null, "ordem": 15, "vigente": true}, {"id": 16, "numero": 16, "numero_texto": "16", "caput": "Art. 16. A lei que alterar o processo eleitoral entrará em vigor na data de sua publicação, não se aplicando à eleição que ocorra até um ano da data de sua vigência.", "tipo": "CF", "titulo_id": 2, "capitulo_id": 4, "secao_id": null, "subsecao_id": null, "ordem": 16, "vigente": true}, {"id": 17, "numero": 17, "numero_texto": "17", "caput": "Art. 17. É livre a criação, fusão, incorporação e extinção de partidos políticos, resguardados a soberania nacional, o regime democrático, o pluripartidarismo, os direitos fundamentais da pessoa humana e observados os seguintes preceitos: Regulamento", "tipo": "CF", "titulo_id": 2, "capitulo_id": 5, "secao_id": null, "subsecao_id": null, "ordem": 17, "vigente": true}, {"id": 18, "numero": 18, "numero_texto": "18", "caput": "Art. 18. A organização político-administrativa da República Federativa do Brasil compreende a União, os Estados, o Distrito Federal e os Municípios, todos autônomos, nos termos desta Constituição.", "tipo": "CF", "titulo_id": 3, "capitulo_id": 6, "secao_id": null, "subsecao_id": null, "ordem": 18, "vigente": true}, {"id": 19, "numero": 19, "numero_texto": "19", "caput": "Art. 19. É vedado à União, aos Estados, ao Distrito Federal e aos Municípios:", "tipo": "CF", "titulo_id": 3, "capitulo_id": 6, "secao_id": null, "subsecao_id": null, "ordem": 19, "vigente": true}, {"id": 20, "numero": 20, "numero_texto": "20", "caput": "Art. 20. São bens da União:", "tipo": "CF", "titulo_id": 3, "capitulo_id": 7, "secao_id": null, "subsecao_id": null, "ordem": 20, "vigente": true}, {"id": 21, "numero": 21, "numero_texto": "21", "caput": "Art. 21. Compete à União:", "tipo": "CF", "titulo_id": 3, "capitulo_id": 7, "secao_id": null, "subsecao_id": null, "ordem": 21, "vigente": true}, {"id": 22, "numero": 22, "numero_texto": "22", "caput": "Art. 22. Compete privativamente à União legislar sobre:", "tipo": "CF", "titulo_id": 3, "capitulo_id": 7, "secao_id": null, "subsecao_id": null, "ordem": 22, "vigente": true}, {"id": 23, "numero": 23, "numero_texto": "23", "caput": "Art. 23. É competência comum da União, dos Estados, do Distrito Federal e dos Municípios:", "tipo": "CF", "titulo_id": 3, "capitulo_id": 7, "secao_id": null, "subsecao_id": null, "ordem": 23, "vigente": true}, {"id": 24, "numero": 24, "numero_texto": "24", "caput": "Art. 24. Compete à União, aos Estados e ao Distrito Federal legislar concorrentemente sobre:", "tipo": "CF", "titulo_id": 3, "capitulo_id": 7, "secao_id": null, "subsecao_id": null, "ordem": 24, "vigente": true}, {"id": 25, "numero": 25, "numero_texto": "25", "caput": "Art. 25. Os Estados organizam-se e regem-se pelas Constituições e leis que adotarem, observados os princípios desta Constituição.", "tipo": "CF", "titulo_id": 3, "capitulo_id": 8, "secao_id": null, "subsecao_id": null, "ordem": 25, "vigente": true}, {"id": 26, "numero": 26, "numero_texto": "26", "caput": "Art. 26. Incluem-se entre os bens dos Estados:", "tipo": "CF", "titulo_id": 3, "capitulo_id": 8, "secao_id": null, "subsecao_id": null, "ordem": 26, "vigente": true}, {"id": 27, "numero": 27, "numero_texto": "27", "caput": "Art. 27. O número de Deputados à Assembléia Legislativa corresponderá ao triplo da representação do Estado na Câmara dos Deputados e, atingido o número de trinta e seis, será acrescido de tantos quantos forem os Deputados Federais acima de doze.", "tipo": "CF", "titulo_id": 3, "capitulo_id": 8, "secao_id": null, "subsecao_id": null, "ordem": 27, "vigente": true}, {"id": 28, "numero": 28, "numero_texto": "28", "caput": "Art. 28. A eleição do Governador e do Vice-Governador de Estado, para mandato de 4 (quatro) anos, realizar-se-á no primeiro domingo de outubro, em primeiro turno, e no último domingo de outubro, em segundo turno, se houver, do ano anterior ao do término do mandato de seus antecessores, e a posse ocorrerá em 6 de janeiro do ano subsequente, observado, quanto ao mais, o disposto no art. 77 desta Constituição.", "tipo": "CF", "titulo_id": 3, "capitulo_id": 8, "secao_id": null, "subsecao_id": null, "ordem": 28, "vigente": true}, {"id": 29, "numero": 29, "numero_texto": "29", "caput": "Art. 29. O Município reger-se-á por lei orgânica, votada em dois turnos, com o interstício mínimo de dez dias, e aprovada por dois terços dos membros da Câmara Municipal, que a promulgará, atendidos os princípios estabelecidos nesta Constituição, na Constituição do respectivo Estado e os seguintes preceitos:", "tipo": "CF", "titulo_id": 3, "capitulo_id": 9, "secao_id": null, "subsecao_id": null, "ordem": 29, "vigente": true}, {"id": 30, "numero": 30, "numero_texto": "30", "caput": "Art. 30. Compete aos Municípios:", "tipo": "CF", "titulo_id": 3, "capitulo_id": 9, "secao_id": null, "subsecao_id": null, "ordem": 30, "vigente": true}, {"id": 31, "numero": 31, "numero_texto": "31", "caput": "Art. 31. A fiscalização do Município será exercida pelo Poder Legislativo Municipal, mediante controle externo, e pelos sistemas de controle interno do Poder Executivo Municipal, na forma da lei.", "tipo": "CF", "titulo_id": 3, "capitulo_id": 9, "secao_id": null, "subsecao_id": null, "ordem": 31, "vigente": true}, {"id": 32, "numero": 32, "numero_texto": "32", "caput": "Art. 32. O Distrito Federal, vedada sua divisão em Municípios, reger- se-á por lei orgânica, votada em dois turnos com interstício mínimo de dez dias, e aprovada por dois terços da Câmara Legislativa, que a promulgará, atendidos os princípios estabelecidos nesta Constituição.", "tipo": "CF", "titulo_id": 3, "capitulo_id": 10, "secao_id": 1, "subsecao_id": null, "ordem": 32, "vigente": true}, {"id": 33, "numero": 33, "numero_texto": "33", "caput": "Art. 33. A lei disporá sobre a organização administrativa e judiciária dos Territórios.", "tipo": "CF", "titulo_id": 3, "capitulo_id": 10, "secao_id": 2, "subsecao_id": null, "ordem": 33, "vigente": true}, {"id": 34, "numero": 34, "numero_texto": "34", "caput": "Art. 34. A União não intervirá nos Estados nem no Distrito Federal, exceto para:", "tipo": "CF", "titulo_id": 3, "capitulo_id": 11, "secao_id": null, "subsecao_id": null, "ordem": 34, "vigente": true}, {"id": 35, "numero": 35, "numero_texto": "35", "caput": "Art. 35. O Estado não intervirá em seus Municípios, nem a União nos Municípios localizados em Território Federal, exceto quando:", "tipo": "CF", "titulo_id": 3, "capitulo_id": 11, "secao_id": null, "subsecao_id": null, "ordem": 35, "vigente": true}, {"id": 36, "numero": 36, "numero_texto": "36", "caput": "Art. 36. A decretação da intervenção dependerá:", "tipo": "CF", "titulo_id": 3, "capitulo_id": 11, "secao_id": null, "subsecao_id": null, "ordem": 36, "vigente": true}, {"id": 37, "numero": 37, "numero_texto": "37", "caput": "Art. 37. A administração pública direta e indireta de qualquer dos Poderes da União, dos Estados, do Distrito Federal e dos Municípios obedecerá aos princípios de legalidade, impessoalidade, moralidade, publicidade e eficiência e, também, ao seguinte:", "tipo": "CF", "titulo_id": 3, "capitulo_id": 12, "secao_id": 3, "subsecao_id": null, "ordem": 37, "vigente": true}, {"id": 38, "numero": 38, "numero_texto": "38", "caput": "Art. 38. Ao servidor público da administração direta, autárquica e fundacional, no exercício de mandato eletivo, aplicam-se as seguintes disposições:", "tipo": "CF", "titulo_id": 3, "capitulo_id": 12, "secao_id": 3, "subsecao_id": null, "ordem": 38, "vigente": true}, {"id": 39, "numero": 39, "numero_texto": "39", "caput": "Art. 39. A União, os Estados, o Distrito Federal e os Municípios instituirão conselho de política de administração e remuneração de pessoal, integrado por servidores designados pelos respectivos Poderes.", "tipo": "CF", "titulo_id": 3, "capitulo_id": 12, "secao_id": 4, "subsecao_id": null, "ordem": 39, "vigente": true}, {"id": 40, "numero": 40, "numero_texto": "40", "caput": "Art. 40. O regime próprio de previdência social dos servidores titulares de cargos efetivos terá caráter contributivo e solidário, mediante contribuição do respectivo ente federativo, de servidores ativos, de aposentados e de pensionistas, observados critérios que preservem o equilíbrio financeiro e atuarial.", "tipo": "CF", "titulo_id": 3, "capitulo_id": 12, "secao_id": 4, "subsecao_id": null, "ordem": 40, "vigente": true}, {"id": 41, "numero": 41, "numero_texto": "41", "caput": "Art. 41. São estáveis após três anos de efetivo exercício os servidores nomeados para cargo de provimento efetivo em virtude de concurso público.", "tipo": "CF", "titulo_id": 3, "capitulo_id": 12, "secao_id": 4, "subsecao_id": null, "ordem": 41, "vigente": true}, {"id": 42, "numero": 42, "numero_texto": "42", "caput": "Art. 42 Os membros das Polícias Militares e Corpos de Bombeiros Militares, instituições organizadas com base na hierarquia e disciplina, são militares dos Estados, do Distrito Federal e dos Territórios.", "tipo": "CF", "titulo_id": 3, "capitulo_id": 12, "secao_id": 5, "subsecao_id": null, "ordem": 42, "vigente": true}, {"id": 43, "numero": 43, "numero_texto": "43", "caput": "Art. 43. Para efeitos administrativos, a União poderá articular sua ação em um mesmo complexo geoeconômico e social, visando a seu desenvolvimento e à redução das desigualdades regionais.", "tipo": "CF", "titulo_id": 3, "capitulo_id": 12, "secao_id": 6, "subsecao_id": null, "ordem": 43, "vigente": true}, {"id": 44, "numero": 44, "numero_texto": "44", "caput": "Art. 44. O Poder Legislativo é exercido pelo Congresso Nacional, que se compõe da Câmara dos Deputados e do Senado Federal.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 7, "subsecao_id": null, "ordem": 44, "vigente": true}, {"id": 45, "numero": 45, "numero_texto": "45", "caput": "Art. 45. A Câmara dos Deputados compõe-se de representantes do povo, eleitos, pelo sistema proporcional, em cada Estado, em cada Território e no Distrito Federal.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 7, "subsecao_id": null, "ordem": 45, "vigente": true}, {"id": 46, "numero": 46, "numero_texto": "46", "caput": "Art. 46. O Senado Federal compõe-se de representantes dos Estados e do Distrito Federal, eleitos segundo o princípio majoritário.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 7, "subsecao_id": null, "ordem": 46, "vigente": true}, {"id": 47, "numero": 47, "numero_texto": "47", "caput": "Art. 47. Salvo disposição constitucional em contrário, as deliberações de cada Casa e de suas Comissões serão tomadas por maioria dos votos, presente a maioria absoluta de seus membros.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 7, "subsecao_id": null, "ordem": 47, "vigente": true}, {"id": 48, "numero": 48, "numero_texto": "48", "caput": "Art. 48. Cabe ao Congresso Nacional, com a sanção do Presidente da República, não exigida esta para o especificado nos arts. 49, 51 e 52, dispor sobre todas as matérias de competência da União, especialmente sobre:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 8, "subsecao_id": null, "ordem": 48, "vigente": true}, {"id": 49, "numero": 49, "numero_texto": "49", "caput": "Art. 49. É da competência exclusiva do Congresso Nacional:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 8, "subsecao_id": null, "ordem": 49, "vigente": true}, {"id": 50, "numero": 50, "numero_texto": "50", "caput": "Art. 50. A Câmara dos Deputados e o Senado Federal, ou qualquer de suas Comissões, poderão convocar Ministro de Estado, quaisquer titulares de órgãos diretamente subordinados à Presidência da República ou o Presidente do Comitê Gestor do Imposto sobre Bens e Serviços para prestarem, pessoalmente, informações sobre assunto previamente determinado, importando crime de responsabilidade a ausência sem justificação adequada.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 8, "subsecao_id": null, "ordem": 50, "vigente": true}, {"id": 51, "numero": 51, "numero_texto": "51", "caput": "Art. 51. Compete privativamente à Câmara dos Deputados:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 9, "subsecao_id": null, "ordem": 51, "vigente": true}, {"id": 52, "numero": 52, "numero_texto": "52", "caput": "Art. 52. Compete privativamente ao Senado Federal:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 10, "subsecao_id": null, "ordem": 52, "vigente": true}, {"id": 53, "numero": 53, "numero_texto": "53", "caput": "Art. 53. Os Deputados e Senadores são invioláveis, civil e penalmente, por quaisquer de suas opiniões, palavras e votos.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 11, "subsecao_id": null, "ordem": 53, "vigente": true}, {"id": 54, "numero": 54, "numero_texto": "54", "caput": "Art. 54. Os Deputados e Senadores não poderão:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 11, "subsecao_id": null, "ordem": 54, "vigente": true}, {"id": 55, "numero": 55, "numero_texto": "55", "caput": "Art. 55. Perderá o mandato o Deputado ou Senador:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 11, "subsecao_id": null, "ordem": 55, "vigente": true}, {"id": 56, "numero": 56, "numero_texto": "56", "caput": "Art. 56. Não perderá o mandato o Deputado ou Senador:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 11, "subsecao_id": null, "ordem": 56, "vigente": true}, {"id": 57, "numero": 57, "numero_texto": "57", "caput": "Art. 57. O Congresso Nacional reunir-se-á, anualmente, na Capital Federal, de 2 de fevereiro a 17 de julho e de 1º de agosto a 22 de dezembro.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 12, "subsecao_id": null, "ordem": 57, "vigente": true}, {"id": 58, "numero": 58, "numero_texto": "58", "caput": "Art. 58. O Congresso Nacional e suas Casas terão comissões permanentes e temporárias, constituídas na forma e com as atribuições previstas no respectivo regimento ou no ato de que resultar sua criação.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 13, "subsecao_id": null, "ordem": 58, "vigente": true}, {"id": 59, "numero": 59, "numero_texto": "59", "caput": "Art. 59. O processo legislativo compreende a elaboração de:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 14, "subsecao_id": null, "ordem": 59, "vigente": true}, {"id": 60, "numero": 60, "numero_texto": "60", "caput": "Art. 60. A Constituição poderá ser emendada mediante proposta:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 14, "subsecao_id": null, "ordem": 60, "vigente": true}, {"id": 61, "numero": 61, "numero_texto": "61", "caput": "Art. 61. A iniciativa das leis complementares e ordinárias cabe a qualquer membro ou Comissão da Câmara dos Deputados, do Senado Federal ou do Congresso Nacional, ao Presidente da República, ao Supremo Tribunal Federal, aos Tribunais Superiores, ao Procurador-Geral da República e aos cidadãos, na forma e nos casos previstos nesta Constituição.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 14, "subsecao_id": null, "ordem": 61, "vigente": true}, {"id": 62, "numero": 62, "numero_texto": "62", "caput": "Art. 62. Em caso de relevância e urgência, o Presidente da República poderá adotar medidas provisórias, com força de lei, devendo submetê-las de imediato ao Congresso Nacional.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 14, "subsecao_id": null, "ordem": 62, "vigente": true}, {"id": 63, "numero": 63, "numero_texto": "63", "caput": "Art. 63. Não será admitido aumento da despesa prevista:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 14, "subsecao_id": null, "ordem": 63, "vigente": true}, {"id": 64, "numero": 64, "numero_texto": "64", "caput": "Art. 64. A discussão e votação dos projetos de lei de iniciativa do Presidente da República, do Supremo Tribunal Federal e dos Tribunais Superiores terão início na Câmara dos Deputados.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 14, "subsecao_id": null, "ordem": 64, "vigente": true}, {"id": 65, "numero": 65, "numero_texto": "65", "caput": "Art. 65. O projeto de lei aprovado por uma Casa será revisto pela outra, em um só turno de discussão e votação, e enviado à sanção ou promulgação, se a Casa revisora o aprovar, ou arquivado, se o rejeitar.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 14, "subsecao_id": null, "ordem": 65, "vigente": true}, {"id": 66, "numero": 66, "numero_texto": "66", "caput": "Art. 66. A Casa na qual tenha sido concluída a votação enviará o projeto de lei ao Presidente da República, que, aquiescendo, o sancionará.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 14, "subsecao_id": null, "ordem": 66, "vigente": true}, {"id": 67, "numero": 67, "numero_texto": "67", "caput": "Art. 67. A matéria constante de projeto de lei rejeitado somente poderá constituir objeto de novo projeto, na mesma sessão legislativa, mediante proposta da maioria absoluta dos membros de qualquer das Casas do Congresso Nacional.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 14, "subsecao_id": null, "ordem": 67, "vigente": true}, {"id": 68, "numero": 68, "numero_texto": "68", "caput": "Art. 68. As leis delegadas serão elaboradas pelo Presidente da República, que deverá solicitar a delegação ao Congresso Nacional.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 14, "subsecao_id": null, "ordem": 68, "vigente": true}, {"id": 69, "numero": 69, "numero_texto": "69", "caput": "Art. 69. As leis complementares serão aprovadas por maioria absoluta.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 14, "subsecao_id": null, "ordem": 69, "vigente": true}, {"id": 70, "numero": 70, "numero_texto": "70", "caput": "Art. 70. A fiscalização contábil, financeira, orçamentária, operacional e patrimonial da União e das entidades da administração direta e indireta, quanto à legalidade, legitimidade, economicidade, aplicação das subvenções e renúncia de receitas, será exercida pelo Congresso Nacional, mediante controle externo, e pelo sistema de controle interno de cada Poder.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 15, "subsecao_id": null, "ordem": 70, "vigente": true}, {"id": 71, "numero": 71, "numero_texto": "71", "caput": "Art. 71. O controle externo, a cargo do Congresso Nacional, será exercido com o auxílio do Tribunal de Contas da União, ao qual compete:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 15, "subsecao_id": null, "ordem": 71, "vigente": true}, {"id": 72, "numero": 72, "numero_texto": "72", "caput": "Art. 72. A Comissão mista permanente a que se refere o art. 166, §1º, diante de indícios de despesas não autorizadas, ainda que sob a forma de investimentos não programados ou de subsídios não aprovados, poderá solicitar à autoridade governamental responsável que, no prazo de cinco dias, preste os esclarecimentos necessários.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 15, "subsecao_id": null, "ordem": 72, "vigente": true}, {"id": 73, "numero": 73, "numero_texto": "73", "caput": "Art. 73. O Tribunal de Contas da União, integrado por nove Ministros, tem sede no Distrito Federal, quadro próprio de pessoal e jurisdição em todo o território nacional, exercendo, no que couber, as atribuições previstas no art. 96.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 15, "subsecao_id": null, "ordem": 73, "vigente": true}, {"id": 74, "numero": 74, "numero_texto": "74", "caput": "Art. 74. Os Poderes Legislativo, Executivo e Judiciário manterão, de forma integrada, sistema de controle interno com a finalidade de:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 15, "subsecao_id": null, "ordem": 74, "vigente": true}, {"id": 75, "numero": 75, "numero_texto": "75", "caput": "Art. 75. As normas estabelecidas nesta seção aplicam-se, no que couber, à organização, composição e fiscalização dos Tribunais de Contas dos Estados e do Distrito Federal, bem como dos Tribunais e Conselhos de Contas dos Municípios.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 13, "secao_id": 15, "subsecao_id": null, "ordem": 75, "vigente": true}, {"id": 76, "numero": 76, "numero_texto": "76", "caput": "Art. 76. O Poder Executivo é exercido pelo Presidente da República, auxiliado pelos Ministros de Estado.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 14, "secao_id": 16, "subsecao_id": null, "ordem": 76, "vigente": true}, {"id": 77, "numero": 77, "numero_texto": "77", "caput": "Art. 77. A eleição do Presidente e do Vice-Presidente da República realizar-se-á, simultaneamente, no primeiro domingo de outubro, em primeiro turno, e no último domingo de outubro, em segundo turno, se houver, do ano anterior ao do término do mandato presidencial vigente.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 14, "secao_id": 16, "subsecao_id": null, "ordem": 77, "vigente": true}, {"id": 78, "numero": 78, "numero_texto": "78", "caput": "Art. 78. O Presidente e o Vice-Presidente da República tomarão posse em sessão do Congresso Nacional, prestando o compromisso de manter, defender e cumprir a Constituição, observar as leis, promover o bem geral do povo brasileiro, sustentar a união, a integridade e a independência do Brasil.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 14, "secao_id": 16, "subsecao_id": null, "ordem": 78, "vigente": true}, {"id": 79, "numero": 79, "numero_texto": "79", "caput": "Art. 79. Substituirá o Presidente, no caso de impedimento, e suceder-lhe-á, no de vaga, o Vice-Presidente.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 14, "secao_id": 16, "subsecao_id": null, "ordem": 79, "vigente": true}, {"id": 80, "numero": 80, "numero_texto": "80", "caput": "Art. 80. Em caso de impedimento do Presidente e do Vice-Presidente, ou vacância dos respectivos cargos, serão sucessivamente chamados ao exercício da Presidência o Presidente da Câmara dos Deputados, o do Senado Federal e o do Supremo Tribunal Federal.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 14, "secao_id": 16, "subsecao_id": null, "ordem": 80, "vigente": true}, {"id": 81, "numero": 81, "numero_texto": "81", "caput": "Art. 81. Vagando os cargos de Presidente e Vice-Presidente da República, far-se-á eleição noventa dias depois de aberta a última vaga.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 14, "secao_id": 16, "subsecao_id": null, "ordem": 81, "vigente": true}, {"id": 82, "numero": 82, "numero_texto": "82", "caput": "Art. 82. O mandato do Presidente da República é de 4 (quatro) anos e terá início em 5 de janeiro do ano seguinte ao de sua eleição.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 14, "secao_id": 16, "subsecao_id": null, "ordem": 82, "vigente": true}, {"id": 83, "numero": 83, "numero_texto": "83", "caput": "Art. 83. O Presidente e o Vice-Presidente da República não poderão, sem licença do Congresso Nacional, ausentar-se do País por período superior a quinze dias, sob pena de perda do cargo.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 14, "secao_id": 16, "subsecao_id": null, "ordem": 83, "vigente": true}, {"id": 84, "numero": 84, "numero_texto": "84", "caput": "Art. 84. Compete privativamente ao Presidente da República:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 14, "secao_id": 17, "subsecao_id": null, "ordem": 84, "vigente": true}, {"id": 85, "numero": 85, "numero_texto": "85", "caput": "Art. 85. São crimes de responsabilidade os atos do Presidente da República que atentem contra a Constituição Federal e, especialmente, contra:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 14, "secao_id": 18, "subsecao_id": null, "ordem": 85, "vigente": true}, {"id": 86, "numero": 86, "numero_texto": "86", "caput": "Art. 86. Admitida a acusação contra o Presidente da República, por dois terços da Câmara dos Deputados, será ele submetido a julgamento perante o Supremo Tribunal Federal, nas infrações penais comuns, ou perante o Senado Federal, nos crimes de responsabilidade.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 14, "secao_id": 18, "subsecao_id": null, "ordem": 86, "vigente": true}, {"id": 87, "numero": 87, "numero_texto": "87", "caput": "Art. 87. Os Ministros de Estado serão escolhidos dentre brasileiros maiores de vinte e um anos e no exercício dos direitos políticos.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 14, "secao_id": 19, "subsecao_id": null, "ordem": 87, "vigente": true}, {"id": 88, "numero": 88, "numero_texto": "88", "caput": "Art. 88. A lei disporá sobre a criação e extinção de Ministérios e órgãos da administração pública.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 14, "secao_id": 19, "subsecao_id": null, "ordem": 88, "vigente": true}, {"id": 89, "numero": 89, "numero_texto": "89", "caput": "Art. 89. O Conselho da República é órgão superior de consulta do Presidente da República, e dele participam:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 14, "secao_id": 20, "subsecao_id": null, "ordem": 89, "vigente": true}, {"id": 90, "numero": 90, "numero_texto": "90", "caput": "Art. 90. Compete ao Conselho da República pronunciar-se sobre:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 14, "secao_id": 20, "subsecao_id": null, "ordem": 90, "vigente": true}, {"id": 91, "numero": 91, "numero_texto": "91", "caput": "Art. 91. O Conselho de Defesa Nacional é órgão de consulta do Presidente da República nos assuntos relacionados com a soberania nacional e a defesa do Estado democrático, e dele participam como membros natos:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 14, "secao_id": 20, "subsecao_id": null, "ordem": 91, "vigente": true}, {"id": 92, "numero": 92, "numero_texto": "92", "caput": "Art. 92. São órgãos do Poder Judiciário:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 21, "subsecao_id": null, "ordem": 92, "vigente": true}, {"id": 93, "numero": 93, "numero_texto": "93", "caput": "Art. 93. Lei complementar, de iniciativa do Supremo Tribunal Federal, disporá sobre o Estatuto da Magistratura, observados os seguintes princípios:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 21, "subsecao_id": null, "ordem": 93, "vigente": true}, {"id": 94, "numero": 94, "numero_texto": "94", "caput": "Art. 94. Um quinto dos lugares dos Tribunais Regionais Federais, dos Tribunais dos Estados, e do Distrito Federal e Territórios será composto de membros, do Ministério Público, com mais de dez anos de carreira, e de advogados de notório saber jurídico e de reputação ilibada, com mais de dez anos de efetiva atividade profissional, indicados em lista sêxtupla pelos órgãos de representação das respectivas classes.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 21, "subsecao_id": null, "ordem": 94, "vigente": true}, {"id": 95, "numero": 95, "numero_texto": "95", "caput": "Art. 95. Os juízes gozam das seguintes garantias:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 21, "subsecao_id": null, "ordem": 95, "vigente": true}, {"id": 96, "numero": 96, "numero_texto": "96", "caput": "Art. 96. Compete privativamente:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 21, "subsecao_id": null, "ordem": 96, "vigente": true}, {"id": 97, "numero": 97, "numero_texto": "97", "caput": "Art. 97. Somente pelo voto da maioria absoluta de seus membros ou dos membros do respectivo órgão especial poderão os tribunais declarar a inconstitucionalidade de lei ou ato normativo do Poder Público. (Vigência)", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 21, "subsecao_id": null, "ordem": 97, "vigente": true}, {"id": 98, "numero": 98, "numero_texto": "98", "caput": "Art. 98. A União, no Distrito Federal e nos Territórios, e os Estados criarão:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 21, "subsecao_id": null, "ordem": 98, "vigente": true}, {"id": 99, "numero": 99, "numero_texto": "99", "caput": "Art. 99. Ao Poder Judiciário é assegurada autonomia administrativa e financeira.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 21, "subsecao_id": null, "ordem": 99, "vigente": true}, {"id": 100, "numero": 100, "numero_texto": "100", "caput": "Art. 100. Os pagamentos devidos pelas Fazendas Públicas Federal, Estaduais, Distrital e Municipais, em virtude de sentença judiciária, far-se-ão exclusivamente na ordem cronológica de apresentação dos precatórios e à conta dos créditos respectivos, proibida a designação de casos ou de pessoas nas dotações orçamentárias e nos créditos adicionais abertos para este fim..", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 21, "subsecao_id": null, "ordem": 100, "vigente": true}, {"id": 101, "numero": 101, "numero_texto": "101", "caput": "Art. 101. O Supremo Tribunal Federal compõe-se de onze Ministros, escolhidos dentre cidadãos com mais de trinta e cinco e menos de setenta anos de idade, de notável saber jurídico e reputação ilibada.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 22, "subsecao_id": null, "ordem": 101, "vigente": true}, {"id": 102, "numero": 102, "numero_texto": "102", "caput": "Art. 102. Compete ao Supremo Tribunal Federal, precipuamente, a guarda da Constituição, cabendo-lhe:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 22, "subsecao_id": null, "ordem": 102, "vigente": true}, {"id": 103, "numero": 103, "numero_texto": "103", "caput": "Art. 103. Podem propor a ação direta de inconstitucionalidade e a ação declaratória de constitucionalidade: (Vigência)", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 22, "subsecao_id": null, "ordem": 103, "vigente": true}, {"id": 104, "numero": 104, "numero_texto": "104", "caput": "Art. 104. O Superior Tribunal de Justiça compõe-se de, no mínimo, trinta e três Ministros.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 23, "subsecao_id": null, "ordem": 104, "vigente": true}, {"id": 105, "numero": 105, "numero_texto": "105", "caput": "Art. 105. Compete ao Superior Tribunal de Justiça:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 23, "subsecao_id": null, "ordem": 105, "vigente": true}, {"id": 106, "numero": 106, "numero_texto": "106", "caput": "Art. 106. São órgãos da Justiça Federal:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 24, "subsecao_id": null, "ordem": 106, "vigente": true}, {"id": 107, "numero": 107, "numero_texto": "107", "caput": "Art. 107. Os Tribunais Regionais Federais compõem-se de, no mínimo, sete juízes, recrutados, quando possível, na respectiva região e nomeados pelo Presidente da República dentre brasileiros com mais de trinta e menos de setenta anos de idade, sendo:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 24, "subsecao_id": null, "ordem": 107, "vigente": true}, {"id": 108, "numero": 108, "numero_texto": "108", "caput": "Art. 108. Compete aos Tribunais Regionais Federais:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 24, "subsecao_id": null, "ordem": 108, "vigente": true}, {"id": 109, "numero": 109, "numero_texto": "109", "caput": "Art. 109. Aos juízes federais compete processar e julgar:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 24, "subsecao_id": null, "ordem": 109, "vigente": true}, {"id": 110, "numero": 110, "numero_texto": "110", "caput": "Art. 110. Cada Estado, bem como o Distrito Federal, constituirá uma seção judiciária que terá por sede a respectiva Capital, e varas localizadas segundo o estabelecido em lei.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 24, "subsecao_id": null, "ordem": 110, "vigente": true}, {"id": 111, "numero": 111, "numero_texto": "111", "caput": "Art. 111. São órgãos da Justiça do Trabalho:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 25, "subsecao_id": null, "ordem": 111, "vigente": true}, {"id": 112, "numero": 112, "numero_texto": "112", "caput": "Art. 112. A lei criará varas da Justiça do Trabalho, podendo, nas comarcas não abrangidas por sua jurisdição, atribuí-la aos juízes de direito, com recurso para o respectivo Tribunal Regional do Trabalho.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 25, "subsecao_id": null, "ordem": 112, "vigente": true}, {"id": 113, "numero": 113, "numero_texto": "113", "caput": "Art. 113. A lei disporá sobre a constituição, investidura, jurisdição, competência, garantias e condições de exercício dos órgãos da Justiça do Trabalho.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 25, "subsecao_id": null, "ordem": 113, "vigente": true}, {"id": 114, "numero": 114, "numero_texto": "114", "caput": "Art. 114. Compete à Justiça do Trabalho processar e julgar:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 25, "subsecao_id": null, "ordem": 114, "vigente": true}, {"id": 115, "numero": 115, "numero_texto": "115", "caput": "Art. 115. Os Tribunais Regionais do Trabalho compõem-se de, no mínimo, sete juízes, recrutados, quando possível, na respectiva região e nomeados pelo Presidente da República dentre brasileiros com mais de trinta e menos de setenta anos de idade, sendo:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 25, "subsecao_id": null, "ordem": 115, "vigente": true}, {"id": 116, "numero": 116, "numero_texto": "116", "caput": "Art. 116. Nas Varas do Trabalho, a jurisdição será exercida por um juiz singular.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 25, "subsecao_id": null, "ordem": 116, "vigente": true}, {"id": 117, "numero": 118, "numero_texto": "118", "caput": "Art. 118. São órgãos da Justiça Eleitoral:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 26, "subsecao_id": null, "ordem": 117, "vigente": true}, {"id": 118, "numero": 119, "numero_texto": "119", "caput": "Art. 119. O Tribunal Superior Eleitoral compor-se-á, no mínimo, de sete membros, escolhidos:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 26, "subsecao_id": null, "ordem": 118, "vigente": true}, {"id": 119, "numero": 120, "numero_texto": "120", "caput": "Art. 120. Haverá um Tribunal Regional Eleitoral na Capital de cada Estado e no Distrito Federal.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 26, "subsecao_id": null, "ordem": 119, "vigente": true}, {"id": 120, "numero": 121, "numero_texto": "121", "caput": "Art. 121. Lei complementar disporá sobre a organização e competência dos tribunais, dos juízes de direito e das juntas eleitorais.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 26, "subsecao_id": null, "ordem": 120, "vigente": true}, {"id": 121, "numero": 122, "numero_texto": "122", "caput": "Art. 122. São órgãos da Justiça Militar:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 27, "subsecao_id": null, "ordem": 121, "vigente": true}, {"id": 122, "numero": 123, "numero_texto": "123", "caput": "Art. 123. O Superior Tribunal Militar compor-se-á de quinze Ministros vitalícios, nomeados pelo Presidente da República, depois de aprovada a indicação pelo Senado Federal, sendo três dentre oficiais-generais da Marinha, quatro dentre oficiais-generais do Exército, três dentre oficiais-generais da Aeronáutica, todos da ativa e do posto mais elevado da carreira, e cinco dentre civis.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 27, "subsecao_id": null, "ordem": 122, "vigente": true}, {"id": 123, "numero": 124, "numero_texto": "124", "caput": "Art. 124. À Justiça Militar compete processar e julgar os crimes militares definidos em lei.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 27, "subsecao_id": null, "ordem": 123, "vigente": true}, {"id": 124, "numero": 125, "numero_texto": "125", "caput": "Art. 125. Os Estados organizarão sua Justiça, observados os princípios estabelecidos nesta Constituição.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 28, "subsecao_id": null, "ordem": 124, "vigente": true}, {"id": 125, "numero": 126, "numero_texto": "126", "caput": "Art. 126. Para dirimir conflitos fundiários, o Tribunal de Justiça proporá a criação de varas especializadas, com competência exclusiva para questões agrárias.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 15, "secao_id": 28, "subsecao_id": null, "ordem": 125, "vigente": true}, {"id": 126, "numero": 127, "numero_texto": "127", "caput": "Art. 127. O Ministério Público é instituição permanente, essencial à função jurisdicional do Estado, incumbindo-lhe a defesa da ordem jurídica, do regime democrático e dos interesses sociais e individuais indisponíveis.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 16, "secao_id": 29, "subsecao_id": null, "ordem": 126, "vigente": true}, {"id": 127, "numero": 128, "numero_texto": "128", "caput": "Art. 128. O Ministério Público abrange:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 16, "secao_id": 29, "subsecao_id": null, "ordem": 127, "vigente": true}, {"id": 128, "numero": 129, "numero_texto": "129", "caput": "Art. 129. São funções institucionais do Ministério Público:", "tipo": "CF", "titulo_id": 4, "capitulo_id": 16, "secao_id": 29, "subsecao_id": null, "ordem": 128, "vigente": true}, {"id": 129, "numero": 130, "numero_texto": "130", "caput": "Art. 130. Aos membros do Ministério Público junto aos Tribunais de Contas aplicam-se as disposições desta seção pertinentes a direitos, vedações e forma de investidura.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 16, "secao_id": 29, "subsecao_id": null, "ordem": 129, "vigente": true}, {"id": 130, "numero": 131, "numero_texto": "131", "caput": "Art. 131. A Advocacia-Geral da União é a instituição que, diretamente ou através de órgão vinculado, representa a União, judicial e extrajudicialmente, cabendo-lhe, nos termos da lei complementar que dispuser sobre sua organização e funcionamento, as atividades de consultoria e assessoramento jurídico do Poder Executivo.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 16, "secao_id": 30, "subsecao_id": null, "ordem": 130, "vigente": true}, {"id": 131, "numero": 132, "numero_texto": "132", "caput": "Art. 132. Os Procuradores dos Estados e do Distrito Federal, organizados em carreira, na qual o ingresso dependerá de concurso público de provas e títulos, com a participação da Ordem dos Advogados do Brasil em todas as suas fases, exercerão a representação judicial e a consultoria jurídica das respectivas unidades federadas.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 16, "secao_id": 30, "subsecao_id": null, "ordem": 131, "vigente": true}, {"id": 132, "numero": 133, "numero_texto": "133", "caput": "Art. 133. O advogado é indispensável à administração da justiça, sendo inviolável por seus atos e manifestações no exercício da profissão, nos limites da lei.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 16, "secao_id": 31, "subsecao_id": null, "ordem": 132, "vigente": true}, {"id": 133, "numero": 134, "numero_texto": "134", "caput": "Art. 134. A Defensoria Pública é instituição permanente, essencial à função jurisdicional do Estado, incumbindo-lhe, como expressão e instrumento do regime democrático, fundamentalmente, a orientação jurídica, a promoção dos direitos humanos e a defesa, em todos os graus, judicial e extrajudicial, dos direitos individuais e coletivos, de forma integral e gratuita, aos necessitados, na forma do inciso LXXIV do art. 5º desta Constituição Federal .", "tipo": "CF", "titulo_id": 4, "capitulo_id": 16, "secao_id": 32, "subsecao_id": null, "ordem": 133, "vigente": true}, {"id": 134, "numero": 135, "numero_texto": "135", "caput": "Art. 135. Os servidores integrantes das carreiras disciplinadas nas Seções II e III deste Capítulo serão remunerados na forma do art. 39, § 4º.", "tipo": "CF", "titulo_id": 4, "capitulo_id": 16, "secao_id": 32, "subsecao_id": null, "ordem": 134, "vigente": true}, {"id": 135, "numero": 136, "numero_texto": "136", "caput": "Art. 136. O Presidente da República pode, ouvidos o Conselho da República e o Conselho de Defesa Nacional, decretar estado de defesa para preservar ou prontamente restabelecer, em locais restritos e determinados, a ordem pública ou a paz social ameaçadas por grave e iminente instabilidade institucional ou atingidas por calamidades de grandes proporções na natureza.", "tipo": "CF", "titulo_id": 5, "capitulo_id": 17, "secao_id": 33, "subsecao_id": null, "ordem": 135, "vigente": true}, {"id": 136, "numero": 137, "numero_texto": "137", "caput": "Art. 137. O Presidente da República pode, ouvidos o Conselho da República e o Conselho de Defesa Nacional, solicitar ao Congresso Nacional autorização para decretar o estado de sítio nos casos de:", "tipo": "CF", "titulo_id": 5, "capitulo_id": 17, "secao_id": 34, "subsecao_id": null, "ordem": 136, "vigente": true}, {"id": 137, "numero": 138, "numero_texto": "138", "caput": "Art. 138. O decreto do estado de sítio indicará sua duração, as normas necessárias a sua execução e as garantias constitucionais que ficarão suspensas, e, depois de publicado, o Presidente da República designará o executor das medidas específicas e as áreas abrangidas.", "tipo": "CF", "titulo_id": 5, "capitulo_id": 17, "secao_id": 34, "subsecao_id": null, "ordem": 137, "vigente": true}, {"id": 138, "numero": 139, "numero_texto": "139", "caput": "Art. 139. Na vigência do estado de sítio decretado com fundamento no art. 137, I, só poderão ser tomadas contra as pessoas as seguintes medidas:", "tipo": "CF", "titulo_id": 5, "capitulo_id": 17, "secao_id": 34, "subsecao_id": null, "ordem": 138, "vigente": true}, {"id": 139, "numero": 140, "numero_texto": "140", "caput": "Art. 140. A Mesa do Congresso Nacional, ouvidos os líderes partidários, designará Comissão composta de cinco de seus membros para acompanhar e fiscalizar a execução das medidas referentes ao estado de defesa e ao estado de sítio.", "tipo": "CF", "titulo_id": 5, "capitulo_id": 17, "secao_id": 35, "subsecao_id": null, "ordem": 139, "vigente": true}, {"id": 140, "numero": 141, "numero_texto": "141", "caput": "Art. 141. Cessado o estado de defesa ou o estado de sítio, cessarão também seus efeitos, sem prejuízo da responsabilidade pelos ilícitos cometidos por seus executores ou agentes.", "tipo": "CF", "titulo_id": 5, "capitulo_id": 17, "secao_id": 35, "subsecao_id": null, "ordem": 140, "vigente": true}, {"id": 141, "numero": 142, "numero_texto": "142", "caput": "Art. 142. As Forças Armadas, constituídas pela Marinha, pelo Exército e pela Aeronáutica, são instituições nacionais permanentes e regulares, organizadas com base na hierarquia e na disciplina, sob a autoridade suprema do Presidente da República, e destinam-se à defesa da Pátria, à garantia dos poderes constitucionais e, por iniciativa de qualquer destes, da lei e da ordem.", "tipo": "CF", "titulo_id": 5, "capitulo_id": 18, "secao_id": null, "subsecao_id": null, "ordem": 141, "vigente": true}, {"id": 142, "numero": 143, "numero_texto": "143", "caput": "Art. 143. O serviço militar é obrigatório nos termos da lei.", "tipo": "CF", "titulo_id": 5, "capitulo_id": 18, "secao_id": null, "subsecao_id": null, "ordem": 142, "vigente": true}, {"id": 143, "numero": 144, "numero_texto": "144", "caput": "Art. 144. A segurança pública, dever do Estado, direito e responsabilidade de todos, é exercida para a preservação da ordem pública e da incolumidade das pessoas e do patrimônio, através dos seguintes órgãos:", "tipo": "CF", "titulo_id": 5, "capitulo_id": 19, "secao_id": null, "subsecao_id": null, "ordem": 143, "vigente": true}, {"id": 144, "numero": 145, "numero_texto": "145", "caput": "Art. 145. A União, os Estados, o Distrito Federal e os Municípios poderão instituir os seguintes tributos:", "tipo": "CF", "titulo_id": 6, "capitulo_id": 20, "secao_id": 36, "subsecao_id": null, "ordem": 144, "vigente": true}, {"id": 145, "numero": 146, "numero_texto": "146", "caput": "Art. 146. Cabe à lei complementar:", "tipo": "CF", "titulo_id": 6, "capitulo_id": 20, "secao_id": 36, "subsecao_id": null, "ordem": 145, "vigente": true}, {"id": 146, "numero": 147, "numero_texto": "147", "caput": "Art. 147. Competem à União, em Território Federal, os impostos estaduais e, se o Território não for dividido em Municípios, cumulativamente, os impostos municipais; ao Distrito Federal cabem os impostos municipais.", "tipo": "CF", "titulo_id": 6, "capitulo_id": 20, "secao_id": 36, "subsecao_id": null, "ordem": 146, "vigente": true}, {"id": 147, "numero": 148, "numero_texto": "148", "caput": "Art. 148. A União, mediante lei complementar, poderá instituir empréstimos compulsórios:", "tipo": "CF", "titulo_id": 6, "capitulo_id": 20, "secao_id": 36, "subsecao_id": null, "ordem": 147, "vigente": true}, {"id": 148, "numero": 149, "numero_texto": "149", "caput": "Art. 149. Compete exclusivamente à União instituir contribuições sociais, de intervenção no domínio econômico e de interesse das categorias profissionais ou econômicas, como instrumento de sua atuação nas respectivas áreas, observado o disposto nos arts. 146, III, e 150, I e III, e sem prejuízo do previsto no art. 195, § 6º, relativamente às contribuições a que alude o dispositivo.", "tipo": "CF", "titulo_id": 6, "capitulo_id": 20, "secao_id": 36, "subsecao_id": null, "ordem": 148, "vigente": true}, {"id": 149, "numero": 150, "numero_texto": "150", "caput": "Art. 150. Sem prejuízo de outras garantias asseguradas ao contribuinte, é vedado à União, aos Estados, ao Distrito Federal e aos Municípios:", "tipo": "CF", "titulo_id": 6, "capitulo_id": 20, "secao_id": 37, "subsecao_id": null, "ordem": 149, "vigente": true}, {"id": 150, "numero": 151, "numero_texto": "151", "caput": "Art. 151. É vedado à União:", "tipo": "CF", "titulo_id": 6, "capitulo_id": 20, "secao_id": 37, "subsecao_id": null, "ordem": 150, "vigente": true}, {"id": 151, "numero": 152, "numero_texto": "152", "caput": "Art. 152. É vedado aos Estados, ao Distrito Federal e aos Municípios estabelecer diferença tributária entre bens e serviços, de qualquer natureza, em razão de sua procedência ou destino.", "tipo": "CF", "titulo_id": 6, "capitulo_id": 20, "secao_id": 37, "subsecao_id": null, "ordem": 151, "vigente": true}, {"id": 152, "numero": 153, "numero_texto": "153", "caput": "Art. 153. Compete à União instituir impostos sobre:", "tipo": "CF", "titulo_id": 6, "capitulo_id": 20, "secao_id": 38, "subsecao_id": null, "ordem": 152, "vigente": true}, {"id": 153, "numero": 154, "numero_texto": "154", "caput": "Art. 154. A União poderá instituir:", "tipo": "CF", "titulo_id": 6, "capitulo_id": 20, "secao_id": 38, "subsecao_id": null, "ordem": 153, "vigente": true}, {"id": 154, "numero": 155, "numero_texto": "155", "caput": "Art. 155. Compete aos Estados e ao Distrito Federal instituir impostos sobre:", "tipo": "CF", "titulo_id": 6, "capitulo_id": 20, "secao_id": 39, "subsecao_id": null, "ordem": 154, "vigente": true}, {"id": 155, "numero": 156, "numero_texto": "156", "caput": "Art. 156. Compete aos Municípios instituir impostos sobre:", "tipo": "CF", "titulo_id": 6, "capitulo_id": 20, "secao_id": 40, "subsecao_id": null, "ordem": 155, "vigente": true}, {"id": 156, "numero": 157, "numero_texto": "157", "caput": "Art. 157. Pertencem aos Estados e ao Distrito Federal:", "tipo": "CF", "titulo_id": 6, "capitulo_id": 20, "secao_id": 41, "subsecao_id": null, "ordem": 156, "vigente": true}, {"id": 157, "numero": 158, "numero_texto": "158", "caput": "Art. 158. Pertencem aos Municípios:", "tipo": "CF", "titulo_id": 6, "capitulo_id": 20, "secao_id": 41, "subsecao_id": null, "ordem": 157, "vigente": true}, {"id": 158, "numero": 159, "numero_texto": "159", "caput": "Art. 159. A União entregará:", "tipo": "CF", "titulo_id": 6, "capitulo_id": 20, "secao_id": 41, "subsecao_id": null, "ordem": 158, "vigente": true}, {"id": 159, "numero": 160, "numero_texto": "160", "caput": "Art. 160. É vedada a retenção ou qualquer restrição à entrega e ao emprego dos recursos atribuídos, nesta seção, aos Estados, ao Distrito Federal e aos Municípios, neles compreendidos adicionais e acréscimos relativos a impostos.", "tipo": "CF", "titulo_id": 6, "capitulo_id": 20, "secao_id": 41, "subsecao_id": null, "ordem": 159, "vigente": true}, {"id": 160, "numero": 161, "numero_texto": "161", "caput": "Art. 161. Cabe à lei complementar:", "tipo": "CF", "titulo_id": 6, "capitulo_id": 20, "secao_id": 41, "subsecao_id": null, "ordem": 160, "vigente": true}, {"id": 161, "numero": 162, "numero_texto": "162", "caput": "Art. 162. A União, os Estados, o Distrito Federal e os Municípios divulgarão, até o último dia do mês subseqüente ao da arrecadação, os montantes de cada um dos tributos arrecadados, os recursos recebidos, os valores de origem tributária entregues e a entregar e a expressão numérica dos critérios de rateio.", "tipo": "CF", "titulo_id": 6, "capitulo_id": 20, "secao_id": 41, "subsecao_id": null, "ordem": 161, "vigente": true}, {"id": 162, "numero": 163, "numero_texto": "163", "caput": "Art. 163. Lei complementar disporá sobre:", "tipo": "CF", "titulo_id": 6, "capitulo_id": 21, "secao_id": 42, "subsecao_id": null, "ordem": 162, "vigente": true}, {"id": 163, "numero": 164, "numero_texto": "164", "caput": "Art. 164. A competência da União para emitir moeda será exercida exclusivamente pelo banco central.", "tipo": "CF", "titulo_id": 6, "capitulo_id": 21, "secao_id": 42, "subsecao_id": null, "ordem": 163, "vigente": true}, {"id": 164, "numero": 165, "numero_texto": "165", "caput": "Art. 165. Leis de iniciativa do Poder Executivo estabelecerão:", "tipo": "CF", "titulo_id": 6, "capitulo_id": 21, "secao_id": 43, "subsecao_id": null, "ordem": 164, "vigente": true}, {"id": 165, "numero": 166, "numero_texto": "166", "caput": "Art. 166. Os projetos de lei relativos ao plano plurianual, às diretrizes orçamentárias, ao orçamento anual e aos créditos adicionais serão apreciados pelas duas Casas do Congresso Nacional, na forma do regimento comum.", "tipo": "CF", "titulo_id": 6, "capitulo_id": 21, "secao_id": 43, "subsecao_id": null, "ordem": 165, "vigente": true}, {"id": 166, "numero": 167, "numero_texto": "167", "caput": "Art. 167. São vedados:", "tipo": "CF", "titulo_id": 6, "capitulo_id": 21, "secao_id": 43, "subsecao_id": null, "ordem": 166, "vigente": true}, {"id": 167, "numero": 168, "numero_texto": "168", "caput": "Art. 168. Os recursos correspondentes às dotações orçamentárias, compreendidos os créditos suplementares e especiais, destinados aos órgãos dos Poderes Legislativo e Judiciário, do Ministério Público e da Defensoria Pública, ser-lhes-ão entregues até o dia 20 de cada mês, em duodécimos, na forma da lei complementar a que se refere o art. 165, § 9º.", "tipo": "CF", "titulo_id": 6, "capitulo_id": 21, "secao_id": 43, "subsecao_id": null, "ordem": 167, "vigente": true}, {"id": 168, "numero": 169, "numero_texto": "169", "caput": "Art. 169. A despesa com pessoal ativo e inativo e pensionistas da União, dos Estados, do Distrito Federal e dos Municípios não pode exceder os limites estabelecidos em lei complementar.", "tipo": "CF", "titulo_id": 6, "capitulo_id": 21, "secao_id": 43, "subsecao_id": null, "ordem": 168, "vigente": true}, {"id": 169, "numero": 170, "numero_texto": "170", "caput": "Art. 170. A ordem econômica, fundada na valorização do trabalho humano e na livre iniciativa, tem por fim assegurar a todos existência digna, conforme os ditames da justiça social, observados os seguintes princípios:", "tipo": "CF", "titulo_id": 7, "capitulo_id": 22, "secao_id": null, "subsecao_id": null, "ordem": 169, "vigente": true}, {"id": 170, "numero": 172, "numero_texto": "172", "caput": "Art. 172. A lei disciplinará, com base no interesse nacional, os investimentos de capital estrangeiro, incentivará os reinvestimentos e regulará a remessa de lucros.", "tipo": "CF", "titulo_id": 7, "capitulo_id": 22, "secao_id": null, "subsecao_id": null, "ordem": 170, "vigente": true}, {"id": 171, "numero": 173, "numero_texto": "173", "caput": "Art. 173. Ressalvados os casos previstos nesta Constituição, a exploração direta de atividade econômica pelo Estado só será permitida quando necessária aos imperativos da segurança nacional ou a relevante interesse coletivo, conforme definidos em lei.", "tipo": "CF", "titulo_id": 7, "capitulo_id": 22, "secao_id": null, "subsecao_id": null, "ordem": 171, "vigente": true}, {"id": 172, "numero": 174, "numero_texto": "174", "caput": "Art. 174. Como agente normativo e regulador da atividade econômica, o Estado exercerá, na forma da lei, as funções de fiscalização, incentivo e planejamento, sendo este determinante para o setor público e indicativo para o setor privado.", "tipo": "CF", "titulo_id": 7, "capitulo_id": 22, "secao_id": null, "subsecao_id": null, "ordem": 172, "vigente": true}, {"id": 173, "numero": 175, "numero_texto": "175", "caput": "Art. 175. Incumbe ao Poder Público, na forma da lei, diretamente ou sob regime de concessão ou permissão, sempre através de licitação, a prestação de serviços públicos.", "tipo": "CF", "titulo_id": 7, "capitulo_id": 22, "secao_id": null, "subsecao_id": null, "ordem": 173, "vigente": true}, {"id": 174, "numero": 176, "numero_texto": "176", "caput": "Art. 176. As jazidas, em lavra ou não, e demais recursos minerais e os potenciais de energia hidráulica constituem propriedade distinta da do solo, para efeito de exploração ou aproveitamento, e pertencem à União, garantida ao concessionário a propriedade do produto da lavra.", "tipo": "CF", "titulo_id": 7, "capitulo_id": 22, "secao_id": null, "subsecao_id": null, "ordem": 174, "vigente": true}, {"id": 175, "numero": 177, "numero_texto": "177", "caput": "Art. 177. Constituem monopólio da União:", "tipo": "CF", "titulo_id": 7, "capitulo_id": 22, "secao_id": null, "subsecao_id": null, "ordem": 175, "vigente": true}, {"id": 176, "numero": 178, "numero_texto": "178", "caput": "Art. 178. A lei disporá sobre a ordenação dos transportes aéreo, aquático e terrestre, devendo, quanto à ordenação do transporte internacional, observar os acordos firmados pela União, atendido o princípio da reciprocidade.", "tipo": "CF", "titulo_id": 7, "capitulo_id": 22, "secao_id": null, "subsecao_id": null, "ordem": 176, "vigente": true}, {"id": 177, "numero": 179, "numero_texto": "179", "caput": "Art. 179. A União, os Estados, o Distrito Federal e os Municípios dispensarão às microempresas e às empresas de pequeno porte, assim definidas em lei, tratamento jurídico diferenciado, visando a incentivá-las pela simplificação de suas obrigações administrativas, tributárias, previdenciárias e creditícias, ou pela eliminação ou redução destas por meio de lei.", "tipo": "CF", "titulo_id": 7, "capitulo_id": 22, "secao_id": null, "subsecao_id": null, "ordem": 177, "vigente": true}, {"id": 178, "numero": 180, "numero_texto": "180", "caput": "Art. 180. A União, os Estados, o Distrito Federal e os Municípios promoverão e incentivarão o turismo como fator de desenvolvimento social e econômico.", "tipo": "CF", "titulo_id": 7, "capitulo_id": 22, "secao_id": null, "subsecao_id": null, "ordem": 178, "vigente": true}, {"id": 179, "numero": 181, "numero_texto": "181", "caput": "Art. 181. O atendimento de requisição de documento ou informação de natureza comercial, feita por autoridade administrativa ou judiciária estrangeira, a pessoa física ou jurídica residente ou domiciliada no País dependerá de autorização do Poder competente.", "tipo": "CF", "titulo_id": 7, "capitulo_id": 22, "secao_id": null, "subsecao_id": null, "ordem": 179, "vigente": true}, {"id": 180, "numero": 182, "numero_texto": "182", "caput": "Art. 182. A política de desenvolvimento urbano, executada pelo Poder Público municipal, conforme diretrizes gerais fixadas em lei, tem por objetivo ordenar o pleno desenvolvimento das funções sociais da cidade e garantir o bem- estar de seus habitantes. (Regulamento)", "tipo": "CF", "titulo_id": 7, "capitulo_id": 23, "secao_id": null, "subsecao_id": null, "ordem": 180, "vigente": true}, {"id": 181, "numero": 183, "numero_texto": "183", "caput": "Art. 183. Aquele que possuir como sua área urbana de até duzentos e cinqüenta metros quadrados, por cinco anos, ininterruptamente e sem oposição, utilizando-a para sua moradia ou de sua família, adquirir-lhe-á o domínio, desde que não seja proprietário de outro imóvel urbano ou rural. (Regulamento)", "tipo": "CF", "titulo_id": 7, "capitulo_id": 23, "secao_id": null, "subsecao_id": null, "ordem": 181, "vigente": true}, {"id": 182, "numero": 184, "numero_texto": "184", "caput": "Art. 184. Compete à União desapropriar por interesse social, para fins de reforma agrária, o imóvel rural que não esteja cumprindo sua função social, mediante prévia e justa indenização em títulos da dívida agrária, com cláusula de preservação do valor real, resgatáveis no prazo de até vinte anos, a partir do segundo ano de sua emissão, e cuja utilização será definida em lei.", "tipo": "CF", "titulo_id": 7, "capitulo_id": 24, "secao_id": null, "subsecao_id": null, "ordem": 182, "vigente": true}, {"id": 183, "numero": 185, "numero_texto": "185", "caput": "Art. 185. São insuscetíveis de desapropriação para fins de reforma agrária:", "tipo": "CF", "titulo_id": 7, "capitulo_id": 24, "secao_id": null, "subsecao_id": null, "ordem": 183, "vigente": true}, {"id": 184, "numero": 186, "numero_texto": "186", "caput": "Art. 186. A função social é cumprida quando a propriedade rural atende, simultaneamente, segundo critérios e graus de exigência estabelecidos em lei, aos seguintes requisitos:", "tipo": "CF", "titulo_id": 7, "capitulo_id": 24, "secao_id": null, "subsecao_id": null, "ordem": 184, "vigente": true}, {"id": 185, "numero": 187, "numero_texto": "187", "caput": "Art. 187. A política agrícola será planejada e executada na forma da lei, com a participação efetiva do setor de produção, envolvendo produtores e trabalhadores rurais, bem como dos setores de comercialização, de armazenamento e de transportes, levando em conta, especialmente:", "tipo": "CF", "titulo_id": 7, "capitulo_id": 24, "secao_id": null, "subsecao_id": null, "ordem": 185, "vigente": true}, {"id": 186, "numero": 188, "numero_texto": "188", "caput": "Art. 188. A destinação de terras públicas e devolutas será compatibilizada com a política agrícola e com o plano nacional de reforma agrária.", "tipo": "CF", "titulo_id": 7, "capitulo_id": 24, "secao_id": null, "subsecao_id": null, "ordem": 186, "vigente": true}, {"id": 187, "numero": 189, "numero_texto": "189", "caput": "Art. 189. Os beneficiários da distribuição de imóveis rurais pela reforma agrária receberão títulos de domínio ou de concessão de uso, inegociáveis pelo prazo de dez anos.", "tipo": "CF", "titulo_id": 7, "capitulo_id": 24, "secao_id": null, "subsecao_id": null, "ordem": 187, "vigente": true}, {"id": 188, "numero": 190, "numero_texto": "190", "caput": "Art. 190. A lei regulará e limitará a aquisição ou o arrendamento de propriedade rural por pessoa física ou jurídica estrangeira e estabelecerá os casos que dependerão de autorização do Congresso Nacional.", "tipo": "CF", "titulo_id": 7, "capitulo_id": 24, "secao_id": null, "subsecao_id": null, "ordem": 188, "vigente": true}, {"id": 189, "numero": 191, "numero_texto": "191", "caput": "Art. 191. Aquele que, não sendo proprietário de imóvel rural ou urbano, possua como seu, por cinco anos ininterruptos, sem oposição, área de terra, em zona rural, não superior a cinqüenta hectares, tornando-a produtiva por seu trabalho ou de sua família, tendo nela sua moradia, adquirir-lhe-á a propriedade.", "tipo": "CF", "titulo_id": 7, "capitulo_id": 24, "secao_id": null, "subsecao_id": null, "ordem": 189, "vigente": true}, {"id": 190, "numero": 192, "numero_texto": "192", "caput": "Art. 192. O sistema financeiro nacional, estruturado de forma a promover o desenvolvimento equilibrado do País e a servir aos interesses da coletividade, em todas as partes que o compõem, abrangendo as cooperativas de crédito, será regulado por leis complementares que disporão, inclusive, sobre a participação do capital estrangeiro nas instituições que o integram.", "tipo": "CF", "titulo_id": 7, "capitulo_id": 25, "secao_id": null, "subsecao_id": null, "ordem": 190, "vigente": true}, {"id": 191, "numero": 193, "numero_texto": "193", "caput": "Art. 193. A ordem social tem como base o primado do trabalho, e como objetivo o bem-estar e a justiça sociais.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 26, "secao_id": null, "subsecao_id": null, "ordem": 191, "vigente": true}, {"id": 192, "numero": 194, "numero_texto": "194", "caput": "Art. 194. A seguridade social compreende um conjunto integrado de ações de iniciativa dos Poderes Públicos e da sociedade, destinadas a assegurar os direitos relativos à saúde, à previdência e à assistência social.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 27, "secao_id": 44, "subsecao_id": null, "ordem": 192, "vigente": true}, {"id": 193, "numero": 195, "numero_texto": "195", "caput": "Art. 195. A seguridade social será financiada por toda a sociedade, de forma direta e indireta, nos termos da lei, mediante recursos provenientes dos orçamentos da União, dos Estados, do Distrito Federal e dos Municípios, e das seguintes contribuições sociais:", "tipo": "CF", "titulo_id": 8, "capitulo_id": 27, "secao_id": 44, "subsecao_id": null, "ordem": 193, "vigente": true}, {"id": 194, "numero": 196, "numero_texto": "196", "caput": "Art. 196. A saúde é direito de todos e dever do Estado, garantido mediante políticas sociais e econômicas que visem à redução do risco de doença e de outros agravos e ao acesso universal e igualitário às ações e serviços para sua promoção, proteção e recuperação.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 27, "secao_id": 45, "subsecao_id": null, "ordem": 194, "vigente": true}, {"id": 195, "numero": 197, "numero_texto": "197", "caput": "Art. 197. São de relevância pública as ações e serviços de saúde, cabendo ao Poder Público dispor, nos termos da lei, sobre sua regulamentação, fiscalização e controle, devendo sua execução ser feita diretamente ou através de terceiros e, também, por pessoa física ou jurídica de direito privado.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 27, "secao_id": 45, "subsecao_id": null, "ordem": 195, "vigente": true}, {"id": 196, "numero": 198, "numero_texto": "198", "caput": "Art. 198. As ações e serviços públicos de saúde integram uma rede regionalizada e hierarquizada e constituem um sistema único, organizado de acordo com as seguintes diretrizes:", "tipo": "CF", "titulo_id": 8, "capitulo_id": 27, "secao_id": 45, "subsecao_id": null, "ordem": 196, "vigente": true}, {"id": 197, "numero": 199, "numero_texto": "199", "caput": "Art. 199. A assistência à saúde é livre à iniciativa privada.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 27, "secao_id": 45, "subsecao_id": null, "ordem": 197, "vigente": true}, {"id": 198, "numero": 200, "numero_texto": "200", "caput": "Art. 200. Ao sistema único de saúde compete, além de outras atribuições, nos termos da lei:", "tipo": "CF", "titulo_id": 8, "capitulo_id": 27, "secao_id": 45, "subsecao_id": null, "ordem": 198, "vigente": true}, {"id": 199, "numero": 201, "numero_texto": "201", "caput": "Art. 201. A previdência social será organizada sob a forma do Regime Geral de Previdência Social, de caráter contributivo e de filiação obrigatória, observados critérios que preservem o equilíbrio financeiro e atuarial, e atenderá, na forma da lei, a:", "tipo": "CF", "titulo_id": 8, "capitulo_id": 27, "secao_id": 46, "subsecao_id": null, "ordem": 199, "vigente": true}, {"id": 200, "numero": 202, "numero_texto": "202", "caput": "Art. 202. O regime de previdência privada, de caráter complementar e organizado de forma autônoma em relação ao regime geral de previdência social, será facultativo, baseado na constituição de reservas que garantam o benefício contratado, e regulado por lei complementar.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 27, "secao_id": 46, "subsecao_id": null, "ordem": 200, "vigente": true}, {"id": 201, "numero": 203, "numero_texto": "203", "caput": "Art. 203. A assistência social será prestada a quem dela necessitar, independentemente de contribuição à seguridade social, e tem por objetivos:", "tipo": "CF", "titulo_id": 8, "capitulo_id": 27, "secao_id": 47, "subsecao_id": null, "ordem": 201, "vigente": true}, {"id": 202, "numero": 204, "numero_texto": "204", "caput": "Art. 204. As ações governamentais na área da assistência social serão realizadas com recursos do orçamento da seguridade social, previstos no art. 195, além de outras fontes, e organizadas com base nas seguintes diretrizes:", "tipo": "CF", "titulo_id": 8, "capitulo_id": 27, "secao_id": 47, "subsecao_id": null, "ordem": 202, "vigente": true}, {"id": 203, "numero": 205, "numero_texto": "205", "caput": "Art. 205. A educação, direito de todos e dever do Estado e da família, será promovida e incentivada com a colaboração da sociedade, visando ao pleno desenvolvimento da pessoa, seu preparo para o exercício da cidadania e sua qualificação para o trabalho.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 28, "secao_id": 48, "subsecao_id": null, "ordem": 203, "vigente": true}, {"id": 204, "numero": 206, "numero_texto": "206", "caput": "Art. 206. O ensino será ministrado com base nos seguintes princípios:", "tipo": "CF", "titulo_id": 8, "capitulo_id": 28, "secao_id": 48, "subsecao_id": null, "ordem": 204, "vigente": true}, {"id": 205, "numero": 207, "numero_texto": "207", "caput": "Art. 207. As universidades gozam de autonomia didático-científica, administrativa e de gestão financeira e patrimonial, e obedecerão ao princípio de indissociabilidade entre ensino, pesquisa e extensão.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 28, "secao_id": 48, "subsecao_id": null, "ordem": 205, "vigente": true}, {"id": 206, "numero": 208, "numero_texto": "208", "caput": "Art. 208. O dever do Estado com a educação será efetivado mediante a garantia de:", "tipo": "CF", "titulo_id": 8, "capitulo_id": 28, "secao_id": 48, "subsecao_id": null, "ordem": 206, "vigente": true}, {"id": 207, "numero": 209, "numero_texto": "209", "caput": "Art. 209. O ensino é livre à iniciativa privada, atendidas as seguintes condições:", "tipo": "CF", "titulo_id": 8, "capitulo_id": 28, "secao_id": 48, "subsecao_id": null, "ordem": 207, "vigente": true}, {"id": 208, "numero": 210, "numero_texto": "210", "caput": "Art. 210. Serão fixados conteúdos mínimos para o ensino fundamental, de maneira a assegurar formação básica comum e respeito aos valores culturais e artísticos, nacionais e regionais.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 28, "secao_id": 48, "subsecao_id": null, "ordem": 208, "vigente": true}, {"id": 209, "numero": 211, "numero_texto": "211", "caput": "Art. 211. A União, os Estados, o Distrito Federal e os Municípios organizarão em regime de colaboração seus sistemas de ensino.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 28, "secao_id": 48, "subsecao_id": null, "ordem": 209, "vigente": true}, {"id": 210, "numero": 212, "numero_texto": "212", "caput": "Art. 212. A União aplicará, anualmente, nunca menos de dezoito, e os Estados, o Distrito Federal e os Municípios vinte e cinco por cento, no mínimo, da receita resultante de impostos, compreendida a proveniente de transferências, na manutenção e desenvolvimento do ensino.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 28, "secao_id": 48, "subsecao_id": null, "ordem": 210, "vigente": true}, {"id": 211, "numero": 213, "numero_texto": "213", "caput": "Art. 213. Os recursos públicos serão destinados às escolas públicas, podendo ser dirigidos a escolas comunitárias, confessionais ou filantrópicas, definidas em lei, que:", "tipo": "CF", "titulo_id": 8, "capitulo_id": 28, "secao_id": 48, "subsecao_id": null, "ordem": 211, "vigente": true}, {"id": 212, "numero": 214, "numero_texto": "214", "caput": "Art. 214. A lei estabelecerá o plano nacional de educação, de duração decenal, com o objetivo de articular o sistema nacional de educação em regime de colaboração e definir diretrizes, objetivos, metas e estratégias de implementação para assegurar a manutenção e desenvolvimento do ensino em seus diversos níveis, etapas e modalidades por meio de ações integradas dos poderes públicos das diferentes esferas federativas que conduzam a:", "tipo": "CF", "titulo_id": 8, "capitulo_id": 28, "secao_id": 48, "subsecao_id": null, "ordem": 212, "vigente": true}, {"id": 213, "numero": 215, "numero_texto": "215", "caput": "Art. 215. O Estado garantirá a todos o pleno exercício dos direitos culturais e acesso às fontes da cultura nacional, e apoiará e incentivará a valorização e a difusão das manifestações culturais.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 28, "secao_id": 49, "subsecao_id": null, "ordem": 213, "vigente": true}, {"id": 214, "numero": 216, "numero_texto": "216", "caput": "Art. 216. Constituem patrimônio cultural brasileiro os bens de natureza material e imaterial, tomados individualmente ou em conjunto, portadores de referência à identidade, à ação, à memória dos diferentes grupos formadores da sociedade brasileira, nos quais se incluem:", "tipo": "CF", "titulo_id": 8, "capitulo_id": 28, "secao_id": 49, "subsecao_id": null, "ordem": 214, "vigente": true}, {"id": 215, "numero": 217, "numero_texto": "217", "caput": "Art. 217. É dever do Estado fomentar práticas desportivas formais e não-formais, como direito de cada um, observados:", "tipo": "CF", "titulo_id": 8, "capitulo_id": 28, "secao_id": 50, "subsecao_id": null, "ordem": 215, "vigente": true}, {"id": 216, "numero": 218, "numero_texto": "218", "caput": "Art. 218. O Estado promoverá e incentivará o desenvolvimento científico, a pesquisa, a capacitação científica e tecnológica e a inovação.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 29, "secao_id": null, "subsecao_id": null, "ordem": 216, "vigente": true}, {"id": 217, "numero": 219, "numero_texto": "219", "caput": "Art. 219. O mercado interno integra o patrimônio nacional e será incentivado de modo a viabilizar o desenvolvimento cultural e sócio-econômico, o bem-estar da população e a autonomia tecnológica do País, nos termos de lei federal.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 29, "secao_id": null, "subsecao_id": null, "ordem": 217, "vigente": true}, {"id": 218, "numero": 220, "numero_texto": "220", "caput": "Art. 220. A manifestação do pensamento, a criação, a expressão e a informação, sob qualquer forma, processo ou veículo não sofrerão qualquer restrição, observado o disposto nesta Constituição.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 30, "secao_id": null, "subsecao_id": null, "ordem": 218, "vigente": true}, {"id": 219, "numero": 221, "numero_texto": "221", "caput": "Art. 221. A produção e a programação das emissoras de rádio e televisão atenderão aos seguintes princípios:", "tipo": "CF", "titulo_id": 8, "capitulo_id": 30, "secao_id": null, "subsecao_id": null, "ordem": 219, "vigente": true}, {"id": 220, "numero": 222, "numero_texto": "222", "caput": "Art. 222. A propriedade de empresa jornalística e de radiodifusão sonora e de sons e imagens é privativa de brasileiros natos ou naturalizados há mais de dez anos, ou de pessoas jurídicas constituídas sob as leis brasileiras e que tenham sede no País.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 30, "secao_id": null, "subsecao_id": null, "ordem": 220, "vigente": true}, {"id": 221, "numero": 223, "numero_texto": "223", "caput": "Art. 223. Compete ao Poder Executivo outorgar e renovar concessão, permissão e autorização para o serviço de radiodifusão sonora e de sons e imagens, observado o princípio da complementaridade dos sistemas privado, público e estatal.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 30, "secao_id": null, "subsecao_id": null, "ordem": 221, "vigente": true}, {"id": 222, "numero": 224, "numero_texto": "224", "caput": "Art. 224. Para os efeitos do disposto neste capítulo, o Congresso Nacional instituirá, como seu órgão auxiliar, o Conselho de Comunicação Social, na forma da lei.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 30, "secao_id": null, "subsecao_id": null, "ordem": 222, "vigente": true}, {"id": 223, "numero": 225, "numero_texto": "225", "caput": "Art. 225. Todos têm direito ao meio ambiente ecologicamente equilibrado, bem de uso comum do povo e essencial à sadia qualidade de vida, impondo-se ao Poder Público e à coletividade o dever de defendê-lo e preservá- lo para as presentes e futuras gerações.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 31, "secao_id": null, "subsecao_id": null, "ordem": 223, "vigente": true}, {"id": 224, "numero": 226, "numero_texto": "226", "caput": "Art. 226. A família, base da sociedade, tem especial proteção do Estado.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 32, "secao_id": null, "subsecao_id": null, "ordem": 224, "vigente": true}, {"id": 225, "numero": 227, "numero_texto": "227", "caput": "Art. 227. É dever da família, da sociedade e do Estado assegurar à criança, ao adolescente e ao jovem, com absoluta prioridade, o direito à vida, à saúde, à alimentação, à educação, ao lazer, à profissionalização, à cultura, à dignidade, ao respeito, à liberdade e à convivência familiar e comunitária, além de colocá-los a salvo de toda forma de negligência, discriminação, exploração, violência, crueldade e opressão.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 32, "secao_id": null, "subsecao_id": null, "ordem": 225, "vigente": true}, {"id": 226, "numero": 228, "numero_texto": "228", "caput": "Art. 228. São penalmente inimputáveis os menores de dezoito anos, sujeitos às normas da legislação especial.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 32, "secao_id": null, "subsecao_id": null, "ordem": 226, "vigente": true}, {"id": 227, "numero": 229, "numero_texto": "229", "caput": "Art. 229. Os pais têm o dever de assistir, criar e educar os filhos menores, e os filhos maiores têm o dever de ajudar e amparar os pais na velhice, carência ou enfermidade.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 32, "secao_id": null, "subsecao_id": null, "ordem": 227, "vigente": true}, {"id": 228, "numero": 230, "numero_texto": "230", "caput": "Art. 230. A família, a sociedade e o Estado têm o dever de amparar as pessoas idosas, assegurando sua participação na comunidade, defendendo sua dignidade e bem-estar e garantindo-lhes o direito à vida.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 32, "secao_id": null, "subsecao_id": null, "ordem": 228, "vigente": true}, {"id": 229, "numero": 231, "numero_texto": "231", "caput": "Art. 231. São reconhecidos aos índios sua organização social, costumes, línguas, crenças e tradições, e os direitos originários sobre as terras que tradicionalmente ocupam, competindo à União demarcá-las, proteger e fazer respeitar todos os seus bens. Regulamento", "tipo": "CF", "titulo_id": 8, "capitulo_id": 33, "secao_id": null, "subsecao_id": null, "ordem": 229, "vigente": true}, {"id": 230, "numero": 232, "numero_texto": "232", "caput": "Art. 232. Os índios, suas comunidades e organizações são partes legítimas para ingressar em juízo em defesa de seus direitos e interesses, intervindo o Ministério Público em todos os atos do processo.", "tipo": "CF", "titulo_id": 8, "capitulo_id": 33, "secao_id": null, "subsecao_id": null, "ordem": 230, "vigente": true}, {"id": 231, "numero": 234, "numero_texto": "234", "caput": "Art. 234. É vedado à União, direta ou indiretamente, assumir, em decorrência da criação de Estado, encargos referentes a despesas com pessoal inativo e com encargos e amortizações da dívida interna ou externa da administração pública, inclusive da indireta.", "tipo": "CF", "titulo_id": 9, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 231, "vigente": true}, {"id": 232, "numero": 235, "numero_texto": "235", "caput": "Art. 235. Nos dez primeiros anos da criação de Estado, serão observadas as seguintes normas básicas:", "tipo": "CF", "titulo_id": 9, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 232, "vigente": true}, {"id": 233, "numero": 236, "numero_texto": "236", "caput": "Art. 236. Os serviços notariais e de registro são exercidos em caráter privado, por delegação do Poder Público. (Regulamento)", "tipo": "CF", "titulo_id": 9, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 233, "vigente": true}, {"id": 234, "numero": 237, "numero_texto": "237", "caput": "Art. 237. A fiscalização e o controle sobre o comércio exterior, essenciais à defesa dos interesses fazendários nacionais, serão exercidos pelo Ministério da Fazenda.", "tipo": "CF", "titulo_id": 9, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 234, "vigente": true}, {"id": 235, "numero": 238, "numero_texto": "238", "caput": "Art. 238. A lei ordenará a venda e revenda de combustíveis de petróleo, álcool carburante e outros combustíveis derivados de matérias-primas renováveis, respeitados os princípios desta Constituição.", "tipo": "CF", "titulo_id": 9, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 235, "vigente": true}, {"id": 236, "numero": 239, "numero_texto": "239", "caput": "Art. 239. A arrecadação decorrente das contribuições para o Programa de Integração Social, criado pela Lei Complementar nº 7, de 7 de setembro de 1970, e para o Programa de Formação do Patrimônio do Servidor Público, criado pela Lei Complementar nº 8, de 3 de dezembro de 1970, passa, a partir da promulgação desta Constituição, a financiar, nos termos que a lei dispuser, o programa do seguro-desemprego, outras ações da previdência social e o abono de que trata o § 3º deste artigo.", "tipo": "CF", "titulo_id": 9, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 236, "vigente": true}, {"id": 237, "numero": 240, "numero_texto": "240", "caput": "Art. 240. Ficam ressalvadas do disposto no art. 195 as atuais contribuições compulsórias dos empregadores sobre a folha de salários, destinadas às entidades privadas de serviço social e de formação profissional vinculadas ao sistema sindical.", "tipo": "CF", "titulo_id": 9, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 237, "vigente": true}, {"id": 238, "numero": 241, "numero_texto": "241", "caput": "Art. 241. A União, os Estados, o Distrito Federal e os Municípios disciplinarão por meio de lei os consórcios públicos e os convênios de cooperação entre os entes federados, autorizando a gestão associada de serviços públicos, bem como a transferência total ou parcial de encargos, serviços, pessoal e bens essenciais à continuidade dos serviços transferidos.", "tipo": "CF", "titulo_id": 9, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 238, "vigente": true}, {"id": 239, "numero": 242, "numero_texto": "242", "caput": "Art. 242. O princípio do art. 206, IV, não se aplica às instituições educacionais oficiais criadas por lei estadual ou municipal e existentes na data da promulgação desta Constituição, que não sejam total ou preponderantemente mantidas com recursos públicos.", "tipo": "CF", "titulo_id": 9, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 239, "vigente": true}, {"id": 240, "numero": 243, "numero_texto": "243", "caput": "Art. 243. As propriedades rurais e urbanas de qualquer região do País onde forem localizadas culturas ilegais de plantas psicotrópicas ou a exploração de trabalho escravo na forma da lei serão expropriadas e destinadas à reforma agrária e a programas de habitação popular, sem qualquer indenização ao proprietário e sem prejuízo de outras sanções previstas em lei, observado, no que couber, o disposto no art. 5º.", "tipo": "CF", "titulo_id": 9, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 240, "vigente": true}, {"id": 241, "numero": 244, "numero_texto": "244", "caput": "Art. 244. A lei disporá sobre a adaptação dos logradouros, dos edifícios de uso público e dos veículos de transporte coletivo atualmente existentes a fim de garantir acesso adequado às pessoas portadoras de deficiência, conforme o disposto no art. 227, § 2º.", "tipo": "CF", "titulo_id": 9, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 241, "vigente": true}, {"id": 242, "numero": 245, "numero_texto": "245", "caput": "Art. 245. A lei disporá sobre as hipóteses e condições em que o Poder Público dará assistência aos herdeiros e dependentes carentes de pessoas vitimadas por crime doloso, sem prejuízo da responsabilidade civil do autor do ilícito.", "tipo": "CF", "titulo_id": 9, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 242, "vigente": true}, {"id": 243, "numero": 246, "numero_texto": "246", "caput": "Art. 246. É vedada a adoção de medida provisória na regulamentação de artigo da Constituição cuja redação tenha sido alterada por meio de emenda promulgada entre 1º de janeiro de 1995 até a promulgação desta emenda, inclusive.", "tipo": "CF", "titulo_id": 9, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 243, "vigente": true}, {"id": 244, "numero": 247, "numero_texto": "247", "caput": "Art. 247. As leis previstas no inciso III do § 1º do art. 41 e no § 7º do art. 169 estabelecerão critérios e garantias especiais para a perda do cargo pelo servidor público estável que, em decorrência das atribuições de seu cargo efetivo, desenvolva atividades exclusivas de Estado.", "tipo": "CF", "titulo_id": 9, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 244, "vigente": true}, {"id": 245, "numero": 248, "numero_texto": "248", "caput": "Art. 248. Os benefícios pagos, a qualquer título, pelo órgão responsável pelo regime geral de previdência social, ainda que à conta do Tesouro Nacional, e os não sujeitos ao limite máximo de valor fixado para os benefícios concedidos por esse regime observarão os limites fixados no art. 37, XI.", "tipo": "CF", "titulo_id": 9, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 245, "vigente": true}, {"id": 246, "numero": 249, "numero_texto": "249", "caput": "Art. 249. Com o objetivo de assegurar recursos para o pagamento de proventos de aposentadoria e pensões concedidas aos respectivos servidores e seus dependentes, em adição aos recursos dos respectivos tesouros, a União, os Estados, o Distrito Federal e os Municípios poderão constituir fundos integrados pelos recursos provenientes de contribuições e por bens, direitos e ativos de qualquer natureza, mediante lei que disporá sobre a natureza e administração desses fundos.", "tipo": "CF", "titulo_id": 9, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 246, "vigente": true}, {"id": 247, "numero": 250, "numero_texto": "250", "caput": "Art. 250. Com o objetivo de assegurar recursos para o pagamento dos benefícios concedidos pelo regime geral de previdência social, em adição aos recursos de sua arrecadação, a União poderá constituir fundo integrado por bens, direitos e ativos de qualquer natureza, mediante lei que disporá sobre a natureza e administração desse fundo.", "tipo": "CF", "titulo_id": 9, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 247, "vigente": true}, {"id": 248, "numero": 1, "numero_texto": "1º", "caput": "Art. 1º. O Presidente da República, o Presidente do Supremo Tribunal Federal e os membros do Congresso Nacional prestarão o compromisso de manter, defender e cumprir a Constituição, no ato e na data de sua promulgação.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 248, "vigente": true}, {"id": 249, "numero": 2, "numero_texto": "2º", "caput": "Art. 2º. No dia 7 de setembro de 1993 o eleitorado definirá, através de plebiscito, a forma (república ou monarquia constitucional) e o sistema de governo (parlamentarismo ou presidencialismo) que devem vigorar no País.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 249, "vigente": true}, {"id": 250, "numero": 3, "numero_texto": "3º", "caput": "Art. 3º. A revisão constitucional será realizada após cinco anos, contados da promulgação da Constituição, pelo voto da maioria absoluta dos membros do Congresso Nacional, em sessão unicameral.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 250, "vigente": true}, {"id": 251, "numero": 4, "numero_texto": "4º", "caput": "Art. 4º. O mandato do atual Presidente da República terminará em 15 de março de 1990.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 251, "vigente": true}, {"id": 252, "numero": 5, "numero_texto": "5º", "caput": "Art. 5º. Não se aplicam às eleições previstas para 15 de novembro de 1988 o disposto no art. 16 e as regras do art. 77 da Constituição.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 252, "vigente": true}, {"id": 253, "numero": 6, "numero_texto": "6º", "caput": "Art. 6º. Nos seis meses posteriores à promulgação da Constituição, parlamentares federais, reunidos em número não inferior a trinta, poderão requerer ao Tribunal Superior Eleitoral o registro de novo partido político, juntando ao requerimento o manifesto, o estatuto e o programa devidamente assinados pelos requerentes.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 253, "vigente": true}, {"id": 254, "numero": 7, "numero_texto": "7º", "caput": "Art. 7º. O Brasil propugnará pela formação de um tribunal internacional dos direitos humanos.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 254, "vigente": true}, {"id": 255, "numero": 8, "numero_texto": "8º", "caput": "Art. 8º. É concedida anistia aos que, no período de 18 de setembro de 1946 até a data da promulgação da Constituição, foram atingidos, em decorrência de motivação exclusivamente política, por atos de exceção, institucionais ou complementares, aos que foram abrangidos pelo Decreto Legislativo nº 18, de 15 de dezembro de 1961 , e aos atingidos pelo Decreto-Lei nº 864, de 12 de setembro de 1969 , asseguradas as promoções, na inatividade, ao cargo, emprego, posto ou graduação a que teriam direito se", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 255, "vigente": true}, {"id": 256, "numero": 9, "numero_texto": "9º", "caput": "Art. 9º. Os que, por motivos exclusivamente políticos, foram cassados ou tiveram seus direitos políticos suspensos no período de 15 de julho a 31 de dezembro de 1969, por ato do então Presidente da República, poderão requerer ao Supremo Tribunal Federal o reconhecimento dos direitos e vantagens interrompidos pelos atos punitivos, desde que comprovem terem sido estes eivados de vício grave.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 256, "vigente": true}, {"id": 257, "numero": 10, "numero_texto": "10", "caput": "Art. 10. Até que seja promulgada a lei complementar a que se refere o art. 7º, I, da Constituição:", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 257, "vigente": true}, {"id": 258, "numero": 11, "numero_texto": "11", "caput": "Art. 11. Cada Assembléia Legislativa, com poderes constituintes, elaborará a Constituição do Estado, no prazo de um ano, contado da promulgação da Constituição Federal, obedecidos os princípios desta.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 258, "vigente": true}, {"id": 259, "numero": 12, "numero_texto": "12", "caput": "Art. 12. Será criada, dentro de noventa dias da promulgação da Constituição, Comissão de Estudos Territoriais, com dez membros indicados pelo Congresso Nacional e cinco pelo Poder Executivo, com a finalidade de apresentar estudos sobre o território nacional e anteprojetos relativos a novas unidades territoriais, notadamente na Amazônia Legal e em áreas pendentes de solução.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 259, "vigente": true}, {"id": 260, "numero": 13, "numero_texto": "13", "caput": "Art. 13. É criado o Estado do Tocantins, pelo desmembramento da área descrita neste artigo, dando-se sua instalação no quadragésimo sexto dia após a eleição prevista no § 3º, mas não antes de 1º de janeiro de 1989.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 260, "vigente": true}, {"id": 261, "numero": 14, "numero_texto": "14", "caput": "Art. 14. Os Territórios Federais de Roraima e do Amapá são transformados em Estados Federados, mantidos seus atuais limites geográficos.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 261, "vigente": true}, {"id": 262, "numero": 15, "numero_texto": "15", "caput": "Art. 15. Fica extinto o Território Federal de Fernando de Noronha, sendo sua área reincorporada ao Estado de Pernambuco.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 262, "vigente": true}, {"id": 263, "numero": 16, "numero_texto": "16", "caput": "Art. 16. Até que se efetive o disposto no art. 32, § 2º, da Constituição, caberá ao Presidente da República, com a aprovação do Senado Federal, indicar o Governador e o Vice-Governador do Distrito Federal.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 263, "vigente": true}, {"id": 264, "numero": 17, "numero_texto": "17", "caput": "Art. 17. Os vencimentos, a remuneração, as vantagens e os adicionais, bem como os proventos de aposentadoria que estejam sendo percebidos em desacordo com a Constituição serão imediatamente reduzidos aos limites dela decorrentes, não se admitindo, neste caso, invocação de direito adquirido ou percepção de excesso a qualquer título.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 264, "vigente": true}, {"id": 265, "numero": 18, "numero_texto": "18", "caput": "Art. 18. Ficam extintos os efeitos jurídicos de qualquer ato legislativo ou administrativo, lavrado a partir da instalação da Assembléia Nacional Constituinte, que tenha por objeto a concessão de estabilidade a servidor admitido sem concurso público, da administração direta ou indireta, inclusive das fundações instituídas e mantidas pelo Poder Público.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 265, "vigente": true}, {"id": 266, "numero": 19, "numero_texto": "19", "caput": "Art. 19. Os servidores públicos civis da União, dos Estados, do Distrito Federal e dos Municípios, da administração direta, autárquica e das fundações públicas, em exercício na data da promulgação da Constituição, há pelo menos cinco anos continuados, e que não tenham sido admitidos na forma regulada no art. 37, da Constituição, são considerados estáveis no serviço público.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 266, "vigente": true}, {"id": 267, "numero": 20, "numero_texto": "20", "caput": "Art. 20. Dentro de cento e oitenta dias, proceder-se-á à revisão dos direitos dos servidores públicos inativos e pensionistas e à atualização dos proventos e pensões a eles devidos, a fim de ajustá-los ao disposto na Constituição.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 267, "vigente": true}, {"id": 268, "numero": 21, "numero_texto": "21", "caput": "Art. 21. Os juízes togados de investidura limitada no tempo, admitidos mediante concurso público de provas e títulos e que estejam em exercício na data da promulgação da Constituição, adquirem estabilidade, observado o estágio probatório, e passam a compor quadro em extinção, mantidas as competências, prerrogativas e restrições da legislação a que se achavam submetidos, salvo as inerentes à transitoriedade da investidura.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 268, "vigente": true}, {"id": 269, "numero": 22, "numero_texto": "22", "caput": "Art. 22. É assegurado aos defensores públicos investidos na função até a data de instalação da Assembléia Nacional Constituinte o direito de opção pela carreira, com a observância das garantias e vedações previstas no art. 134, parágrafo único, da Constituição.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 269, "vigente": true}, {"id": 270, "numero": 23, "numero_texto": "23", "caput": "Art. 23. Até que se edite a regulamentação do art. 21, XVI, da Constituição, os atuais ocupantes do cargo de censor federal continuarão exercendo funções com este compatíveis, no Departamento de Polícia Federal, observadas as disposições constitucionais.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 270, "vigente": true}, {"id": 271, "numero": 24, "numero_texto": "24", "caput": "Art. 24. A União, os Estados, o Distrito Federal e os Municípios editarão leis que estabeleçam critérios para a compatibilização de seus quadros de pessoal ao disposto no art. 39 da Constituição e à reforma administrativa dela decorrente, no prazo de dezoito meses, contados da sua promulgação.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 271, "vigente": true}, {"id": 272, "numero": 25, "numero_texto": "25", "caput": "Art. 25. Ficam revogados, a partir de cento e oitenta dias da promulgação da Constituição, sujeito este prazo a prorrogação por lei, todos os dispositivos legais que atribuam ou deleguem a órgão do Poder Executivo competência assinalada pela Constituição ao Congresso Nacional, especialmente no que tange a:", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 272, "vigente": true}, {"id": 273, "numero": 26, "numero_texto": "26", "caput": "Art. 26. No prazo de um ano a contar da promulgação da Constituição, o Congresso Nacional promoverá, através de Comissão mista, exame analítico e pericial dos atos e fatos geradores do endividamento externo brasileiro.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 273, "vigente": true}, {"id": 274, "numero": 27, "numero_texto": "27", "caput": "Art. 27. O Superior Tribunal de Justiça será instalado sob a Presidência do Supremo Tribunal Federal.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 274, "vigente": true}, {"id": 275, "numero": 28, "numero_texto": "28", "caput": "Art. 28. Os juízes federais de que trata o art. 123, § 2º, da Constituição de 1967, com a redação dada pela Emenda Constitucional nº 7, de 1977 , ficam investidos na titularidade de varas na Seção Judiciária para a qual tenham sido nomeados ou designados; na inexistência de vagas, proceder-se-á ao desdobramento das varas existentes.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 275, "vigente": true}, {"id": 276, "numero": 29, "numero_texto": "29", "caput": "Art. 29. Enquanto não aprovadas as leis complementares relativas ao Ministério Público e à Advocacia-Geral da União, o Ministério Público Federal, a Procuradoria-Geral da Fazenda Nacional, as Consultorias Jurídicas dos Ministérios, as Procuradorias e Departamentos Jurídicos de autarquias federais com representação própria e os membros das Procuradorias das Universidades fundacionais públicas continuarão a exercer suas atividades na área das respectivas atribuições.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 276, "vigente": true}, {"id": 277, "numero": 30, "numero_texto": "30", "caput": "Art. 30. A legislação que criar a justiça de paz manterá os atuais juízes de paz até a posse dos novos titulares, assegurando-lhes os direitos e atribuições conferidos a estes, e designará o dia para a eleição prevista no art. 98, II, da Constituição.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 277, "vigente": true}, {"id": 278, "numero": 31, "numero_texto": "31", "caput": "Art. 31. Serão estatizadas as serventias do foro judicial, assim definidas em lei, respeitados os direitos dos atuais titulares.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 278, "vigente": true}, {"id": 279, "numero": 32, "numero_texto": "32", "caput": "Art. 32. O disposto no art. 236 não se aplica aos serviços notariais e de registro que já tenham sido oficializados pelo Poder Público, respeitando-se o direito de seus servidores.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 279, "vigente": true}, {"id": 280, "numero": 33, "numero_texto": "33", "caput": "Art. 33. Ressalvados os créditos de natureza alimentar, o valor dos precatórios judiciais pendentes de pagamento na data da promulgação da Constituição, incluído o remanescente de juros e correção monetária, poderá ser pago em moeda corrente, com atualização, em prestações anuais, iguais e sucessivas, no prazo máximo de oito anos, a partir de 1º de julho de 1989, por decisão editada pelo Poder Executivo até cento e oitenta dias da promulgação da Constituição.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 280, "vigente": true}, {"id": 281, "numero": 34, "numero_texto": "34", "caput": "Art. 34. O sistema tributário nacional entrará em vigor a partir do primeiro dia do quinto mês seguinte ao da promulgação da Constituição, mantido, até então, o da Constituição de 1967, com a redação dada pela Emenda nº 1, de 1969, e pelas posteriores.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 281, "vigente": true}, {"id": 282, "numero": 35, "numero_texto": "35", "caput": "Art. 35. O disposto no art. 165, § 7º, será cumprido de forma progressiva, no prazo de até dez anos, distribuindo-se os recursos entre as regiões macroeconômicas em razão proporcional à população, a partir da situação verificada no biênio 1986-87.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 282, "vigente": true}, {"id": 283, "numero": 36, "numero_texto": "36", "caput": "Art. 36. Os fundos existentes na data da promulgação da Constituição, excetuados os resultantes de isenções fiscais que passem a integrar patrimônio privado e os que interessem à defesa nacional, extinguir-se-ão, se não forem ratificados pelo Congresso Nacional no prazo de dois anos.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 283, "vigente": true}, {"id": 284, "numero": 37, "numero_texto": "37", "caput": "Art. 37. A adaptação ao que estabelece o art. 167, III, deverá processar-se no prazo de cinco anos, reduzindo-se o excesso à base de, pelo menos, um quinto por ano.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 284, "vigente": true}, {"id": 285, "numero": 38, "numero_texto": "38", "caput": "Art. 38. Até a promulgação da lei complementar referida no art. 169, a União, os Estados, o Distrito Federal e os Municípios não poderão despender com pessoal mais do que sessenta e cinco por cento do valor das respectivas receitas correntes.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 285, "vigente": true}, {"id": 286, "numero": 39, "numero_texto": "39", "caput": "Art. 39. Para efeito do cumprimento das disposições constitucionais que impliquem variações de despesas e receitas da União, após a promulgação da Constituição, o Poder Executivo deverá elaborar e o Poder Legislativo apreciar projeto de revisão da lei orçamentária referente ao exercício financeiro de 1989.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 286, "vigente": true}, {"id": 287, "numero": 40, "numero_texto": "40", "caput": "Art. 40. É mantida a Zona Franca de Manaus, com suas características de área livre de comércio, de exportação e importação, e de incentivos fiscais, pelo prazo de vinte e cinco anos, a partir da promulgação da Constituição.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 287, "vigente": true}, {"id": 288, "numero": 41, "numero_texto": "41", "caput": "Art. 41. Os Poderes Executivos da União, dos Estados, do Distrito Federal e dos Municípios reavaliarão todos os incentivos fiscais de natureza setorial ora em vigor, propondo aos Poderes Legislativos respectivos as medidas cabíveis.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 288, "vigente": true}, {"id": 289, "numero": 42, "numero_texto": "42", "caput": "Art. 42. Durante 40 (quarenta) anos, a União aplicará dos recursos destinados à irrigação:", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 289, "vigente": true}, {"id": 290, "numero": 43, "numero_texto": "43", "caput": "Art. 43. Na data da promulgação da lei que disciplinar a pesquisa e a lavra de recursos e jazidas minerais, ou no prazo de um ano, a contar da promulgação da Constituição, tornar-se-ão sem efeito as autorizações, concessões e demais títulos atributivos de direitos minerários, caso os trabalhos de pesquisa ou de lavra não hajam sido comprovadamente iniciados nos prazos legais ou estejam inativos. (Regulamento)", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 290, "vigente": true}, {"id": 291, "numero": 44, "numero_texto": "44", "caput": "Art. 44. As atuais empresas brasileiras titulares de autorização de pesquisa, concessão de lavra de recursos minerais e de aproveitamento dos potenciais de energia hidráulica em vigor terão quatro anos, a partir da promulgação da Constituição, para cumprir os requisitos do art. 176, § 1º.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 291, "vigente": true}, {"id": 292, "numero": 45, "numero_texto": "45", "caput": "Art. 45. Ficam excluídas do monopólio estabelecido pelo art. 177, II, da Constituição as refinarias em funcionamento no País amparadas pelo art. 43 e nas condições do art. 45 da Lei nº 2.004, de 3 de outubro de 1953 .", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 292, "vigente": true}, {"id": 293, "numero": 46, "numero_texto": "46", "caput": "Art. 46. São sujeitos à correção monetária desde o vencimento, até seu efetivo pagamento, sem interrupção ou suspensão, os créditos junto a entidades submetidas aos regimes de intervenção ou liquidação extrajudicial, mesmo quando esses regimes sejam convertidos em falência.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 293, "vigente": true}, {"id": 294, "numero": 47, "numero_texto": "47", "caput": "Art. 47. Na liquidação dos débitos, inclusive suas renegociações e composições posteriores, ainda que ajuizados, decorrentes de quaisquer empréstimos concedidos por bancos e por instituições financeiras, não existirá correção monetária desde que o empréstimo tenha sido concedido:", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 294, "vigente": true}, {"id": 295, "numero": 48, "numero_texto": "48", "caput": "Art. 48. O Congresso Nacional, dentro de cento e vinte dias da promulgação da Constituição, elaborará código de defesa do consumidor.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 295, "vigente": true}, {"id": 296, "numero": 49, "numero_texto": "49", "caput": "Art. 49. A lei disporá sobre o instituto da enfiteuse em imóveis urbanos, sendo facultada aos foreiros, no caso de sua extinção, a remição dos aforamentos mediante aquisição do domínio direto, na conformidade do que dispuserem os respectivos contratos.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 296, "vigente": true}, {"id": 297, "numero": 50, "numero_texto": "50", "caput": "Art. 50. Lei agrícola a ser promulgada no prazo de um ano disporá, nos termos da Constituição, sobre os objetivos e instrumentos de política agrícola, prioridades, planejamento de safras, comercialização, abastecimento interno, mercado externo e instituição de crédito fundiário.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 297, "vigente": true}, {"id": 298, "numero": 51, "numero_texto": "51", "caput": "Art. 51. Serão revistos pelo Congresso Nacional, através de Comissão mista, nos três anos a contar da data da promulgação da Constituição, todas as doações, vendas e concessões de terras públicas com área superior a três mil hectares, realizadas no período de 1º de janeiro de 1962 a 31 de dezembro de 1987.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 298, "vigente": true}, {"id": 299, "numero": 52, "numero_texto": "52", "caput": "Art. 52. Até que sejam fixadas as condições do art. 192, são vedados:", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 299, "vigente": true}, {"id": 300, "numero": 53, "numero_texto": "53", "caput": "Art. 53. Ao ex-combatente que tenha efetivamente participado de operações bélicas durante a Segunda Guerra Mundial, nos termos da Lei nº 5.315, de 12 de setembro de 1967 , serão assegurados os seguintes direitos:", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 300, "vigente": true}, {"id": 301, "numero": 54, "numero_texto": "54", "caput": "Art. 54. Os seringueiros recrutados nos termos do Decreto-Lei nº 5.813, de 14 de setembro de 1943 , e amparados pelo Decreto-Lei nº 9.882, de 16 de setembro de 1946 , receberão, quando carentes, pensão mensal vitalícia no valor de dois salários mínimos.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 301, "vigente": true}, {"id": 302, "numero": 55, "numero_texto": "55", "caput": "Art. 55. Até que seja aprovada a lei de diretrizes orçamentárias, trinta por cento, no mínimo, do orçamento da seguridade social, excluído o seguro-desemprego, serão destinados ao setor de saúde.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 302, "vigente": true}, {"id": 303, "numero": 56, "numero_texto": "56", "caput": "Art. 56. Até que a lei disponha sobre o art. 195, I, a arrecadação decorrente de, no mínimo, cinco dos seis décimos percentuais correspondentes à alíquota da contribuição de que trata o Decreto-Lei nº 1.940, de 25 de maio de 1982 , alterada pelo Decreto-Lei nº 2.049, de 1º de agosto de 1983 , pelo Decreto nº 91.236, de 8 de maio de 1985 , e pela Lei nº 7.611, de 8 de julho de 1987 , passa a integrar a receita da seguridade social, ressalvados, exclusivamente no exercício de 1988, os compromissos", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 303, "vigente": true}, {"id": 304, "numero": 57, "numero_texto": "57", "caput": "Art. 57. Os débitos dos Estados e dos Municípios relativos às contribuições previdenciárias até 30 de junho de 1988 serão liquidados, com correção monetária, em cento e vinte parcelas mensais, dispensados os juros e multas sobre eles incidentes, desde que os devedores requeiram o parcelamento e iniciem seu pagamento no prazo de cento e oitenta dias a contar da promulgação da Constituição.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 304, "vigente": true}, {"id": 305, "numero": 58, "numero_texto": "58", "caput": "Art. 58. Os benefícios de prestação continuada, mantidos pela previdência social na data da promulgação da Constituição, terão seus valores revistos, a fim de que seja restabelecido o poder aquisitivo, expresso em número de salários mínimos, que tinham na data de sua concessão, obedecendo-se a esse critério de atualização até a implantação do plano de custeio e benefícios referidos no artigo seguinte.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 305, "vigente": true}, {"id": 306, "numero": 59, "numero_texto": "59", "caput": "Art. 59. Os projetos de lei relativos à organização da seguridade social e aos planos de custeio e de benefício serão apresentados no prazo máximo de seis meses da promulgação da Constituição ao Congresso Nacional, que terá seis meses para apreciá-los.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 306, "vigente": true}, {"id": 307, "numero": 60, "numero_texto": "60", "caput": "Art. 60. A complementação da União referida no inciso IV do caput do art. 212-A da Constituição Federal será implementada progressivamente até alcançar a proporção estabelecida no inciso V do caput do mesmo artigo, a partir de 1º de janeiro de 2021, nos seguintes valores mínimos:", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 307, "vigente": true}, {"id": 308, "numero": 61, "numero_texto": "61", "caput": "Art. 61. As entidades educacionais a que se refere o art. 213, bem como as fundações de ensino e pesquisa cuja criação tenha sido autorizada por lei, que preencham os requisitos dos incisos I e II do referido artigo e que, nos últimos três anos, tenham recebido recursos públicos, poderão continuar a recebê-los, salvo disposição legal em contrário.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 308, "vigente": true}, {"id": 309, "numero": 62, "numero_texto": "62", "caput": "Art. 62. A lei criará o Serviço Nacional de Aprendizagem Rural (SENAR) nos moldes da legislação relativa ao Serviço Nacional de Aprendizagem Industrial (SENAI) e ao Serviço Nacional de Aprendizagem do Comércio (SENAC), sem prejuízo das atribuições dos órgãos públicos que atuam na área.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 309, "vigente": true}, {"id": 310, "numero": 63, "numero_texto": "63", "caput": "Art. 63. É criada uma Comissão composta de nove membros, sendo três do Poder Legislativo, três do Poder Judiciário e três do Poder Executivo, para promover as comemorações do centenário da proclamação da República e da promulgação da primeira Constituição republicana do País, podendo, a seu critério, desdobrar-se em tantas subcomissões quantas forem necessárias.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 310, "vigente": true}, {"id": 311, "numero": 64, "numero_texto": "64", "caput": "Art. 64. A Imprensa Nacional e demais gráficas da União, dos Estados, do Distrito Federal e dos Municípios, da administração direta ou indireta, inclusive fundações instituídas e mantidas pelo Poder Público, promoverão edição popular do texto integral da Constituição, que será posta à disposição das escolas e dos cartórios, dos sindicatos, dos quartéis, das igrejas e de outras instituições representativas da comunidade, gratuitamente, de modo que cada cidadão brasileiro possa receber do Estado u", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 311, "vigente": true}, {"id": 312, "numero": 65, "numero_texto": "65", "caput": "Art. 65. O Poder Legislativo regulamentará, no prazo de doze meses, o art. 220, § 4º.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 312, "vigente": true}, {"id": 313, "numero": 66, "numero_texto": "66", "caput": "Art. 66. São mantidas as concessões de serviços públicos de telecomunicações atualmente em vigor, nos termos da lei.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 313, "vigente": true}, {"id": 314, "numero": 67, "numero_texto": "67", "caput": "Art. 67. A União concluirá a demarcação das terras indígenas no prazo de cinco anos a partir da promulgação da Constituição.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 314, "vigente": true}, {"id": 315, "numero": 68, "numero_texto": "68", "caput": "Art. 68. Aos remanescentes das comunidades dos quilombos que estejam ocupando suas terras é reconhecida a propriedade definitiva, devendo o Estado emitir-lhes os títulos respectivos.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 315, "vigente": true}, {"id": 316, "numero": 69, "numero_texto": "69", "caput": "Art. 69. Será permitido aos Estados manter consultorias jurídicas separadas de suas Procuradorias-Gerais ou Advocacias-Gerais, desde que, na data da promulgação da Constituição, tenham órgãos distintos para as respectivas funções.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 316, "vigente": true}, {"id": 317, "numero": 70, "numero_texto": "70", "caput": "Art. 70. Fica mantida atual competência dos tribunais estaduais até que a mesma seja definida na Constituição do Estado, nos termos do art. 125, § 1º, da Constituição.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 317, "vigente": true}, {"id": 318, "numero": 71, "numero_texto": "71", "caput": "Art. 71. É instituído, nos exercícios financeiros de 1994 e 1995, bem assim nos períodos de 01/01/1996 a 30/06/97 e 01/07/97 a 31/12/1999, o Fundo Social de Emergência, com o objetivo de saneamento financeiro da Fazenda Pública Federal e de estabilização econômica, cujos recursos serão aplicados prioritariamente no custeio das ações dos sistemas de saúde e educação, incluindo a complementação de recursos de que trata o § 3º do art. 60 do Ato das Disposições Constitucionais Transitórias, benefíci", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 318, "vigente": true}, {"id": 319, "numero": 72, "numero_texto": "72", "caput": "Art. 72. Integram o Fundo Social de Emergência:", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 319, "vigente": true}, {"id": 320, "numero": 73, "numero_texto": "73", "caput": "Art. 73. Na regulação do Fundo Social de Emergência não poderá ser utilizado o instrumento previsto no inciso V do art. 59 da Constituição.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 320, "vigente": true}, {"id": 321, "numero": 74, "numero_texto": "74", "caput": "Art. 74. A União poderá instituir contribuição provisória sobre movimentação ou transmissão de valores e de créditos e direitos de natureza financeira.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 321, "vigente": true}, {"id": 322, "numero": 75, "numero_texto": "75", "caput": "Art. 75. É prorrogada, por trinta e seis meses, a cobrança da contribuição provisória sobre movimentação ou transmissão de valores e de créditos e direitos de natureza financeira de que trata o art. 74, instituída pela Lei nº 9.311, de 24 de outubro de 1996 , modificada pela Lei nº 9.539, de 12 de dezembro de 1997 , cuja vigência é também prorrogada por idêntico prazo.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 322, "vigente": true}, {"id": 323, "numero": 76, "numero_texto": "76", "caput": "Art. 76. São desvinculados de órgão, fundo ou despesa, até 31 de dezembro de 2032, 30% (trinta por cento) da arrecadação da União relativa às contribuições sociais, sem prejuízo do pagamento das despesas do Regime Geral de Previdência Social, às contribuições de intervenção no domínio econômico, às taxas e às receitas patrimoniais, já instituídas ou que vierem a ser criadas até a referida data.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 323, "vigente": true}, {"id": 324, "numero": 77, "numero_texto": "77", "caput": "Art. 77. Até o exercício financeiro de 2004, os recursos mínimos aplicados nas ações e serviços públicos de saúde serão equivalentes:", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 324, "vigente": true}, {"id": 325, "numero": 78, "numero_texto": "78", "caput": "Art. 78. Ressalvados os créditos definidos em lei como de pequeno valor, os de natureza alimentícia, os de que trata o art. 33 deste Ato das Disposições Constitucionais Transitórias e suas complementações e os que já tiverem os seus respectivos recursos liberados ou depositados em juízo, os precatórios pendentes na data de promulgação desta Emenda e os que decorram de ações iniciais ajuizadas até 31 de dezembro de 1999 serão liquidados pelo seu valor real, em moeda corrente, acrescido de juros l", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 325, "vigente": true}, {"id": 326, "numero": 79, "numero_texto": "79", "caput": "Art. 79. É instituído, para vigorar até o ano de 2010, no âmbito do Poder Executivo Federal, o Fundo de Combate e Erradicação da Pobreza, a ser regulado por lei complementar com o objetivo de viabilizar a todos os brasileiros acesso a níveis dignos de subsistência, cujos recursos serão aplicados em ações suplementares de nutrição, habitação, educação, saúde, reforço de renda familiar e outros programas de relevante interesse social voltados para melhoria da qualidade de vida.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 326, "vigente": true}, {"id": 327, "numero": 80, "numero_texto": "80", "caput": "Art. 80. Compõem o Fundo de Combate e Erradicação da Pobreza:", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 327, "vigente": true}, {"id": 328, "numero": 81, "numero_texto": "81", "caput": "Art. 81. É instituído Fundo constituído pelos recursos recebidos pela União em decorrência da desestatização de sociedades de economia mista ou empresas públicas por ela controladas, direta ou indiretamente, quando a operação envolver a alienação do respectivo controle acionário a pessoa ou entidade não integrante da Administração Pública, ou de participação societária remanescente após a alienação, cujos rendimentos, gerados a partir de 18 de junho de 2002, reverterão ao Fundo de Combate e Erra", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 328, "vigente": true}, {"id": 329, "numero": 82, "numero_texto": "82", "caput": "Art. 82. Os Estados, o Distrito Federal e os Municípios devem instituir Fundos de Combate à Pobreza, com os recursos de que trata este artigo e outros que vierem a destinar, devendo os referidos Fundos ser geridos por entidades que contem com a participação da sociedade civil.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 329, "vigente": true}, {"id": 330, "numero": 83, "numero_texto": "83", "caput": "Art. 83. Lei federal definirá os produtos e serviços supérfluos a que se referem os arts. 80, II, e 82, § 2º. Vigência", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 330, "vigente": true}, {"id": 331, "numero": 84, "numero_texto": "84", "caput": "Art. 84. A contribuição provisória sobre movimentação ou transmissão de valores e de créditos e direitos de natureza financeira, prevista nos arts. 74, 75 e 80, I, deste Ato das Disposições Constitucionais Transitórias, será cobrada até 31 de dezembro de 2004.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 331, "vigente": true}, {"id": 332, "numero": 85, "numero_texto": "85", "caput": "Art. 85. A contribuição a que se refere o art. 84 deste Ato das Disposições Constitucionais Transitórias não incidirá, a partir do trigésimo dia da data de publicação desta Emenda Constitucional, nos lançamentos:", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 332, "vigente": true}, {"id": 333, "numero": 86, "numero_texto": "86", "caput": "Art. 86. Serão pagos conforme disposto no art. 100 da Constituição Federal, não se lhes aplicando a regra de parcelamento estabelecida no caput do art. 78 deste Ato das Disposições Constitucionais Transitórias, os débitos da Fazenda Federal, Estadual, Distrital ou Municipal oriundos de sentenças transitadas em julgado, que preencham, cumulativamente, as seguintes condições:", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 333, "vigente": true}, {"id": 334, "numero": 87, "numero_texto": "87", "caput": "Art. 87. Para efeito do que dispõem o § 3º do art. 100 da Constituição Federal e o art. 78 deste Ato das Disposições Constitucionais Transitórias serão considerados de pequeno valor, até que se dê a publicação oficial das respectivas leis definidoras pelos entes da Federação, observado o disposto no § 4º do art. 100 da Constituição Federal, os débitos ou obrigações consignados em precatório judiciário, que tenham valor igual ou inferior a:", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 334, "vigente": true}, {"id": 335, "numero": 88, "numero_texto": "88", "caput": "Art. 88. Enquanto lei complementar não disciplinar o disposto nos incisos I e III do § 3º do art. 156 da Constituição Federal, o imposto a que se refere o inciso III do caput do mesmo artigo:", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 335, "vigente": true}, {"id": 336, "numero": 89, "numero_texto": "89", "caput": "Art. 89. Os integrantes da carreira policial militar e os servidores municipais do ex-Território Federal de Rondônia que, comprovadamente, se encontravam no exercício regular de suas funções prestando serviço àquele ex-Território na data em que foi transformado em Estado, bem como os servidores e os policiais militares alcançados pelo disposto no art. 36 da Lei Complementar nº 41, de 22 de dezembro de 1981 , e aqueles admitidos regularmente nos quadros do Estado de Rondônia até a data de posse d", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 336, "vigente": true}, {"id": 337, "numero": 90, "numero_texto": "90", "caput": "Art. 90. O prazo previsto no caput do art. 84 deste Ato das Disposições Constitucionais Transitórias fica prorrogado até 31 de dezembro de 2007.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 337, "vigente": true}, {"id": 338, "numero": 92, "numero_texto": "92", "caput": "Art. 92. São acrescidos dez anos ao prazo fixado no art. 40 deste Ato das Disposições Constitucionais Transitórias.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 338, "vigente": true}, {"id": 339, "numero": 93, "numero_texto": "93", "caput": "Art. 93. A vigência do disposto no art. 159, III, e § 4º, iniciará somente após a edição da lei de que trata o referido inciso III.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 339, "vigente": true}, {"id": 340, "numero": 94, "numero_texto": "94", "caput": "Art. 94. Os regimes especiais de tributação para microempresas e empresas de pequeno porte próprios da União, dos Estados, do Distrito Federal e dos Municípios cessarão a partir da entrada em vigor do regime previsto no art. 146, III, d, da Constituição.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 340, "vigente": true}, {"id": 341, "numero": 95, "numero_texto": "95", "caput": "Art. 95. Os nascidos no estrangeiro entre 7 de junho de 1994 e a data da promulgação desta Emenda Constitucional, filhos de pai brasileiro ou mãe brasileira, poderão ser registrados em repartição diplomática ou consular brasileira competente ou em ofício de registro, se vierem a residir na República Federativa do Brasil.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 341, "vigente": true}, {"id": 342, "numero": 96, "numero_texto": "96", "caput": "Art. 96. Ficam convalidados os atos de criação, fusão, incorporação e desmembramento de Municípios, cuja lei tenha sido publicada até 31 de dezembro de 2006, atendidos os requisitos estabelecidos na legislação do respectivo Estado à época de sua criação..", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 342, "vigente": true}, {"id": 343, "numero": 97, "numero_texto": "97", "caput": "Art. 97. Até que seja editada a lei complementar de que trata o § 15 do art. 100 da Constituição Federal, os Estados, o Distrito Federal e os Municípios que, na data de publicação desta Emenda Constitucional, estejam em mora na quitação de precatórios vencidos, relativos às suas administrações direta e indireta, inclusive os emitidos durante o período de vigência do regime especial instituído por este artigo, farão esses pagamentos de acordo com as normas a seguir estabelecidas, sendo inaplicáve", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 343, "vigente": true}, {"id": 344, "numero": 98, "numero_texto": "98", "caput": "Art. 98. O número de defensores públicos na unidade jurisdicional será proporcional à efetiva demanda pelo serviço da Defensoria Pública e à respectiva população.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 344, "vigente": true}, {"id": 345, "numero": 99, "numero_texto": "99", "caput": "Art. 99. Para efeito do disposto no inciso VII do § 2º do art. 155, no caso de operações e prestações que destinem bens e serviços a consumidor final não contribuinte localizado em outro Estado, o imposto correspondente à diferença entre a alíquota interna e a interestadual será partilhado entre os Estados de origem e de destino, na seguinte proporção:", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 345, "vigente": true}, {"id": 346, "numero": 100, "numero_texto": "100", "caput": "Art. 100. Até que entre em vigor a lei complementar de que trata o inciso II do § 1º do art. 40 da Constituição Federal , os Ministros do Supremo Tribunal Federal, dos Tribunais Superiores e do Tribunal de Contas da União aposentar-se-ão, compulsoriamente, aos 75 (setenta e cinco) anos de idade, nas condições do art. 52 da Constituição Federal .", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 346, "vigente": true}, {"id": 347, "numero": 101, "numero_texto": "101", "caput": "Art. 101. Os Estados, o Distrito Federal e os Municípios que, em 25 de março de 2015, se encontravam em mora no pagamento de seus precatórios quitarão, até 31 de dezembro de 2029, seus débitos vencidos e os que vencerão dentro desse período, atualizados pelo Índice Nacional de Preços ao Consumidor Amplo Especial (IPCA-E), ou por outro índice que venha a substituí-lo, depositando mensalmente em conta especial do Tribunal de Justiça local, sob única e exclusiva administração deste, 1/12 (um doze a", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 347, "vigente": true}, {"id": 348, "numero": 102, "numero_texto": "102", "caput": "Art. 102. Enquanto viger o regime especial previsto nesta Emenda Constitucional, pelo menos 50% (cinquenta por cento) dos recursos que, nos termos do art. 101 deste Ato das Disposições Constitucionais Transitórias, forem destinados ao pagamento dos precatórios em mora serão utilizados no pagamento segundo a ordem cronológica de apresentação, respeitadas as preferências dos créditos alimentares, e, nessas, as relativas à idade, ao estado de saúde e à deficiência, nos termos do § 2º do art. 100 da", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 348, "vigente": true}, {"id": 349, "numero": 103, "numero_texto": "103", "caput": "Art. 103. Enquanto os Estados, o Distrito Federal e os Municípios estiverem efetuando o pagamento da parcela mensal devida como previsto no caput do art. 101 deste Ato das Disposições Constitucionais Transitórias, nem eles, nem as respectivas autarquias, fundações e empresas estatais dependentes poderão sofrer sequestro de valores, exceto no caso de não liberação tempestiva dos recursos.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 349, "vigente": true}, {"id": 350, "numero": 104, "numero_texto": "104", "caput": "Art. 104. Se os recursos referidos no art. 101 deste Ato das Disposições Constitucionais Transitórias para o pagamento de precatórios não forem tempestivamente liberados, no todo ou em parte:", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 350, "vigente": true}, {"id": 351, "numero": 105, "numero_texto": "105", "caput": "Art. 105. Enquanto viger o regime de pagamento de precatórios previsto no art. 101 deste Ato das Disposições Constitucionais Transitórias, é facultada aos credores de precatórios, próprios ou de terceiros, a compensação com débitos de natureza tributária ou de outra natureza que até 25 de março de 2015 tenham sido inscritos na dívida ativa dos Estados, do Distrito Federal ou dos Municípios, observados os requisitos definidos em lei própria do ente federado.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 351, "vigente": true}, {"id": 352, "numero": 107, "numero_texto": "107", "caput": "Art. 107-A. Até o fim de 2026, fica estabelecido, para cada exercício financeiro, limite para alocação na proposta orçamentária das despesas com pagamentos em virtude de sentença judiciária de que trata o art. 100 da Constituição Federal, equivalente ao valor da despesa paga no exercício de 2016, incluídos os restos a pagar pagos, corrigido, para o exercício de 2017, em 7,2% (sete inteiros e dois décimos por cento) e, para os exercícios posteriores, pela variação do Índice Nacional de Preços ao ", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 352, "vigente": true}, {"id": 353, "numero": 113, "numero_texto": "113", "caput": "Art. 113. A proposição legislativa que crie ou altere despesa obrigatória ou renúncia de receita deverá ser acompanhada da estimativa do seu impacto orçamentário e financeiro.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 353, "vigente": true}, {"id": 354, "numero": 115, "numero_texto": "115", "caput": "Art. 115. Fica excepcionalmente autorizado o parcelamento das contribuições previdenciárias e dos demais débitos dos Estados, do Distrito Federal e dos Municípios, incluídas suas autarquias e fundações, com os respectivos regimes próprios de previdência social, com vencimento até 31 de agosto de 2025, inclusive os parcelados anteriormente, no prazo máximo de 300 (trezentas) prestações mensais, mediante autorização em lei específica do ente federativo, desde que comprovem, em até 15 (quinze) mese", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 354, "vigente": true}, {"id": 355, "numero": 116, "numero_texto": "116", "caput": "Art. 116. Fica excepcionalmente autorizado o parcelamento dos débitos decorrentes de contribuições previdenciárias dos Municípios, incluídas suas autarquias e fundações, com o Regime Geral de Previdência Social, com vencimento até 31 de agosto de 2025, ainda que em fase de execução fiscal ajuizada, inclusive os decorrentes do descumprimento de obrigações acessórias e os que tenham sido objeto de parcelamento anterior não integralmente quitado, no prazo máximo de 300 (trezentas) prestações mensai", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 355, "vigente": true}, {"id": 356, "numero": 117, "numero_texto": "117", "caput": "Art. 117. A formalização dos parcelamentos de que tratam os arts. 115, 116 e 116-A deste Ato das Disposições Constitucionais Transitórias deverá ocorrer até 31 de agosto de 2026 e ficará condicionada à autorização de vinculação do Fundo de Participação dos Municípios para fins de pagamento das prestações acordadas nos termos de parcelamento, observada a seguinte ordem de preferência:", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 356, "vigente": true}, {"id": 357, "numero": 118, "numero_texto": "118", "caput": "Art. 118. Os limites, as condições, as normas de acesso e os demais requisitos para o atendimento do disposto no parágrafo único do art. 6º e no inciso VI do caput do art. 203 da Constituição Federal serão determinados, na forma da lei e respectivo regulamento, até 31 de dezembro de 2022, dispensada, exclusivamente no exercício de 2022, a observância das limitações legais quanto à criação, à expansão ou ao aperfeiçoamento de ação governamental que acarrete aumento de despesa no referido exercíci", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 357, "vigente": true}, {"id": 358, "numero": 119, "numero_texto": "119", "caput": "Art. 119. Em decorrência do estado de calamidade pública provocado pela pandemia da Covid-19, os Estados, o Distrito Federal, os Municípios e os agentes públicos desses entes federados não poderão ser responsabilizados administrativa, civil ou criminalmente pelo descumprimento, exclusivamente nos exercícios financeiros de 2020 e 2021, do disposto no caput do art. 212 da Constituição Federal.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 358, "vigente": true}, {"id": 359, "numero": 120, "numero_texto": "120", "caput": "Art. 120. Fica reconhecido, no ano de 2022, o estado de emergência decorrente da elevação extraordinária e imprevisível dos preços do petróleo, combustíveis e seus derivados e dos impactos sociais dela decorrentes.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 359, "vigente": true}, {"id": 360, "numero": 121, "numero_texto": "121", "caput": "Art. 121. As contas referentes aos patrimônios acumulados de que trata o § 2º do art. 239 da Constituição Federal cujos recursos não tenham sido reclamados por prazo superior a 20 (vinte) anos serão encerradas após o prazo de 60 (sessenta) dias da publicação de aviso no Diário Oficial da União, ressalvada reivindicação por eventual interessado legítimo dentro do referido prazo.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 360, "vigente": true}, {"id": 361, "numero": 122, "numero_texto": "122", "caput": "Art. 122. As transferências financeiras realizadas pelo Fundo Nacional de Saúde e pelo Fundo Nacional de Assistência Social diretamente aos fundos de saúde e assistência social estaduais, municipais e distritais, para enfrentamento da pandemia da Covid-19, poderão ser executadas pelos entes federativos até 31 de dezembro de 2023.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 361, "vigente": true}, {"id": 362, "numero": 123, "numero_texto": "123", "caput": "Art. 123. Todos os termos de credenciamentos, contratos, aditivos e outras formas de ajuste de permissão lotérica, em vigor, indistintamente, na data de publicação deste dispositivo, destinados a viabilizar a venda de serviços lotéricos, disciplinados em lei ou em outros instrumentos de alcance específico, terão assegurado prazo de vigência adicional, contado do término do prazo do instrumento vigente, independentemente da data de seu termo inicial.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 362, "vigente": true}, {"id": 363, "numero": 124, "numero_texto": "124", "caput": "Art. 124. A transição para os tributos previstos no art. 156-A e no art. 195, V, todos da Constituição Federal, atenderá aos critérios estabelecidos nos arts. 125 a 133 deste Ato das Disposições Constitucionais Transitórias.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 363, "vigente": true}, {"id": 364, "numero": 125, "numero_texto": "125", "caput": "Art. 125. Em 2026, o imposto previsto no art. 156-A será cobrado à alíquota estadual de 0,1% (um décimo por cento), e a contribuição prevista no art. 195, V, ambos da Constituição Federal, será cobrada à alíquota de 0,9% (nove décimos por cento).", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 364, "vigente": true}, {"id": 365, "numero": 126, "numero_texto": "126", "caput": "Art. 126. A partir de 2027:", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 365, "vigente": true}, {"id": 366, "numero": 127, "numero_texto": "127", "caput": "Art. 127. Em 2027 e 2028, o imposto previsto no art. 156-A da Constituição Federal será cobrado à alíquota estadual de 0,05% (cinco centésimos por cento) e à alíquota municipal de 0,05% (cinco centésimos por cento).", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 366, "vigente": true}, {"id": 367, "numero": 128, "numero_texto": "128", "caput": "Art. 128. De 2029 a 2032, as alíquotas dos impostos previstos nos arts. 155, II, e 156, III, da Constituição Federal, serão fixadas nas seguintes proporções das alíquotas fixadas nas respectivas legislações:", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 367, "vigente": true}, {"id": 368, "numero": 129, "numero_texto": "129", "caput": "Art. 129. Ficam extintos, a partir de 2033, os impostos previstos nos arts. 155, II, e 156, III, da Constituição Federal.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 368, "vigente": true}, {"id": 369, "numero": 130, "numero_texto": "130", "caput": "Art. 130. Resolução do Senado Federal fixará, para todas as esferas federativas, as alíquotas de referência dos tributos previstos nos arts. 156-A e 195, V, da Constituição Federal, observados a forma de cálculo e os limites previstos em lei complementar, de forma a assegurar:", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 369, "vigente": true}, {"id": 370, "numero": 131, "numero_texto": "131", "caput": "Art. 131. De 2029 a 2077, o produto da arrecadação dos Estados, do Distrito Federal e dos Municípios com o imposto de que trata o art. 156-A da Constituição Federal será distribuído a esses entes federativos conforme o disposto neste artigo.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 370, "vigente": true}, {"id": 371, "numero": 132, "numero_texto": "132", "caput": "Art. 132. Do imposto dos Estados, do Distrito Federal e dos Municípios apurado com base nas alíquotas de referência de que trata o art. 130 deste Ato das Disposições Constitucionais Transitórias, deduzida a retenção de que trata o art. 131, § 1º, será retido montante correspondente a 5% (cinco por cento) para distribuição aos entes com as menores razões entre:", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 371, "vigente": true}, {"id": 372, "numero": 133, "numero_texto": "133", "caput": "Art. 133. Os tributos de que tratam os arts. 153, IV, 155, II, 156, III, e 195, I, \"b\", e IV, e a contribuição para o Programa de Integração Social a que se refere o art. 239 não integrarão a base de cálculo do imposto de que trata o art. 156-A e da contribuição de que trata o art. 195, V, todos da Constituição Federal.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 372, "vigente": true}, {"id": 373, "numero": 134, "numero_texto": "134", "caput": "Art. 134. Os saldos credores relativos ao imposto previsto no art. 155, II, da Constituição Federal, existentes ao final de 2032 serão aproveitados pelos contribuintes na forma deste artigo e nos termos de lei complementar.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 373, "vigente": true}, {"id": 374, "numero": 135, "numero_texto": "135", "caput": "Art. 135. Lei complementar disciplinará a forma de utilização dos créditos, inclusive presumidos, do imposto de que trata o art. 153, IV, e das contribuições de que tratam o art. 195, I, \"b\", e IV, e da contribuição para o Programa de Integração Social a que se refere o art. 239, todos da Constituição Federal, não apropriados ou não utilizados até a extinção, mantendo-se, apenas para os créditos que cumpram os requisitos estabelecidos na legislação vigente na data da extinção de tais tributos, a", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 374, "vigente": true}, {"id": 375, "numero": 136, "numero_texto": "136", "caput": "Art. 136. Os Estados que possuíam, em 30 de abril de 2023, fundos destinados a investimentos em obras de infraestrutura e habitação e financiados por contribuições sobre produtos primários e semielaborados estabelecidas como condição à aplicação de diferimento, regime especial ou outro tratamento diferenciado, relativos ao imposto de que trata o art. 155, II, da Constituição Federal, poderão instituir contribuições semelhantes, não vinculadas ao referido imposto, observado que:", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 375, "vigente": true}, {"id": 376, "numero": 137, "numero_texto": "137", "caput": "Art. 137. Os saldos financeiros dos recursos transferidos pelo Fundo Nacional de Saúde e pelo Fundo Nacional de Assistência Social, para enfrentamento da pandemia de Covid-19 no período de 2020 a 2022, aos fundos de saúde e assistência social estaduais, municipais e do Distrito Federal poderão ser aplicados, até 31 de dezembro de 2024, para o custeio de ações e serviços públicos de saúde e de assistência social, observadas, respectivamente, as diretrizes emanadas do Sistema Único de Saúde e do S", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 376, "vigente": true}, {"id": 377, "numero": 138, "numero_texto": "138", "caput": "Art. 138. Até 2032, qualquer criação, alteração ou prorrogação de vinculação legal ou constitucional de receitas a despesas, inclusive na hipótese de aplicação mínima de montante de recursos, não poderá resultar em crescimento anual da respectiva despesa primária superior à variação do limite de despesas primárias, na forma prevista na lei complementar de que trata o art. 6º da Emenda Constitucional nº 126, de 21 de dezembro de 2022.", "tipo": "ADCT", "titulo_id": null, "capitulo_id": null, "secao_id": null, "subsecao_id": null, "ordem": 377, "vigente": true}]
  const PARAGRAFOS = [{"id": 1, "artigo_id": 1, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Todo o poder emana do povo, que o exerce por meio de representantes eleitos ou diretamente, nos termos desta Constituição.", "ordem": 1}, {"id": 2, "artigo_id": 4, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. A República Federativa do Brasil buscará a integração econômica, política, social e cultural dos povos da América Latina, visando à formação de uma comunidade latino-americana de nações.", "ordem": 2}, {"id": 3, "artigo_id": 5, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º As normas definidoras dos direitos e garantias fundamentais têm aplicação imediata.", "ordem": 3}, {"id": 4, "artigo_id": 5, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os direitos e garantias expressos nesta Constituição não excluem outros decorrentes do regime e dos princípios por ela adotados, ou dos tratados internacionais em que a República Federativa do Brasil seja parte.", "ordem": 4}, {"id": 5, "artigo_id": 5, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Os tratados e convenções internacionais sobre direitos humanos que forem aprovados, em cada Casa do Congresso Nacional, em dois turnos, por três quintos dos votos dos respectivos membros, serão equivalentes às emendas constitucionais.", "ordem": 5}, {"id": 6, "artigo_id": 5, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º O Brasil se submete à jurisdição de Tribunal Penal Internacional a cuja criação tenha manifestado adesão.", "ordem": 6}, {"id": 7, "artigo_id": 6, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Todo brasileiro em situação de vulnerabilidade social terá direito a uma renda básica familiar, garantida pelo poder público em programa permanente de transferência de renda, cujas normas e requisitos de acesso serão determinados em lei, observada a legislação fiscal e orçamentária", "ordem": 7}, {"id": 8, "artigo_id": 7, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. São assegurados à categoria dos trabalhadores domésticos os direitos previstos nos incisos IV, VI, VII, VIII, X, XIII, XV, XVI, XVII, XVIII, XIX, XXI, XXII, XXIV, XXVI, XXX, XXXI e XXXIII e, atendidas as condições estabelecidas em lei e observada a simplificação do cumprimento das obrigações tributárias, principais e acessórias, decorrentes da relação de trabalho e suas peculiaridades, os previstos nos incisos I, II, III, IX, XII, XXV e XXVIII, bem como a sua integração à previdência social.", "ordem": 8}, {"id": 9, "artigo_id": 8, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. As disposições deste artigo aplicam-se à organização de sindicatos rurais e de colônias de pescadores, atendidas as condições que a lei estabelecer.", "ordem": 9}, {"id": 10, "artigo_id": 9, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A lei definirá os serviços ou atividades essenciais e disporá sobre o atendimento das necessidades inadiáveis da comunidade.", "ordem": 10}, {"id": 11, "artigo_id": 9, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os abusos cometidos sujeitam os responsáveis às penas da lei.", "ordem": 11}, {"id": 12, "artigo_id": 12, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Aos portugueses com residência permanente no País, se houver reciprocidade em favor de brasileiros, serão atribuídos os direitos inerentes ao brasileiro, salvo os casos previstos nesta Constituição.", "ordem": 12}, {"id": 13, "artigo_id": 12, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A lei não poderá estabelecer distinção entre brasileiros natos e naturalizados, salvo nos casos previstos nesta Constituição.", "ordem": 13}, {"id": 14, "artigo_id": 12, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º São privativos de brasileiro nato os cargos:", "ordem": 14}, {"id": 15, "artigo_id": 12, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º - Será declarada a perda da nacionalidade do brasileiro que:", "ordem": 15}, {"id": 16, "artigo_id": 12, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º A renúncia da nacionalidade, nos termos do inciso II do § 4º deste artigo, não impede o interessado de readquirir sua nacionalidade brasileira originária, nos termos da lei.", "ordem": 16}, {"id": 17, "artigo_id": 13, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º São símbolos da República Federativa do Brasil a bandeira, o hino, as armas e o selo nacionais.", "ordem": 17}, {"id": 18, "artigo_id": 13, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os Estados, o Distrito Federal e os Municípios poderão ter símbolos próprios.", "ordem": 18}, {"id": 19, "artigo_id": 14, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O alistamento eleitoral e o voto são:", "ordem": 19}, {"id": 20, "artigo_id": 14, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Não podem alistar-se como eleitores os estrangeiros e, durante o período do serviço militar obrigatório, os conscritos.", "ordem": 20}, {"id": 21, "artigo_id": 14, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º São condições de elegibilidade, na forma da lei:", "ordem": 21}, {"id": 22, "artigo_id": 14, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º São inelegíveis os inalistáveis e os analfabetos.", "ordem": 22}, {"id": 23, "artigo_id": 14, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º O Presidente da República, os Governadores de Estado e do Distrito Federal, os Prefeitos e quem os houver sucedido, ou substituído no curso dos mandatos poderão ser reeleitos para um único período subseqüente.", "ordem": 23}, {"id": 24, "artigo_id": 14, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Para concorrerem a outros cargos, o Presidente da República, os Governadores de Estado e do Distrito Federal e os Prefeitos devem renunciar aos respectivos mandatos até seis meses antes do pleito.", "ordem": 24}, {"id": 25, "artigo_id": 14, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º São inelegíveis, no território de jurisdição do titular, o cônjuge e os parentes consangüíneos ou afins, até o segundo grau ou por adoção, do Presidente da República, de Governador de Estado ou Território, do Distrito Federal, de Prefeito ou de quem os haja substituído dentro dos seis meses anteriores ao pleito, salvo se já titular de mandato eletivo e candidato à reeleição.", "ordem": 25}, {"id": 26, "artigo_id": 14, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º O militar alistável é elegível, atendidas as seguintes condições:", "ordem": 26}, {"id": 27, "artigo_id": 14, "tipo": "numerado", "numero": 9, "numero_texto": "9º", "texto": "§ 9º Lei complementar estabelecerá outros casos de inelegibilidade e os prazos de sua cessação, a fim de proteger a probidade administrativa, a moralidade para exercício de mandato considerada vida pregressa do candidato, e a normalidade e legitimidade das eleições contra a influência do poder econômico ou o abuso do exercício de função, cargo ou emprego na administração direta ou indireta.", "ordem": 27}, {"id": 28, "artigo_id": 14, "tipo": "numerado", "numero": 10, "numero_texto": "10º", "texto": "§ 10 - O mandato eletivo poderá ser impugnado ante a Justiça Eleitoral no prazo de quinze dias contados da diplomação, instruída a ação com provas de abuso do poder econômico, corrupção ou fraude.", "ordem": 28}, {"id": 29, "artigo_id": 14, "tipo": "numerado", "numero": 11, "numero_texto": "11º", "texto": "§ 11 - A ação de impugnação de mandato tramitará em segredo de justiça, respondendo o autor, na forma da lei, se temerária ou de manifesta má-fé.", "ordem": 29}, {"id": 30, "artigo_id": 17, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º É assegurada aos partidos políticos autonomia para definir sua estrutura interna e estabelecer regras sobre escolha, formação e duração de seus órgãos permanentes e provisórios e sobre sua organização e funcionamento e para adotar os critérios de escolha e o regime de suas coligações nas eleições majoritárias, vedada a sua celebração nas eleições proporcionais, sem obrigatoriedade de vinculação entre as candidaturas em âmbito nacional, estadual, distrital ou municipal, devendo seus estatutos estabelecer normas de disciplina e fidelidade partidária.", "ordem": 30}, {"id": 31, "artigo_id": 17, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os partidos políticos, após adquirirem personalidade jurídica, na forma da lei civil, registrarão seus estatutos no Tribunal Superior Eleitoral.", "ordem": 31}, {"id": 32, "artigo_id": 17, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Somente terão direito a recursos do fundo partidário e acesso gratuito ao rádio e à televisão, na forma da lei, os partidos políticos que alternativamente:", "ordem": 32}, {"id": 33, "artigo_id": 17, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º É vedada a utilização pelos partidos políticos de organização paramilitar.", "ordem": 33}, {"id": 34, "artigo_id": 17, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Ao eleito por partido que não preencher os requisitos previstos no § 3º deste artigo é assegurado o mandato e facultada a filiação, sem perda do mandato, a outro partido que os tenha atingido, não sendo essa filiação considerada para fins de distribuição dos recursos do fundo partidário e de acesso gratuito ao tempo de rádio e de televisão.", "ordem": 34}, {"id": 35, "artigo_id": 17, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Os Deputados Federais, os Deputados Estaduais, os Deputados Distritais e os Vereadores que se desligarem do partido pelo qual tenham sido eleitos perderão o mandato, salvo nos casos de anuência do partido ou de outras hipóteses de justa causa estabelecidas em lei, não computada, em qualquer caso, a migração de partido para fins de distribuição de recursos do fundo partidário ou de outros fundos públicos e de acesso gratuito ao rádio e à televisão.", "ordem": 35}, {"id": 36, "artigo_id": 17, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º Os partidos políticos devem aplicar no mínimo 5% (cinco por cento) dos recursos do fundo partidário na criação e na manutenção de programas de promoção e difusão da participação política das mulheres, de acordo com os interesses intrapartidários.", "ordem": 36}, {"id": 37, "artigo_id": 17, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º O montante do Fundo Especial de Financiamento de Campanha e da parcela do fundo partidário destinada a campanhas eleitorais, bem como o tempo de propaganda gratuita no rádio e na televisão a ser distribuído pelos partidos às respectivas candidatas, deverão ser de no mínimo 30% (trinta por cento), proporcional ao número de candidatas, e a distribuição deverá ser realizada conforme critérios definidos pelos respectivos órgãos de direção e pelas normas estatutárias, considerados a autonomia e o interesse partidário.", "ordem": 37}, {"id": 38, "artigo_id": 17, "tipo": "numerado", "numero": 9, "numero_texto": "9º", "texto": "§ 9º Dos recursos oriundos do Fundo Especial de Financiamento de Campanha e do fundo partidário destinados às campanhas eleitorais, os partidos políticos devem, obrigatoriamente, aplicar 30% (trinta por cento) em candidaturas de pessoas pretas e pardas, nas circunscrições que melhor atendam aos interesses e às estratégias partidárias.", "ordem": 38}, {"id": 39, "artigo_id": 18, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Brasília é a Capital Federal.", "ordem": 39}, {"id": 40, "artigo_id": 18, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os Territórios Federais integram a União, e sua criação, transformação em Estado ou reintegração ao Estado de origem serão reguladas em lei complementar.", "ordem": 40}, {"id": 41, "artigo_id": 18, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Os Estados podem incorporar-se entre si, subdividir-se ou desmembrar-se para se anexarem a outros, ou formarem novos Estados ou Territórios Federais, mediante aprovação da população diretamente interessada, através de plebiscito, e do Congresso Nacional, por lei complementar.", "ordem": 41}, {"id": 42, "artigo_id": 18, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º A criação, a incorporação, a fusão e o desmembramento de Municípios, far-se-ão por lei estadual, dentro do período determinado por Lei Complementar Federal, e dependerão de consulta prévia, mediante plebiscito, às populações dos Municípios envolvidos, após divulgação dos Estudos de Viabilidade Municipal, apresentados e publicados na forma da lei. Vide art. 96 - ADCT", "ordem": 42}, {"id": 43, "artigo_id": 20, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º É assegurada, nos termos da lei, à União, aos Estados, ao Distrito Federal e aos Municípios a participação no resultado da exploração de petróleo ou gás natural, de recursos hídricos para fins de geração de energia elétrica e de outros recursos minerais no respectivo território, plataforma continental, mar territorial ou zona econômica exclusiva, ou compensação financeira por essa exploração. (Produção de efeito)", "ordem": 43}, {"id": 44, "artigo_id": 20, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A faixa de até cento e cinqüenta quilômetros de largura, ao longo das fronteiras terrestres, designada como faixa de fronteira, é considerada fundamental para defesa do território nacional, e sua ocupação e utilização serão reguladas em lei.", "ordem": 44}, {"id": 45, "artigo_id": 22, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Lei complementar poderá autorizar os Estados a legislar sobre questões específicas das matérias relacionadas neste artigo.", "ordem": 45}, {"id": 46, "artigo_id": 23, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Leis complementares fixarão normas para a cooperação entre a União e os Estados, o Distrito Federal e os Municípios, tendo em vista o equilíbrio do desenvolvimento e do bem-estar em âmbito nacional.", "ordem": 46}, {"id": 47, "artigo_id": 24, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º No âmbito da legislação concorrente, a competência da União limitar-se-á a estabelecer normas gerais.", "ordem": 47}, {"id": 48, "artigo_id": 24, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A competência da União para legislar sobre normas gerais não exclui a competência suplementar dos Estados.", "ordem": 48}, {"id": 49, "artigo_id": 24, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Inexistindo lei federal sobre normas gerais, os Estados exercerão a competência legislativa plena, para atender a suas peculiaridades.", "ordem": 49}, {"id": 50, "artigo_id": 24, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º A superveniência de lei federal sobre normas gerais suspende a eficácia da lei estadual, no que lhe for contrário.", "ordem": 50}, {"id": 51, "artigo_id": 25, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º São reservadas aos Estados as competências que não lhes sejam vedadas por esta Constituição.", "ordem": 51}, {"id": 52, "artigo_id": 25, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Cabe aos Estados explorar diretamente, ou mediante concessão, os serviços locais de gás canalizado, na forma da lei, vedada a edição de medida provisória para a sua regulamentação.", "ordem": 52}, {"id": 53, "artigo_id": 25, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Os Estados poderão, mediante lei complementar, instituir regiões metropolitanas, aglomerações urbanas e microrregiões, constituídas por agrupamentos de municípios limítrofes, para integrar a organização, o planejamento e a execução de funções públicas de interesse comum.", "ordem": 53}, {"id": 54, "artigo_id": 27, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Será de quatro anos o mandato dos Deputados Estaduais, aplicando- sê-lhes as regras desta Constituição sobre sistema eleitoral, inviolabilidade, imunidades, remuneração, perda de mandato, licença, impedimentos e incorporação às Forças Armadas.", "ordem": 54}, {"id": 55, "artigo_id": 27, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O subsídio dos Deputados Estaduais será fixado por lei de iniciativa da Assembléia Legislativa, na razão de, no máximo, setenta e cinco por cento daquele estabelecido, em espécie, para os Deputados Federais, observado o que dispõem os arts. 39, § 4º, 57, § 7º, 150, II, 153, III, e 153, § 2º, I.", "ordem": 55}, {"id": 56, "artigo_id": 27, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Compete às Assembléias Legislativas dispor sobre seu regimento interno, polícia e serviços administrativos de sua secretaria, e prover os respectivos cargos.", "ordem": 56}, {"id": 57, "artigo_id": 27, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º A lei disporá sobre a iniciativa popular no processo legislativo estadual.", "ordem": 57}, {"id": 58, "artigo_id": 28, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Perderá o mandato o Governador que assumir outro cargo ou função na administração pública direta ou indireta, ressalvada a posse em virtude de concurso público e observado o disposto no art. 38, I, IV e V. (Renumerado do parágrafo único, pela Emenda Constitucional nº 19, de 1998)", "ordem": 58}, {"id": 59, "artigo_id": 28, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os subsídios do Governador, do Vice-Governador e dos Secretários de Estado serão fixados por lei de iniciativa da Assembléia Legislativa, observado o que dispõem os arts. 37, XI, 39, § 4º, 150, II, 153, III, e 153, § 2º, I.", "ordem": 59}, {"id": 60, "artigo_id": 29, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1 o A Câmara Municipal não gastará mais de setenta por cento de sua receita com folha de pagamento, incluído o gasto com o subsídio de seus Vereadores.", "ordem": 60}, {"id": 61, "artigo_id": 29, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2 o Constitui crime de responsabilidade do Prefeito Municipal:", "ordem": 61}, {"id": 62, "artigo_id": 29, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3 o Constitui crime de responsabilidade do Presidente da Câmara Municipal o desrespeito ao § 1 o deste artigo.", "ordem": 62}, {"id": 63, "artigo_id": 31, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O controle externo da Câmara Municipal será exercido com o auxílio dos Tribunais de Contas dos Estados ou do Município ou dos Conselhos ou Tribunais de Contas dos Municípios, onde houver.", "ordem": 63}, {"id": 64, "artigo_id": 31, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O parecer prévio, emitido pelo órgão competente sobre as contas que o Prefeito deve anualmente prestar, só deixará de prevalecer por decisão de dois terços dos membros da Câmara Municipal.", "ordem": 64}, {"id": 65, "artigo_id": 31, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º As contas dos Municípios ficarão, durante sessenta dias, anualmente, à disposição de qualquer contribuinte, para exame e apreciação, o qual poderá questionar-lhes a legitimidade, nos termos da lei.", "ordem": 65}, {"id": 66, "artigo_id": 31, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º É vedada a criação de Tribunais, Conselhos ou órgãos de Contas Municipais.", "ordem": 66}, {"id": 67, "artigo_id": 32, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Ao Distrito Federal são atribuídas as competências legislativas reservadas aos Estados e Municípios.", "ordem": 67}, {"id": 68, "artigo_id": 32, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A eleição do Governador e do Vice-Governador, observadas as regras do art. 77, e dos Deputados Distritais coincidirá com a dos Governadores e Deputados Estaduais, para mandato de igual duração.", "ordem": 68}, {"id": 69, "artigo_id": 32, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Aos Deputados Distritais e à Câmara Legislativa aplica-se o disposto no art. 27.", "ordem": 69}, {"id": 70, "artigo_id": 32, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Lei federal disporá sobre a utilização, pelo Governo do Distrito Federal, da polícia civil, da polícia penal, da polícia militar e do corpo de bombeiros militar.", "ordem": 70}, {"id": 71, "artigo_id": 33, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Os Territórios poderão ser divididos em Municípios, aos quais se aplicará, no que couber, o disposto no Capítulo IV deste Título.", "ordem": 71}, {"id": 72, "artigo_id": 33, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º As contas do Governo do Território serão submetidas ao Congresso Nacional, com parecer prévio do Tribunal de Contas da União.", "ordem": 72}, {"id": 73, "artigo_id": 33, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Nos Territórios Federais com mais de cem mil habitantes, além do Governador nomeado na forma desta Constituição, haverá órgãos judiciários de primeira e segunda instância, membros do Ministério Público e defensores públicos federais; a lei disporá sobre as eleições para a Câmara Territorial e sua competência deliberativa.", "ordem": 73}, {"id": 74, "artigo_id": 36, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O decreto de intervenção, que especificará a amplitude, o prazo e as condições de execução e que, se couber, nomeará o interventor, será submetido à apreciação do Congresso Nacional ou da Assembléia Legislativa do Estado, no prazo de vinte e quatro horas.", "ordem": 74}, {"id": 75, "artigo_id": 36, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Se não estiver funcionando o Congresso Nacional ou a Assembléia Legislativa, far-se-á convocação extraordinária, no mesmo prazo de vinte e quatro horas.", "ordem": 75}, {"id": 76, "artigo_id": 36, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Nos casos do art. 34, VI e VII, ou do art. 35, IV, dispensada a apreciação pelo Congresso Nacional ou pela Assembléia Legislativa, o decreto limitar-se-á a suspender a execução do ato impugnado, se essa medida bastar ao restabelecimento da normalidade.", "ordem": 76}, {"id": 77, "artigo_id": 36, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Cessados os motivos da intervenção, as autoridades afastadas de seus cargos a estes voltarão, salvo impedimento legal.", "ordem": 77}, {"id": 78, "artigo_id": 37, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A publicidade dos atos, programas, obras, serviços e campanhas dos órgãos públicos deverá ter caráter educativo, informativo ou de orientação social, dela não podendo constar nomes, símbolos ou imagens que caracterizem promoção pessoal de autoridades ou servidores públicos.", "ordem": 78}, {"id": 79, "artigo_id": 37, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A não observância do disposto nos incisos II e III implicará a nulidade do ato e a punição da autoridade responsável, nos termos da lei.", "ordem": 79}, {"id": 80, "artigo_id": 37, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º A lei disciplinará as formas de participação do usuário na administração pública direta e indireta, regulando especialmente:", "ordem": 80}, {"id": 81, "artigo_id": 37, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Os atos de improbidade administrativa importarão a suspensão dos direitos políticos, a perda da função pública, a indisponibilidade dos bens e o ressarcimento ao erário, na forma e gradação previstas em lei, sem prejuízo da ação penal cabível.", "ordem": 81}, {"id": 82, "artigo_id": 37, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º A lei estabelecerá os prazos de prescrição para ilícitos praticados por qualquer agente, servidor ou não, que causem prejuízos ao erário, ressalvadas as respectivas ações de ressarcimento.", "ordem": 82}, {"id": 83, "artigo_id": 37, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º As pessoas jurídicas de direito público e as de direito privado prestadoras de serviços públicos responderão pelos danos que seus agentes, nessa qualidade, causarem a terceiros, assegurado o direito de regresso contra o responsável nos casos de dolo ou culpa.", "ordem": 83}, {"id": 84, "artigo_id": 37, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º A lei disporá sobre os requisitos e as restrições ao ocupante de cargo ou emprego da administração direta e indireta que possibilite o acesso a informações privilegiadas.", "ordem": 84}, {"id": 85, "artigo_id": 37, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º A autonomia gerencial, orçamentária e financeira dos órgãos e entidades da administração direta e indireta poderá ser ampliada mediante contrato, a ser firmado entre seus administradores e o poder público, que tenha por objeto a fixação de metas de desempenho para o órgão ou entidade, cabendo à lei dispor sobre: (Regulamento) (Vigência)", "ordem": 85}, {"id": 86, "artigo_id": 37, "tipo": "numerado", "numero": 9, "numero_texto": "9º", "texto": "§ 9º O disposto no inciso XI aplica-se às empresas públicas e às sociedades de economia mista, e suas subsidiárias, que receberem recursos da União, dos Estados, do Distrito Federal ou dos Municípios para pagamento de despesas de pessoal ou de custeio em geral.", "ordem": 86}, {"id": 87, "artigo_id": 39, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A fixação dos padrões de vencimento e dos demais componentes do sistema remuneratório observará:", "ordem": 87}, {"id": 88, "artigo_id": 39, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A União, os Estados e o Distrito Federal manterão escolas de governo para a formação e o aperfeiçoamento dos servidores públicos, constituindo-se a participação nos cursos um dos requisitos para a promoção na carreira, facultada, para isso, a celebração de convênios ou contratos entre os entes federados.", "ordem": 88}, {"id": 89, "artigo_id": 39, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Aplica-se aos servidores ocupantes de cargo público o disposto no art. 7º, IV, VII, VIII, IX, XII, XIII, XV, XVI, XVII, XVIII, XIX, XX, XXII e XXX, podendo a lei estabelecer requisitos diferenciados de admissão quando a natureza do cargo o exigir.", "ordem": 89}, {"id": 90, "artigo_id": 39, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º O membro de Poder, o detentor de mandato eletivo, os Ministros de Estado e os Secretários Estaduais e Municipais serão remunerados exclusivamente por subsídio fixado em parcela única, vedado o acréscimo de qualquer gratificação, adicional, abono, prêmio, verba de representação ou outra espécie remuneratória, obedecido, em qualquer caso, o disposto no art. 37, X e XI.", "ordem": 90}, {"id": 91, "artigo_id": 39, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Lei da União, dos Estados, do Distrito Federal e dos Municípios poderá estabelecer a relação entre a maior e a menor remuneração dos servidores públicos, obedecido, em qualquer caso, o disposto no art. 37, XI.", "ordem": 91}, {"id": 92, "artigo_id": 39, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Os Poderes Executivo, Legislativo e Judiciário publicarão anualmente os valores do subsídio e da remuneração dos cargos e empregos públicos.", "ordem": 92}, {"id": 93, "artigo_id": 39, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º Lei da União, dos Estados, do Distrito Federal e dos Municípios disciplinará a aplicação de recursos orçamentários provenientes da economia com despesas correntes em cada órgão, autarquia e fundação, para aplicação no desenvolvimento de programas de qualidade e produtividade, treinamento e desenvolvimento, modernização, reaparelhamento e racionalização do serviço público, inclusive sob a forma de adicional ou prêmio de produtividade.", "ordem": 93}, {"id": 94, "artigo_id": 39, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º A remuneração dos servidores públicos organizados em carreira poderá ser fixada nos termos do § 4º.", "ordem": 94}, {"id": 95, "artigo_id": 39, "tipo": "numerado", "numero": 9, "numero_texto": "9º", "texto": "§ 9º É vedada a incorporação de vantagens de caráter temporário ou vinculadas ao exercício de função de confiança ou de cargo em comissão à remuneração do cargo efetivo.", "ordem": 95}, {"id": 96, "artigo_id": 40, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O servidor abrangido por regime próprio de previdência social será aposentado:", "ordem": 96}, {"id": 97, "artigo_id": 40, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os proventos de aposentadoria não poderão ser inferiores ao valor mínimo a que se refere o § 2º do art. 201 ou superiores ao limite máximo estabelecido para o Regime Geral de Previdência Social, observado o disposto nos §§ 14 a 16.", "ordem": 97}, {"id": 98, "artigo_id": 40, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º As regras para cálculo de proventos de aposentadoria serão disciplinadas em lei do respectivo ente federativo.", "ordem": 98}, {"id": 99, "artigo_id": 40, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º É vedada a adoção de requisitos ou critérios diferenciados para concessão de benefícios em regime próprio de previdência social, ressalvado o disposto nos §§ 4º-A, 4º-B, 4º-C e 5º.", "ordem": 99}, {"id": 100, "artigo_id": 40, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Os ocupantes do cargo de professor terão idade mínima reduzida em 5 (cinco) anos em relação às idades decorrentes da aplicação do disposto no inciso III do § 1º, desde que comprovem tempo de efetivo exercício das funções de magistério na educação infantil e no ensino fundamental e médio fixado em lei complementar do respectivo ente federativo.", "ordem": 100}, {"id": 101, "artigo_id": 40, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Ressalvadas as aposentadorias decorrentes dos cargos acumuláveis na forma desta Constituição, é vedada a percepção de mais de uma aposentadoria à conta de regime próprio de previdência social, aplicando-se outras vedações, regras e condições para a acumulação de benefícios previdenciários estabelecidas no Regime Geral de Previdência Social.", "ordem": 101}, {"id": 102, "artigo_id": 40, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º Observado o disposto no § 2º do art. 201, quando se tratar da única fonte de renda formal auferida pelo dependente, o benefício de pensão por morte será concedido nos termos de lei do respectivo ente federativo, a qual tratará de forma diferenciada a hipótese de morte dos servidores de que trata o § 4º-B decorrente de agressão sofrida no exercício ou em razão da função.", "ordem": 102}, {"id": 103, "artigo_id": 40, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º É assegurado o reajustamento dos benefícios para preservar-lhes, em caráter permanente, o valor real, conforme critérios estabelecidos em lei.", "ordem": 103}, {"id": 104, "artigo_id": 40, "tipo": "numerado", "numero": 9, "numero_texto": "9º", "texto": "§ 9º O tempo de contribuição federal, estadual, distrital ou municipal será contado para fins de aposentadoria, observado o disposto nos §§ 9º e 9º-A do art. 201, e o tempo de serviço correspondente será contado para fins de disponibilidade.", "ordem": 104}, {"id": 105, "artigo_id": 40, "tipo": "numerado", "numero": 10, "numero_texto": "10º", "texto": "§ 10 - A lei não poderá estabelecer qualquer forma de contagem de tempo de contribuição fictício.", "ordem": 105}, {"id": 106, "artigo_id": 40, "tipo": "numerado", "numero": 11, "numero_texto": "11º", "texto": "§ 11 - Aplica-se o limite fixado no art. 37, XI, à soma total dos proventos de inatividade, inclusive quando decorrentes da acumulação de cargos ou empregos públicos, bem como de outras atividades sujeitas a contribuição para o regime geral de previdência social, e ao montante resultante da adição de proventos de inatividade com remuneração de cargo acumulável na forma desta Constituição, cargo em comissão declarado em lei de livre nomeação e exoneração, e de cargo eletivo.", "ordem": 106}, {"id": 107, "artigo_id": 40, "tipo": "numerado", "numero": 16, "numero_texto": "16º", "texto": "§ 16 - Somente mediante sua prévia e expressa opção, o disposto nos § § 14 e 15 poderá ser aplicado ao servidor que tiver ingressado no serviço público até a data da publicação do ato de instituição do correspondente regime de previdência complementar.", "ordem": 107}, {"id": 108, "artigo_id": 41, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O servidor público estável só perderá o cargo:", "ordem": 108}, {"id": 109, "artigo_id": 41, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Invalidada por sentença judicial a demissão do servidor estável, será ele reintegrado, e o eventual ocupante da vaga, se estável, reconduzido ao cargo de origem, sem direito a indenização, aproveitado em outro cargo ou posto em disponibilidade com remuneração proporcional ao tempo de serviço.", "ordem": 109}, {"id": 110, "artigo_id": 41, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Extinto o cargo ou declarada a sua desnecessidade, o servidor estável ficará em disponibilidade, com remuneração proporcional ao tempo de serviço, até seu adequado aproveitamento em outro cargo.", "ordem": 110}, {"id": 111, "artigo_id": 41, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Como condição para a aquisição da estabilidade, é obrigatória a avaliação especial de desempenho por comissão instituída para essa finalidade.", "ordem": 111}, {"id": 112, "artigo_id": 42, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Aplicam-se aos militares dos Estados, do Distrito Federal e dos Territórios, além do que vier a ser fixado em lei, as disposições do art. 14, § 8º; do art. 40, § 9º; e do art. 142, §§ 2º e 3º, cabendo a lei estadual específica dispor sobre as matérias do art. 142, § 3º, inciso X, sendo as patentes dos oficiais conferidas pelos respectivos governadores.", "ordem": 112}, {"id": 113, "artigo_id": 42, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Aos pensionistas dos militares dos Estados, do Distrito Federal e dos Territórios aplica-se o que for fixado em lei específica do respectivo ente estatal.", "ordem": 113}, {"id": 114, "artigo_id": 42, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Aplica-se aos militares dos Estados, do Distrito Federal e dos Territórios o disposto no art. 37, inciso XVI, com prevalência da atividade militar.", "ordem": 114}, {"id": 115, "artigo_id": 43, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Lei complementar disporá sobre:", "ordem": 115}, {"id": 116, "artigo_id": 43, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os incentivos regionais compreenderão, além de outros, na forma da lei:", "ordem": 116}, {"id": 117, "artigo_id": 43, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Nas áreas a que se refere o § 2º, IV, a União incentivará a recuperação de terras áridas e cooperará com os pequenos e médios proprietários rurais para o estabelecimento, em suas glebas, de fontes de água e de pequena irrigação.", "ordem": 117}, {"id": 118, "artigo_id": 43, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Sempre que possível, a concessão dos incentivos regionais a que se refere o § 2º, III, considerará critérios de sustentabilidade ambiental e redução das emissões de carbono.", "ordem": 118}, {"id": 119, "artigo_id": 44, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Cada legislatura terá a duração de quatro anos.", "ordem": 119}, {"id": 120, "artigo_id": 45, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O número total de Deputados, bem como a representação por Estado e pelo Distrito Federal, será estabelecido por lei complementar, proporcionalmente à população, procedendo-se aos ajustes necessários, no ano anterior às eleições, para que nenhuma daquelas unidades da Federação tenha menos de oito ou mais de setenta Deputados.", "ordem": 120}, {"id": 121, "artigo_id": 45, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Cada Território elegerá quatro Deputados.", "ordem": 121}, {"id": 122, "artigo_id": 46, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Cada Estado e o Distrito Federal elegerão três Senadores, com mandato de oito anos.", "ordem": 122}, {"id": 123, "artigo_id": 46, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A representação de cada Estado e do Distrito Federal será renovada de quatro em quatro anos, alternadamente, por um e dois terços.", "ordem": 123}, {"id": 124, "artigo_id": 46, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Cada Senador será eleito com dois suplentes.", "ordem": 124}, {"id": 125, "artigo_id": 50, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Os Ministros de Estado poderão comparecer ao Senado Federal, à Câmara dos Deputados, ou a qualquer de suas Comissões, por sua iniciativa e mediante entendimentos com a Mesa respectiva, para expor assunto de relevância de seu Ministério.", "ordem": 125}, {"id": 126, "artigo_id": 50, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º As Mesas da Câmara dos Deputados e do Senado Federal poderão encaminhar pedidos escritos de informações a Ministros de Estado ou a qualquer das pessoas referidas no caput deste artigo, importando em crime de responsabilidade a recusa, ou o não - atendimento, no prazo de trinta dias, bem como a prestação de informações falsas.", "ordem": 126}, {"id": 127, "artigo_id": 52, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Nos casos previstos nos incisos I e II, funcionará como Presidente o do Supremo Tribunal Federal, limitando-se a condenação, que somente será proferida por dois terços dos votos do Senado Federal, à perda do cargo, com inabilitação, por oito anos, para o exercício de função pública, sem prejuízo das demais sanções judiciais cabíveis.", "ordem": 127}, {"id": 128, "artigo_id": 53, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Os Deputados e Senadores, desde a expedição do diploma, serão submetidos a julgamento perante o Supremo Tribunal Federal.", "ordem": 128}, {"id": 129, "artigo_id": 53, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Desde a expedição do diploma, os membros do Congresso Nacional não poderão ser presos, salvo em flagrante de crime inafiançável. Nesse caso, os autos serão remetidos dentro de vinte e quatro horas à Casa respectiva, para que, pelo voto da maioria de seus membros, resolva sobre a prisão.", "ordem": 129}, {"id": 130, "artigo_id": 53, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Recebida a denúncia contra o Senador ou Deputado, por crime ocorrido após a diplomação, o Supremo Tribunal Federal dará ciência à Casa respectiva, que, por iniciativa de partido político nela representado e pelo voto da maioria de seus membros, poderá, até a decisão final, sustar o andamento da ação.", "ordem": 130}, {"id": 131, "artigo_id": 53, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º O pedido de sustação será apreciado pela Casa respectiva no prazo improrrogável de quarenta e cinco dias do seu recebimento pela Mesa Diretora.", "ordem": 131}, {"id": 132, "artigo_id": 53, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º A sustação do processo suspende a prescrição, enquanto durar o mandato.", "ordem": 132}, {"id": 133, "artigo_id": 53, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Os Deputados e Senadores não serão obrigados a testemunhar sobre informações recebidas ou prestadas em razão do exercício do mandato, nem sobre as pessoas que lhes confiaram ou deles receberam informações.", "ordem": 133}, {"id": 134, "artigo_id": 53, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º A incorporação às Forças Armadas de Deputados e Senadores, embora militares e ainda que em tempo de guerra, dependerá de prévia licença da Casa respectiva.", "ordem": 134}, {"id": 135, "artigo_id": 53, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º As imunidades de Deputados ou Senadores subsistirão durante o estado de sítio, só podendo ser suspensas mediante o voto de dois terços dos membros da Casa respectiva, nos casos de atos praticados fora do recinto do Congresso Nacional, que sejam incompatíveis com a execução da medida.", "ordem": 135}, {"id": 136, "artigo_id": 55, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º - É incompatível com o decoro parlamentar, além dos casos definidos no regimento interno, o abuso das prerrogativas asseguradas a membro do Congresso Nacional ou a percepção de vantagens indevidas.", "ordem": 136}, {"id": 137, "artigo_id": 55, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Nos casos dos incisos I, II e VI, a perda do mandato será decidida pela Câmara dos Deputados ou pelo Senado Federal, por maioria absoluta, mediante provocação da respectiva Mesa ou de partido político representado no Congresso Nacional, assegurada ampla defesa.", "ordem": 137}, {"id": 138, "artigo_id": 55, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Nos casos previstos nos incisos III a V, a perda será declarada pela Mesa da Casa respectiva, de ofício ou mediante provocação de qualquer de seus membros, ou de partido político representado no Congresso Nacional, assegurada ampla defesa.", "ordem": 138}, {"id": 139, "artigo_id": 55, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º A renúncia de parlamentar submetido a processo que vise ou possa levar à perda do mandato, nos termos deste artigo, terá seus efeitos suspensos até as deliberações finais de que tratam os §§ 2º e 3º.", "ordem": 139}, {"id": 140, "artigo_id": 56, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O suplente será convocado nos casos de vaga, de investidura em funções previstas neste artigo ou de licença superior a cento e vinte dias.", "ordem": 140}, {"id": 141, "artigo_id": 56, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Ocorrendo vaga e não havendo suplente, far-se-á eleição para preenchê-la se faltarem mais de quinze meses para o término do mandato.", "ordem": 141}, {"id": 142, "artigo_id": 56, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Na hipótese do inciso I, o Deputado ou Senador poderá optar pela remuneração do mandato.", "ordem": 142}, {"id": 143, "artigo_id": 57, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º As reuniões marcadas para essas datas serão transferidas para o primeiro dia útil subseqüente, quando recaírem em sábados, domingos ou feriados.", "ordem": 143}, {"id": 144, "artigo_id": 57, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A sessão legislativa não será interrompida sem a aprovação do projeto de lei de diretrizes orçamentárias.", "ordem": 144}, {"id": 145, "artigo_id": 57, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Além de outros casos previstos nesta Constituição, a Câmara dos Deputados e o Senado Federal reunir-se-ão em sessão conjunta para:", "ordem": 145}, {"id": 146, "artigo_id": 57, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Cada uma das Casas reunir-se-á em sessões preparatórias, a partir de 1º de fevereiro, no primeiro ano da legislatura, para a posse de seus membros e eleição das respectivas Mesas, para mandato de 2 (dois) anos, vedada a recondução para o mesmo cargo na eleição imediatamente subseqüente.", "ordem": 146}, {"id": 147, "artigo_id": 57, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º A Mesa do Congresso Nacional será presidida pelo Presidente do Senado Federal, e os demais cargos serão exercidos, alternadamente, pelos ocupantes de cargos equivalentes na Câmara dos Deputados e no Senado Federal.", "ordem": 147}, {"id": 148, "artigo_id": 57, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º A convocação extraordinária do Congresso Nacional far-se-á:", "ordem": 148}, {"id": 149, "artigo_id": 57, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º Na sessão legislativa extraordinária, o Congresso Nacional somente deliberará sobre a matéria para a qual foi convocado, ressalvada a hipótese do § 8º deste artigo, vedado o pagamento de parcela indenizatória, em razão da convocação.", "ordem": 149}, {"id": 150, "artigo_id": 57, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º Havendo medidas provisórias em vigor na data de convocação extraordinária do Congresso Nacional, serão elas automaticamente incluídas na pauta da convocação.", "ordem": 150}, {"id": 151, "artigo_id": 58, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Na constituição das Mesas e de cada Comissão, é assegurada, tanto quanto possível, a representação proporcional dos partidos ou dos blocos parlamentares que participam da respectiva Casa.", "ordem": 151}, {"id": 152, "artigo_id": 58, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Às comissões, em razão da matéria de sua competência, cabe:", "ordem": 152}, {"id": 153, "artigo_id": 58, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º As comissões parlamentares de inquérito, que terão poderes de investigação próprios das autoridades judiciais, além de outros previstos nos regimentos das respectivas Casas, serão criadas pela Câmara dos Deputados e pelo Senado Federal, em conjunto ou separadamente, mediante requerimento de um terço de seus membros, para a apuração de fato determinado e por prazo certo, sendo suas conclusões, se for o caso, encaminhadas ao Ministério Público, para que promova a responsabilidade civil ou criminal dos infratores.", "ordem": 153}, {"id": 154, "artigo_id": 58, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Durante o recesso, haverá uma Comissão representativa do Congresso Nacional, eleita por suas Casas na última sessão ordinária do período legislativo, com atribuições definidas no regimento comum, cuja composição reproduzirá, quanto possível, a proporcionalidade da representação partidária.", "ordem": 154}, {"id": 155, "artigo_id": 59, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Lei complementar disporá sobre a elaboração, redação, alteração e consolidação das leis.", "ordem": 155}, {"id": 156, "artigo_id": 60, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A Constituição não poderá ser emendada na vigência de intervenção federal, de estado de defesa ou de estado de sítio.", "ordem": 156}, {"id": 157, "artigo_id": 60, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A proposta será discutida e votada em cada Casa do Congresso Nacional, em dois turnos, considerando-se aprovada se obtiver, em ambos, três quintos dos votos dos respectivos membros.", "ordem": 157}, {"id": 158, "artigo_id": 60, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º A emenda à Constituição será promulgada pelas Mesas da Câmara dos Deputados e do Senado Federal, com o respectivo número de ordem.", "ordem": 158}, {"id": 159, "artigo_id": 60, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Não será objeto de deliberação a proposta de emenda tendente a abolir:", "ordem": 159}, {"id": 160, "artigo_id": 60, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º A matéria constante de proposta de emenda rejeitada ou havida por prejudicada não pode ser objeto de nova proposta na mesma sessão legislativa.", "ordem": 160}, {"id": 161, "artigo_id": 61, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º São de iniciativa privativa do Presidente da República as leis que:", "ordem": 161}, {"id": 162, "artigo_id": 61, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A iniciativa popular pode ser exercida pela apresentação à Câmara dos Deputados de projeto de lei subscrito por, no mínimo, um por cento do eleitorado nacional, distribuído pelo menos por cinco Estados, com não menos de três décimos por cento dos eleitores de cada um deles.", "ordem": 162}, {"id": 163, "artigo_id": 62, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º É vedada a edição de medidas provisórias sobre matéria:", "ordem": 163}, {"id": 164, "artigo_id": 62, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Medida provisória que implique instituição ou majoração de impostos, exceto os previstos nos arts. 153, I, II, IV, V, e 154, II, só produzirá efeitos no exercício financeiro seguinte se houver sido convertida em lei até o último dia daquele em que foi editada.", "ordem": 164}, {"id": 165, "artigo_id": 62, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º As medidas provisórias, ressalvado o disposto nos §§ 11 e 12 perderão eficácia, desde a edição, se não forem convertidas em lei no prazo de sessenta dias, prorrogável, nos termos do § 7º, uma vez por igual período, devendo o Congresso Nacional disciplinar, por decreto legislativo, as relações jurídicas delas decorrentes.", "ordem": 165}, {"id": 166, "artigo_id": 62, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º O prazo a que se refere o § 3º contar-se-á da publicação da medida provisória, suspendendo-se durante os períodos de recesso do Congresso Nacional.", "ordem": 166}, {"id": 167, "artigo_id": 62, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º A deliberação de cada uma das Casas do Congresso Nacional sobre o mérito das medidas provisórias dependerá de juízo prévio sobre o atendimento de seus pressupostos constitucionais.", "ordem": 167}, {"id": 168, "artigo_id": 62, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Se a medida provisória não for apreciada em até quarenta e cinco dias contados de sua publicação, entrará em regime de urgência, subseqüentemente, em cada uma das Casas do Congresso Nacional, ficando sobrestadas, até que se ultime a votação, todas as demais deliberações legislativas da Casa em que estiver tramitando.", "ordem": 168}, {"id": 169, "artigo_id": 62, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º Prorrogar-se-á uma única vez por igual período a vigência de medida provisória que, no prazo de sessenta dias, contado de sua publicação, não tiver a sua votação encerrada nas duas Casas do Congresso Nacional.", "ordem": 169}, {"id": 170, "artigo_id": 62, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º As medidas provisórias terão sua votação iniciada na Câmara dos Deputados.", "ordem": 170}, {"id": 171, "artigo_id": 62, "tipo": "numerado", "numero": 9, "numero_texto": "9º", "texto": "§ 9º Caberá à comissão mista de Deputados e Senadores examinar as medidas provisórias e sobre elas emitir parecer, antes de serem apreciadas, em sessão separada, pelo plenário de cada uma das Casas do Congresso Nacional.", "ordem": 171}, {"id": 172, "artigo_id": 64, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º - O Presidente da República poderá solicitar urgência para apreciação de projetos de sua iniciativa.", "ordem": 172}, {"id": 173, "artigo_id": 64, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Se, no caso do § 1º, a Câmara dos Deputados e o Senado Federal não se manifestarem sobre a proposição, cada qual sucessivamente, em até quarenta e cinco dias, sobrestar-se-ão todas as demais deliberações legislativas da respectiva Casa, com exceção das que tenham prazo constitucional determinado, até que se ultime a votação.", "ordem": 173}, {"id": 174, "artigo_id": 64, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º A apreciação das emendas do Senado Federal pela Câmara dos Deputados far-se-á no prazo de dez dias, observado quanto ao mais o disposto no parágrafo anterior.", "ordem": 174}, {"id": 175, "artigo_id": 64, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Os prazos do § 2º não correm nos períodos de recesso do Congresso Nacional, nem se aplicam aos projetos de código.", "ordem": 175}, {"id": 176, "artigo_id": 65, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Sendo o projeto emendado, voltará à Casa iniciadora.", "ordem": 176}, {"id": 177, "artigo_id": 66, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Se o Presidente da República considerar o projeto, no todo ou em parte, inconstitucional ou contrário ao interesse público, vetá-lo-á total ou parcialmente, no prazo de quinze dias úteis, contados da data do recebimento, e comunicará, dentro de quarenta e oito horas, ao Presidente do Senado Federal os motivos do veto.", "ordem": 177}, {"id": 178, "artigo_id": 66, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O veto parcial somente abrangerá texto integral de artigo, de parágrafo, de inciso ou de alínea.", "ordem": 178}, {"id": 179, "artigo_id": 66, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Decorrido o prazo de quinze dias, o silêncio do Presidente da República importará sanção.", "ordem": 179}, {"id": 180, "artigo_id": 66, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º O veto será apreciado em sessão conjunta, dentro de trinta dias a contar de seu recebimento, só podendo ser rejeitado pelo voto da maioria absoluta dos Deputados e Senadores.", "ordem": 180}, {"id": 181, "artigo_id": 66, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Se o veto não for mantido, será o projeto enviado, para promulgação, ao Presidente da República.", "ordem": 181}, {"id": 182, "artigo_id": 66, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Esgotado sem deliberação o prazo estabelecido no § 4º, o veto será colocado na ordem do dia da sessão imediata, sobrestadas as demais proposições, até sua votação final.", "ordem": 182}, {"id": 183, "artigo_id": 66, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º Se a lei não for promulgada dentro de quarenta e oito horas pelo Presidente da República, nos casos dos § 3º e § 5º, o Presidente do Senado a promulgará, e, se este não o fizer em igual prazo, caberá ao Vice-Presidente do Senado fazê-lo.", "ordem": 183}, {"id": 184, "artigo_id": 68, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Não serão objeto de delegação os atos de competência exclusiva do Congresso Nacional, os de competência privativa da Câmara dos Deputados ou do Senado Federal, a matéria reservada à lei complementar, nem a legislação sobre:", "ordem": 184}, {"id": 185, "artigo_id": 68, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A delegação ao Presidente da República terá a forma de resolução do Congresso Nacional, que especificará seu conteúdo e os termos de seu exercício.", "ordem": 185}, {"id": 186, "artigo_id": 68, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Se a resolução determinar a apreciação do projeto pelo Congresso Nacional, este a fará em votação única, vedada qualquer emenda.", "ordem": 186}, {"id": 187, "artigo_id": 70, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Prestará contas qualquer pessoa física ou jurídica, pública ou privada, que utilize, arrecade, guarde, gerencie ou administre dinheiros, bens e valores públicos ou pelos quais a União responda, ou que, em nome desta, assuma obrigações de natureza pecuniária.", "ordem": 187}, {"id": 188, "artigo_id": 71, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º No caso de contrato, o ato de sustação será adotado diretamente pelo Congresso Nacional, que solicitará, de imediato, ao Poder Executivo as medidas cabíveis.", "ordem": 188}, {"id": 189, "artigo_id": 71, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Se o Congresso Nacional ou o Poder Executivo, no prazo de noventa dias, não efetivar as medidas previstas no parágrafo anterior, o Tribunal decidirá a respeito.", "ordem": 189}, {"id": 190, "artigo_id": 71, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º As decisões do Tribunal de que resulte imputação de débito ou multa terão eficácia de título executivo.", "ordem": 190}, {"id": 191, "artigo_id": 71, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º O Tribunal encaminhará ao Congresso Nacional, trimestral e anualmente, relatório de suas atividades.", "ordem": 191}, {"id": 192, "artigo_id": 72, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Não prestados os esclarecimentos, ou considerados estes insuficientes, a Comissão solicitará ao Tribunal pronunciamento conclusivo sobre a matéria, no prazo de trinta dias.", "ordem": 192}, {"id": 193, "artigo_id": 72, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Entendendo o Tribunal irregular a despesa, a Comissão, se julgar que o gasto possa causar dano irreparável ou grave lesão à economia pública, proporá ao Congresso Nacional sua sustação.", "ordem": 193}, {"id": 194, "artigo_id": 73, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Os Ministros do Tribunal de Contas da União serão nomeados dentre brasileiros que satisfaçam os seguintes requisitos:", "ordem": 194}, {"id": 195, "artigo_id": 73, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os Ministros do Tribunal de Contas da União serão escolhidos:", "ordem": 195}, {"id": 196, "artigo_id": 73, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3° Os Ministros do Tribunal de Contas da União terão as mesmas garantias, prerrogativas, impedimentos, vencimentos e vantagens dos Ministros do Superior Tribunal de Justiça, aplicando-se-lhes, quanto à aposentadoria e pensão, as normas constantes do art. 40.", "ordem": 196}, {"id": 197, "artigo_id": 73, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º O auditor, quando em substituição a Ministro, terá as mesmas garantias e impedimentos do titular e, quando no exercício das demais atribuições da judicatura, as de juiz de Tribunal Regional Federal.", "ordem": 197}, {"id": 198, "artigo_id": 74, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Os responsáveis pelo controle interno, ao tomarem conhecimento de qualquer irregularidade ou ilegalidade, dela darão ciência ao Tribunal de Contas da União, sob pena de responsabilidade solidária.", "ordem": 198}, {"id": 199, "artigo_id": 74, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Qualquer cidadão, partido político, associação ou sindicato é parte legítima para, na forma da lei, denunciar irregularidades ou ilegalidades perante o Tribunal de Contas da União.", "ordem": 199}, {"id": 200, "artigo_id": 75, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. As Constituições estaduais disporão sobre os Tribunais de Contas respectivos, que serão integrados por sete Conselheiros.", "ordem": 200}, {"id": 201, "artigo_id": 77, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A eleição do Presidente da República importará a do Vice-Presidente com ele registrado.", "ordem": 201}, {"id": 202, "artigo_id": 77, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Será considerado eleito Presidente o candidato que, registrado por partido político, obtiver a maioria absoluta de votos, não computados os em branco e os nulos.", "ordem": 202}, {"id": 203, "artigo_id": 77, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Se nenhum candidato alcançar maioria absoluta na primeira votação, far-se-á nova eleição em até vinte dias após a proclamação do resultado, concorrendo os dois candidatos mais votados e considerando-se eleito aquele que obtiver a maioria dos votos válidos.", "ordem": 203}, {"id": 204, "artigo_id": 77, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Se, antes de realizado o segundo turno, ocorrer morte, desistência ou impedimento legal de candidato, convocar-se-á, dentre os remanescentes, o de maior votação.", "ordem": 204}, {"id": 205, "artigo_id": 77, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Se, na hipótese dos parágrafos anteriores, remanescer, em segundo lugar, mais de um candidato com a mesma votação, qualificar-se-á o mais idoso.", "ordem": 205}, {"id": 206, "artigo_id": 78, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Se, decorridos dez dias da data fixada para a posse, o Presidente ou o Vice-Presidente, salvo motivo de força maior, não tiver assumido o cargo, este será declarado vago.", "ordem": 206}, {"id": 207, "artigo_id": 79, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. O Vice-Presidente da República, além de outras atribuições que lhe forem conferidas por lei complementar, auxiliará o Presidente, sempre que por ele convocado para missões especiais.", "ordem": 207}, {"id": 208, "artigo_id": 81, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Ocorrendo a vacância nos últimos dois anos do período presidencial, a eleição para ambos os cargos será feita trinta dias depois da última vaga, pelo Congresso Nacional, na forma da lei.", "ordem": 208}, {"id": 209, "artigo_id": 81, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Em qualquer dos casos, os eleitos deverão completar o período de seus antecessores.", "ordem": 209}, {"id": 210, "artigo_id": 84, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. O Presidente da República poderá delegar as atribuições mencionadas nos incisos VI, XII e XXV, primeira parte, aos Ministros de Estado, ao Procurador-Geral da República ou ao Advogado-Geral da União, que observarão os limites traçados nas respectivas delegações.", "ordem": 210}, {"id": 211, "artigo_id": 85, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Esses crimes serão definidos em lei especial, que estabelecerá as normas de processo e julgamento.", "ordem": 211}, {"id": 212, "artigo_id": 86, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O Presidente ficará suspenso de suas funções:", "ordem": 212}, {"id": 213, "artigo_id": 86, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Se, decorrido o prazo de cento e oitenta dias, o julgamento não estiver concluído, cessará o afastamento do Presidente, sem prejuízo do regular prosseguimento do processo.", "ordem": 213}, {"id": 214, "artigo_id": 86, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Enquanto não sobrevier sentença condenatória, nas infrações comuns, o Presidente da República não estará sujeito a prisão.", "ordem": 214}, {"id": 215, "artigo_id": 86, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º O Presidente da República, na vigência de seu mandato, não pode ser responsabilizado por atos estranhos ao exercício de suas funções.", "ordem": 215}, {"id": 216, "artigo_id": 87, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Compete ao Ministro de Estado, além de outras atribuições estabelecidas nesta Constituição e na lei:", "ordem": 216}, {"id": 217, "artigo_id": 90, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O Presidente da República poderá convocar Ministro de Estado para participar da reunião do Conselho, quando constar da pauta questão relacionada com o respectivo Ministério.", "ordem": 217}, {"id": 218, "artigo_id": 90, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A lei regulará a organização e o funcionamento do Conselho da República.", "ordem": 218}, {"id": 219, "artigo_id": 91, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Compete ao Conselho de Defesa Nacional:", "ordem": 219}, {"id": 220, "artigo_id": 91, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A lei regulará a organização e o funcionamento do Conselho de Defesa Nacional.", "ordem": 220}, {"id": 221, "artigo_id": 92, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O Supremo Tribunal Federal, o Conselho Nacional de Justiça e os Tribunais Superiores têm sede na Capital Federal.", "ordem": 221}, {"id": 222, "artigo_id": 92, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O Supremo Tribunal Federal e os Tribunais Superiores têm jurisdição em todo o território nacional.", "ordem": 222}, {"id": 223, "artigo_id": 94, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Recebidas as indicações, o tribunal formará lista tríplice, enviando-a ao Poder Executivo, que, nos vinte dias subseqüentes, escolherá um de seus integrantes para nomeação.", "ordem": 223}, {"id": 224, "artigo_id": 95, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Aos juízes é vedado:", "ordem": 224}, {"id": 225, "artigo_id": 96, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Nos Tribunais de Justiça compostos de mais de 170 (cento e setenta) desembargadores em efetivo exercício, a eleição para os cargos diretivos, de que trata a alínea \"a\" do inciso I docaputdeste artigo, será realizada entre os membros do tribunal pleno, por maioria absoluta e por voto direto e secreto, para um mandato de 2 (dois) anos, vedada mais de 1 (uma) recondução sucessiva.", "ordem": 225}, {"id": 226, "artigo_id": 98, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Lei federal disporá sobre a criação de juizados especiais no âmbito da Justiça Federal. (Renumerado pela Emenda Constitucional nº 45, de 2004)", "ordem": 226}, {"id": 227, "artigo_id": 98, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º As custas e emolumentos serão destinados exclusivamente ao custeio dos serviços afetos às atividades específicas da Justiça.", "ordem": 227}, {"id": 228, "artigo_id": 99, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Os tribunais elaborarão suas propostas orçamentárias dentro dos limites estipulados conjuntamente com os demais Poderes na lei de diretrizes orçamentárias.", "ordem": 228}, {"id": 229, "artigo_id": 99, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O encaminhamento da proposta, ouvidos os outros tribunais interessados, compete:", "ordem": 229}, {"id": 230, "artigo_id": 99, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Se os órgãos referidos no § 2º não encaminharem as respectivas propostas orçamentárias dentro do prazo estabelecido na lei de diretrizes orçamentárias, o Poder Executivo considerará, para fins de consolidação da proposta orçamentária anual, os valores aprovados na lei orçamentária vigente, ajustados de acordo com os limites estipulados na forma do § 1º deste artigo.", "ordem": 230}, {"id": 231, "artigo_id": 99, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Se as propostas orçamentárias de que trata este artigo forem encaminhadas em desacordo com os limites estipulados na forma do § 1º, o Poder Executivo procederá aos ajustes necessários para fins de consolidação da proposta orçamentária anual.", "ordem": 231}, {"id": 232, "artigo_id": 99, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Durante a execução orçamentária do exercício, não poderá haver a realização de despesas ou a assunção de obrigações que extrapolem os limites estabelecidos na lei de diretrizes orçamentárias, exceto se previamente autorizadas, mediante a abertura de créditos suplementares ou especiais.", "ordem": 232}, {"id": 233, "artigo_id": 100, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Os débitos de natureza alimentícia compreendem aqueles decorrentes da relação laboral ou previdenciária, independentemente da sua natureza tributária, inclusive os oriundos de repetição de indébito incidente sobre remuneração ou proventos de aposentadoria, bem como indenizações por morte ou por invalidez, fundadas em responsabilidade civil, em virtude de sentença judicial transitada em julgado, e serão pagos com preferência sobre todos os demais débitos, exceto sobre aqueles referidos no § 2º deste artigo.", "ordem": 233}, {"id": 234, "artigo_id": 100, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os débitos de natureza alimentícia cujos titulares, originários ou por sucessão hereditária, tenham 60 (sessenta) anos de idade, ou sejam portadores de doença grave, ou pessoas com deficiência, assim definidos na forma da lei, serão pagos com preferência sobre todos os demais débitos, até o valor equivalente ao triplo fixado em lei para os fins do disposto no § 3º deste artigo, admitido o fracionamento para essa finalidade, sendo que o restante será pago na ordem cronológica de apresentação do precatório.", "ordem": 234}, {"id": 235, "artigo_id": 100, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O disposto no caput deste artigo relativamente à expedição de precatórios não se aplica aos pagamentos de obrigações definidas em leis como de pequeno valor que as Fazendas referidas devam fazer em virtude de sentença judicial transitada em julgado..", "ordem": 235}, {"id": 236, "artigo_id": 100, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Para os fins do disposto no § 3º, poderão ser fixados, por leis próprias, valores distintos às entidades de direito público, segundo as diferentes capacidades econômicas, sendo o mínimo igual ao valor do maior benefício do regime geral de previdência social..", "ordem": 236}, {"id": 237, "artigo_id": 100, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º É obrigatória a inclusão no orçamento das entidades de direito público de verba necessária ao pagamento de seus débitos oriundos de sentenças transitadas em julgado constantes de precatórios judiciários apresentados até 1º de fevereiro, fazendo-se o pagamento até o final do exercício seguinte, quando terão seus valores atualizados monetariamente.", "ordem": 237}, {"id": 238, "artigo_id": 100, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º As dotações orçamentárias e os créditos abertos serão consignados diretamente ao Poder Judiciário, cabendo ao Presidente do Tribunal que proferir a decisão exequenda determinar o pagamento integral e autorizar, a requerimento do credor e exclusivamente para os casos de preterimento de seu direito de precedência ou de não alocação orçamentária do valor necessário à satisfação do seu débito, o sequestro da quantia respectiva..", "ordem": 238}, {"id": 239, "artigo_id": 100, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º O Presidente do Tribunal competente que, por ato comissivo ou omissivo, retardar ou tentar frustrar a liquidação regular de precatórios incorrerá em crime de responsabilidade e responderá, também, perante o Conselho Nacional de Justiça..", "ordem": 239}, {"id": 240, "artigo_id": 100, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º É vedada a expedição de precatórios complementares ou suplementares de valor pago, bem como o fracionamento, repartição ou quebra do valor da execução para fins de enquadramento de parcela do total ao que dispõe o § 3º deste artigo..", "ordem": 240}, {"id": 241, "artigo_id": 100, "tipo": "numerado", "numero": 9, "numero_texto": "9º", "texto": "§ 9º Sem que haja interrupção no pagamento do precatório e mediante comunicação da Fazenda Pública ao Tribunal, o valor correspondente aos eventuais débitos inscritos em dívida ativa contra o credor do requisitório e seus substituídos deverá ser depositado à conta do juízo responsável pela ação de cobrança, que decidirá pelo seu destino definitivo.", "ordem": 241}, {"id": 242, "artigo_id": 101, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Os Ministros do Supremo Tribunal Federal serão nomeados pelo Presidente da República, depois de aprovada a escolha pela maioria absoluta do Senado Federal.", "ordem": 242}, {"id": 243, "artigo_id": 102, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A argüição de descumprimento de preceito fundamental, decorrente desta Constituição, será apreciada pelo Supremo Tribunal Federal, na forma da lei. (Transformado em § 1º pela Emenda Constitucional nº 3, de 17/03/93)", "ordem": 243}, {"id": 244, "artigo_id": 102, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º As decisões definitivas de mérito, proferidas pelo Supremo Tribunal Federal, nas ações diretas de inconstitucionalidade e nas ações declaratórias de constitucionalidade produzirão eficácia contra todos e efeito vinculante, relativamente aos demais órgãos do Poder Judiciário e à administração pública direta e indireta, nas esferas federal, estadual e municipal.", "ordem": 244}, {"id": 245, "artigo_id": 102, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º No recurso extraordinário o recorrente deverá demonstrar a repercussão geral das questões constitucionais discutidas no caso, nos termos da lei, a fim de que o Tribunal examine a admissão do recurso, somente podendo recusá-lo pela manifestação de dois terços de seus membros.", "ordem": 245}, {"id": 246, "artigo_id": 103, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O Procurador-Geral da República deverá ser previamente ouvido nas ações de inconstitucionalidade e em todos os processos de competência do Supremo Tribunal Federal.", "ordem": 246}, {"id": 247, "artigo_id": 103, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Declarada a inconstitucionalidade por omissão de medida para tornar efetiva norma constitucional, será dada ciência ao Poder competente para a adoção das providências necessárias e, em se tratando de órgão administrativo, para fazê-lo em trinta dias.", "ordem": 247}, {"id": 248, "artigo_id": 103, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Quando o Supremo Tribunal Federal apreciar a inconstitucionalidade, em tese, de norma legal ou ato normativo, citará, previamente, o Advogado-Geral da União, que defenderá o ato ou texto impugnado.", "ordem": 248}, {"id": 249, "artigo_id": 103, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A súmula terá por objetivo a validade, a interpretação e a eficácia de normas determinadas, acerca das quais haja controvérsia atual entre órgãos judiciários ou entre esses e a administração pública que acarrete grave insegurança jurídica e relevante multiplicação de processos sobre questão idêntica.", "ordem": 249}, {"id": 250, "artigo_id": 103, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Sem prejuízo do que vier a ser estabelecido em lei, a aprovação, revisão ou cancelamento de súmula poderá ser provocada por aqueles que podem propor a ação direta de inconstitucionalidade.", "ordem": 250}, {"id": 251, "artigo_id": 103, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Do ato administrativo ou decisão judicial que contrariar a súmula aplicável ou que indevidamente a aplicar, caberá reclamação ao Supremo Tribunal Federal que, julgando-a procedente, anulará o ato administrativo ou cassará a decisão judicial reclamada, e determinará que outra seja proferida com ou sem a aplicação da súmula, conforme o caso.", "ordem": 251}, {"id": 252, "artigo_id": 103, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O Conselho será presidido pelo Presidente do Supremo Tribunal Federal e, nas suas ausências e impedimentos, pelo Vice-Presidente do Supremo Tribunal Federal.", "ordem": 252}, {"id": 253, "artigo_id": 103, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os demais membros do Conselho serão nomeados pelo Presidente da República, depois de aprovada a escolha pela maioria absoluta do Senado Federal.", "ordem": 253}, {"id": 254, "artigo_id": 103, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Não efetuadas, no prazo legal, as indicações previstas neste artigo, caberá a escolha ao Supremo Tribunal Federal.", "ordem": 254}, {"id": 255, "artigo_id": 103, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Compete ao Conselho o controle da atuação administrativa e financeira do Poder Judiciário e do cumprimento dos deveres funcionais dos juízes, cabendo-lhe, além de outras atribuições que lhe forem conferidas pelo Estatuto da Magistratura:", "ordem": 255}, {"id": 256, "artigo_id": 103, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º O Ministro do Superior Tribunal de Justiça exercerá a função de Ministro-Corregedor e ficará excluído da distribuição de processos no Tribunal, competindo-lhe, além das atribuições que lhe forem conferidas pelo Estatuto da Magistratura, as seguintes:", "ordem": 256}, {"id": 257, "artigo_id": 103, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Junto ao Conselho oficiarão o Procurador-Geral da República e o Presidente do Conselho Federal da Ordem dos Advogados do Brasil.", "ordem": 257}, {"id": 258, "artigo_id": 103, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º A União, inclusive no Distrito Federal e nos Territórios, criará ouvidorias de justiça, competentes para receber reclamações e denúncias de qualquer interessado contra membros ou órgãos do Poder Judiciário, ou contra seus serviços auxiliares, representando diretamente ao Conselho Nacional de Justiça.", "ordem": 258}, {"id": 259, "artigo_id": 104, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Os Ministros do Superior Tribunal de Justiça serão nomeados pelo Presidente da República, dentre brasileiros com mais de trinta e cinco e menos de setenta anos de idade, de notável saber jurídico e reputação ilibada, depois de aprovada a escolha pela maioria absoluta do Senado Federal, sendo:", "ordem": 259}, {"id": 260, "artigo_id": 105, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Funcionarão junto ao Superior Tribunal de Justiça:", "ordem": 260}, {"id": 261, "artigo_id": 105, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º No recurso especial, o recorrente deve demonstrar a relevância das questões de direito federal infraconstitucional discutidas no caso, nos termos da lei, a fim de que a admissão do recurso seja examinada pelo Tribunal, o qual somente pode dele não conhecer com base nesse motivo pela manifestação de 2/3 (dois terços) dos membros do órgão competente para o julgamento.", "ordem": 261}, {"id": 262, "artigo_id": 105, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Haverá a relevância de que trata o § 2º deste artigo nos seguintes casos:", "ordem": 262}, {"id": 263, "artigo_id": 107, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A lei disciplinará a remoção ou a permuta de juízes dos Tribunais Regionais Federais e determinará sua jurisdição e sede. (Renumerado do parágrafo único, pela Emenda Constitucional nº 45, de 2004)", "ordem": 263}, {"id": 264, "artigo_id": 107, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os Tribunais Regionais Federais instalarão a justiça itinerante, com a realização de audiências e demais funções da atividade jurisdicional, nos limites territoriais da respectiva jurisdição, servindo-se de equipamentos públicos e comunitários.", "ordem": 264}, {"id": 265, "artigo_id": 107, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Os Tribunais Regionais Federais poderão funcionar descentralizadamente, constituindo Câmaras regionais, a fim de assegurar o pleno acesso do jurisdicionado à justiça em todas as fases do processo.", "ordem": 265}, {"id": 266, "artigo_id": 109, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º As causas em que a União for autora serão aforadas na seção judiciária onde tiver domicílio a outra parte.", "ordem": 266}, {"id": 267, "artigo_id": 109, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º As causas intentadas contra a União poderão ser aforadas na seção judiciária em que for domiciliado o autor, naquela onde houver ocorrido o ato ou fato que deu origem à demanda ou onde esteja situada a coisa, ou, ainda, no Distrito Federal.", "ordem": 267}, {"id": 268, "artigo_id": 109, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Lei poderá autorizar que as causas de competência da Justiça Federal em que forem parte instituição de previdência social e segurado possam ser processadas e julgadas na justiça estadual quando a comarca do domicílio do segurado não for sede de vara federal.", "ordem": 268}, {"id": 269, "artigo_id": 109, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Na hipótese do parágrafo anterior, o recurso cabível será sempre para o Tribunal Regional Federal na área de jurisdição do juiz de primeiro grau.", "ordem": 269}, {"id": 270, "artigo_id": 109, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Nas hipóteses de grave violação de direitos humanos, o Procurador-Geral da República, com a finalidade de assegurar o cumprimento de obrigações decorrentes de tratados internacionais de direitos humanos dos quais o Brasil seja parte, poderá suscitar, perante o Superior Tribunal de Justiça, em qualquer fase do inquérito ou processo, incidente de deslocamento de competência para a Justiça Federal.", "ordem": 270}, {"id": 271, "artigo_id": 110, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Nos Territórios Federais, a jurisdição e as atribuições cometidas aos juízes federais caberão aos juízes da justiça local, na forma da lei.", "ordem": 271}, {"id": 272, "artigo_id": 111, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A lei disporá sobre a competência do Tribunal Superior do Trabalho.", "ordem": 272}, {"id": 273, "artigo_id": 111, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Funcionarão junto ao Tribunal Superior do Trabalho:", "ordem": 273}, {"id": 274, "artigo_id": 111, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Compete ao Tribunal Superior do Trabalho processar e julgar, originariamente, a reclamação para a preservação de sua competência e garantia da autoridade de suas decisões.", "ordem": 274}, {"id": 275, "artigo_id": 114, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Frustrada a negociação coletiva, as partes poderão eleger árbitros.", "ordem": 275}, {"id": 276, "artigo_id": 114, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Recusando-se qualquer das partes à negociação coletiva ou à arbitragem, é facultado às mesmas, de comum acordo, ajuizar dissídio coletivo de natureza econômica, podendo a Justiça do Trabalho decidir o conflito, respeitadas as disposições mínimas legais de proteção ao trabalho, bem como as convencionadas anteriormente.", "ordem": 276}, {"id": 277, "artigo_id": 114, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Em caso de greve em atividade essencial, com possibilidade de lesão do interesse público, o Ministério Público do Trabalho poderá ajuizar dissídio coletivo, competindo à Justiça do Trabalho decidir o conflito.", "ordem": 277}, {"id": 278, "artigo_id": 115, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Os Tribunais Regionais do Trabalho instalarão a justiça itinerante, com a realização de audiências e demais funções de atividade jurisdicional, nos limites territoriais da respectiva jurisdição, servindo-se de equipamentos públicos e comunitários.", "ordem": 278}, {"id": 279, "artigo_id": 115, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os Tribunais Regionais do Trabalho poderão funcionar descentralizadamente, constituindo Câmaras regionais, a fim de assegurar o pleno acesso do jurisdicionado à justiça em todas as fases do processo.", "ordem": 279}, {"id": 280, "artigo_id": 118, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. O Tribunal Superior Eleitoral elegerá seu Presidente e o Vice-Presidente dentre os Ministros do Supremo Tribunal Federal, e o Corregedor Eleitoral dentre os Ministros do Superior Tribunal de Justiça.", "ordem": 280}, {"id": 281, "artigo_id": 119, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º - Os Tribunais Regionais Eleitorais compor-se-ão:", "ordem": 281}, {"id": 282, "artigo_id": 119, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º - O Tribunal Regional Eleitoral elegerá seu Presidente e o Vice-Presidente- dentre os desembargadores.", "ordem": 282}, {"id": 283, "artigo_id": 120, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º - Os membros dos tribunais, os juízes de direito e os integrantes das juntas eleitorais, no exercício de suas funções, e no que lhes for aplicável, gozarão de plenas garantias e serão inamovíveis.", "ordem": 283}, {"id": 284, "artigo_id": 120, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º - Os juízes dos tribunais eleitorais, salvo motivo justificado, servirão por dois anos, no mínimo, e nunca por mais de dois biênios consecutivos, sendo os substitutos escolhidos na mesma ocasião e pelo mesmo processo, em número igual para cada categoria.", "ordem": 284}, {"id": 285, "artigo_id": 120, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º - São irrecorríveis as decisões do Tribunal Superior Eleitoral, salvo as que contrariarem esta Constituição e as denegatórias de habeas corpus ou mandado de segurança.", "ordem": 285}, {"id": 286, "artigo_id": 120, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º - Das decisões dos Tribunais Regionais Eleitorais somente caberá recurso quando:", "ordem": 286}, {"id": 287, "artigo_id": 122, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Os Ministros civis serão escolhidos pelo Presidente da República dentre brasileiros com mais de trinta e cinco e menos de setenta anos de idade, sendo:", "ordem": 287}, {"id": 288, "artigo_id": 123, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. A lei disporá sobre a organização, o funcionamento e a competência da Justiça Militar.", "ordem": 288}, {"id": 289, "artigo_id": 124, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A competência dos tribunais será definida na Constituição do Estado, sendo a lei de organização judiciária de iniciativa do Tribunal de Justiça.", "ordem": 289}, {"id": 290, "artigo_id": 124, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Cabe aos Estados a instituição de representação de inconstitucionalidade de leis ou atos normativos estaduais ou municipais em face da Constituição Estadual, vedada a atribuição da legitimação para agir a um único órgão.", "ordem": 290}, {"id": 291, "artigo_id": 124, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º A lei estadual poderá criar, mediante proposta do Tribunal de Justiça, a Justiça Militar estadual, constituída, em primeiro grau, pelos juízes de direito e pelos Conselhos de Justiça e, em segundo grau, pelo próprio Tribunal de Justiça, ou por Tribunal de Justiça Militar nos Estados em que o efetivo militar seja superior a vinte mil integrantes.", "ordem": 291}, {"id": 292, "artigo_id": 124, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Compete à Justiça Militar estadual processar e julgar os militares dos Estados, nos crimes militares definidos em lei e as ações judiciais contra atos disciplinares militares, ressalvada a competência do júri quando a vítima for civil, cabendo ao tribunal competente decidir sobre a perda do posto e da patente dos oficiais e da graduação das praças.", "ordem": 292}, {"id": 293, "artigo_id": 124, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Compete aos juízes de direito do juízo militar processar e julgar, singularmente, os crimes militares cometidos contra civis e as ações judiciais contra atos disciplinares militares, cabendo ao Conselho de Justiça, sob a presidência de juiz de direito, processar e julgar os demais crimes militares.", "ordem": 293}, {"id": 294, "artigo_id": 124, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º O Tribunal de Justiça poderá funcionar descentralizadamente, constituindo Câmaras regionais, a fim de assegurar o pleno acesso do jurisdicionado à justiça em todas as fases do processo.", "ordem": 294}, {"id": 295, "artigo_id": 124, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º O Tribunal de Justiça instalará a justiça itinerante, com a realização de audiências e demais funções da atividade jurisdicional, nos limites territoriais da respectiva jurisdição, servindo-se de equipamentos públicos e comunitários.", "ordem": 295}, {"id": 296, "artigo_id": 125, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Sempre que necessário à eficiente prestação jurisdicional, o juiz far-se-á presente no local do litígio.", "ordem": 296}, {"id": 297, "artigo_id": 126, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º - São princípios institucionais do Ministério Público a unidade, a indivisibilidade e a independência funcional.", "ordem": 297}, {"id": 298, "artigo_id": 126, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Ao Ministério Público é assegurada autonomia funcional e administrativa, podendo, observado o disposto no art. 169, propor ao Poder Legislativo a criação e extinção de seus cargos e serviços auxiliares, provendo-os por concurso público de provas ou de provas e títulos, a política remuneratória e os planos de carreira; a lei disporá sobre sua organização e funcionamento.", "ordem": 298}, {"id": 299, "artigo_id": 126, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O Ministério Público elaborará sua proposta orçamentária dentro dos limites estabelecidos na lei de diretrizes orçamentárias.", "ordem": 299}, {"id": 300, "artigo_id": 126, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Se o Ministério Público não encaminhar a respectiva proposta orçamentária dentro do prazo estabelecido na lei de diretrizes orçamentárias, o Poder Executivo considerará, para fins de consolidação da proposta orçamentária anual, os valores aprovados na lei orçamentária vigente, ajustados de acordo com os limites estipulados na forma do § 3º.", "ordem": 300}, {"id": 301, "artigo_id": 126, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Se a proposta orçamentária de que trata este artigo for encaminhada em desacordo com os limites estipulados na forma do § 3º, o Poder Executivo procederá aos ajustes necessários para fins de consolidação da proposta orçamentária anual.", "ordem": 301}, {"id": 302, "artigo_id": 126, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Durante a execução orçamentária do exercício, não poderá haver a realização de despesas ou a assunção de obrigações que extrapolem os limites estabelecidos na lei de diretrizes orçamentárias, exceto se previamente autorizadas, mediante a abertura de créditos suplementares ou especiais.", "ordem": 302}, {"id": 303, "artigo_id": 127, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O Ministério Público da União tem por chefe o Procurador-Geral da República, nomeado pelo Presidente da República dentre integrantes da carreira, maiores de trinta e cinco anos, após a aprovação de seu nome pela maioria absoluta dos membros do Senado Federal, para mandato de dois anos, permitida a recondução.", "ordem": 303}, {"id": 304, "artigo_id": 127, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A destituição do Procurador-Geral da República, por iniciativa do Presidente da República, deverá ser precedida de autorização da maioria absoluta do Senado Federal.", "ordem": 304}, {"id": 305, "artigo_id": 127, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Os Ministérios Públicos dos Estados e o do Distrito Federal e Territórios formarão lista tríplice dentre integrantes da carreira, na forma da lei respectiva, para escolha de seu Procurador-Geral, que será nomeado pelo Chefe do Poder Executivo, para mandato de dois anos, permitida uma recondução.", "ordem": 305}, {"id": 306, "artigo_id": 127, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Os Procuradores-Gerais nos Estados e no Distrito Federal e Territórios poderão ser destituídos por deliberação da maioria absoluta do Poder Legislativo, na forma da lei complementar respectiva.", "ordem": 306}, {"id": 307, "artigo_id": 127, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Leis complementares da União e dos Estados, cuja iniciativa é facultada aos respectivos Procuradores-Gerais, estabelecerão a organização, as atribuições e o estatuto de cada Ministério Público, observadas, relativamente a seus membros:", "ordem": 307}, {"id": 308, "artigo_id": 127, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Aplica-se aos membros do Ministério Público o disposto no art. 95, parágrafo único, V.", "ordem": 308}, {"id": 309, "artigo_id": 128, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º - A legitimação do Ministério Público para as ações civis previstas neste artigo não impede a de terceiros, nas mesmas hipóteses, segundo o disposto nesta Constituição e na lei.", "ordem": 309}, {"id": 310, "artigo_id": 128, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º As funções do Ministério Público só podem ser exercidas por integrantes da carreira, que deverão residir na comarca da respectiva lotação, salvo autorização do chefe da instituição.", "ordem": 310}, {"id": 311, "artigo_id": 128, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O ingresso na carreira do Ministério Público far-se-á mediante concurso público de provas e títulos, assegurada a participação da Ordem dos Advogados do Brasil em sua realização, exigindo-se do bacharel em direito, no mínimo, três anos de atividade jurídica e observando-se, nas nomeações, a ordem de classificação.", "ordem": 311}, {"id": 312, "artigo_id": 128, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Aplica-se ao Ministério Público, no que couber, o disposto no art. 93.", "ordem": 312}, {"id": 313, "artigo_id": 128, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º A distribuição de processos no Ministério Público será imediata.", "ordem": 313}, {"id": 314, "artigo_id": 129, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Os membros do Conselho oriundos do Ministério Público serão indicados pelos respectivos Ministérios Públicos, na forma da lei.", "ordem": 314}, {"id": 315, "artigo_id": 129, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Compete ao Conselho Nacional do Ministério Público o controle da atuação administrativa e financeira do Ministério Público e do cumprimento dos deveres funcionais de seus membros, cabendo lhe:", "ordem": 315}, {"id": 316, "artigo_id": 129, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O Conselho escolherá, em votação secreta, um Corregedor nacional, dentre os membros do Ministério Público que o integram, vedada a recondução, competindo-lhe, além das atribuições que lhe forem conferidas pela lei, as seguintes:", "ordem": 316}, {"id": 317, "artigo_id": 129, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º O Presidente do Conselho Federal da Ordem dos Advogados do Brasil oficiará junto ao Conselho.", "ordem": 317}, {"id": 318, "artigo_id": 129, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Leis da União e dos Estados criarão ouvidorias do Ministério Público, competentes para receber reclamações e denúncias de qualquer interessado contra membros ou órgãos do Ministério Público, inclusive contra seus serviços auxiliares, representando diretamente ao Conselho Nacional do Ministério Público.", "ordem": 318}, {"id": 319, "artigo_id": 130, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º - A Advocacia-Geral da União tem por chefe o Advogado-Geral da União, de livre nomeação pelo Presidente da República dentre cidadãos maiores de trinta e cinco anos, de notável saber jurídico e reputação ilibada.", "ordem": 319}, {"id": 320, "artigo_id": 130, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º - O ingresso nas classes iniciais das carreiras da instituição de que trata este artigo far-se-á mediante concurso público de provas e títulos.", "ordem": 320}, {"id": 321, "artigo_id": 130, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º - Na execução da dívida ativa de natureza tributária, a representação da União cabe à Procuradoria-Geral da Fazenda Nacional, observado o disposto em lei.", "ordem": 321}, {"id": 322, "artigo_id": 131, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Aos procuradores referidos neste artigo é assegurada estabilidade após três anos de efetivo exercício, mediante avaliação de desempenho perante os órgãos próprios, após relatório circunstanciado das corregedorias.", "ordem": 322}, {"id": 323, "artigo_id": 133, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Lei complementar organizará a Defensoria Pública da União e do Distrito Federal e dos Territórios e prescreverá normas gerais para sua organização nos Estados, em cargos de carreira, providos, na classe inicial, mediante concurso público de provas e títulos, assegurada a seus integrantes a garantia da inamovibilidade e vedado o exercício da advocacia fora das atribuições institucionais. (Renumerado do parágrafo único pela Emenda Constitucional nº 45, de 2004)", "ordem": 323}, {"id": 324, "artigo_id": 133, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Às Defensorias Públicas Estaduais são asseguradas autonomia funcional e administrativa e a iniciativa de sua proposta orçamentária dentro dos limites estabelecidos na lei de diretrizes orçamentárias e subordinação ao disposto no art. 99, § 2º .", "ordem": 324}, {"id": 325, "artigo_id": 133, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Aplica-se o disposto no § 2º às Defensorias Públicas da União e do Distrito Federal.", "ordem": 325}, {"id": 326, "artigo_id": 133, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º São princípios institucionais da Defensoria Pública a unidade, a indivisibilidade e a independência funcional, aplicando-se também, no que couber, o disposto no art. 93 e no inciso II do art. 96 desta Constituição Federal.", "ordem": 326}, {"id": 327, "artigo_id": 135, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O decreto que instituir o estado de defesa determinará o tempo de sua duração, especificará as áreas a serem abrangidas e indicará, nos termos e limites da lei, as medidas coercitivas a vigorarem, dentre as seguintes:", "ordem": 327}, {"id": 328, "artigo_id": 135, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O tempo de duração do estado de defesa não será superior a trinta dias, podendo ser prorrogado uma vez, por igual período, se persistirem as razões que justificaram a sua decretação.", "ordem": 328}, {"id": 329, "artigo_id": 135, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Na vigência do estado de defesa:", "ordem": 329}, {"id": 330, "artigo_id": 135, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Decretado o estado de defesa ou sua prorrogação, o Presidente da República, dentro de vinte e quatro horas, submeterá o ato com a respectiva justificação ao Congresso Nacional, que decidirá por maioria absoluta.", "ordem": 330}, {"id": 331, "artigo_id": 135, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Se o Congresso Nacional estiver em recesso, será convocado, extraordinariamente, no prazo de cinco dias.", "ordem": 331}, {"id": 332, "artigo_id": 135, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º O Congresso Nacional apreciará o decreto dentro de dez dias contados de seu recebimento, devendo continuar funcionando enquanto vigorar o estado de defesa.", "ordem": 332}, {"id": 333, "artigo_id": 135, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º Rejeitado o decreto, cessa imediatamente o estado de defesa.", "ordem": 333}, {"id": 334, "artigo_id": 136, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. O Presidente da República, ao solicitar autorização para decretar o estado de sítio ou sua prorrogação, relatará os motivos determinantes do pedido, devendo o Congresso Nacional decidir por maioria absoluta.", "ordem": 334}, {"id": 335, "artigo_id": 137, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O estado de sítio, no caso do art. 137, I, não poderá ser decretado por mais de trinta dias, nem prorrogado, de cada vez, por prazo superior; no do inciso II, poderá ser decretado por todo o tempo que perdurar a guerra ou a agressão armada estrangeira.", "ordem": 335}, {"id": 336, "artigo_id": 137, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Solicitada autorização para decretar o estado de sítio durante o recesso parlamentar, o Presidente do Senado Federal, de imediato, convocará extraordinariamente o Congresso Nacional para se reunir dentro de cinco dias, a fim de apreciar o ato.", "ordem": 336}, {"id": 337, "artigo_id": 137, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O Congresso Nacional permanecerá em funcionamento até o término das medidas coercitivas.", "ordem": 337}, {"id": 338, "artigo_id": 138, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Não se inclui nas restrições do inciso III a difusão de pronunciamentos de parlamentares efetuados em suas Casas Legislativas, desde que liberada pela respectiva Mesa.", "ordem": 338}, {"id": 339, "artigo_id": 140, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Logo que cesse o estado de defesa ou o estado de sítio, as medidas aplicadas em sua vigência serão relatadas pelo Presidente da República, em mensagem ao Congresso Nacional, com especificação e justificação das providências adotadas, com relação nominal dos atingidos e indicação das restrições aplicadas.", "ordem": 339}, {"id": 340, "artigo_id": 141, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Lei complementar estabelecerá as normas gerais a serem adotadas na organização, no preparo e no emprego das Forças Armadas.", "ordem": 340}, {"id": 341, "artigo_id": 141, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Não caberá habeas corpus em relação a punições disciplinares militares.", "ordem": 341}, {"id": 342, "artigo_id": 141, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Os membros das Forças Armadas são denominados militares, aplicando-se-lhes, além das que vierem a ser fixadas em lei, as seguintes disposições:", "ordem": 342}, {"id": 343, "artigo_id": 142, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Às Forças Armadas compete, na forma da lei, atribuir serviço alternativo aos que, em tempo de paz, após alistados, alegarem imperativo de consciência, entendendo-se como tal o decorrente de crença religiosa e de convicção filosófica ou política, para se eximirem de atividades de caráter essencialmente militar. (Regulamento)", "ordem": 343}, {"id": 344, "artigo_id": 142, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º - As mulheres e os eclesiásticos ficam isentos do serviço militar obrigatório em tempo de paz, sujeitos, porém, a outros encargos que a lei lhes atribuir. (Regulamento)", "ordem": 344}, {"id": 345, "artigo_id": 143, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A polícia federal, instituída por lei como órgão permanente, organizado e mantido pela União e estruturado em carreira, destina-se a:", "ordem": 345}, {"id": 346, "artigo_id": 143, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A polícia rodoviária federal, órgão permanente, organizado e mantido pela União e estruturado em carreira, destina-se, na forma da lei, ao patrulhamento ostensivo das rodovias federais.", "ordem": 346}, {"id": 347, "artigo_id": 143, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º A polícia ferroviária federal, órgão permanente, organizado e mantido pela União e estruturado em carreira, destina-se, na forma da lei, ao patrulhamento ostensivo das ferrovias federais.", "ordem": 347}, {"id": 348, "artigo_id": 143, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Às polícias civis, dirigidas por delegados de polícia de carreira, incumbem, ressalvada a competência da União, as funções de polícia judiciária e a apuração de infrações penais, exceto as militares.", "ordem": 348}, {"id": 349, "artigo_id": 143, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Às polícias militares cabem a polícia ostensiva e a preservação da ordem pública; aos corpos de bombeiros militares, além das atribuições definidas em lei, incumbe a execução de atividades de defesa civil.", "ordem": 349}, {"id": 350, "artigo_id": 143, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º As polícias militares e os corpos de bombeiros militares, forças auxiliares e reserva do Exército subordinam-se, juntamente com as polícias civis e as polícias penais estaduais e distrital, aos Governadores dos Estados, do Distrito Federal e dos Territórios.", "ordem": 350}, {"id": 351, "artigo_id": 143, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º A lei disciplinará a organização e o funcionamento dos órgãos responsáveis pela segurança pública, de maneira a garantir a eficiência de suas atividades. Vigência", "ordem": 351}, {"id": 352, "artigo_id": 143, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º Os Municípios poderão constituir guardas municipais destinadas à proteção de seus bens, serviços e instalações, conforme dispuser a lei.", "ordem": 352}, {"id": 353, "artigo_id": 143, "tipo": "numerado", "numero": 9, "numero_texto": "9º", "texto": "§ 9º A remuneração dos servidores policiais integrantes dos órgãos relacionados neste artigo será fixada na forma do § 4º do art. 39.", "ordem": 353}, {"id": 354, "artigo_id": 144, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Sempre que possível, os impostos terão caráter pessoal e serão graduados segundo a capacidade econômica do contribuinte, facultado à administração tributária, especialmente para conferir efetividade a esses objetivos, identificar, respeitados os direitos individuais e nos termos da lei, o patrimônio, os rendimentos e as atividades econômicas do contribuinte.", "ordem": 354}, {"id": 355, "artigo_id": 144, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º As taxas não poderão ter base de cálculo própria de impostos.", "ordem": 355}, {"id": 356, "artigo_id": 144, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O Sistema Tributário Nacional deve observar os princípios da simplicidade, da transparência, da justiça tributária, da cooperação e da defesa do meio ambiente.", "ordem": 356}, {"id": 357, "artigo_id": 144, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º As alterações na legislação tributária buscarão atenuar efeitos regressivos.", "ordem": 357}, {"id": 358, "artigo_id": 145, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A lei complementar de que trata o inciso III, d, também poderá instituir um regime único de arrecadação dos impostos e contribuições da União, dos Estados, do Distrito Federal e dos Municípios, observado que:", "ordem": 358}, {"id": 359, "artigo_id": 145, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º É facultado ao optante pelo regime único de que trata o § 1º apurar e recolher os tributos previstos nos arts. 156-A e 195, V, nos termos estabelecidos nesses artigos, hipótese em que as parcelas a eles relativas não serão cobradas pelo regime único.", "ordem": 359}, {"id": 360, "artigo_id": 145, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Na hipótese de o recolhimento dos tributos previstos nos arts. 156-A e 195, V, ser realizado por meio do regime único de que trata o § 1º, enquanto perdurar a opção:", "ordem": 360}, {"id": 361, "artigo_id": 147, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. A aplicação dos recursos provenientes de empréstimo compulsório será vinculada à despesa que fundamentou sua instituição.", "ordem": 361}, {"id": 362, "artigo_id": 148, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A União, os Estados, o Distrito Federal e os Municípios instituirão, por meio de lei, contribuições para custeio de regime próprio de previdência social, cobradas dos servidores ativos, dos aposentados e dos pensionistas, que poderão ter alíquotas progressivas de acordo com o valor da base de contribuição ou dos proventos de aposentadoria e de pensões. (Vigência)", "ordem": 362}, {"id": 363, "artigo_id": 148, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º As contribuições sociais e de intervenção no domínio econômico de que trata o caput deste artigo:", "ordem": 363}, {"id": 364, "artigo_id": 148, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º A pessoa natural destinatária das operações de importação poderá ser equiparada a pessoa jurídica, na forma da lei.", "ordem": 364}, {"id": 365, "artigo_id": 148, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º A lei definirá as hipóteses em que as contribuições incidirão uma única vez.", "ordem": 365}, {"id": 366, "artigo_id": 148, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. É facultada a cobrança da contribuição a que se refere o caput, na fatura de consumo de energia elétrica.", "ordem": 366}, {"id": 367, "artigo_id": 148, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Os tributos de que trata o caput observarão as imunidades previstas no art. 150, VI, não se aplicando a ambos os tributos o disposto no art. 195, § 7º.", "ordem": 367}, {"id": 368, "artigo_id": 148, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º As operações de que trata o caput poderão ter alíquotas reduzidas de modo uniforme, nos termos de lei complementar.", "ordem": 368}, {"id": 369, "artigo_id": 148, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Lei complementar poderá prever hipóteses em que não se aplicará o disposto no caput e no § 1º.", "ordem": 369}, {"id": 370, "artigo_id": 148, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Nas importações efetuadas pela administração pública direta, por autarquias e por fundações públicas, o disposto no art. 150, VI, \"a\", será implementado na forma do disposto no caput e no § 1º, assegurada a igualdade de tratamento em relação às aquisições internas.", "ordem": 370}, {"id": 371, "artigo_id": 149, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A vedação do inciso III, b, não se aplica aos tributos previstos nos arts. 148, I, 153, I, II, IV e V; e 154, II; e a vedação do inciso III, c, não se aplica aos tributos previstos nos arts. 148, I, 153, I, II, III e V; e 154, II, nem à fixação da base de cálculo dos impostos previstos nos arts. 155, III, e 156, I.", "ordem": 371}, {"id": 372, "artigo_id": 149, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A vedação do inciso VI, \"a\", é extensiva às autarquias e às fundações instituídas e mantidas pelo poder público e à empresa pública prestadora de serviço postal, no que se refere ao patrimônio, à renda e aos serviços vinculados a suas finalidades essenciais ou às delas decorrentes.", "ordem": 372}, {"id": 373, "artigo_id": 149, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º - As vedações do inciso VI, \"a\", e do parágrafo anterior não se aplicam ao patrimônio, à renda e aos serviços, relacionados com exploração de atividades econômicas regidas pelas normas aplicáveis a empreendimentos privados, ou em que haja contraprestação ou pagamento de preços ou tarifas pelo usuário, nem exonera o promitente comprador da obrigação de pagar imposto relativamente ao bem imóvel.", "ordem": 373}, {"id": 374, "artigo_id": 149, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º - As vedações expressas no inciso VI, alíneas \"b\" e \"c\", compreendem somente o patrimônio, a renda e os serviços, relacionados com as finalidades essenciais das entidades nelas mencionadas.", "ordem": 374}, {"id": 375, "artigo_id": 149, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º - A lei determinará medidas para que os consumidores sejam esclarecidos acerca dos impostos que incidam sobre mercadorias e serviços.", "ordem": 375}, {"id": 376, "artigo_id": 149, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Qualquer subsídio ou isenção, redução de base de cálculo, concessão de crédito presumido, anistia ou remissão, relativos a impostos, taxas ou contribuições, só poderá ser concedido mediante lei específica, federal, estadual ou municipal, que regule exclusivamente as matérias acima enumeradas ou o correspondente tributo ou contribuição, sem prejuízo do disposto no art. 155, § 2.º, XII, g.", "ordem": 376}, {"id": 377, "artigo_id": 149, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º A lei poderá atribuir a sujeito passivo de obrigação tributária a condição de responsável pelo pagamento de imposto ou contribuição, cujo fato gerador deva ocorrer posteriormente, assegurada a imediata e preferencial restituição da quantia paga, caso não se realize o fato gerador presumido.", "ordem": 377}, {"id": 378, "artigo_id": 152, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º É facultado ao Poder Executivo, atendidas as condições e os limites estabelecidos em lei, alterar as alíquotas dos impostos enumerados nos incisos I, II, IV e V.", "ordem": 378}, {"id": 379, "artigo_id": 152, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O imposto previsto no inciso III:", "ordem": 379}, {"id": 380, "artigo_id": 152, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O imposto previsto no inciso IV:", "ordem": 380}, {"id": 381, "artigo_id": 152, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º O imposto previsto no inciso VI do capu t:", "ordem": 381}, {"id": 382, "artigo_id": 152, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º O ouro, quando definido em lei como ativo financeiro ou instrumento cambial, sujeita-se exclusivamente à incidência do imposto de que trata o inciso V do \"caput\" deste artigo, devido na operação de origem; a alíquota mínima será de um por cento, assegurada a transferência do montante da arrecadação nos seguintes termos:", "ordem": 382}, {"id": 383, "artigo_id": 152, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º O imposto previsto no inciso VIII do caput deste artigo:", "ordem": 383}, {"id": 384, "artigo_id": 154, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O imposto previsto no inciso I:", "ordem": 384}, {"id": 385, "artigo_id": 154, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O imposto previsto no inciso II atenderá ao seguinte: Vigência", "ordem": 385}, {"id": 386, "artigo_id": 154, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º À exceção dos impostos de que tratam o inciso II do caput deste artigo e os arts. 153, I e II, e 156-A, nenhum outro imposto poderá incidir sobre operações relativas a energia elétrica e serviços de telecomunicações e, à exceção destes e do previsto no art. 153, VIII, nenhum outro imposto poderá incidir sobre operações relativas a derivados de petróleo, combustíveis e minerais do País.", "ordem": 386}, {"id": 387, "artigo_id": 154, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Na hipótese do inciso XII, h , observar-se-á o seguinte: Vigência", "ordem": 387}, {"id": 388, "artigo_id": 154, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º As regras necessárias à aplicação do disposto no § 4º, inclusive as relativas à apuração e à destinação do imposto, serão estabelecidas mediante deliberação dos Estados e do Distrito Federal, nos termos do § 2º, XII, g . Vigência", "ordem": 388}, {"id": 389, "artigo_id": 154, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º O imposto previsto no inciso III:", "ordem": 389}, {"id": 390, "artigo_id": 155, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Sem prejuízo da progressividade no tempo a que se refere o art. 182, § 4º, inciso II, o imposto previsto no inciso I poderá:", "ordem": 390}, {"id": 391, "artigo_id": 155, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O imposto previsto no inciso II:", "ordem": 391}, {"id": 392, "artigo_id": 155, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Em relação ao imposto previsto no inciso III do caput deste artigo, cabe à lei complementar: Vigência", "ordem": 392}, {"id": 393, "artigo_id": 155, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O imposto previsto no caput será informado pelo princípio da neutralidade e atenderá ao seguinte:", "ordem": 393}, {"id": 394, "artigo_id": 155, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Para fins do disposto no § 1º, V, o Distrito Federal exercerá as competências estadual e municipal na fixação de suas alíquotas.", "ordem": 394}, {"id": 395, "artigo_id": 155, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Lei complementar poderá definir como sujeito passivo do imposto a pessoa que concorrer para a realização, a execução ou o pagamento da operação, ainda que residente ou domiciliada no exterior.", "ordem": 395}, {"id": 396, "artigo_id": 155, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Para fins de distribuição do produto da arrecadação do imposto, o Comitê Gestor do Imposto sobre Bens e Serviços:", "ordem": 396}, {"id": 397, "artigo_id": 155, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Lei complementar disporá sobre:", "ordem": 397}, {"id": 398, "artigo_id": 155, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Lei complementar disporá sobre regimes específicos de tributação para:", "ordem": 398}, {"id": 399, "artigo_id": 155, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º A isenção e a imunidade:", "ordem": 399}, {"id": 400, "artigo_id": 155, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º Para fins do disposto neste artigo, a lei complementar de que trata o caput poderá estabelecer o conceito de operações com serviços, seu conteúdo e alcance, admitida essa definição para qualquer operação que não seja classificada como operação com bens materiais ou imateriais, inclusive direitos.", "ordem": 400}, {"id": 401, "artigo_id": 155, "tipo": "numerado", "numero": 9, "numero_texto": "9º", "texto": "§ 9º Qualquer alteração na legislação federal que reduza ou eleve a arrecadação do imposto:", "ordem": 401}, {"id": 402, "artigo_id": 155, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O Comitê Gestor do Imposto sobre Bens e Serviços, entidade pública sob regime especial, terá independência técnica, administrativa, orçamentária e financeira.", "ordem": 402}, {"id": 403, "artigo_id": 155, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Na forma da lei complementar:", "ordem": 403}, {"id": 404, "artigo_id": 155, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º A participação dos entes federativos na instância máxima de deliberação do Comitê Gestor do Imposto sobre Bens e Serviços observará a seguinte composição:", "ordem": 404}, {"id": 405, "artigo_id": 155, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º As deliberações no âmbito do Comitê Gestor do Imposto sobre Bens e Serviços serão consideradas aprovadas se obtiverem, cumulativamente, os votos:", "ordem": 405}, {"id": 406, "artigo_id": 155, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º O Presidente do Comitê Gestor do Imposto sobre Bens e Serviços deverá ter notórios conhecimentos de administração tributária.", "ordem": 406}, {"id": 407, "artigo_id": 155, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º O Comitê Gestor do Imposto sobre Bens e Serviços, a administração tributária da União e a Procuradoria-Geral da Fazenda Nacional compartilharão informações fiscais relacionadas aos tributos previstos nos arts. 156-A e 195, V, e atuarão com vistas a harmonizar normas, interpretações, obrigações acessórias e procedimentos a eles relativos.", "ordem": 407}, {"id": 408, "artigo_id": 155, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º O Comitê Gestor do Imposto sobre Bens e Serviços e a administração tributária da União poderão implementar soluções integradas para a administração e cobrança dos tributos previstos nos arts. 156-A e 195, V.", "ordem": 408}, {"id": 409, "artigo_id": 155, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º Lei complementar poderá prever a integração do contencioso administrativo relativo aos tributos previstos nos arts. 156-A e 195, V.", "ordem": 409}, {"id": 410, "artigo_id": 157, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º As parcelas de receita pertencentes aos Municípios mencionadas no inciso IV, \"a\", serão creditadas conforme os seguintes critérios: Vigência", "ordem": 410}, {"id": 411, "artigo_id": 157, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º As parcelas de receita pertencentes aos Municípios mencionadas no inciso IV, \"b\", serão creditadas conforme os seguintes critérios:", "ordem": 411}, {"id": 412, "artigo_id": 158, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Para efeito de cálculo da entrega a ser efetuada de acordo com o previsto no inciso I, excluir-se-á a parcela da arrecadação do imposto de renda e proventos de qualquer natureza pertencente aos Estados, ao Distrito Federal e aos Municípios, nos termos do disposto nos arts. 157, I, e 158, I.", "ordem": 412}, {"id": 413, "artigo_id": 158, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A nenhuma unidade federada poderá ser destinada parcela superior a vinte por cento do montante a que se refere o inciso II, devendo o eventual excedente ser distribuído entre os demais participantes, mantido, em relação a esses, o critério de partilha nele estabelecido.", "ordem": 413}, {"id": 414, "artigo_id": 158, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Os Estados entregarão aos respectivos Municípios 25% (vinte e cinco por cento) dos recursos que receberem nos termos do inciso II docaputdeste artigo, observados os critérios estabelecidos no art. 158, § 1º, para a parcela relativa ao imposto sobre produtos industrializados, e no art. 158, § 2º, para a parcela relativa ao imposto previsto no art. 153, VIII.", "ordem": 414}, {"id": 415, "artigo_id": 158, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Do montante de recursos de que trata o inciso III que cabe a cada Estado, vinte e cinco por cento serão destinados aos seus Municípios, na forma da lei a que se refere o mencionado inciso.", "ordem": 415}, {"id": 416, "artigo_id": 158, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º É vedada a retenção ou qualquer restrição ao recebimento dos recursos de que trata o caput.", "ordem": 416}, {"id": 417, "artigo_id": 158, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Na aplicação dos recursos de que trata o caput, os Estados e o Distrito Federal priorizarão projetos que prevejam ações de sustentabilidade ambiental e redução das emissões de carbono.", "ordem": 417}, {"id": 418, "artigo_id": 158, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Observado o disposto neste artigo, caberá aos Estados e ao Distrito Federal a decisão quanto à aplicação dos recursos de que trata o caput.", "ordem": 418}, {"id": 419, "artigo_id": 158, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Os recursos de que trata o caput serão entregues aos Estados e ao Distrito Federal de acordo com coeficientes individuais de participação, calculados com base nos seguintes indicadores e com os seguintes pesos:", "ordem": 419}, {"id": 420, "artigo_id": 158, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º O Tribunal de Contas da União será o órgão responsável por regulamentar e calcular os coeficientes individuais de participação de que trata o § 4º.", "ordem": 420}, {"id": 421, "artigo_id": 159, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A vedação prevista neste artigo não impede a União e os Estados de condicionarem a entrega de recursos: (Renumerado do Parágrafo único pela Emenda Constitucional nº 113, de 2021)", "ordem": 421}, {"id": 422, "artigo_id": 159, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os contratos, os acordos, os ajustes, os convênios, os parcelamentos ou as renegociações de débitos de qualquer espécie, inclusive tributários, firmados pela União com os entes federativos conterão cláusulas para autorizar a dedução dos valores devidos dos montantes a serem repassados relacionados às respectivas cotas nos Fundos de Participação ou aos precatórios federais.", "ordem": 422}, {"id": 423, "artigo_id": 160, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. O Tribunal de Contas da União efetuará o cálculo das quotas referentes aos fundos de participação a que alude o inciso II.", "ordem": 423}, {"id": 424, "artigo_id": 161, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Os dados divulgados pela União serão discriminados por Estado e por Município; os dos Estados, por Município.", "ordem": 424}, {"id": 425, "artigo_id": 162, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. A lei complementar de que trata o inciso VIII do caput deste artigo pode autorizar a aplicação das vedações previstas no art. 167-A desta Constituição.", "ordem": 425}, {"id": 426, "artigo_id": 163, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º É vedado ao banco central conceder, direta ou indiretamente, empréstimos ao Tesouro Nacional e a qualquer órgão ou entidade que não seja instituição financeira.", "ordem": 426}, {"id": 427, "artigo_id": 163, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O banco central poderá comprar e vender títulos de emissão do Tesouro Nacional, com o objetivo de regular a oferta de moeda ou a taxa de juros.", "ordem": 427}, {"id": 428, "artigo_id": 163, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º As disponibilidades de caixa da União serão depositadas no banco central; as dos Estados, do Distrito Federal, dos Municípios e dos órgãos ou entidades do Poder Público e das empresas por ele controladas, em instituições financeiras oficiais, ressalvados os casos previstos em lei.", "ordem": 428}, {"id": 429, "artigo_id": 163, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. A elaboração e a execução de planos e orçamentos devem refletir a compatibilidade dos indicadores fiscais com a sustentabilidade da dívida.", "ordem": 429}, {"id": 430, "artigo_id": 164, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A lei que instituir o plano plurianual estabelecerá, de forma regionalizada, as diretrizes, objetivos e metas da administração pública federal para as despesas de capital e outras delas decorrentes e para as relativas aos programas de duração continuada.", "ordem": 430}, {"id": 431, "artigo_id": 164, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A lei de diretrizes orçamentárias compreenderá as metas e prioridades da administração pública federal, estabelecerá as diretrizes de política fiscal e respectivas metas, em consonância com trajetória sustentável da dívida pública, orientará a elaboração da lei orçamentária anual, disporá sobre as alterações na legislação tributária e estabelecerá a política de aplicação das agências financeiras oficiais de fomento.", "ordem": 431}, {"id": 432, "artigo_id": 164, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O Poder Executivo publicará, até trinta dias após o encerramento de cada bimestre, relatório resumido da execução orçamentária.", "ordem": 432}, {"id": 433, "artigo_id": 164, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Os planos e programas nacionais, regionais e setoriais previstos nesta Constituição serão elaborados em consonância com o plano plurianual e apreciados pelo Congresso Nacional.", "ordem": 433}, {"id": 434, "artigo_id": 164, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º A lei orçamentária anual compreenderá:", "ordem": 434}, {"id": 435, "artigo_id": 164, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º O projeto de lei orçamentária será acompanhado de demonstrativo regionalizado do efeito, sobre as receitas e despesas, decorrente de isenções, anistias, remissões, subsídios e benefícios de natureza financeira, tributária e creditícia.", "ordem": 435}, {"id": 436, "artigo_id": 164, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º Os orçamentos previstos no § 5º, I e II, deste artigo, compatibilizados com o plano plurianual, terão entre suas funções a de reduzir desigualdades inter-regionais, segundo critério populacional.", "ordem": 436}, {"id": 437, "artigo_id": 164, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º A lei orçamentária anual não conterá dispositivo estranho à previsão da receita e à fixação da despesa, não se incluindo na proibição a autorização para abertura de créditos suplementares e contratação de operações de crédito, ainda que por antecipação de receita, nos termos da lei.", "ordem": 437}, {"id": 438, "artigo_id": 164, "tipo": "numerado", "numero": 9, "numero_texto": "9º", "texto": "§ 9º Cabe à lei complementar:", "ordem": 438}, {"id": 439, "artigo_id": 165, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Caberá a uma Comissão mista permanente de Senadores e Deputados:", "ordem": 439}, {"id": 440, "artigo_id": 165, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º As emendas serão apresentadas na Comissão mista, que sobre elas emitirá parecer, e apreciadas, na forma regimental, pelo Plenário das duas Casas do Congresso Nacional.", "ordem": 440}, {"id": 441, "artigo_id": 165, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º As emendas ao projeto de lei do orçamento anual ou aos projetos que o modifiquem somente podem ser aprovadas caso:", "ordem": 441}, {"id": 442, "artigo_id": 165, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º As emendas ao projeto de lei de diretrizes orçamentárias não poderão ser aprovadas quando incompatíveis com o plano plurianual.", "ordem": 442}, {"id": 443, "artigo_id": 165, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º O Presidente da República poderá enviar mensagem ao Congresso Nacional para propor modificação nos projetos a que se refere este artigo enquanto não iniciada a votação, na Comissão mista, da parte cuja alteração é proposta.", "ordem": 443}, {"id": 444, "artigo_id": 165, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Os projetos de lei do plano plurianual, das diretrizes orçamentárias e do orçamento anual serão enviados pelo Presidente da República ao Congresso Nacional, nos termos da lei complementar a que se refere o art. 165, § 9º.", "ordem": 444}, {"id": 445, "artigo_id": 165, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º Aplicam-se aos projetos mencionados neste artigo, no que não contrariar o disposto nesta seção, as demais normas relativas ao processo legislativo.", "ordem": 445}, {"id": 446, "artigo_id": 165, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º Os recursos que, em decorrência de veto, emenda ou rejeição do projeto de lei orçamentária anual, ficarem sem despesas correspondentes poderão ser utilizados, conforme o caso, mediante créditos especiais ou suplementares, com prévia e específica autorização legislativa.", "ordem": 446}, {"id": 447, "artigo_id": 165, "tipo": "numerado", "numero": 9, "numero_texto": "9º", "texto": "§ 9º As emendas individuais ao projeto de lei orçamentária serão aprovadas no limite de 2% (dois por cento) da receita corrente líquida do exercício anterior ao do encaminhamento do projeto, observado que a metade desse percentual será destinada a ações e serviços públicos de saúde.", "ordem": 447}, {"id": 448, "artigo_id": 165, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Os recursos transferidos na forma do caput deste artigo não integrarão a receita do Estado, do Distrito Federal e dos Municípios para fins de repartição e para o cálculo dos limites da despesa com pessoal ativo e inativo, nos termos do § 16 do art. 166, e de endividamento do ente federado, vedada, em qualquer caso, a aplicação dos recursos a que se refere o caput deste artigo no pagamento de:", "ordem": 448}, {"id": 449, "artigo_id": 165, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Na transferência especial a que se refere o inciso I do caput deste artigo, os recursos:", "ordem": 449}, {"id": 450, "artigo_id": 165, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O ente federado beneficiado da transferência especial a que se refere o inciso I do caput deste artigo poderá firmar contratos de cooperação técnica para fins de subsidiar o acompanhamento da execução orçamentária na aplicação dos recursos.", "ordem": 450}, {"id": 451, "artigo_id": 165, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Na transferência com finalidade definida a que se refere o inciso II do caput deste artigo, os recursos serão:", "ordem": 451}, {"id": 452, "artigo_id": 165, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Pelo menos 70% (setenta por cento) das transferências especiais de que trata o inciso I do caput deste artigo deverão ser aplicadas em despesas de capital, observada a restrição a que se refere o inciso II do § 1º deste artigo.", "ordem": 452}, {"id": 453, "artigo_id": 166, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Nenhum investimento cuja execução ultrapasse um exercício financeiro poderá ser iniciado sem prévia inclusão no plano plurianual, ou sem lei que autorize a inclusão, sob pena de crime de responsabilidade.", "ordem": 453}, {"id": 454, "artigo_id": 166, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os créditos especiais e extraordinários terão vigência no exercício financeiro em que forem autorizados, salvo se o ato de autorização for promulgado nos últimos quatro meses daquele exercício, caso em que, reabertos nos limites de seus saldos, serão incorporados ao orçamento do exercício financeiro subseqüente.", "ordem": 454}, {"id": 455, "artigo_id": 166, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º A abertura de crédito extraordinário somente será admitida para atender a despesas imprevisíveis e urgentes, como as decorrentes de guerra, comoção interna ou calamidade pública, observado o disposto no art. 62.", "ordem": 455}, {"id": 456, "artigo_id": 166, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º É permitida a vinculação das receitas a que se referem os arts. 155, 156, 156-A, 157, 158 e as alíneas \"a\", \"b\", \"d\", \"e\" e \"f\" do inciso I e o inciso II do caput do art. 159 desta Constituição para pagamento de débitos com a União e para prestar-lhe garantia ou contragarantia.", "ordem": 456}, {"id": 457, "artigo_id": 166, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º A transposição, o remanejamento ou a transferência de recursos de uma categoria de programação para outra poderão ser admitidos, no âmbito das atividades de ciência, tecnologia e inovação, com o objetivo de viabilizar os resultados de projetos restritos a essas funções, mediante ato do Poder Executivo, sem necessidade da prévia autorização legislativa prevista no inciso VI deste artigo.", "ordem": 457}, {"id": 458, "artigo_id": 166, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Para fins da apuração ao término do exercício financeiro do cumprimento do limite de que trata o inciso III do caput deste artigo, as receitas das operações de crédito efetuadas no contexto da gestão da dívida pública mobiliária federal somente serão consideradas no exercício financeiro em que for realizada a respectiva despesa.", "ordem": 458}, {"id": 459, "artigo_id": 166, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º A lei não imporá nem transferirá qualquer encargo financeiro decorrente da prestação de serviço público, inclusive despesas de pessoal e seus encargos, para a União, os Estados, o Distrito Federal ou os Municípios, sem a previsão de fonte orçamentária e financeira necessária à realização da despesa ou sem a previsão da correspondente transferência de recursos financeiros necessários ao seu custeio, ressalvadas as obrigações assumidas espontaneamente pelos entes federados e aquelas decorrentes da fixação do salário mínimo, na forma do inciso IV do caput do art. 7º desta Constituição.", "ordem": 459}, {"id": 460, "artigo_id": 166, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Apurado que a despesa corrente supera 85% (oitenta e cinco por cento) da receita corrente, sem exceder o percentual mencionado no caput deste artigo, as medidas nele indicadas podem ser, no todo ou em parte, implementadas por atos do Chefe do Poder Executivo com vigência imediata, facultado aos demais Poderes e órgãos autônomos implementá-las em seus respectivos âmbitos.", "ordem": 460}, {"id": 461, "artigo_id": 166, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O ato de que trata o § 1º deste artigo deve ser submetido, em regime de urgência, à apreciação do Poder Legislativo.", "ordem": 461}, {"id": 462, "artigo_id": 166, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O ato perde a eficácia, reconhecida a validade dos atos praticados na sua vigência, quando:", "ordem": 462}, {"id": 463, "artigo_id": 166, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º A apuração referida neste artigo deve ser realizada bimestralmente.", "ordem": 463}, {"id": 464, "artigo_id": 166, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º As disposições de que trata este artigo:", "ordem": 464}, {"id": 465, "artigo_id": 166, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Ocorrendo a hipótese de que trata o caput deste artigo, até que todas as medidas nele previstas tenham sido adotadas por todos os Poderes e órgãos nele mencionados, de acordo com declaração do respectivo Tribunal de Contas, é vedada:", "ordem": 465}, {"id": 466, "artigo_id": 166, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Durante a vigência da calamidade pública de âmbito nacional de que trata o art. 167-B, não se aplica o disposto no § 3º do art. 195 desta Constituição.", "ordem": 466}, {"id": 467, "artigo_id": 166, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Lei complementar pode definir outras suspensões, dispensas e afastamentos aplicáveis durante a vigência do estado de calamidade pública de âmbito nacional.", "ordem": 467}, {"id": 468, "artigo_id": 166, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O disposto no inciso II do caput deste artigo não se aplica às fontes de recursos:", "ordem": 468}, {"id": 469, "artigo_id": 166, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Na hipótese de medidas de combate à calamidade pública cuja vigência e efeitos não ultrapassem a sua duração, não se aplicam as vedações referidas nos incisos II, IV, VII, IX e X do caput do art. 167-A desta Constituição.", "ordem": 469}, {"id": 470, "artigo_id": 166, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Na hipótese de que trata o art. 167-B, não se aplica a alínea \"c\" do inciso I do caput do art. 159 desta Constituição, devendo a transferência a que se refere aquele dispositivo ser efetuada nos mesmos montantes transferidos no exercício anterior à decretação da calamidade.", "ordem": 470}, {"id": 471, "artigo_id": 166, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º É facultada aos Estados, ao Distrito Federal e aos Municípios a aplicação das vedações referidas no caput, nos termos deste artigo, e, até que as tenham adotado na integralidade, estarão submetidos às restrições do § 6º do art. 167-A desta Constituição, enquanto perdurarem seus efeitos para a União.", "ordem": 471}, {"id": 472, "artigo_id": 167, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º É vedada a transferência a fundos de recursos financeiros oriundos de repasses duodecimais.", "ordem": 472}, {"id": 473, "artigo_id": 167, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O saldo financeiro decorrente dos recursos entregues na forma do caput deste artigo deve ser restituído ao caixa único do Tesouro do ente federativo, ou terá seu valor deduzido das primeiras parcelas duodecimais do exercício seguinte.", "ordem": 473}, {"id": 474, "artigo_id": 168, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A concessão de qualquer vantagem ou aumento de remuneração, a criação de cargos, empregos e funções ou alteração de estrutura de carreiras, bem como a admissão ou contratação de pessoal, a qualquer título, pelos órgãos e entidades da administração direta ou indireta, inclusive fundações instituídas e mantidas pelo poder público, só poderão ser feitas: (Renumerado do parágrafo único, pela Emenda Constitucional nº 19, de 1998)", "ordem": 474}, {"id": 475, "artigo_id": 168, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Decorrido o prazo estabelecido na lei complementar referida neste artigo para a adaptação aos parâmetros ali previstos, serão imediatamente suspensos todos os repasses de verbas federais ou estaduais aos Estados, ao Distrito Federal e aos Municípios que não observarem os referidos limites.", "ordem": 475}, {"id": 476, "artigo_id": 168, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Para o cumprimento dos limites estabelecidos com base neste artigo, durante o prazo fixado na lei complementar referida no caput, a União, os Estados, o Distrito Federal e os Municípios adotarão as seguintes providências:", "ordem": 476}, {"id": 477, "artigo_id": 168, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Se as medidas adotadas com base no parágrafo anterior não forem suficientes para assegurar o cumprimento da determinação da lei complementar referida neste artigo, o servidor estável poderá perder o cargo, desde que ato normativo motivado de cada um dos Poderes especifique a atividade funcional, o órgão ou unidade administrativa objeto da redução de pessoal.", "ordem": 477}, {"id": 478, "artigo_id": 168, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º O servidor que perder o cargo na forma do parágrafo anterior fará jus a indenização correspondente a um mês de remuneração por ano de serviço.", "ordem": 478}, {"id": 479, "artigo_id": 168, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º O cargo objeto da redução prevista nos parágrafos anteriores será considerado extinto, vedada a criação de cargo, emprego ou função com atribuições iguais ou assemelhadas pelo prazo de quatro anos.", "ordem": 479}, {"id": 480, "artigo_id": 168, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º Lei federal disporá sobre as normas gerais a serem obedecidas na efetivação do disposto no § 4º.", "ordem": 480}, {"id": 481, "artigo_id": 169, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. É assegurado a todos o livre exercício de qualquer atividade econômica, independentemente de autorização de órgãos públicos, salvo nos casos previstos em lei.", "ordem": 481}, {"id": 482, "artigo_id": 171, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A lei estabelecerá o estatuto jurídico da empresa pública, da sociedade de economia mista e de suas subsidiárias que explorem atividade econômica de produção ou comercialização de bens ou de prestação de serviços, dispondo sobre:", "ordem": 482}, {"id": 483, "artigo_id": 171, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º As empresas públicas e as sociedades de economia mista não poderão gozar de privilégios fiscais não extensivos às do setor privado.", "ordem": 483}, {"id": 484, "artigo_id": 171, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º A lei regulamentará as relações da empresa pública com o Estado e a sociedade.", "ordem": 484}, {"id": 485, "artigo_id": 171, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º A lei reprimirá o abuso do poder econômico que vise à dominação dos mercados, à eliminação da concorrência e ao aumento arbitrário dos lucros.", "ordem": 485}, {"id": 486, "artigo_id": 171, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º A lei, sem prejuízo da responsabilidade individual dos dirigentes da pessoa jurídica, estabelecerá a responsabilidade desta, sujeitando-a às punições compatíveis com sua natureza, nos atos praticados contra a ordem econômica e financeira e contra a economia popular.", "ordem": 486}, {"id": 487, "artigo_id": 172, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A lei estabelecerá as diretrizes e bases do planejamento do desenvolvimento nacional equilibrado, o qual incorporará e compatibilizará os planos nacionais e regionais de desenvolvimento.", "ordem": 487}, {"id": 488, "artigo_id": 172, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A lei apoiará e estimulará o cooperativismo e outras formas de associativismo.", "ordem": 488}, {"id": 489, "artigo_id": 172, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O Estado favorecerá a organização da atividade garimpeira em cooperativas, levando em conta a proteção do meio ambiente e a promoção econômico-social dos garimpeiros.", "ordem": 489}, {"id": 490, "artigo_id": 172, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º As cooperativas a que se refere o parágrafo anterior terão prioridade na autorização ou concessão para pesquisa e lavra dos recursos e jazidas de minerais garimpáveis, nas áreas onde estejam atuando, e naquelas fixadas de acordo com o art. 21, XXV, na forma da lei.", "ordem": 490}, {"id": 491, "artigo_id": 173, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. A lei disporá sobre:", "ordem": 491}, {"id": 492, "artigo_id": 174, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A pesquisa e a lavra de recursos minerais e o aproveitamento dos potenciais a que se refere o \"caput\" deste artigo somente poderão ser efetuados mediante autorização ou concessão da União, no interesse nacional, por brasileiros ou empresa constituída sob as leis brasileiras e que tenha sua sede e administração no País, na forma da lei, que estabelecerá as condições específicas quando essas atividades se desenvolverem em faixa de fronteira ou terras indígenas.", "ordem": 492}, {"id": 493, "artigo_id": 174, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º É assegurada participação ao proprietário do solo nos resultados da lavra, na forma e no valor que dispuser a lei.", "ordem": 493}, {"id": 494, "artigo_id": 174, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º A autorização de pesquisa será sempre por prazo determinado, e as autorizações e concessões previstas neste artigo não poderão ser cedidas ou transferidas, total ou parcialmente, sem prévia anuência do poder concedente.", "ordem": 494}, {"id": 495, "artigo_id": 174, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Não dependerá de autorização ou concessão o aproveitamento do potencial de energia renovável de capacidade reduzida.", "ordem": 495}, {"id": 496, "artigo_id": 175, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A União poderá contratar com empresas estatais ou privadas a realização das atividades previstas nos incisos I a IV deste artigo observadas as condições estabelecidas em lei.", "ordem": 496}, {"id": 497, "artigo_id": 175, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A lei a que se refere o § 1º disporá sobre:", "ordem": 497}, {"id": 498, "artigo_id": 175, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º A lei disporá sobre o transporte e a utilização de materiais radioativos no território nacional. (Renumerado de § 2º para 3º pela Emenda Constitucional nº 9, de 1995)", "ordem": 498}, {"id": 499, "artigo_id": 175, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º A lei que instituir contribuição de intervenção no domínio econômico relativa às atividades de importação ou comercialização de petróleo e seus derivados, gás natural e seus derivados e álcool combustível deverá atender aos seguintes requisitos:", "ordem": 499}, {"id": 500, "artigo_id": 176, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Na ordenação do transporte aquático, a lei estabelecerá as condições em que o transporte de mercadorias na cabotagem e a navegação interior poderão ser feitos por embarcações estrangeiras.", "ordem": 500}, {"id": 501, "artigo_id": 180, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O plano diretor, aprovado pela Câmara Municipal, obrigatório para cidades com mais de vinte mil habitantes, é o instrumento básico da política de desenvolvimento e de expansão urbana.", "ordem": 501}, {"id": 502, "artigo_id": 180, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A propriedade urbana cumpre sua função social quando atende às exigências fundamentais de ordenação da cidade expressas no plano diretor.", "ordem": 502}, {"id": 503, "artigo_id": 180, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º As desapropriações de imóveis urbanos serão feitas com prévia e justa indenização em dinheiro.", "ordem": 503}, {"id": 504, "artigo_id": 180, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º É facultado ao Poder Público municipal, mediante lei específica para área incluída no plano diretor, exigir, nos termos da lei federal, do proprietário do solo urbano não edificado, subutilizado ou não utilizado, que promova seu adequado aproveitamento, sob pena, sucessivamente, de:", "ordem": 504}, {"id": 505, "artigo_id": 181, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O título de domínio e a concessão de uso serão conferidos ao homem ou à mulher, ou a ambos, independentemente do estado civil.", "ordem": 505}, {"id": 506, "artigo_id": 181, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Esse direito não será reconhecido ao mesmo possuidor mais de uma vez.", "ordem": 506}, {"id": 507, "artigo_id": 181, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Os imóveis públicos não serão adquiridos por usucapião.", "ordem": 507}, {"id": 508, "artigo_id": 182, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º As benfeitorias úteis e necessárias serão indenizadas em dinheiro.", "ordem": 508}, {"id": 509, "artigo_id": 182, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O decreto que declarar o imóvel como de interesse social, para fins de reforma agrária, autoriza a União a propor a ação de desapropriação.", "ordem": 509}, {"id": 510, "artigo_id": 182, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Cabe à lei complementar estabelecer procedimento contraditório especial, de rito sumário, para o processo judicial de desapropriação.", "ordem": 510}, {"id": 511, "artigo_id": 182, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º O orçamento fixará anualmente o volume total de títulos da dívida agrária, assim como o montante de recursos para atender ao programa de reforma agrária no exercício.", "ordem": 511}, {"id": 512, "artigo_id": 182, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º São isentas de impostos federais, estaduais e municipais as operações de transferência de imóveis desapropriados para fins de reforma agrária.", "ordem": 512}, {"id": 513, "artigo_id": 183, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. A lei garantirá tratamento especial à propriedade produtiva e fixará normas para o cumprimento dos requisitos relativos a sua função social.", "ordem": 513}, {"id": 514, "artigo_id": 185, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Incluem-se no planejamento agrícola as atividades agro-industriais, agropecuárias, pesqueiras e florestais.", "ordem": 514}, {"id": 515, "artigo_id": 185, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Serão compatibilizadas as ações de política agrícola e de reforma agrária.", "ordem": 515}, {"id": 516, "artigo_id": 186, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A alienação ou a concessão, a qualquer título, de terras públicas com área superior a dois mil e quinhentos hectares a pessoa física ou jurídica, ainda que por interposta pessoa, dependerá de prévia aprovação do Congresso Nacional.", "ordem": 516}, {"id": 517, "artigo_id": 186, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Excetuam-se do disposto no parágrafo anterior as alienações ou as concessões de terras públicas para fins de reforma agrária.", "ordem": 517}, {"id": 518, "artigo_id": 187, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. O título de domínio e a concessão de uso serão conferidos ao homem ou à mulher, ou a ambos, independentemente do estado civil, nos termos e condições previstos em lei.", "ordem": 518}, {"id": 519, "artigo_id": 189, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Os imóveis públicos não serão adquiridos por usucapião.", "ordem": 519}, {"id": 520, "artigo_id": 191, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. O Estado exercerá a função de planejamento das políticas sociais, assegurada, na forma da lei, a participação da sociedade nos processos de formulação, de monitoramento, de controle e de avaliação dessas políticas.", "ordem": 520}, {"id": 521, "artigo_id": 192, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Compete ao Poder Público, nos termos da lei, organizar a seguridade social, com base nos seguintes objetivos:", "ordem": 521}, {"id": 522, "artigo_id": 193, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º As receitas dos Estados, do Distrito Federal e dos Municípios destinadas à seguridade social constarão dos respectivos orçamentos, não integrando o orçamento da União.", "ordem": 522}, {"id": 523, "artigo_id": 193, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A proposta de orçamento da seguridade social será elaborada de forma integrada pelos órgãos responsáveis pela saúde, previdência social e assistência social, tendo em vista as metas e prioridades estabelecidas na lei de diretrizes orçamentárias, assegurada a cada área a gestão de seus recursos.", "ordem": 523}, {"id": 524, "artigo_id": 193, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º A pessoa jurídica em débito com o sistema da seguridade social, como estabelecido em lei, não poderá contratar com o Poder Público nem dele receber benefícios ou incentivos fiscais ou creditícios.", "ordem": 524}, {"id": 525, "artigo_id": 193, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º A lei poderá instituir outras fontes destinadas a garantir a manutenção ou expansão da seguridade social, obedecido o disposto no art. 154, I.", "ordem": 525}, {"id": 526, "artigo_id": 193, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Nenhum benefício ou serviço da seguridade social poderá ser criado, majorado ou estendido sem a correspondente fonte de custeio total.", "ordem": 526}, {"id": 527, "artigo_id": 193, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º As contribuições sociais de que trata este artigo só poderão ser exigidas após decorridos noventa dias da data da publicação da lei que as houver instituído ou modificado, não se lhes aplicando o disposto no art. 150, III, \"b\".", "ordem": 527}, {"id": 528, "artigo_id": 193, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º São isentas de contribuição para a seguridade social as entidades beneficentes de assistência social que atendam às exigências estabelecidas em lei.", "ordem": 528}, {"id": 529, "artigo_id": 193, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º O produtor, o parceiro, o meeiro e o arrendatário rurais e o pescador artesanal, bem como os respectivos cônjuges, que exerçam suas atividades em regime de economia familiar, sem empregados permanentes, contribuirão para a seguridade social mediante a aplicação de uma alíquota sobre o resultado da comercialização da produção e farão jus aos benefícios nos termos da lei.", "ordem": 529}, {"id": 530, "artigo_id": 193, "tipo": "numerado", "numero": 9, "numero_texto": "9º", "texto": "§ 9º As contribuições sociais previstas no inciso I do caput deste artigo poderão ter alíquotas diferenciadas em razão da atividade econômica, da utilização intensiva de mão de obra, do porte da empresa ou da condição estrutural do mercado de trabalho, sendo também autorizada a adoção de bases de cálculo diferenciadas apenas no caso das alíneas \"b\" e \"c\" do inciso I do caput.", "ordem": 530}, {"id": 531, "artigo_id": 196, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A União, os Estados, o Distrito Federal e os Municípios aplicarão, anualmente, em ações e serviços públicos de saúde recursos mínimos derivados da aplicação de percentuais calculados sobre:", "ordem": 531}, {"id": 532, "artigo_id": 196, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Lei complementar, que será reavaliada pelo menos a cada cinco anos, estabelecerá: Regulamento", "ordem": 532}, {"id": 533, "artigo_id": 196, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Os gestores locais do sistema único de saúde poderão admitir agentes comunitários de saúde e agentes de combate às endemias por meio de processo seletivo público, de acordo com a natureza e complexidade de suas atribuições e requisitos específicos para sua atuação.", "ordem": 533}, {"id": 534, "artigo_id": 196, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Lei federal disporá sobre o regime jurídico, o piso salarial profissional nacional, as diretrizes para os Planos de Carreira e a regulamentação das atividades de agente comunitário de saúde e agente de combate às endemias, competindo à União, nos termos da lei, prestar assistência financeira complementar aos Estados, ao Distrito Federal e aos Municípios, para o cumprimento do referido piso salarial. Regulamento", "ordem": 534}, {"id": 535, "artigo_id": 196, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Além das hipóteses previstas no § 1º do art. 41 e no § 4º do art. 169 da Constituição Federal, o servidor que exerça funções equivalentes às de agente comunitário de saúde ou de agente de combate às endemias poderá perder o cargo em caso de descumprimento dos requisitos específicos, fixados em lei, para o seu exercício.", "ordem": 535}, {"id": 536, "artigo_id": 196, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º O vencimento dos agentes comunitários de saúde e dos agentes de combate às endemias fica sob responsabilidade da União, e cabe aos Estados, ao Distrito Federal e aos Municípios estabelecer, além de outros consectários e vantagens, incentivos, auxílios, gratificações e indenizações, a fim de valorizar o trabalho desses profissionais.", "ordem": 536}, {"id": 537, "artigo_id": 196, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º Os recursos destinados ao pagamento do vencimento dos agentes comunitários de saúde e dos agentes de combate às endemias serão consignados no orçamento geral da União com dotação própria e exclusiva.", "ordem": 537}, {"id": 538, "artigo_id": 196, "tipo": "numerado", "numero": 9, "numero_texto": "9º", "texto": "§ 9º O vencimento dos agentes comunitários de saúde e dos agentes de combate às endemias não será inferior a 2 (dois) salários mínimos, repassados pela União aos Municípios, aos Estados e ao Distrito Federal.", "ordem": 538}, {"id": 539, "artigo_id": 197, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º - As instituições privadas poderão participar de forma complementar do sistema único de saúde, segundo diretrizes deste, mediante contrato de direito público ou convênio, tendo preferência as entidades filantrópicas e as sem fins lucrativos.", "ordem": 539}, {"id": 540, "artigo_id": 197, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º É vedada a destinação de recursos públicos para auxílios ou subvenções às instituições privadas com fins lucrativos.", "ordem": 540}, {"id": 541, "artigo_id": 197, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º É vedada a participação direta ou indireta de empresas ou capitais estrangeiros na assistência à saúde no País, salvo nos casos previstos em lei.", "ordem": 541}, {"id": 542, "artigo_id": 197, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º A lei disporá sobre as condições e os requisitos que facilitem a remoção de órgãos, tecidos e substâncias humanas para fins de transplante, pesquisa e tratamento, bem como a coleta, processamento e transfusão de sangue e seus derivados, sendo vedado todo tipo de comercialização.", "ordem": 542}, {"id": 543, "artigo_id": 199, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º É vedada a adoção de requisitos ou critérios diferenciados para concessão de benefícios, ressalvada, nos termos de lei complementar, a possibilidade de previsão de idade e tempo de contribuição distintos da regra geral para concessão de aposentadoria exclusivamente em favor dos segurados:", "ordem": 543}, {"id": 544, "artigo_id": 199, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Nenhum benefício que substitua o salário de contribuição ou o rendimento do trabalho do segurado terá valor mensal inferior ao salário mínimo.", "ordem": 544}, {"id": 545, "artigo_id": 199, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Todos os salários de contribuição considerados para o cálculo de benefício serão devidamente atualizados, na forma da lei.", "ordem": 545}, {"id": 546, "artigo_id": 199, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º É assegurado o reajustamento dos benefícios para preservar-lhes, em caráter permanente, o valor real, conforme critérios definidos em lei.", "ordem": 546}, {"id": 547, "artigo_id": 199, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º É vedada a filiação ao regime geral de previdência social, na qualidade de segurado facultativo, de pessoa participante de regime próprio de previdência.", "ordem": 547}, {"id": 548, "artigo_id": 199, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º A gratificação natalina dos aposentados e pensionistas terá por base o valor dos proventos do mês de dezembro de cada ano.", "ordem": 548}, {"id": 549, "artigo_id": 199, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º É assegurada aposentadoria no regime geral de previdência social, nos termos da lei, obedecidas as seguintes condições:", "ordem": 549}, {"id": 550, "artigo_id": 199, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º O requisito de idade a que se refere o inciso I do § 7º será reduzido em 5 (cinco) anos, para o professor que comprove tempo de efetivo exercício das funções de magistério na educação infantil e no ensino fundamental e médio fixado em lei complementar.", "ordem": 550}, {"id": 551, "artigo_id": 199, "tipo": "numerado", "numero": 9, "numero_texto": "9º", "texto": "§ 9º Para fins de aposentadoria, será assegurada a contagem recíproca do tempo de contribuição entre o Regime Geral de Previdência Social e os regimes próprios de previdência social, e destes entre si, observada a compensação financeira, de acordo com os critérios estabelecidos em lei.", "ordem": 551}, {"id": 552, "artigo_id": 200, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1° A lei complementar de que trata este artigo assegurará ao participante de planos de benefícios de entidades de previdência privada o pleno acesso às informações relativas à gestão de seus respectivos planos.", "ordem": 552}, {"id": 553, "artigo_id": 200, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2° As contribuições do empregador, os benefícios e as condições contratuais previstas nos estatutos, regulamentos e planos de benefícios das entidades de previdência privada não integram o contrato de trabalho dos participantes, assim como, à exceção dos benefícios concedidos, não integram a remuneração dos participantes, nos termos da lei.", "ordem": 553}, {"id": 554, "artigo_id": 200, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º É vedado o aporte de recursos a entidade de previdência privada pela União, Estados, Distrito Federal e Municípios, suas autarquias, fundações, empresas públicas, sociedades de economia mista e outras entidades públicas, salvo na qualidade de patrocinador, situação na qual, em hipótese alguma, sua contribuição normal poderá exceder a do segurado.", "ordem": 554}, {"id": 555, "artigo_id": 200, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Lei complementar disciplinará a relação entre a União, Estados, Distrito Federal ou Municípios, inclusive suas autarquias, fundações, sociedades de economia mista e empresas controladas direta ou indiretamente, enquanto patrocinadores de planos de benefícios previdenciários, e as entidades de previdência complementar.", "ordem": 555}, {"id": 556, "artigo_id": 200, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º A lei complementar de que trata o § 4º aplicar-se-á, no que couber, às empresas privadas permissionárias ou concessionárias de prestação de serviços públicos, quando patrocinadoras de planos de benefícios em entidades de previdência complementar.", "ordem": 556}, {"id": 557, "artigo_id": 200, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Lei complementar estabelecerá os requisitos para a designação dos membros das diretorias das entidades fechadas de previdência complementar instituídas pelos patrocinadores de que trata o § 4º e disciplinará a inserção dos participantes nos colegiados e instâncias de decisão em que seus interesses sejam objeto de discussão e deliberação.", "ordem": 557}, {"id": 558, "artigo_id": 202, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. É facultado aos Estados e ao Distrito Federal vincular a programa de apoio à inclusão e promoção social até cinco décimos por cento de sua receita tributária líquida, vedada a aplicação desses recursos no pagamento de:", "ordem": 558}, {"id": 559, "artigo_id": 204, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. A lei disporá sobre as categorias de trabalhadores considerados profissionais da educação básica e sobre a fixação de prazo para a elaboração ou adequação de seus planos de carreira, no âmbito da União, dos Estados, do Distrito Federal e dos Municípios.", "ordem": 559}, {"id": 560, "artigo_id": 205, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º É facultado às universidades admitir professores, técnicos e cientistas estrangeiros, na forma da lei.", "ordem": 560}, {"id": 561, "artigo_id": 205, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O disposto neste artigo aplica-se às instituições de pesquisa científica e tecnológica.", "ordem": 561}, {"id": 562, "artigo_id": 206, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O acesso ao ensino obrigatório e gratuito é direito público subjetivo.", "ordem": 562}, {"id": 563, "artigo_id": 206, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O não-oferecimento do ensino obrigatório pelo Poder Público, ou sua oferta irregular, importa responsabilidade da autoridade competente.", "ordem": 563}, {"id": 564, "artigo_id": 206, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Compete ao Poder Público recensear os educandos no ensino fundamental, fazer-lhes a chamada e zelar, junto aos pais ou responsáveis, pela freqüência à escola.", "ordem": 564}, {"id": 565, "artigo_id": 208, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O ensino religioso, de matrícula facultativa, constituirá disciplina dos horários normais das escolas públicas de ensino fundamental.", "ordem": 565}, {"id": 566, "artigo_id": 208, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O ensino fundamental regular será ministrado em língua portuguesa, assegurada às comunidades indígenas também a utilização de suas línguas maternas e processos próprios de aprendizagem.", "ordem": 566}, {"id": 567, "artigo_id": 209, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A União organizará o sistema federal de ensino e o dos Territórios, financiará as instituições de ensino públicas federais e exercerá, em matéria educacional, função redistributiva e supletiva, de forma a garantir equalização de oportunidades educacionais e padrão mínimo de qualidade do ensino mediante assistência técnica e financeira aos Estados, ao Distrito Federal e aos Municípios;", "ordem": 567}, {"id": 568, "artigo_id": 209, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os Municípios atuarão prioritariamente no ensino fundamental e na educação infantil.", "ordem": 568}, {"id": 569, "artigo_id": 209, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Os Estados e o Distrito Federal atuarão prioritariamente no ensino fundamental e médio.", "ordem": 569}, {"id": 570, "artigo_id": 209, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Na organização de seus sistemas de ensino, a União, os Estados, o Distrito Federal e os Municípios definirão formas de colaboração, de forma a assegurar a universalização, a qualidade e a equidade do ensino obrigatório.", "ordem": 570}, {"id": 571, "artigo_id": 209, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º A educação básica pública atenderá prioritariamente ao ensino regular.", "ordem": 571}, {"id": 572, "artigo_id": 209, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º A União, os Estados, o Distrito Federal e os Municípios exercerão ação redistributiva em relação a suas escolas.", "ordem": 572}, {"id": 573, "artigo_id": 209, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º O padrão mínimo de qualidade de que trata o § 1º deste artigo considerará as condições adequadas de oferta e terá como referência o Custo Aluno Qualidade (CAQ), pactuados em regime de colaboração na forma disposta em lei complementar, conforme o parágrafo único do art. 23 desta Constituição.", "ordem": 573}, {"id": 574, "artigo_id": 210, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A parcela da arrecadação de impostos transferida pela União aos Estados, ao Distrito Federal e aos Municípios, ou pelos Estados aos respectivos Municípios, não é considerada, para efeito do cálculo previsto neste artigo, receita do governo que a transferir.", "ordem": 574}, {"id": 575, "artigo_id": 210, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Para efeito do cumprimento do disposto no \"caput\" deste artigo, serão considerados os sistemas de ensino federal, estadual e municipal e os recursos aplicados na forma do art. 213.", "ordem": 575}, {"id": 576, "artigo_id": 210, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º A distribuição dos recursos públicos assegurará prioridade ao atendimento das necessidades do ensino obrigatório, no que se refere a universalização, garantia de padrão de qualidade e equidade, nos termos do plano nacional de educação.", "ordem": 576}, {"id": 577, "artigo_id": 210, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Os programas suplementares de alimentação e assistência à saúde previstos no art. 208, VII, serão financiados com recursos provenientes de contribuições sociais e outros recursos orçamentários.", "ordem": 577}, {"id": 578, "artigo_id": 210, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º A educação básica pública terá como fonte adicional de financiamento a contribuição social do salário-educação, recolhida pelas empresas na forma da lei.", "ordem": 578}, {"id": 579, "artigo_id": 210, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º As cotas estaduais e municipais da arrecadação da contribuição social do salário-educação serão distribuídas proporcionalmente ao número de alunos matriculados na educação básica nas respectivas redes públicas de ensino.", "ordem": 579}, {"id": 580, "artigo_id": 210, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º É vedado o uso dos recursos referidos no caput e nos §§ 5º e 6º deste artigo para pagamento de aposentadorias e de pensões.", "ordem": 580}, {"id": 581, "artigo_id": 210, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º Na hipótese de extinção ou de substituição de impostos, serão redefinidos os percentuais referidos no caput deste artigo e no inciso II do caput do art. 212-A, de modo que resultem recursos vinculados à manutenção e ao desenvolvimento do ensino, bem como os recursos subvinculados aos fundos de que trata o art. 212-A desta Constituição, em aplicações equivalentes às anteriormente praticadas.", "ordem": 581}, {"id": 582, "artigo_id": 210, "tipo": "numerado", "numero": 9, "numero_texto": "9º", "texto": "§ 9º A lei disporá sobre normas de fiscalização, de avaliação e de controle das despesas com educação nas esferas estadual, distrital e municipal.", "ordem": 582}, {"id": 583, "artigo_id": 210, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O cálculo do VAAT, referido no inciso VI do caput deste artigo, deverá considerar, além dos recursos previstos no inciso II do caput deste artigo, pelo menos, as seguintes disponibilidades:", "ordem": 583}, {"id": 584, "artigo_id": 210, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Além das ponderações previstas na alínea \"a\" do inciso X do caput deste artigo, a lei definirá outras relativas ao nível socioeconômico dos educandos e aos indicadores de disponibilidade de recursos vinculados à educação e de potencial de arrecadação tributária de cada ente federado, bem como seus prazos de implementação.", "ordem": 584}, {"id": 585, "artigo_id": 210, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Será destinada à educação infantil a proporção de 50% (cinquenta por cento) dos recursos globais a que se refere a alínea \"b\" do inciso V do caput deste artigo, nos termos da lei.\"", "ordem": 585}, {"id": 586, "artigo_id": 211, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Os recursos de que trata este artigo poderão ser destinados a bolsas de estudo para o ensino fundamental e médio, na forma da lei, para os que demonstrarem insuficiência de recursos, quando houver falta de vagas e cursos regulares da rede pública na localidade da residência do educando, ficando o Poder Público obrigado a investir prioritariamente na expansão de sua rede na localidade.", "ordem": 586}, {"id": 587, "artigo_id": 211, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º As atividades de pesquisa, de extensão e de estímulo e fomento à inovação realizadas por universidades e/ou por instituições de educação profissional e tecnológica poderão receber apoio financeiro do Poder Público.", "ordem": 587}, {"id": 588, "artigo_id": 213, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O Estado protegerá as manifestações das culturas populares, indígenas e afro-brasileiras, e das de outros grupos participantes do processo civilizatório nacional. Regulamento", "ordem": 588}, {"id": 589, "artigo_id": 213, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A lei disporá sobre a fixação de datas comemorativas de alta significação para os diferentes segmentos étnicos nacionais.", "ordem": 589}, {"id": 590, "artigo_id": 213, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º A lei estabelecerá o Plano Nacional de Cultura, de duração plurianual, visando ao desenvolvimento cultural do País e à integração das ações do poder público que conduzem à:", "ordem": 590}, {"id": 591, "artigo_id": 214, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O Poder Público, com a colaboração da comunidade, promoverá e protegerá o patrimônio cultural brasileiro, por meio de inventários, registros, vigilância, tombamento e desapropriação, e de outras formas de acautelamento e preservação.", "ordem": 591}, {"id": 592, "artigo_id": 214, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Cabem à administração pública, na forma da lei, a gestão da documentação governamental e as providências para franquear sua consulta a quantos dela necessitem.", "ordem": 592}, {"id": 593, "artigo_id": 214, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º A lei estabelecerá incentivos para a produção e o conhecimento de bens e valores culturais.", "ordem": 593}, {"id": 594, "artigo_id": 214, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Os danos e ameaças ao patrimônio cultural serão punidos, na forma da lei.", "ordem": 594}, {"id": 595, "artigo_id": 214, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Ficam tombados todos os documentos e os sítios detentores de reminiscências históricas dos antigos quilombos.", "ordem": 595}, {"id": 596, "artigo_id": 214, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6 º É facultado aos Estados e ao Distrito Federal vincular a fundo estadual de fomento à cultura até cinco décimos por cento de sua receita tributária líquida, para o financiamento de programas e projetos culturais, vedada a aplicação desses recursos no pagamento de:", "ordem": 596}, {"id": 597, "artigo_id": 214, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O Sistema Nacional de Cultura fundamenta-se na política nacional de cultura e nas suas diretrizes, estabelecidas no Plano Nacional de Cultura, e rege-se pelos seguintes princípios:", "ordem": 597}, {"id": 598, "artigo_id": 214, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Constitui a estrutura do Sistema Nacional de Cultura, nas respectivas esferas da Federação:", "ordem": 598}, {"id": 599, "artigo_id": 214, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Lei federal disporá sobre a regulamentação do Sistema Nacional de Cultura, bem como de sua articulação com os demais sistemas nacionais ou políticas setoriais de governo.", "ordem": 599}, {"id": 600, "artigo_id": 214, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Os Estados, o Distrito Federal e os Municípios organizarão seus respectivos sistemas de cultura em leis próprias.", "ordem": 600}, {"id": 601, "artigo_id": 215, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O Poder Judiciário só admitirá ações relativas à disciplina e às competições desportivas após esgotarem-se as instâncias da justiça desportiva, regulada em lei.", "ordem": 601}, {"id": 602, "artigo_id": 215, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A justiça desportiva terá o prazo máximo de sessenta dias, contados da instauração do processo, para proferir decisão final.", "ordem": 602}, {"id": 603, "artigo_id": 215, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O Poder Público incentivará o lazer, como forma de promoção social.", "ordem": 603}, {"id": 604, "artigo_id": 216, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A pesquisa científica básica e tecnológica receberá tratamento prioritário do Estado, tendo em vista o bem público e o progresso da ciência, tecnologia e inovação.", "ordem": 604}, {"id": 605, "artigo_id": 216, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A pesquisa tecnológica voltar-se-á preponderantemente para a solução dos problemas brasileiros e para o desenvolvimento do sistema produtivo nacional e regional.", "ordem": 605}, {"id": 606, "artigo_id": 216, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O Estado apoiará a formação de recursos humanos nas áreas de ciência, pesquisa, tecnologia e inovação, inclusive por meio do apoio às atividades de extensão tecnológica, e concederá aos que delas se ocupem meios e condições especiais de trabalho.", "ordem": 606}, {"id": 607, "artigo_id": 216, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º A lei apoiará e estimulará as empresas que invistam em pesquisa, criação de tecnologia adequada ao País, formação e aperfeiçoamento de seus recursos humanos e que pratiquem sistemas de remuneração que assegurem ao empregado, desvinculada do salário, participação nos ganhos econômicos resultantes da produtividade de seu trabalho.", "ordem": 607}, {"id": 608, "artigo_id": 216, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º É facultado aos Estados e ao Distrito Federal vincular parcela de sua receita orçamentária a entidades públicas de fomento ao ensino e à pesquisa científica e tecnológica.", "ordem": 608}, {"id": 609, "artigo_id": 216, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º O Estado, na execução das atividades previstas no caput , estimulará a articulação entre entes, tanto públicos quanto privados, nas diversas esferas de governo.", "ordem": 609}, {"id": 610, "artigo_id": 216, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º O Estado promoverá e incentivará a atuação no exterior das instituições públicas de ciência, tecnologia e inovação, com vistas à execução das atividades previstas no caput.", "ordem": 610}, {"id": 611, "artigo_id": 217, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. O Estado estimulará a formação e o fortalecimento da inovação nas empresas, bem como nos demais entes, públicos ou privados, a constituição e a manutenção de parques e polos tecnológicos e de demais ambientes promotores da inovação, a atuação dos inventores independentes e a criação, absorção, difusão e transferência de tecnologia.", "ordem": 611}, {"id": 612, "artigo_id": 217, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Lei federal disporá sobre as normas gerais do SNCTI.", "ordem": 612}, {"id": 613, "artigo_id": 217, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os Estados, o Distrito Federal e os Municípios legislarão concorrentemente sobre suas peculiaridades.", "ordem": 613}, {"id": 614, "artigo_id": 218, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Nenhuma lei conterá dispositivo que possa constituir embaraço à plena liberdade de informação jornalística em qualquer veículo de comunicação social, observado o disposto no art. 5º, IV, V, X, XIII e XIV.", "ordem": 614}, {"id": 615, "artigo_id": 218, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º É vedada toda e qualquer censura de natureza política, ideológica e artística.", "ordem": 615}, {"id": 616, "artigo_id": 218, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Compete à lei federal:", "ordem": 616}, {"id": 617, "artigo_id": 218, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º A propaganda comercial de tabaco, bebidas alcoólicas, agrotóxicos, medicamentos e terapias estará sujeita a restrições legais, nos termos do inciso II do parágrafo anterior, e conterá, sempre que necessário, advertência sobre os malefícios decorrentes de seu uso.", "ordem": 617}, {"id": 618, "artigo_id": 218, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Os meios de comunicação social não podem, direta ou indiretamente, ser objeto de monopólio ou oligopólio.", "ordem": 618}, {"id": 619, "artigo_id": 218, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º A publicação de veículo impresso de comunicação independe de licença de autoridade.", "ordem": 619}, {"id": 620, "artigo_id": 220, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Em qualquer caso, pelo menos setenta por cento do capital total e do capital votante das empresas jornalísticas e de radiodifusão sonora e de sons e imagens deverá pertencer, direta ou indiretamente, a brasileiros natos ou naturalizados há mais de dez anos, que exercerão obrigatoriamente a gestão das atividades e estabelecerão o conteúdo da programação.", "ordem": 620}, {"id": 621, "artigo_id": 220, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A responsabilidade editorial e as atividades de seleção e direção da programação veiculada são privativas de brasileiros natos ou naturalizados há mais de dez anos, em qualquer meio de comunicação social.", "ordem": 621}, {"id": 622, "artigo_id": 220, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Os meios de comunicação social eletrônica, independentemente da tecnologia utilizada para a prestação do serviço, deverão observar os princípios enunciados no art. 221, na forma de lei específica, que também garantirá a prioridade de profissionais brasileiros na execução de produções nacionais.", "ordem": 622}, {"id": 623, "artigo_id": 220, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Lei disciplinará a participação de capital estrangeiro nas empresas de que trata o § 1º.", "ordem": 623}, {"id": 624, "artigo_id": 220, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º As alterações de controle societário das empresas de que trata o § 1º serão comunicadas ao Congresso Nacional.", "ordem": 624}, {"id": 625, "artigo_id": 221, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O Congresso Nacional apreciará o ato no prazo do art. 64, § 2º e § 4º, a contar do recebimento da mensagem.", "ordem": 625}, {"id": 626, "artigo_id": 221, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A não renovação da concessão ou permissão dependerá de aprovação de, no mínimo, dois quintos do Congresso Nacional, em votação nominal.", "ordem": 626}, {"id": 627, "artigo_id": 221, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O ato de outorga ou renovação somente produzirá efeitos legais após deliberação do Congresso Nacional, na forma dos parágrafos anteriores.", "ordem": 627}, {"id": 628, "artigo_id": 221, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º O cancelamento da concessão ou permissão, antes de vencido o prazo, depende de decisão judicial.", "ordem": 628}, {"id": 629, "artigo_id": 221, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º O prazo da concessão ou permissão será de dez anos para as emissoras de rádio e de quinze para as de televisão.", "ordem": 629}, {"id": 630, "artigo_id": 223, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Para assegurar a efetividade desse direito, incumbe ao Poder Público:", "ordem": 630}, {"id": 631, "artigo_id": 223, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Aquele que explorar recursos minerais fica obrigado a recuperar o meio ambiente degradado, de acordo com solução técnica exigida pelo órgão público competente, na forma da lei.", "ordem": 631}, {"id": 632, "artigo_id": 223, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º As condutas e atividades consideradas lesivas ao meio ambiente sujeitarão os infratores, pessoas físicas ou jurídicas, a sanções penais e administrativas, independentemente da obrigação de reparar os danos causados.", "ordem": 632}, {"id": 633, "artigo_id": 223, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º A Floresta Amazônica brasileira, a Mata Atlântica, a Serra do Mar, o Pantanal Mato-Grossense e a Zona Costeira são patrimônio nacional, e sua utilização far-se-á, na forma da lei, dentro de condições que assegurem a preservação do meio ambiente, inclusive quanto ao uso dos recursos naturais. (Regulamento) (Regulamento)", "ordem": 633}, {"id": 634, "artigo_id": 223, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º São indisponíveis as terras devolutas ou arrecadadas pelos Estados, por ações discriminatórias, necessárias à proteção dos ecossistemas naturais.", "ordem": 634}, {"id": 635, "artigo_id": 223, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º As usinas que operem com reator nuclear deverão ter sua localização definida em lei federal, sem o que não poderão ser instaladas.", "ordem": 635}, {"id": 636, "artigo_id": 223, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º Para fins do disposto na parte final do inciso VII do § 1º deste artigo, não se consideram cruéis as práticas desportivas que utilizem animais, desde que sejam manifestações culturais, conforme o § 1º do art. 215 desta Constituição Federal, registradas como bem de natureza imaterial integrante do patrimônio cultural brasileiro, devendo ser regulamentadas por lei específica que assegure o bem-estar dos animais envolvidos.", "ordem": 636}, {"id": 637, "artigo_id": 224, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O casamento é civil e gratuita a celebração.", "ordem": 637}, {"id": 638, "artigo_id": 224, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O casamento religioso tem efeito civil, nos termos da lei.", "ordem": 638}, {"id": 639, "artigo_id": 224, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Para efeito da proteção do Estado, é reconhecida a união estável entre o homem e a mulher como entidade familiar, devendo a lei facilitar sua conversão em casamento. (Regulamento)", "ordem": 639}, {"id": 640, "artigo_id": 224, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Entende-se, também, como entidade familiar a comunidade formada por qualquer dos pais e seus descendentes.", "ordem": 640}, {"id": 641, "artigo_id": 224, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Os direitos e deveres referentes à sociedade conjugal são exercidos igualmente pelo homem e pela mulher.", "ordem": 641}, {"id": 642, "artigo_id": 224, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º O casamento civil pode ser dissolvido pelo divórcio.", "ordem": 642}, {"id": 643, "artigo_id": 224, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º Fundado nos princípios da dignidade da pessoa humana e da paternidade responsável, o planejamento familiar é livre decisão do casal, competindo ao Estado propiciar recursos educacionais e científicos para o exercício desse direito, vedada qualquer forma coercitiva por parte de instituições oficiais ou privadas. Regulamento", "ordem": 643}, {"id": 644, "artigo_id": 224, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º O Estado assegurará a assistência à família na pessoa de cada um dos que a integram, criando mecanismos para coibir a violência no âmbito de suas relações.", "ordem": 644}, {"id": 645, "artigo_id": 225, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O Estado promoverá programas de assistência integral à saúde da criança, do adolescente e do jovem, admitida a participação de entidades não governamentais, mediante políticas específicas e obedecendo aos seguintes preceitos:", "ordem": 645}, {"id": 646, "artigo_id": 225, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A lei disporá sobre normas de construção dos logradouros e dos edifícios de uso público e de fabricação de veículos de transporte coletivo, a fim de garantir acesso adequado às pessoas portadoras de deficiência.", "ordem": 646}, {"id": 647, "artigo_id": 225, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O direito a proteção especial abrangerá os seguintes aspectos:", "ordem": 647}, {"id": 648, "artigo_id": 225, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º A lei punirá severamente o abuso, a violência e a exploração sexual da criança e do adolescente.", "ordem": 648}, {"id": 649, "artigo_id": 225, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º A adoção será assistida pelo Poder Público, na forma da lei, que estabelecerá casos e condições de sua efetivação por parte de estrangeiros.", "ordem": 649}, {"id": 650, "artigo_id": 225, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Os filhos, havidos ou não da relação do casamento, ou por adoção, terão os mesmos direitos e qualificações, proibidas quaisquer designações discriminatórias relativas à filiação.", "ordem": 650}, {"id": 651, "artigo_id": 225, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º No atendimento dos direitos da criança e do adolescente levar-se- á em consideração o disposto no art. 204.", "ordem": 651}, {"id": 652, "artigo_id": 225, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º A lei estabelecerá:", "ordem": 652}, {"id": 653, "artigo_id": 228, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Os programas de amparo aos idosos serão executados preferencialmente em seus lares.", "ordem": 653}, {"id": 654, "artigo_id": 228, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Aos maiores de sessenta e cinco anos é garantida a gratuidade dos transportes coletivos urbanos.", "ordem": 654}, {"id": 655, "artigo_id": 229, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º São terras tradicionalmente ocupadas pelos índios as por eles habitadas em caráter permanente, as utilizadas para suas atividades produtivas, as imprescindíveis à preservação dos recursos ambientais necessários a seu bem-estar e as necessárias a sua reprodução física e cultural, segundo seus usos, costumes e tradições.", "ordem": 655}, {"id": 656, "artigo_id": 229, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º As terras tradicionalmente ocupadas pelos índios destinam-se a sua posse permanente, cabendo-lhes o usufruto exclusivo das riquezas do solo, dos rios e dos lagos nelas existentes.", "ordem": 656}, {"id": 657, "artigo_id": 229, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O aproveitamento dos recursos hídricos, incluídos os potenciais energéticos, a pesquisa e a lavra das riquezas minerais em terras indígenas só podem ser efetivados com autorização do Congresso Nacional, ouvidas as comunidades afetadas, ficando-lhes assegurada participação nos resultados da lavra, na forma da lei.", "ordem": 657}, {"id": 658, "artigo_id": 229, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º As terras de que trata este artigo são inalienáveis e indisponíveis, e os direitos sobre elas, imprescritíveis.", "ordem": 658}, {"id": 659, "artigo_id": 229, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º É vedada a remoção dos grupos indígenas de suas terras, salvo, \"ad referendum\" do Congresso Nacional, em caso de catástrofe ou epidemia que ponha em risco sua população, ou no interesse da soberania do País, após deliberação do Congresso Nacional, garantido, em qualquer hipótese, o retorno imediato logo que cesse o risco.", "ordem": 659}, {"id": 660, "artigo_id": 229, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º São nulos e extintos, não produzindo efeitos jurídicos, os atos que tenham por objeto a ocupação, o domínio e a posse das terras a que se refere este artigo, ou a exploração das riquezas naturais do solo, dos rios e dos lagos nelas existentes, ressalvado relevante interesse público da União, segundo o que dispuser lei complementar, não gerando a nulidade e a extinção direito a indenização ou a ações contra a União, salvo, na forma da lei, quanto às benfeitorias derivadas da ocupação de boa fé.", "ordem": 660}, {"id": 661, "artigo_id": 229, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º Não se aplica às terras indígenas o disposto no art. 174, § 3º e § 4º.", "ordem": 661}, {"id": 662, "artigo_id": 233, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Lei regulará as atividades, disciplinará a responsabilidade civil e criminal dos notários, dos oficiais de registro e de seus prepostos, e definirá a fiscalização de seus atos pelo Poder Judiciário.", "ordem": 662}, {"id": 663, "artigo_id": 233, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Lei federal estabelecerá normas gerais para fixação de emolumentos relativos aos atos praticados pelos serviços notariais e de registro. (Regulamento)", "ordem": 663}, {"id": 664, "artigo_id": 233, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O ingresso na atividade notarial e de registro depende de concurso público de provas e títulos, não se permitindo que qualquer serventia fique vaga, sem abertura de concurso de provimento ou de remoção, por mais de seis meses.", "ordem": 664}, {"id": 665, "artigo_id": 236, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Dos recursos mencionados no caput, no mínimo 28% (vinte e oito por cento) serão destinados para o financiamento de programas de desenvolvimento econômico, por meio do Banco Nacional de Desenvolvimento Econômico e Social, com critérios de remuneração que preservem o seu valor.", "ordem": 665}, {"id": 666, "artigo_id": 236, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os patrimônios acumulados do Programa de Integração Social e do Programa de Formação do Patrimônio do Servidor Público são preservados, mantendo-se os critérios de saque nas situações previstas nas leis específicas, com exceção da retirada por motivo de casamento, ficando vedada a distribuição da arrecadação de que trata o \"caput\" deste artigo, para depósito nas contas individuais dos participantes.", "ordem": 666}, {"id": 667, "artigo_id": 236, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Aos empregados que percebam de empregadores que contribuem para o Programa de Integração Social ou para o Programa de Formação do Patrimônio do Servidor Público remuneração mensal de até 2 (duas) vezes o salário mínimo do ano-base para pagamento em 2025, corrigida, a partir de 2026, pela variação anual do Índice Nacional de Preços ao Consumidor (INPC), calculado e divulgado pela Fundação Instituto Brasileiro de Geografia e Estatística (IBGE), ou de outro índice que vier a substituí-lo, acumulada no segundo exercício anterior ao de pagamento do benefício, é assegurado o pagamento de 1 (um) salário mínimo anual, computado nesse valor o rendimento das contas individuais, no caso daqueles que já participavam dos referidos Programas, até a data de promulgação desta Constituição.", "ordem": 667}, {"id": 668, "artigo_id": 236, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º O financiamento do seguro-desemprego receberá uma contribuição adicional da empresa cujo índice de rotatividade da força de trabalho superar o índice médio da rotatividade do setor, na forma estabelecida por lei.", "ordem": 668}, {"id": 669, "artigo_id": 236, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Os programas de desenvolvimento econômico financiados na forma do § 1º e seus resultados serão anualmente avaliados e divulgados em meio de comunicação social eletrônico e apresentados em reunião da comissão mista permanente de que trata o § 1º do art. 166.", "ordem": 669}, {"id": 670, "artigo_id": 239, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O ensino da História do Brasil levará em conta as contribuições das diferentes culturas e etnias para a formação do povo brasileiro.", "ordem": 670}, {"id": 671, "artigo_id": 239, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O Colégio Pedro II, localizado na cidade do Rio de Janeiro, será mantido na órbita federal.", "ordem": 671}, {"id": 672, "artigo_id": 240, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Todo e qualquer bem de valor econômico apreendido em decorrência do tráfico ilícito de entorpecentes e drogas afins e da exploração de trabalho escravo será confiscado e reverterá a fundo especial com destinação específica, na forma da lei.", "ordem": 672}, {"id": 673, "artigo_id": 244, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Na hipótese de insuficiência de desempenho, a perda do cargo somente ocorrerá mediante processo administrativo em que lhe sejam assegurados o contraditório e a ampla defesa.", "ordem": 673}, {"id": 674, "artigo_id": 249, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Será assegurada gratuidade na livre divulgação dessas formas e sistemas, através dos meios de comunicação de massa cessionários de serviço público.", "ordem": 674}, {"id": 675, "artigo_id": 249, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O Tribunal Superior Eleitoral, promulgada a Constituição, expedirá as normas regulamentadoras deste artigo.", "ordem": 675}, {"id": 676, "artigo_id": 251, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A primeira eleição para Presidente da República após a promulgação da Constituição será realizada no dia 15 de novembro de 1989, não se lhe aplicando o disposto no art. 16 da Constituição.", "ordem": 676}, {"id": 677, "artigo_id": 251, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º É assegurada a irredutibilidade da atual representação dos Estados e do Distrito Federal na Câmara dos Deputados.", "ordem": 677}, {"id": 678, "artigo_id": 251, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Os mandatos dos Governadores e dos Vice-Governadores eleitos em 15 de novembro de 1986 terminarão em 15 de março de 1991.", "ordem": 678}, {"id": 679, "artigo_id": 251, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Os mandatos dos atuais Prefeitos, Vice-Prefeitos e Vereadores terminarão no dia 1º de janeiro de 1989, com a posse dos eleitos.", "ordem": 679}, {"id": 680, "artigo_id": 252, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Para as eleições de 15 de novembro de 1988 será exigido domicílio eleitoral na circunscrição pelo menos durante os quatro meses anteriores ao pleito, podendo os candidatos que preencham este requisito, atendidas as demais exigências da lei, ter seu registro efetivado pela Justiça Eleitoral após a promulgação da Constituição.", "ordem": 680}, {"id": 681, "artigo_id": 252, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Na ausência de norma legal específica, caberá ao Tribunal Superior Eleitoral editar as normas necessárias à realização das eleições de 1988, respeitada a legislação vigente.", "ordem": 681}, {"id": 682, "artigo_id": 252, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Os atuais parlamentares federais e estaduais eleitos Vice-Prefeitos, se convocados a exercer a função de Prefeito, não perderão o mandato parlamentar.", "ordem": 682}, {"id": 683, "artigo_id": 252, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º O número de vereadores por município será fixado, para a representação a ser eleita em 1988, pelo respectivo Tribunal Regional Eleitoral, respeitados os limites estipulados no art. 29, IV, da Constituição.", "ordem": 683}, {"id": 684, "artigo_id": 252, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º - Para as eleições de 15 de novembro de 1988, ressalvados os que já exercem mandato eletivo, são inelegíveis para qualquer cargo, no território de jurisdição do titular, o cônjuge e os parentes por consangüinidade ou afinidade, até o segundo grau, ou por adoção, do Presidente da República, do Governador de Estado, do Governador do Distrito Federal e do Prefeito que tenham exercido mais da metade do mandato.", "ordem": 684}, {"id": 685, "artigo_id": 253, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O registro provisório, que será concedido de plano pelo Tribunal Superior Eleitoral, nos termos deste artigo, defere ao novo partido todos os direitos, deveres e prerrogativas dos atuais, entre eles o de participar, sob legenda própria, das eleições que vierem a ser realizadas nos doze meses seguintes a sua formação.", "ordem": 685}, {"id": 686, "artigo_id": 253, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O novo partido perderá automaticamente seu registro provisório se, no prazo de vinte e quatro meses, contados de sua formação, não obtiver registro definitivo no Tribunal Superior Eleitoral, na forma que a lei dispuser.", "ordem": 686}, {"id": 687, "artigo_id": 255, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O disposto neste artigo somente gerará efeitos financeiros a partir da promulgação da Constituição, vedada a remuneração de qualquer espécie em caráter retroativo.", "ordem": 687}, {"id": 688, "artigo_id": 255, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Ficam assegurados os benefícios estabelecidos neste artigo aos trabalhadores do setor privado, dirigentes e representantes sindicais que, por motivos exclusivamente políticos, tenham sido punidos, demitidos ou compelidos ao afastamento das atividades remuneradas que exerciam, bem como aos que foram impedidos de exercer atividades profissionais em virtude de pressões ostensivas ou expedientes oficiais sigilosos.", "ordem": 688}, {"id": 689, "artigo_id": 255, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Aos cidadãos que foram impedidos de exercer, na vida civil, atividade profissional específica, em decorrência das Portarias Reservadas do Ministério da Aeronáutica nº S-50-GM5, de 19 de junho de 1964, e nº S-285-GM5 será concedida reparação de natureza econômica, na forma que dispuser lei de iniciativa do Congresso Nacional e a entrar em vigor no prazo de doze meses a contar da promulgação da Constituição.", "ordem": 689}, {"id": 690, "artigo_id": 255, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Aos que, por força de atos institucionais, tenham exercido gratuitamente mandato eletivo de vereador serão computados, para efeito de aposentadoria no serviço público e previdência social, os respectivos períodos.", "ordem": 690}, {"id": 691, "artigo_id": 255, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º A anistia concedida nos termos deste artigo aplica-se aos servidores públicos civis e aos empregados em todos os níveis de governo ou em suas fundações, empresas públicas ou empresas mistas sob controle estatal, exceto nos Ministérios militares, que tenham sido punidos ou demitidos por atividades profissionais interrompidas em virtude de decisão de seus trabalhadores, bem como em decorrência do Decreto-Lei nº 1.632, de 4 de agosto de 1978 , ou por motivos exclusivamente políticos, assegurada a readmissão dos que foram atingidos a partir de 1979, observado o disposto no § 1º.", "ordem": 691}, {"id": 692, "artigo_id": 256, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. O Supremo Tribunal Federal proferirá a decisão no prazo de cento e vinte dias, a contar do pedido do interessado.", "ordem": 692}, {"id": 693, "artigo_id": 257, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Até que a lei venha a disciplinar o disposto no art. 7º, XIX, da Constituição, o prazo da licença-paternidade a que se refere o inciso é de cinco dias.", "ordem": 693}, {"id": 694, "artigo_id": 257, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Até ulterior disposição legal, a cobrança das contribuições para o custeio das atividades dos sindicatos rurais será feita juntamente com a do imposto territorial rural, pelo mesmo órgão arrecadador.", "ordem": 694}, {"id": 695, "artigo_id": 257, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Na primeira comprovação do cumprimento das obrigações trabalhistas pelo empregador rural, na forma do art. 233, após a promulgação da Constituição, será certificada perante a Justiça do Trabalho a regularidade do contrato e das atualizações das obrigações trabalhistas de todo o período.", "ordem": 695}, {"id": 696, "artigo_id": 258, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Promulgada a Constituição do Estado, caberá à Câmara Municipal, no prazo de seis meses, votar a Lei Orgânica respectiva, em dois turnos de discussão e votação, respeitado o disposto na Constituição Federal e na Constituição Estadual.", "ordem": 696}, {"id": 697, "artigo_id": 259, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º No prazo de um ano, a Comissão submeterá ao Congresso Nacional os resultados de seus estudos para, nos termos da Constituição, serem apreciados nos doze meses subseqüentes, extinguindo-se logo após.", "ordem": 697}, {"id": 698, "artigo_id": 259, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os Estados e os Municípios deverão, no prazo de três anos, a contar da promulgação da Constituição, promover, mediante acordo ou arbitramento, a demarcação de suas linhas divisórias atualmente litigiosas, podendo para isso fazer alterações e compensações de área que atendam aos acidentes naturais, critérios históricos, conveniências administrativas e comodidade das populações limítrofes.", "ordem": 698}, {"id": 699, "artigo_id": 259, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Havendo solicitação dos Estados e Municípios interessados, a União poderá encarregar-se dos trabalhos demarcatórios.", "ordem": 699}, {"id": 700, "artigo_id": 259, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Se, decorrido o prazo de três anos, a contar da promulgação da Constituição, os trabalhos demarcatórios não tiverem sido concluídos, caberá à União determinar os limites das áreas litigiosas.", "ordem": 700}, {"id": 701, "artigo_id": 259, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Ficam reconhecidos e homologados os atuais limites do Estado do Acre com os Estados do Amazonas e de Rondônia, conforme levantamentos cartográficos e geodésicos realizados pela Comissão Tripartite integrada por representantes dos Estados e dos serviços técnico-especializados do Instituto Brasileiro de Geografia e Estatística.", "ordem": 701}, {"id": 702, "artigo_id": 260, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O Estado do Tocantins integra a Região Norte e limita-se com o Estado de Goiás pelas divisas norte dos Municípios de São Miguel do Araguaia, Porangatu, Formoso, Minaçu, Cavalcante, Monte Alegre de Goiás e Campos Belos, conservando a leste, norte e oeste as divisas atuais de Goiás com os Estados da Bahia, Piauí, Maranhão, Pará e Mato Grosso.", "ordem": 702}, {"id": 703, "artigo_id": 260, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O Poder Executivo designará uma das cidades do Estado para sua Capital provisória até a aprovação da sede definitiva do governo pela Assembléia Constituinte.", "ordem": 703}, {"id": 704, "artigo_id": 260, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O Governador, o Vice-Governador, os Senadores, os Deputados Federais e os Deputados Estaduais serão eleitos, em um único turno, até setenta e cinco dias após a promulgação da Constituição, mas não antes de 15 de novembro de 1988, a critério do Tribunal Superior Eleitoral, obedecidas, entre outras, as seguintes normas:", "ordem": 704}, {"id": 705, "artigo_id": 260, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Os mandatos do Governador, do Vice-Governador, dos Deputados Federais e Estaduais eleitos na forma do parágrafo anterior extinguir-se-ão concomitantemente aos das demais unidades da Federação; o mandato do Senador eleito menos votado extinguir-se-á nessa mesma oportunidade, e os dos outros dois, juntamente com os dos Senadores eleitos em 1986 nos demais Estados.", "ordem": 705}, {"id": 706, "artigo_id": 260, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º A Assembléia Estadual Constituinte será instalada no quadragésimo sexto dia da eleição de seus integrantes, mas não antes de 1º de janeiro de 1989, sob a presidência do Presidente do Tribunal Regional Eleitoral do Estado de Goiás, e dará posse, na mesma data, ao Governador e ao Vice-Governador eleitos.", "ordem": 706}, {"id": 707, "artigo_id": 260, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Aplicam-se à criação e instalação do Estado do Tocantins, no que couber, as normas legais disciplinadoras da divisão do Estado de Mato Grosso, observado o disposto no art. 234 da Constituição.", "ordem": 707}, {"id": 708, "artigo_id": 260, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º Fica o Estado de Goiás liberado dos débitos e encargos decorrentes de empreendimentos no território do novo Estado, e autorizada a União, a seu critério, a assumir os referidos débitos.", "ordem": 708}, {"id": 709, "artigo_id": 261, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A instalação dos Estados dar-se-á com a posse dos governadores eleitos em 1990.", "ordem": 709}, {"id": 710, "artigo_id": 261, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Aplicam-se à transformação e instalação dos Estados de Roraima e Amapá as normas e critérios seguidos na criação do Estado de Rondônia, respeitado o disposto na Constituição e neste Ato.", "ordem": 710}, {"id": 711, "artigo_id": 261, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O Presidente da República, até quarenta e cinco dias após a promulgação da Constituição, encaminhará à apreciação do Senado Federal os nomes dos governadores dos Estados de Roraima e do Amapá que exercerão o Poder Executivo até a instalação dos novos Estados com a posse dos governadores eleitos.", "ordem": 711}, {"id": 712, "artigo_id": 261, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Enquanto não concretizada a transformação em Estados, nos termos deste artigo, os Territórios Federais de Roraima e do Amapá serão beneficiados pela transferência de recursos prevista nos arts. 159, I, \"a\", da Constituição, e 34, § 2º, II, deste Ato.", "ordem": 712}, {"id": 713, "artigo_id": 263, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A competência da Câmara Legislativa do Distrito Federal, até que se instale, será exercida pelo Senado Federal.", "ordem": 713}, {"id": 714, "artigo_id": 263, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A fiscalização contábil, financeira, orçamentária, operacional e patrimonial do Distrito Federal, enquanto não for instalada a Câmara Legislativa, será exercida pelo Senado Federal, mediante controle externo, com o auxílio do Tribunal de Contas do Distrito Federal, observado o disposto no art. 72 da Constituição.", "ordem": 714}, {"id": 715, "artigo_id": 263, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Incluem-se entre os bens do Distrito Federal aqueles que lhe vierem a ser atribuídos pela União na forma da lei.", "ordem": 715}, {"id": 716, "artigo_id": 264, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º É assegurado o exercício cumulativo de dois cargos ou empregos privativos de médico que estejam sendo exercidos por médico militar na administração pública direta ou indireta.", "ordem": 716}, {"id": 717, "artigo_id": 264, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º É assegurado o exercício cumulativo de dois cargos ou empregos privativos de profissionais de saúde que estejam sendo exercidos na administração pública direta ou indireta.", "ordem": 717}, {"id": 718, "artigo_id": 266, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O tempo de serviço dos servidores referidos neste artigo será contado como título quando se submeterem a concurso para fins de efetivação, na forma da lei.", "ordem": 718}, {"id": 719, "artigo_id": 266, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O disposto neste artigo não se aplica aos ocupantes de cargos, funções e empregos de confiança ou em comissão, nem aos que a lei declare de livre exoneração, cujo tempo de serviço não será computado para os fins do \"caput\" deste artigo, exceto se se tratar de servidor.", "ordem": 719}, {"id": 720, "artigo_id": 266, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O disposto neste artigo não se aplica aos professores de nível superior, nos termos da lei.", "ordem": 720}, {"id": 721, "artigo_id": 268, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. A aposentadoria dos juízes de que trata este artigo regular-se-á pelas normas fixadas para os demais juízes estaduais.", "ordem": 721}, {"id": 722, "artigo_id": 270, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. A lei referida disporá sobre o aproveitamento dos Censores Federais, nos termos deste artigo.", "ordem": 722}, {"id": 723, "artigo_id": 272, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Os decretos-lei em tramitação no Congresso Nacional e por este não apreciados até a promulgação da Constituição terão seus efeitos regulados da seguinte forma:", "ordem": 723}, {"id": 724, "artigo_id": 272, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os decretos-lei editados entre 3 de setembro de 1988 e a promulgação da Constituição serão convertidos, nesta data, em medidas provisórias, aplicando-se-lhes as regras estabelecidas no art. 62, parágrafo único.", "ordem": 724}, {"id": 725, "artigo_id": 273, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A Comissão terá a força legal de Comissão parlamentar de inquérito para os fins de requisição e convocação, e atuará com o auxílio do Tribunal de Contas da União.", "ordem": 725}, {"id": 726, "artigo_id": 273, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Apurada irregularidade, o Congresso Nacional proporá ao Poder Executivo a declaração de nulidade do ato e encaminhará o processo ao Ministério Público Federal, que formalizará, no prazo de sessenta dias, a ação cabível.", "ordem": 726}, {"id": 727, "artigo_id": 274, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Até que se instale o Superior Tribunal de Justiça, o Supremo Tribunal Federal exercerá as atribuições e competências definidas na ordem constitucional precedente.", "ordem": 727}, {"id": 728, "artigo_id": 274, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A composição inicial do Superior Tribunal de Justiça far-se-á:", "ordem": 728}, {"id": 729, "artigo_id": 274, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Para os efeitos do disposto na Constituição, os atuais Ministros do Tribunal Federal de Recursos serão considerados pertencentes à classe de que provieram, quando de sua nomeação.", "ordem": 729}, {"id": 730, "artigo_id": 274, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Instalado o Tribunal, os Ministros aposentados do Tribunal Federal de Recursos tornar-se-ão, automaticamente, Ministros aposentados do Superior Tribunal de Justiça.", "ordem": 730}, {"id": 731, "artigo_id": 274, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Os Ministros a que se refere o § 2º, II, serão indicados em lista tríplice pelo Tribunal Federal de Recursos, observado o disposto no art. 104, parágrafo único, da Constituição.", "ordem": 731}, {"id": 732, "artigo_id": 274, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Ficam criados cinco Tribunais Regionais Federais, a serem instalados no prazo de seis meses a contar da promulgação da Constituição, com a jurisdição e sede que lhes fixar o Tribunal Federal de Recursos, tendo em conta o número de processos e sua localização geográfica.", "ordem": 732}, {"id": 733, "artigo_id": 274, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º Até que se instalem os Tribunais Regionais Federais, o Tribunal Federal de Recursos exercerá a competência a eles atribuída em todo o território nacional, cabendo-lhe promover sua instalação e indicar os candidatos a todos os cargos da composição inicial, mediante lista tríplice, podendo desta constar juízes federais de qualquer região, observado o disposto no § 9º.", "ordem": 733}, {"id": 734, "artigo_id": 274, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º É vedado, a partir da promulgação da Constituição, o provimento de vagas de Ministros do Tribunal Federal de Recursos.", "ordem": 734}, {"id": 735, "artigo_id": 274, "tipo": "numerado", "numero": 9, "numero_texto": "9º", "texto": "§ 9º Quando não houver juiz federal que conte o tempo mínimo previsto no art. 107, II, da Constituição, a promoção poderá contemplar juiz com menos de cinco anos no exercício do cargo.", "ordem": 735}, {"id": 736, "artigo_id": 275, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Para efeito de promoção por antigüidade, o tempo de serviço desses juízes será computado a partir do dia de sua posse.", "ordem": 736}, {"id": 737, "artigo_id": 276, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O Presidente da República, no prazo de cento e vinte dias, encaminhará ao Congresso Nacional projeto de lei complementar dispondo sobre a organização e o funcionamento da Advocacia-Geral da União.", "ordem": 737}, {"id": 738, "artigo_id": 276, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Aos atuais Procuradores da República, nos termos da lei complementar, será facultada a opção, de forma irretratável, entre as carreiras do Ministério Público Federal e da Advocacia-Geral da União.", "ordem": 738}, {"id": 739, "artigo_id": 276, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Poderá optar pelo regime anterior, no que respeita às garantias e vantagens, o membro do Ministério Público admitido antes da promulgação da Constituição, observando-se, quanto às vedações, a situação jurídica na data desta.", "ordem": 739}, {"id": 740, "artigo_id": 276, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Os atuais integrantes do quadro suplementar dos Ministérios Públicos do Trabalho e Militar que tenham adquirido estabilidade nessas funções passam a integrar o quadro da respectiva carreira.", "ordem": 740}, {"id": 741, "artigo_id": 276, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Cabe à atual Procuradoria-Geral da Fazenda Nacional, diretamente ou por delegação, que pode ser ao Ministério Público Estadual, representar judicialmente a União nas causas de natureza fiscal, na área da respectiva competência, até a promulgação das leis complementares previstas neste artigo.", "ordem": 741}, {"id": 742, "artigo_id": 280, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Poderão as entidades devedoras, para o cumprimento do disposto neste artigo, emitir, em cada ano, no exato montante do dispêndio, títulos de dívida pública não computáveis para efeito do limite global de endividamento.", "ordem": 742}, {"id": 743, "artigo_id": 281, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Entrarão em vigor com a promulgação da Constituição os arts. 148, 149, 150, 154, I, 156, III, e 159, I, \"c\", revogadas as disposições em contrário da Constituição de 1967 e das Emendas que a modificaram, especialmente de seu art. 25, III.", "ordem": 743}, {"id": 744, "artigo_id": 281, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O Fundo de Participação dos Estados e do Distrito Federal e o Fundo de Participação dos Municípios obedecerão às seguintes determinações:", "ordem": 744}, {"id": 745, "artigo_id": 281, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Promulgada a Constituição, a União, os Estados, o Distrito Federal e os Municípios poderão editar as leis necessárias à aplicação do sistema tributário nacional nela previsto.", "ordem": 745}, {"id": 746, "artigo_id": 281, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º As leis editadas nos termos do parágrafo anterior produzirão efeitos a partir da entrada em vigor do sistema tributário nacional previsto na Constituição.", "ordem": 746}, {"id": 747, "artigo_id": 281, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Vigente o novo sistema tributário nacional, fica assegurada a aplicação da legislação anterior, no que não seja incompatível com ele e com a legislação referida nos §3º e § 4º.", "ordem": 747}, {"id": 748, "artigo_id": 281, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Até 31 de dezembro de 1989, o disposto no art. 150, III, \"b\", não se aplica aos impostos de que tratam os arts. 155, I, \"a\" e \"b\", e 156, II e III, que podem ser cobrados trinta dias após a publicação da lei que os tenha instituído ou aumentado.", "ordem": 748}, {"id": 749, "artigo_id": 281, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º Até que sejam fixadas em lei complementar, as alíquotas máximas do imposto municipal sobre vendas a varejo de combustíveis líquidos e gasosos não excederão a três por cento.", "ordem": 749}, {"id": 750, "artigo_id": 281, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º Se, no prazo de sessenta dias contados da promulgação da Constituição, não for editada a lei complementar necessária à instituição do imposto de que trata o art. 155, I, \"b\", os Estados e o Distrito Federal, mediante convênio celebrado nos termos da Lei Complementar nº 24, de 7 de janeiro de 1975 , fixarão normas para regular provisoriamente a matéria.", "ordem": 750}, {"id": 751, "artigo_id": 281, "tipo": "numerado", "numero": 9, "numero_texto": "9º", "texto": "§ 9º Até que lei complementar disponha sobre a matéria, as empresas distribuidoras de energia elétrica, na condição de contribuintes ou de substitutos tributários, serão as responsáveis, por ocasião da saída do produto de seus estabelecimentos, ainda que destinado a outra unidade da Federação, pelo pagamento do imposto sobre operações relativas à circulação de mercadorias incidente sobre energia elétrica, desde a produção ou importação até a última operação, calculado o imposto sobre o preço então praticado na operação final e assegurado seu recolhimento ao Estado ou ao Distrito Federal, conforme o local onde deva ocorrer essa operação.", "ordem": 751}, {"id": 752, "artigo_id": 282, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Para aplicação dos critérios de que trata este artigo, excluem-se das despesas totais as relativas:", "ordem": 752}, {"id": 753, "artigo_id": 282, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Até a entrada em vigor da lei complementar a que se refere o art. 165, § 9º, I e II, serão obedecidas as seguintes normas:", "ordem": 753}, {"id": 754, "artigo_id": 285, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A União, os Estados, o Distrito Federal e os Municípios, quando a respectiva despesa de pessoal exceder o limite previsto neste artigo, deverão retornar àquele limite, reduzindo o percentual excedente à razão de um quinto por ano.", "ordem": 754}, {"id": 755, "artigo_id": 285, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º As despesas com pessoal resultantes do cumprimento do disposto nos §§ 12, 13, 14 e 15 do art. 198 da Constituição Federal serão contabilizadas, para fins dos limites de que trata o art. 169 da Constituição Federal, da seguinte forma:", "ordem": 755}, {"id": 756, "artigo_id": 286, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. O Congresso Nacional deverá votar no prazo de doze meses a lei complementar prevista no art. 161, II.", "ordem": 756}, {"id": 757, "artigo_id": 287, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Somente por lei federal podem ser modificados os critérios que disciplinaram ou venham a disciplinar a aprovação dos projetos na Zona Franca de Manaus.", "ordem": 757}, {"id": 758, "artigo_id": 288, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Considerar-se-ão revogados após dois anos, a partir da data da promulgação da Constituição, os incentivos que não forem confirmados por lei.", "ordem": 758}, {"id": 759, "artigo_id": 288, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A revogação não prejudicará os direitos que já tiverem sido adquiridos, àquela data, em relação a incentivos concedidos sob condição e com prazo certo.", "ordem": 759}, {"id": 760, "artigo_id": 288, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Os incentivos concedidos por convênio entre Estados, celebrados nos termos do art. 23, § 6º, da Constituição de 1967 , com a redação da Emenda Constitucional nº 1, de 17 de outubro de 1969, também deverão ser reavaliados e reconfirmados nos prazos deste artigo.", "ordem": 760}, {"id": 761, "artigo_id": 289, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Dos percentuais previstos nos incisos I e II do caput, no mínimo 50% (cinquenta por cento) serão destinados a projetos de irrigação que beneficiem agricultores familiares que atendam aos requisitos previstos em legislação específica.", "ordem": 761}, {"id": 762, "artigo_id": 291, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Ressalvadas as disposições de interesse nacional previstas no texto constitucional, as empresas brasileiras ficarão dispensadas do cumprimento do disposto no art. 176, § 1º, desde que, no prazo de até quatro anos da data da promulgação da Constituição, tenham o produto de sua lavra e beneficiamento destinado a industrialização no território nacional, em seus próprios estabelecimentos ou em empresa industrial controladora ou controlada.", "ordem": 762}, {"id": 763, "artigo_id": 291, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Ficarão também dispensadas do cumprimento do disposto no art. 176, § 1º, as empresas brasileiras titulares de concessão de energia hidráulica para uso em seu processo de industrialização.", "ordem": 763}, {"id": 764, "artigo_id": 291, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º As empresas brasileiras referidas no § 1º somente poderão ter autorizações de pesquisa e concessões de lavra ou potenciais de energia hidráulica, desde que a energia e o produto da lavra sejam utilizados nos respectivos processos industriais.", "ordem": 764}, {"id": 765, "artigo_id": 292, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Ficam ressalvados da vedação do art. 177, § 1º, os contratos de risco feitos com a Petróleo Brasileiro S.A. (Petrobrás), para pesquisa de petróleo, que estejam em vigor na data da promulgação da Constituição.", "ordem": 765}, {"id": 766, "artigo_id": 293, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. O disposto neste artigo aplica-se também:", "ordem": 766}, {"id": 767, "artigo_id": 294, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Consideram-se, para efeito deste artigo, microempresas as pessoas jurídicas e as firmas individuais com receitas anuais de até dez mil Obrigações do Tesouro Nacional, e pequenas empresas as pessoas jurídicas e as firmas individuais com receita anual de até vinte e cinco mil Obrigações do Tesouro Nacional.", "ordem": 767}, {"id": 768, "artigo_id": 294, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A classificação de mini, pequeno e médio produtor rural será feita obedecendo-se às normas de crédito rural vigentes à época do contrato.", "ordem": 768}, {"id": 769, "artigo_id": 294, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º A isenção da correção monetária a que se refere este artigo só será concedida nos seguintes casos:", "ordem": 769}, {"id": 770, "artigo_id": 294, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Os benefícios de que trata este artigo não se estendem aos débitos já quitados e aos devedores que sejam constituintes.", "ordem": 770}, {"id": 771, "artigo_id": 294, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º No caso de operações com prazos de vencimento posteriores à data- limite de liquidação da dívida, havendo interesse do mutuário, os bancos e as instituições financeiras promoverão, por instrumento próprio, alteração nas condições contratuais originais de forma a ajustá-las ao presente benefício.", "ordem": 771}, {"id": 772, "artigo_id": 294, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º A concessão do presente benefício por bancos comerciais privados em nenhuma hipótese acarretará ônus para o Poder Público, ainda que através de refinanciamento e repasse de recursos pelo banco central.", "ordem": 772}, {"id": 773, "artigo_id": 294, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º No caso de repasse a agentes financeiros oficiais ou cooperativas de crédito, o ônus recairá sobre a fonte de recursos originária.", "ordem": 773}, {"id": 774, "artigo_id": 296, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Quando não existir cláusula contratual, serão adotados os critérios e bases hoje vigentes na legislação especial dos imóveis da União.", "ordem": 774}, {"id": 775, "artigo_id": 296, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os direitos dos atuais ocupantes inscritos ficam assegurados pela aplicação de outra modalidade de contrato.", "ordem": 775}, {"id": 776, "artigo_id": 296, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º A enfiteuse continuará sendo aplicada aos terrenos de marinha e seus acrescidos, situados na faixa de segurança, a partir da orla marítima.", "ordem": 776}, {"id": 777, "artigo_id": 296, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Remido o foro, o antigo titular do domínio direto deverá, no prazo de noventa dias, sob pena de responsabilidade, confiar à guarda do registro de imóveis competente toda a documentação a ele relativa.", "ordem": 777}, {"id": 778, "artigo_id": 298, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º No tocante às vendas, a revisão será feita com base exclusivamente no critério de legalidade da operação.", "ordem": 778}, {"id": 779, "artigo_id": 298, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º No caso de concessões e doações, a revisão obedecerá aos critérios de legalidade e de conveniência do interesse público.", "ordem": 779}, {"id": 780, "artigo_id": 298, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Nas hipóteses previstas nos parágrafos anteriores, comprovada a ilegalidade, ou havendo interesse público, as terras reverterão ao patrimônio da União, dos Estados, do Distrito Federal ou dos Municípios.", "ordem": 780}, {"id": 781, "artigo_id": 299, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. A vedação a que se refere este artigo não se aplica às autorizações resultantes de acordos internacionais, de reciprocidade, ou de interesse do Governo brasileiro.", "ordem": 781}, {"id": 782, "artigo_id": 300, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. A concessão da pensão especial do inciso II substitui, para todos os efeitos legais, qualquer outra pensão já concedida ao ex-combatente.", "ordem": 782}, {"id": 783, "artigo_id": 301, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O benefício é estendido aos seringueiros que, atendendo a apelo do Governo brasileiro, contribuíram para o esforço de guerra, trabalhando na produção de borracha, na Região Amazônica, durante a Segunda Guerra Mundial.", "ordem": 783}, {"id": 784, "artigo_id": 301, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os benefícios estabelecidos neste artigo são transferíveis aos dependentes reconhecidamente carentes.", "ordem": 784}, {"id": 785, "artigo_id": 301, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º A concessão do benefício far-se-á conforme lei a ser proposta pelo Poder Executivo dentro de cento e cinqüenta dias da promulgação da Constituição.", "ordem": 785}, {"id": 786, "artigo_id": 304, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O montante a ser pago em cada um dos dois primeiros anos não será inferior a cinco por cento do total do débito consolidado e atualizado, sendo o restante dividido em parcelas mensais de igual valor.", "ordem": 786}, {"id": 787, "artigo_id": 304, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A liquidação poderá incluir pagamentos na forma de cessão de bens e prestação de serviços, nos termos da Lei nº 7.578, de 23 de dezembro de 198 6.", "ordem": 787}, {"id": 788, "artigo_id": 304, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Em garantia do cumprimento do parcelamento, os Estados e os Municípios consignarão, anualmente, nos respectivos orçamentos as dotações necessárias ao pagamento de seus débitos.", "ordem": 788}, {"id": 789, "artigo_id": 304, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Descumprida qualquer das condições estabelecidas para concessão do parcelamento, o débito será considerado vencido em sua totalidade, sobre ele incidindo juros de mora; nesta hipótese, parcela dos recursos correspondentes aos Fundos de Participação, destinada aos Estados e Municípios devedores, será bloqueada e repassada à previdência social para pagamento de seus débitos.", "ordem": 789}, {"id": 790, "artigo_id": 305, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. As prestações mensais dos benefícios atualizadas de acordo com este artigo serão devidas e pagas a partir do sétimo mês a contar da promulgação da Constituição.", "ordem": 790}, {"id": 791, "artigo_id": 306, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Aprovados pelo Congresso Nacional, os planos serão implantados progressivamente nos dezoito meses seguintes.", "ordem": 791}, {"id": 792, "artigo_id": 307, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A parcela da complementação de que trata a alínea \"b\" do inciso V do caput do art. 212-A da Constituição Federal observará, no mínimo, os seguintes valores:", "ordem": 792}, {"id": 793, "artigo_id": 307, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A parcela da complementação de que trata a alínea \"c\" do inciso V do caput do art. 212-A da Constituição Federal observará os seguintes valores:", "ordem": 793}, {"id": 794, "artigo_id": 310, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. No desenvolvimento de suas atribuições, a Comissão promoverá estudos, debates e avaliações sobre a evolução política, social, econômica e cultural do País, podendo articular-se com os governos estaduais e municipais e com instituições públicas e privadas que desejem participar dos eventos.", "ordem": 794}, {"id": 795, "artigo_id": 318, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Ao Fundo criado por este artigo não se aplica o disposto na parte final do inciso II do § 9º do art. 165 da Constituição. (Renumerado do parágrafo único, pela Emenda Constitucional nº 10, de 1996) ]", "ordem": 795}, {"id": 796, "artigo_id": 318, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O Fundo criado por este artigo passa a ser denominado Fundo de Estabilização Fiscal a partir do início do exercício financeiro de 1996.", "ordem": 796}, {"id": 797, "artigo_id": 318, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O Poder Executivo publicará demonstrativo da execução orçamentária, de periodicidade bimestral, no qual se discriminarão as fontes e usos do Fundo criado por este artigo.", "ordem": 797}, {"id": 798, "artigo_id": 319, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º As parcelas de que tratam os incisos I, II, III e V serão previamente deduzidas da base de cálculo de qualquer vinculação ou participação constitucional ou legal, não se lhes aplicando o disposto nos artigos, 159, 212 e 239 da Constituição.", "ordem": 798}, {"id": 799, "artigo_id": 319, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º A parcela de que trata o inciso IV será previamente deduzida da base de cálculo das vinculações ou participações constitucionais previstas nos artigos 153, § 5º, 157, II, 212 e 239 da Constituição.", "ordem": 799}, {"id": 800, "artigo_id": 319, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º O disposto no parágrafo anterior não se aplica aos recursos previstos nos Artigos 158, II e 159 da Constituição.", "ordem": 800}, {"id": 801, "artigo_id": 319, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º A parcela dos recursos provenientes do imposto sobre renda e proventos de qualquer natureza, destinada ao Fundo Social de Emergência, nos termos do inciso II deste artigo, não poderá exceder a cinco inteiros e seis décimos por cento do total do produto da sua arrecadação.", "ordem": 801}, {"id": 802, "artigo_id": 321, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A alíquota da contribuição de que trata este artigo não excederá a vinte e cinco centésimos por cento, facultado ao Poder Executivo reduzi-la ou restabelecê-la, total ou parcialmente, nas condições e limites fixados em lei.", "ordem": 802}, {"id": 803, "artigo_id": 321, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A contribuição de que trata este artigo não se aplica o disposto nos arts. 153, § 5º, e 154, I, da Constituição.", "ordem": 803}, {"id": 804, "artigo_id": 321, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O produto da arrecadação da contribuição de que trata este artigo será destinado integralmente ao Fundo Nacional de Saúde, para financiamento das ações e serviços de saúde.", "ordem": 804}, {"id": 805, "artigo_id": 321, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º A contribuição de que trata este artigo terá sua exigibilidade subordinada ao disposto no art. 195, § 6º, da Constituição, e não poderá ser cobrada por prazo superior a dois anos.", "ordem": 805}, {"id": 806, "artigo_id": 322, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Observado o disposto no § 6º do art. 195 da Constituição Federal, a alíquota da contribuição será de trinta e oito centésimos por cento, nos primeiros doze meses, e de trinta centésimos, nos meses subseqüentes, facultado ao Poder Executivo reduzi-la total ou parcialmente, nos limites aqui definidos.", "ordem": 806}, {"id": 807, "artigo_id": 322, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O resultado do aumento da arrecadação, decorrente da alteração da alíquota, nos exercícios financeiros de 1999, 2000 e 2001, será destinado ao custeio da previdência social.", "ordem": 807}, {"id": 808, "artigo_id": 322, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º É a União autorizada a emitir títulos da dívida pública interna, cujos recursos serão destinados ao custeio da saúde e da previdência social, em montante equivalente ao produto da arrecadação da contribuição, prevista e não realizada em 1999.", "ordem": 808}, {"id": 809, "artigo_id": 323, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2° Excetua-se da desvinculação de que trata o caput a arrecadação da contribuição social do salário-educação a que se refere o § 5º do art. 212 da Constituição Federal ..", "ordem": 809}, {"id": 810, "artigo_id": 323, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º A desvinculação de que trata o caput não se aplica às receitas das contribuições sociais destinadas ao custeio da seguridade social.", "ordem": 810}, {"id": 811, "artigo_id": 323, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º A desvinculação de que trata ocaputdeste artigo não opera efeitos sobre recursos que, por expressa disposição em norma constitucional ou legal, devam ser transferidos a Estados, ao Distrito Federal e a Municípios.", "ordem": 811}, {"id": 812, "artigo_id": 323, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º A desvinculação de que trata ocaputdeste artigo não se aplica às receitas destinadas ao fundo criado pelo art. 47 da Lei nº 12.351, de 22 de dezembro de 2010, e aos recursos a que se refere o art. 2º da Lei nº 12.858, de 9 de setembro de 2013.", "ordem": 812}, {"id": 813, "artigo_id": 323, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Excetuam-se da desvinculação de que trata o caput: Produção de efeitos", "ordem": 813}, {"id": 814, "artigo_id": 323, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Excetuam-se das desvinculações de que trata o caput deste artigo:", "ordem": 814}, {"id": 815, "artigo_id": 323, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A cada exercício financeiro, até a data de que trata o caput deste artigo, poderão ser utilizados, exclusivamente para o financiamento de políticas públicas locais de saúde, educação e adaptação às mudanças climáticas, os superávits financeiros, verificados no exercício financeiro imediatamente anterior, dos fundos públicos instituídos pelo Poder Executivo municipal.", "ordem": 815}, {"id": 816, "artigo_id": 324, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Os Estados, o Distrito Federal e os Municípios que apliquem percentuais inferiores aos fixados nos incisos II e III deverão elevá-los gradualmente, até o exercício financeiro de 2004, reduzida a diferença à razão de, pelo menos, um quinto por ano, sendo que, a partir de 2000, a aplicação será de pelo menos sete por cento.", "ordem": 816}, {"id": 817, "artigo_id": 324, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Dos recursos da União apurados nos termos deste artigo, quinze por cento, no mínimo, serão aplicados nos Municípios, segundo o critério populacional, em ações e serviços básicos de saúde, na forma da lei.", "ordem": 817}, {"id": 818, "artigo_id": 324, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Os recursos dos Estados, do Distrito Federal e dos Municípios destinados às ações e serviços públicos de saúde e os transferidos pela União para a mesma finalidade serão aplicados por meio de Fundo de Saúde que será acompanhado e fiscalizado por Conselho de Saúde, sem prejuízo do disposto no art. 74 da Constituição Federal.", "ordem": 818}, {"id": 819, "artigo_id": 324, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Na ausência da lei complementar a que se refere o art. 198, § 3º, a partir do exercício financeiro de 2005, aplicar-se-á à União, aos Estados, ao Distrito Federal e aos Municípios o disposto neste artigo.", "ordem": 819}, {"id": 820, "artigo_id": 325, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º É permitida a decomposição de parcelas, a critério do credor.", "ordem": 820}, {"id": 821, "artigo_id": 325, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º As prestações anuais a que se refere o caput deste artigo terão, se não liquidadas até o final do exercício a que se referem, poder liberatório do pagamento de tributos da entidade devedora.", "ordem": 821}, {"id": 822, "artigo_id": 325, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O prazo referido no caput deste artigo fica reduzido para dois anos, nos casos de precatórios judiciais originários de desapropriação de imóvel residencial do credor, desde que comprovadamente único à época da imissão na posse.", "ordem": 822}, {"id": 823, "artigo_id": 325, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º O Presidente do Tribunal competente deverá, vencido o prazo ou em caso de omissão no orçamento, ou preterição ao direito de precedência, a requerimento do credor, requisitar ou determinar o seqüestro de recursos financeiros da entidade executada, suficientes à satisfação da prestação.", "ordem": 823}, {"id": 824, "artigo_id": 326, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. O Fundo previsto neste artigo terá Conselho Consultivo e de Acompanhamento que conte com a participação de representantes da sociedade civil, nos termos da lei.", "ordem": 824}, {"id": 825, "artigo_id": 327, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Aos recursos integrantes do Fundo de que trata este artigo não se aplica o disposto nos arts. 159 e 167, inciso IV, da Constituição, assim como qualquer desvinculação de recursos orçamentários.", "ordem": 825}, {"id": 826, "artigo_id": 327, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º A arrecadação decorrente do disposto no inciso I deste artigo, no período compreendido entre 18 de junho de 2000 e o início da vigência da lei complementar a que se refere a art. 79, será integralmente repassada ao Fundo, preservado o seu valor real, em títulos públicos federais, progressivamente resgatáveis após 18 de junho de 2002, na forma da lei.", "ordem": 826}, {"id": 827, "artigo_id": 328, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Caso o montante anual previsto nos rendimentos transferidos ao Fundo de Combate e Erradicação da Pobreza, na forma deste artigo, não alcance o valor de quatro bilhões de reais. far-se-à complementação na forma do art. 80, inciso IV, do Ato das disposições Constitucionais Transitórias.", "ordem": 827}, {"id": 828, "artigo_id": 328, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Sem prejuízo do disposto no § 1º, o Poder Executivo poderá destinar ao Fundo a que se refere este artigo outras receitas decorrentes da alienação de bens da União.", "ordem": 828}, {"id": 829, "artigo_id": 328, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º A constituição do Fundo a que se refere o caput, a transferência de recursos ao Fundo de Combate e Erradicação da Pobreza e as demais disposições referentes ao § 1º deste artigo serão disciplinadas em lei, não se aplicando o disposto no art. 165, § 9º, inciso II, da Constituição.", "ordem": 829}, {"id": 830, "artigo_id": 329, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Para o financiamento dos Fundos Estaduais e Distrital, poderá ser criado adicional de até dois pontos percentuais na alíquota do Imposto sobre Circulação de Mercadorias e Serviços - ICMS, sobre os produtos e serviços supérfluos e nas condições definidas na lei complementar de que trata o art. 155, § 2º, XII, da Constituição, não se aplicando, sobre este percentual, o disposto no art. 158, IV, da Constituição.", "ordem": 830}, {"id": 831, "artigo_id": 329, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Para o financiamento dos Fundos Municipais, poderá ser criado adicional de até meio ponto percentual na alíquota do Imposto sobre serviços ou do imposto que vier a substituí-lo, sobre serviços supérfluos. Vigência", "ordem": 831}, {"id": 832, "artigo_id": 331, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Fica prorrogada até a data referida no caput deste artigo, a vigência da Lei nº 9.311, de 24 de outubro de 1996 , e suas alterações.", "ordem": 832}, {"id": 833, "artigo_id": 331, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Do produto da arrecadação da contribuição social de que trata este artigo será destinada a parcela correspondente à alíquota de:", "ordem": 833}, {"id": 834, "artigo_id": 331, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º A alíquota da contribuição de que trata este artigo será de:", "ordem": 834}, {"id": 835, "artigo_id": 332, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O Poder Executivo disciplinará o disposto neste artigo no prazo de trinta dias da data de publicação desta Emenda Constitucional.", "ordem": 835}, {"id": 836, "artigo_id": 332, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O disposto no inciso I deste artigo aplica-se somente às operações relacionadas em ato do Poder Executivo, dentre aquelas que constituam o objeto social das referidas entidades.", "ordem": 836}, {"id": 837, "artigo_id": 332, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O disposto no inciso II deste artigo aplica-se somente a operações e contratos efetuados por intermédio de instituições financeiras, sociedades corretoras de títulos e valores mobiliários, sociedades distribuidoras de títulos e valores mobiliários e sociedades corretoras de mercadorias.", "ordem": 837}, {"id": 838, "artigo_id": 333, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Os débitos a que se refere o caput deste artigo, ou os respectivos saldos, serão pagos na ordem cronológica de apresentação dos respectivos precatórios, com precedência sobre os de maior valor.", "ordem": 838}, {"id": 839, "artigo_id": 333, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os débitos a que se refere o caput deste artigo, se ainda não tiverem sido objeto de pagamento parcial, nos termos do art. 78 deste Ato das Disposições Constitucionais Transitórias, poderão ser pagos em duas parcelas anuais, se assim dispuser a lei.", "ordem": 839}, {"id": 840, "artigo_id": 333, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Observada a ordem cronológica de sua apresentação, os débitos de natureza alimentícia previstos neste artigo terão precedência para pagamento sobre todos os demais.", "ordem": 840}, {"id": 841, "artigo_id": 334, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Se o valor da execução ultrapassar o estabelecido neste artigo, o pagamento far-se-á, sempre, por meio de precatório, sendo facultada à parte exeqüente a renúncia ao crédito do valor excedente, para que possa optar pelo pagamento do saldo sem o precatório, da forma prevista no § 3º do art. 100.", "ordem": 841}, {"id": 842, "artigo_id": 336, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Os membros da Polícia Militar continuarão prestando serviços ao Estado de Rondônia, na condição de cedidos, submetidos às corporações da Polícia Militar, observadas as atribuições de função compatíveis com o grau hierárquico.", "ordem": 842}, {"id": 843, "artigo_id": 336, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os servidores a que se refere o caput continuarão prestando serviços ao Estado de Rondônia na condição de cedidos, até seu aproveitamento em órgão ou entidade da administração federal direta, autárquica ou fundacional.", "ordem": 843}, {"id": 844, "artigo_id": 337, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Fica prorrogada, até a data referida no caput deste artigo, a vigência da Lei nº 9.311, de 24 de outubro de 1996 , e suas alterações.", "ordem": 844}, {"id": 845, "artigo_id": 337, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Até a data referida no caput deste artigo, a alíquota da contribuição de que trata o art. 84 deste Ato das Disposições Constitucionais Transitórias será de trinta e oito centésimos por cento.", "ordem": 845}, {"id": 846, "artigo_id": 338, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Para assegurar o disposto no caput, serão utilizados, isolada ou cumulativamente, instrumentos fiscais, econômicos ou financeiros.", "ordem": 846}, {"id": 847, "artigo_id": 338, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Lei complementar instituirá Fundo de Sustentabilidade e Diversificação Econômica do Estado do Amazonas, que será constituído com recursos da União e por ela gerido, com a efetiva participação do Estado do Amazonas na definição das políticas, com o objetivo de fomentar o desenvolvimento e a diversificação das atividades econômicas no Estado.", "ordem": 847}, {"id": 848, "artigo_id": 338, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º A lei complementar de que trata o § 2º:", "ordem": 848}, {"id": 849, "artigo_id": 338, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º A União, mediante acordo com o Estado do Amazonas, poderá reduzir o alcance dos instrumentos previstos no § 1º, condicionado ao aporte de recursos adicionais ao Fundo de que trata o § 2º, asseguradas a diversificação das atividades econômicas e a antecedência mínima de 3 (três) anos.", "ordem": 849}, {"id": 850, "artigo_id": 338, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Não se aplica aos mecanismos previstos no caput o disposto nos incisos III e IV do caput do art. 149-B da Constituição Federal.", "ordem": 850}, {"id": 851, "artigo_id": 338, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Lei complementar instituirá Fundo de Desenvolvimento Sustentável dos Estados da Amazônia Ocidental e do Amapá, que será constituído com recursos da União e por ela gerido, com a efetiva participação desses Estados na definição das políticas, com o objetivo de fomentar o desenvolvimento e a diversificação de suas atividades econômicas.", "ordem": 851}, {"id": 852, "artigo_id": 338, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º O Fundo de que trata o § 6º será integrado pelos Estados onde estão localizadas as áreas de livre comércio de que trata ocapute observará, no que couber, o disposto no § 3º, I e II, sendo, quanto a este inciso, considerados os respectivos Estados, e no § 4º.", "ordem": 852}, {"id": 853, "artigo_id": 343, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Os Estados, o Distrito Federal e os Municípios sujeitos ao regime especial de que trata este artigo optarão, por meio de ato do Poder Executivo:", "ordem": 853}, {"id": 854, "artigo_id": 343, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Para saldar os precatórios, vencidos e a vencer, pelo regime especial, os Estados, o Distrito Federal e os Municípios devedores depositarão mensalmente, em conta especial criada para tal fim, 1/12 (um doze avos) do valor calculado percentualmente sobre as respectivas receitas correntes líquidas, apuradas no segundo mês anterior ao mês de pagamento, sendo que esse percentual, calculado no momento de opção pelo regime e mantido fixo até o final do prazo a que se refere o § 14 deste artigo, será:", "ordem": 854}, {"id": 855, "artigo_id": 343, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Entende-se como receita corrente líquida, para os fins de que trata este artigo, o somatório das receitas tributárias, patrimoniais, industriais, agropecuárias, de contribuições e de serviços, transferências correntes e outras receitas correntes, incluindo as oriundas do § 1º do art. 20 da Constituição Federal, verificado no período compreendido pelo mês de referência e os 11 (onze) meses anteriores, excluídas as duplicidades, e deduzidas:", "ordem": 855}, {"id": 856, "artigo_id": 343, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º As contas especiais de que tratam os §§ 1º e 2º serão administradas pelo Tribunal de Justiça local, para pagamento de precatórios expedidos pelos tribunais.", "ordem": 856}, {"id": 857, "artigo_id": 343, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Os recursos depositados nas contas especiais de que tratam os §§ 1º e 2º deste artigo não poderão retornar para Estados, Distrito Federal e Municípios devedores.", "ordem": 857}, {"id": 858, "artigo_id": 343, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Pelo menos 50% (cinquenta por cento) dos recursos de que tratam os §§ 1º e 2º deste artigo serão utilizados para pagamento de precatórios em ordem cronológica de apresentação, respeitadas as preferências definidas no § 1º, para os requisitórios do mesmo ano e no § 2º do art. 100, para requisitórios de todos os anos.", "ordem": 858}, {"id": 859, "artigo_id": 343, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º Nos casos em que não se possa estabelecer a precedência cronológica entre 2 (dois) precatórios, pagar-se-á primeiramente o precatório de menor valor.", "ordem": 859}, {"id": 860, "artigo_id": 343, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º A aplicação dos recursos restantes dependerá de opção a ser exercida por Estados, Distrito Federal e Municípios devedores, por ato do Poder Executivo, obedecendo à seguinte forma, que poderá ser aplicada isoladamente ou simultaneamente:", "ordem": 860}, {"id": 861, "artigo_id": 343, "tipo": "numerado", "numero": 9, "numero_texto": "9º", "texto": "§ 9º Os leilões de que trata o inciso I do § 8º deste artigo:", "ordem": 861}, {"id": 862, "artigo_id": 344, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º No prazo de 8 (oito) anos, a União, os Estados e o Distrito Federal deverão contar com defensores públicos em todas as unidades jurisdicionais, observado o disposto no caput deste artigo.", "ordem": 862}, {"id": 863, "artigo_id": 344, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Durante o decurso do prazo previsto no § 1º deste artigo, a lotação dos defensores públicos ocorrerá, prioritariamente, atendendo as regiões com maiores índices de exclusão social e adensamento populacional.", "ordem": 863}, {"id": 864, "artigo_id": 347, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Entende-se como receita corrente líquida, para os fins de que trata este artigo, o somatório das receitas tributárias, patrimoniais, industriais, agropecuárias, de contribuições e de serviços, de transferências correntes e outras receitas correntes, incluindo as oriundas do § 1º do art. 20 da Constituição Federal, verificado no período compreendido pelo segundo mês imediatamente anterior ao de referência e os 11 (onze) meses precedentes, excluídas as duplicidades, e deduzidas:", "ordem": 864}, {"id": 865, "artigo_id": 347, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O débito de precatórios será pago com recursos orçamentários próprios provenientes das fontes de receita corrente líquida referidas no § 1º deste artigo e, adicionalmente, poderão ser utilizados recursos dos seguintes instrumentos:", "ordem": 865}, {"id": 866, "artigo_id": 347, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Os recursos adicionais previstos nos incisos I, II e IV do § 2º deste artigo serão transferidos diretamente pela instituição financeira depositária para a conta especial referida no caput deste artigo, sob única e exclusiva administração do Tribunal de Justiça local, e essa transferência deverá ser realizada em até sessenta dias contados a partir da entrada em vigor deste parágrafo, sob pena de responsabilização pessoal do dirigente da instituição financeira por improbidade.", "ordem": 866}, {"id": 867, "artigo_id": 347, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Os empréstimos de que trata o inciso III do § 2º deste artigo poderão ser destinados, por meio de ato do Poder Executivo, exclusivamente ao pagamento de precatórios por acordo direto com os credores, na forma do disposto no inciso III do § 8º do art. 97 deste Ato das Disposições Constitucionais Transitórias.", "ordem": 867}, {"id": 868, "artigo_id": 347, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Aplica-se ao regime de pagamento de precatórios descrito no caput deste artigo o disposto nos §§ 23 a 30 do art. 100 da Constituição Federal.", "ordem": 868}, {"id": 869, "artigo_id": 348, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º A aplicação dos recursos remanescentes, por opção a ser exercida por Estados, Distrito Federal e Municípios, por ato do respectivo Poder Executivo, observada a ordem de preferência dos credores, poderá ser destinada ao pagamento mediante acordos diretos, perante Juízos Auxiliares de Conciliação de Precatórios, com redução máxima de 40% (quarenta por cento) do valor do crédito atualizado, desde que em relação ao crédito não penda recurso ou defesa judicial e que sejam observados os requisitos definidos na regulamentação editada pelo ente federado. (Numerado do parágrafo único pela Emenda constitucional nº 99, de 2017)", "ordem": 869}, {"id": 870, "artigo_id": 348, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Na vigência do regime especial previsto no art. 101 deste Ato das Disposições Constitucionais Transitórias, as preferências relativas à idade, ao estado de saúde e à deficiência serão atendidas até o valor equivalente ao quíntuplo fixado em lei para os fins do disposto no § 3º do art. 100 da Constituição Federal, admitido o fracionamento para essa finalidade, e o restante será pago em ordem cronológica de apresentação do precatório.", "ordem": 870}, {"id": 871, "artigo_id": 349, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Na vigência do regime especial previsto no art. 101 deste Ato das Disposições Constitucionais Transitórias, ficam vedadas desapropriações pelos Estados, pelo Distrito Federal e pelos Municípios, cujos estoques de precatórios ainda pendentes de pagamento, incluídos os precatórios a pagar de suas entidades da administração indireta, sejam superiores a 70% (setenta por cento) das respectivas receitas correntes líquidas, excetuadas as desapropriações para fins de necessidade pública nas áreas de saúde, educação, segurança pública, transporte público, saneamento básico e habitação de interesse social.", "ordem": 871}, {"id": 872, "artigo_id": 350, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Enquanto perdurar a omissão, o ente federado não poderá contrair empréstimo externo ou interno, exceto para os fins previstos no § 2º do art. 101 deste Ato das Disposições Constitucionais Transitórias, e ficará impedido de receber transferências voluntárias.", "ordem": 872}, {"id": 873, "artigo_id": 351, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Não se aplica às compensações referidas no caput deste artigo qualquer tipo de vinculação, como as transferências a outros entes e as destinadas à educação, à saúde e a outras finalidades. (Numerado do parágrafo único pela Emenda constitucional nº 99, de 2017)", "ordem": 873}, {"id": 874, "artigo_id": 351, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os Estados, o Distrito Federal e os Municípios regulamentarão nas respectivas leis o disposto no caput deste artigo em até cento e vinte dias a partir de 1º de janeiro de 2018.", "ordem": 874}, {"id": 875, "artigo_id": 351, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Decorrido o prazo estabelecido no § 2º deste artigo sem a regulamentação nele prevista, ficam os credores de precatórios autorizados a exercer a faculdade a que se refere o caput deste artigo.", "ordem": 875}, {"id": 876, "artigo_id": 352, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O limite para o pagamento de precatórios corresponderá, em cada exercício, ao limite previsto no caput deste artigo, reduzido da projeção para a despesa com o pagamento de requisições de pequeno valor para o mesmo exercício, que terão prioridade no pagamento.", "ordem": 876}, {"id": 877, "artigo_id": 352, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os precatórios que não forem pagos em razão do previsto neste artigo terão prioridade para pagamento em exercícios seguintes, observada a ordem cronológica e o disposto no § 8º deste artigo.", "ordem": 877}, {"id": 878, "artigo_id": 352, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º É facultado ao credor de precatório que não tenha sido pago em razão do disposto neste artigo, além das hipóteses previstas no § 11 do art. 100 da Constituição Federal e sem prejuízo dos procedimentos previstos nos §§ 9º e 21 do referido artigo, optar pelo recebimento, mediante acordos diretos perante Juízos Auxiliares de Conciliação de Pagamento de Condenações Judiciais contra a Fazenda Pública Federal, em parcela única, até o final do exercício seguinte, com renúncia de 40% (quarenta por cento) do valor desse crédito.", "ordem": 878}, {"id": 879, "artigo_id": 352, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º O Conselho Nacional de Justiça regulamentará a atuação dos Presidentes dos Tribunais competentes para o cumprimento deste artigo.", "ordem": 879}, {"id": 880, "artigo_id": 352, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Não se incluem no limite estabelecido neste artigo as despesas para fins de cumprimento do disposto nos §§ 11, 20 e 21 do art. 100 da Constituição Federal e no § 3º deste artigo, bem como a atualização monetária dos precatórios inscritos no exercício.", "ordem": 880}, {"id": 881, "artigo_id": 352, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Não se incluem nos limites estabelecidos no art. 107 deste Ato das Disposições Constitucionais Transitórias o previsto nos §§ 11, 20 e 21 do art. 100 da Constituição Federal e no § 3º deste artigo.", "ordem": 881}, {"id": 882, "artigo_id": 352, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º Na situação prevista no § 3º deste artigo, para os precatórios não incluídos na proposta orçamentária de 2022, os valores necessários à sua quitação serão providenciados pela abertura de créditos adicionais durante o exercício de 2022.", "ordem": 882}, {"id": 883, "artigo_id": 352, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º Os pagamentos em virtude de sentença judiciária de que trata o art. 100 da Constituição Federal serão realizados na seguinte ordem:", "ordem": 883}, {"id": 884, "artigo_id": 354, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Ato do Ministério da Previdência Social, no âmbito de suas competências, definirá os critérios para o parcelamento previsto neste artigo, inclusive quanto ao cumprimento do disposto nos incisos I, II, III e IV do caput deste artigo e à adesão ao Programa de Regularidade Previdenciária, que contemplará prazos e condições diferenciados para o cumprimento das exigências do Certificado de Regularidade Previdenciária e para a busca do equilíbrio financeiro e atuarial dos regimes próprios, bem como disponibilizará as informações aos entes federativos subnacionais sobre o montante das dívidas, as formas de parcelamento, os juros e os encargos incidentes, de modo a possibilitar o acompanhamento da evolução desses débitos.", "ordem": 884}, {"id": 885, "artigo_id": 354, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º O ente federativo que não comprovar o atendimento das condições cumulativas previstas no caput deste artigo em até 15 (quinze) meses após a data da promulgação deste parágrafo terá seu parcelamento suspenso e não poderá renegociar a respectiva dívida até ulterior cumprimento das condições.", "ordem": 885}, {"id": 886, "artigo_id": 354, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O parcelamento será suspenso na hipótese de inadimplência por 3 (três) meses consecutivos ou por 6 (seis) meses alternados, relativa às contribuições previdenciárias referidas no caput deste artigo ou de descumprimento do Programa de Regularidade Previdenciária.", "ordem": 886}, {"id": 887, "artigo_id": 355, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Os Municípios que possuam regime próprio de previdência social deverão comprovar, para fins de continuidade do parcelamento com o Regime Geral de Previdência Social de que trata este artigo, ter atendido, até 1º de março de 2027, as condições estabelecidas nos incisos I, II, III e IV do caput do art. 115 deste Ato das Disposições Constitucionais Transitórias, sob pena de suspensão do parcelamento e de proibição de renegociação de suas respectivas dívidas até ulterior cumprimento das condições.", "ordem": 887}, {"id": 888, "artigo_id": 355, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os débitos parcelados terão redução de 40% (quarenta por cento) das multas de mora, de ofício e isoladas, de 80% (oitenta por cento) dos juros de mora, de 40% (quarenta por cento) dos encargos legais e de 25% (vinte e cinco por cento) dos honorários advocatícios.", "ordem": 888}, {"id": 889, "artigo_id": 355, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O valor de cada parcela será acrescido de atualização monetária e juros, acumulados mensalmente, calculados a partir do mês subsequente ao da consolidação até o mês anterior ao do pagamento, nos seguintes termos:", "ordem": 889}, {"id": 890, "artigo_id": 355, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Não constituem débitos dos Municípios aqueles considerados prescritos ou atingidos pela decadência.", "ordem": 890}, {"id": 891, "artigo_id": 355, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º A Secretaria Especial da Receita Federal do Brasil e a Procuradoria-Geral da Fazenda Nacional, no âmbito de suas competências, deverão fixar os critérios para o parcelamento previsto neste artigo, bem como disponibilizar as informações aos Municípios sobre o montante das dívidas, as formas de parcelamento, os juros e os encargos incidentes, de modo a possibilitar o acompanhamento da evolução desses débitos.", "ordem": 891}, {"id": 892, "artigo_id": 355, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º O parcelamento será excluído na hipótese de inadimplência por 3 (três) meses consecutivos ou por 6 (seis) meses alternados, relativa às contribuições previdenciárias referidas no caput deste artigo.", "ordem": 892}, {"id": 893, "artigo_id": 355, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º Em caso de exclusão por inadimplência, o Município ficará impedido de receber transferências voluntárias da União, inclusive de emendas parlamentares, enquanto perdurar a inadimplência.", "ordem": 893}, {"id": 894, "artigo_id": 355, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º O chefe do Poder Executivo do Município inadimplente responderá na forma da legislação de responsabilidade fiscal e de improbidade administrativa.", "ordem": 894}, {"id": 895, "artigo_id": 355, "tipo": "numerado", "numero": 9, "numero_texto": "9º", "texto": "§ 9º Não serão responsabilizados os Municípios e os respectivos chefes do Poder Executivo que demonstrarem que a inadimplência ocorreu por variações negativas inesperadas e significativas nas receitas ou por incremento nas despesas não decorrentes de decisões próprias do Município ou do respectivo chefe do Poder Executivo.", "ordem": 895}, {"id": 896, "artigo_id": 355, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Aplica-se ao refinanciamento de que trata este artigo o disposto nos §§ 2º, 3º, 4º, 5º e 6º do art. 116 deste Ato das Disposições Constitucionais Transitórias.", "ordem": 896}, {"id": 897, "artigo_id": 358, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Para efeitos do disposto no caput deste artigo, o ente deverá complementar na aplicação da manutenção e desenvolvimento do ensino, até o exercício financeiro de 2023, a diferença a menor entre o valor aplicado, conforme informação registrada no sistema integrado de planejamento e orçamento, e o valor mínimo exigível constitucionalmente para os exercícios de 2020 e 2021.", "ordem": 897}, {"id": 898, "artigo_id": 359, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Para enfretamento ou mitigação dos impactos decorrentes do estado de emergência reconhecido, as medidas implementadas, até os limites de despesas previstos em uma única e exclusiva norma constitucional observarão o seguinte:", "ordem": 898}, {"id": 899, "artigo_id": 360, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. Os valores referidos no caput deste artigo serão tidos por abandonados, nos termos do inciso III do caput do art. 1.275 da Lei nº 10.406, de 10 de janeiro de 2002 (Código Civil), e serão apropriados pelo Tesouro Nacional como receita primária para realização de despesas de investimento de que trata o § 6º-B do art. 107, que não serão computadas nos limites previstos no art. 107, ambos deste Ato das Disposições Constitucionais Transitórias, podendo o interessado reclamar ressarcimento à União no prazo de até 5 (cinco) anos do encerramento das contas.", "ordem": 899}, {"id": 900, "artigo_id": 363, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. A contribuição prevista no art. 195, V, será instituída pela mesma lei complementar de que trata o art. 156-A, ambos da Constituição Federal.", "ordem": 900}, {"id": 901, "artigo_id": 364, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O montante recolhido na forma do caput será compensado com o valor devido das contribuições previstas no art. 195, I, \"b\", e IV, e da contribuição para o Programa de Integração Social a que se refere o art. 239, ambos da Constituição Federal.", "ordem": 901}, {"id": 902, "artigo_id": 364, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Caso o contribuinte não possua débitos suficientes para efetuar a compensação de que trata o § 1º, o valor recolhido poderá ser compensado com qualquer outro tributo federal ou ser ressarcido em até 60 (sessenta) dias, mediante requerimento.", "ordem": 902}, {"id": 903, "artigo_id": 364, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º A arrecadação do imposto previsto no art. 156-A da Constituição Federal decorrente do disposto no caput deste artigo não observará as vinculações, repartições e destinações previstas na Constituição Federal, devendo ser aplicada, integral e sucessivamente, para:", "ordem": 903}, {"id": 904, "artigo_id": 364, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º Durante o período de que trata o caput, os sujeitos passivos que cumprirem as obrigações acessórias relativas aos tributos referidos no caput poderão ser dispensados do seu recolhimento, nos termos de lei complementar.", "ordem": 904}, {"id": 905, "artigo_id": 366, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. No período referido no caput, a alíquota da contribuição prevista no art. 195, V, da Constituição Federal, será reduzida em 0,1 (um décimo) ponto percentual.", "ordem": 905}, {"id": 906, "artigo_id": 367, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Os benefícios ou os incentivos fiscais ou financeiros relativos aos impostos previstos nos arts. 155, II, e 156, III, da Constituição Federal não alcançados pelo disposto no caput deste artigo serão reduzidos na mesma proporção.", "ordem": 906}, {"id": 907, "artigo_id": 367, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Os benefícios e incentivos fiscais ou financeiros referidos no art. 3º da Lei Complementar nº 160, de 7 de agosto de 2017, serão reduzidos na forma deste artigo, não se aplicando a redução prevista no § 2º-A do art. 3º da referida Lei Complementar.", "ordem": 907}, {"id": 908, "artigo_id": 367, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Ficam mantidos em sua integralidade, até 31 de dezembro de 2032, os percentuais utilizados para calcular os benefícios ou incentivos fiscais ou financeiros já reduzidos por força da redução das alíquotas, em decorrência do disposto no caput.", "ordem": 908}, {"id": 909, "artigo_id": 369, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º As alíquotas de referência serão fixadas no ano anterior ao de sua vigência, não se aplicando o disposto no art. 150, III, \"c\", da Constituição Federal, com base em cálculo realizado pelo Tribunal de Contas da União.", "ordem": 909}, {"id": 910, "artigo_id": 369, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Na fixação das alíquotas de referência, deverão ser considerados os efeitos sobre a arrecadação dos regimes específicos, diferenciados ou favorecidos e de qualquer outro regime que resulte em arrecadação menor do que a que seria obtida com a aplicação da alíquota padrão.", "ordem": 910}, {"id": 911, "artigo_id": 369, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Para fins do disposto nos §§ 4º a 6º, entende-se por:", "ordem": 911}, {"id": 912, "artigo_id": 369, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º A alíquota de referência da contribuição a que se refere o art. 195, V, da Constituição Federal será reduzida em 2030 caso a média da Receita-Base da União em 2027 e 2028 exceda o Teto de Referência da União.", "ordem": 912}, {"id": 913, "artigo_id": 369, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º As alíquotas de referência da contribuição a que se refere o art. 195, V, e do imposto a que se refere o art. 156-A, ambos da Constituição Federal, serão reduzidas em 2035 caso a média da Receita-Base Total entre 2029 e 2033 exceda o Teto de Referência Total.", "ordem": 913}, {"id": 914, "artigo_id": 369, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º As reduções de que tratam os §§ 4º e 5º serão:", "ordem": 914}, {"id": 915, "artigo_id": 369, "tipo": "numerado", "numero": 7, "numero_texto": "7º", "texto": "§ 7º A revisão das alíquotas de referência em função do disposto nos §§ 4º, 5º e 6º não implicará cobrança ou restituição de tributo relativo a anos anteriores ou transferência de recursos entre os entes federativos.", "ordem": 915}, {"id": 916, "artigo_id": 369, "tipo": "numerado", "numero": 8, "numero_texto": "8º", "texto": "§ 8º Os entes federativos e o Comitê Gestor do Imposto sobre Bens e Serviços fornecerão ao Tribunal de Contas da União as informações necessárias para o cálculo a que se referem os §§ 1º, 4º e 5º.", "ordem": 916}, {"id": 917, "artigo_id": 369, "tipo": "numerado", "numero": 9, "numero_texto": "9º", "texto": "§ 9º Nos cálculos das alíquotas de que trata o caput, deverá ser considerada a arrecadação dos tributos previstos nos arts. 156-A e 195, V, da Constituição Federal, cuja cobrança tenha sido iniciada antes dos períodos de que tratam os incisos I, II e III do caput.", "ordem": 917}, {"id": 918, "artigo_id": 370, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Serão retidos do produto da arrecadação do imposto de cada Estado, do Distrito Federal e de cada Município apurada com base nas alíquotas de referência de que trata o art. 130 deste Ato das Disposições Constitucionais Transitórias, nos termos dos arts. 149-C e 156-A, § 4º, II, e § 5º, I e IV, antes da aplicação do disposto no art. 158, IV, \"b\", todos da Constituição Federal:", "ordem": 918}, {"id": 919, "artigo_id": 370, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Na forma estabelecida em lei complementar, o montante retido nos termos do § 1º será distribuído entre os Estados, o Distrito Federal e os Municípios proporcionalmente à receita média de cada ente federativo, devendo ser consideradas:", "ordem": 919}, {"id": 920, "artigo_id": 370, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Não se aplica o disposto no art. 158, IV, \"b\", da Constituição Federal aos recursos distribuídos na forma do § 2º, I, deste artigo.", "ordem": 920}, {"id": 921, "artigo_id": 370, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º A parcela do produto da arrecadação do imposto não retida nos termos do § 1º, após a retenção de que trata o art. 132 deste Ato das Disposições Constitucionais Transitórias, será distribuída a cada Estado, ao Distrito Federal e a cada Município de acordo com os critérios da lei complementar de que trata o art. 156-A, § 5º, I, da Constituição Federal, nela computada a variação de alíquota fixada pelo ente em relação à de referência.", "ordem": 921}, {"id": 922, "artigo_id": 370, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º Os recursos de que trata este artigo serão distribuídos nos termos estabelecidos em lei complementar, aplicando-se o seguinte:", "ordem": 922}, {"id": 923, "artigo_id": 370, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Durante o período de que trata o caput deste artigo, é vedado aos Estados, ao Distrito Federal e aos Municípios fixar alíquotas próprias do imposto de que trata o art. 156-A da Constituição Federal inferiores às necessárias para garantir as retenções de que tratam o § 1º deste artigo e o art. 132 deste Ato das Disposições Constitucionais Transitórias.", "ordem": 923}, {"id": 924, "artigo_id": 371, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º Os recursos serão distribuídos, sequencial e sucessivamente, aos entes com as menores razões de que trata o caput, de maneira que, ao final da distribuição, para todos os entes que receberem recursos, seja observada a mesma a razão entre:", "ordem": 924}, {"id": 925, "artigo_id": 371, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Aplica-se aos recursos distribuídos na forma deste artigo o disposto no art. 131, § 5º deste Ato das Disposições Constitucionais Transitórias.", "ordem": 925}, {"id": 926, "artigo_id": 371, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º Lei complementar estabelecerá os critérios para a redução gradativa, entre 2078 e 2097, do percentual de que trata o caput, até a sua extinção.", "ordem": 926}, {"id": 927, "artigo_id": 373, "tipo": "numerado", "numero": 1, "numero_texto": "1º", "texto": "§ 1º O disposto neste artigo alcança os saldos credores cujos aproveitamento ou ressarcimento sejam admitidos pela legislação em vigor em 31 de dezembro de 2032 e que tenham sido homologados pelos respectivos entes federativos, observadas as seguintes diretrizes:", "ordem": 927}, {"id": 928, "artigo_id": 373, "tipo": "numerado", "numero": 2, "numero_texto": "2º", "texto": "§ 2º Aplica-se o disposto neste artigo também aos créditos reconhecidos após o prazo previsto no caput.", "ordem": 928}, {"id": 929, "artigo_id": 373, "tipo": "numerado", "numero": 3, "numero_texto": "3º", "texto": "§ 3º O saldo dos créditos homologados será informado pelos Estados e pelo Distrito Federal ao Comitê Gestor do Imposto sobre Bens e Serviços para que seja compensado com o imposto de que trata o art. 156-A da Constituição Federal:", "ordem": 929}, {"id": 930, "artigo_id": 373, "tipo": "numerado", "numero": 4, "numero_texto": "4º", "texto": "§ 4º O Comitê Gestor do Imposto sobre Bens e Serviços deduzirá do produto da arrecadação do imposto previsto no art. 156-A devido ao respectivo ente federativo o valor compensado na forma do § 3º, o qual não comporá base de cálculo para fins do disposto nos arts. 158, IV, 198, § 2º, 204, parágrafo único, 212, 212-A, II, e 216, § 6º, todos da Constituição Federal.", "ordem": 930}, {"id": 931, "artigo_id": 373, "tipo": "numerado", "numero": 5, "numero_texto": "5º", "texto": "§ 5º A partir de 2033, os saldos credores serão atualizados pelo IPCA ou por outro índice que venha a substituí-lo.", "ordem": 931}, {"id": 932, "artigo_id": 373, "tipo": "numerado", "numero": 6, "numero_texto": "6º", "texto": "§ 6º Lei complementar disporá sobre:", "ordem": 932}, {"id": 933, "artigo_id": 375, "tipo": "unico", "numero": null, "numero_texto": "único", "texto": "Parágrafo único. As receitas das contribuições mantidas nos termos deste artigo não serão consideradas como receita do respectivo Estado para fins do disposto nos arts. 130, II, \"b\", e 131, § 2º, I, \"b\", deste Ato das Disposições Constitucionais Transitórias.", "ordem": 933}]
  const INCISOS = [{"id": 1, "artigo_id": 1, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - a soberania;", "ordem": 1}, {"id": 2, "artigo_id": 1, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - a cidadania;", "ordem": 2}, {"id": 3, "artigo_id": 1, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - a dignidade da pessoa humana;", "ordem": 3}, {"id": 4, "artigo_id": 1, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - os valores sociais do trabalho e da livre iniciativa;", "ordem": 4}, {"id": 5, "artigo_id": 1, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - o pluralismo político.", "ordem": 5}, {"id": 6, "artigo_id": 3, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - construir uma sociedade livre, justa e solidária;", "ordem": 6}, {"id": 7, "artigo_id": 3, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - garantir o desenvolvimento nacional;", "ordem": 7}, {"id": 8, "artigo_id": 3, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - erradicar a pobreza e a marginalização e reduzir as desigualdades sociais e regionais;", "ordem": 8}, {"id": 9, "artigo_id": 3, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - promover o bem de todos, sem preconceitos de origem, raça, sexo, cor, idade e quaisquer outras formas de discriminação.", "ordem": 9}, {"id": 10, "artigo_id": 4, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - independência nacional;", "ordem": 10}, {"id": 11, "artigo_id": 4, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - prevalência dos direitos humanos;", "ordem": 11}, {"id": 12, "artigo_id": 4, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - autodeterminação dos povos;", "ordem": 12}, {"id": 13, "artigo_id": 4, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - não-intervenção;", "ordem": 13}, {"id": 14, "artigo_id": 4, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - igualdade entre os Estados;", "ordem": 14}, {"id": 15, "artigo_id": 4, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - defesa da paz;", "ordem": 15}, {"id": 16, "artigo_id": 4, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - solução pacífica dos conflitos;", "ordem": 16}, {"id": 17, "artigo_id": 4, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - repúdio ao terrorismo e ao racismo;", "ordem": 17}, {"id": 18, "artigo_id": 4, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - cooperação entre os povos para o progresso da humanidade;", "ordem": 18}, {"id": 19, "artigo_id": 4, "paragrafo_id": null, "numero_romano": "X", "numero_int": 10, "texto": "X - concessão de asilo político.", "ordem": 19}, {"id": 20, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - homens e mulheres são iguais em direitos e obrigações, nos termos desta Constituição;", "ordem": 20}, {"id": 21, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - ninguém será obrigado a fazer ou deixar de fazer alguma coisa senão em virtude de lei;", "ordem": 21}, {"id": 22, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - ninguém será submetido a tortura nem a tratamento desumano ou degradante;", "ordem": 22}, {"id": 23, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - é livre a manifestação do pensamento, sendo vedado o anonimato;", "ordem": 23}, {"id": 24, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - é assegurado o direito de resposta, proporcional ao agravo, além da indenização por dano material, moral ou à imagem;", "ordem": 24}, {"id": 25, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - é inviolável a liberdade de consciência e de crença, sendo assegurado o livre exercício dos cultos religiosos e garantida, na forma da lei, a proteção aos locais de culto e a suas liturgias;", "ordem": 25}, {"id": 26, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - é assegurada, nos termos da lei, a prestação de assistência religiosa nas entidades civis e militares de internação coletiva;", "ordem": 26}, {"id": 27, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - ninguém será privado de direitos por motivo de crença religiosa ou de convicção filosófica ou política, salvo se as invocar para eximir-se de obrigação legal a todos imposta e recusar-se a cumprir prestação alternativa, fixada em lei;", "ordem": 27}, {"id": 28, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - é livre a expressão da atividade intelectual, artística, científica e de comunicação, independentemente de censura ou licença;", "ordem": 28}, {"id": 29, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "X", "numero_int": 10, "texto": "X - são invioláveis a intimidade, a vida privada, a honra e a imagem das pessoas, assegurado o direito a indenização pelo dano material ou moral decorrente de sua violação;", "ordem": 29}, {"id": 30, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XI", "numero_int": 11, "texto": "XI - a casa é asilo inviolável do indivíduo, ninguém nela podendo penetrar sem consentimento do morador, salvo em caso de flagrante delito ou desastre, ou para prestar socorro, ou, durante o dia, por determinação judicial; (Vigência)", "ordem": 30}, {"id": 31, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XII", "numero_int": 12, "texto": "XII - é inviolável o sigilo da correspondência e das comunicações telegráficas, de dados e das comunicações telefônicas, salvo, no último caso, por ordem judicial, nas hipóteses e na forma que a lei estabelecer para fins de investigação criminal ou instrução processual penal;", "ordem": 31}, {"id": 32, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XIII", "numero_int": 13, "texto": "XIII - é livre o exercício de qualquer trabalho, ofício ou profissão, atendidas as qualificações profissionais que a lei estabelecer;", "ordem": 32}, {"id": 33, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XIV", "numero_int": 14, "texto": "XIV - é assegurado a todos o acesso à informação e resguardado o sigilo da fonte, quando necessário ao exercício profissional;", "ordem": 33}, {"id": 34, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XV", "numero_int": 15, "texto": "XV - é livre a locomoção no território nacional em tempo de paz, podendo qualquer pessoa, nos termos da lei, nele entrar, permanecer ou dele sair com seus bens;", "ordem": 34}, {"id": 35, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XVI", "numero_int": 16, "texto": "XVI - todos podem reunir-se pacificamente, sem armas, em locais abertos ao público, independentemente de autorização, desde que não frustrem outra reunião anteriormente convocada para o mesmo local, sendo apenas exigido prévio aviso à autoridade competente;", "ordem": 35}, {"id": 36, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XVII", "numero_int": 17, "texto": "XVII - é plena a liberdade de associação para fins lícitos, vedada a de caráter paramilitar;", "ordem": 36}, {"id": 37, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XVIII", "numero_int": 18, "texto": "XVIII - a criação de associações e, na forma da lei, a de cooperativas independem de autorização, sendo vedada a interferência estatal em seu funcionamento;", "ordem": 37}, {"id": 38, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XIX", "numero_int": 19, "texto": "XIX - as associações só poderão ser compulsoriamente dissolvidas ou ter suas atividades suspensas por decisão judicial, exigindo-se, no primeiro caso, o trânsito em julgado;", "ordem": 38}, {"id": 39, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XX", "numero_int": 20, "texto": "XX - ninguém poderá ser compelido a associar-se ou a permanecer associado;", "ordem": 39}, {"id": 40, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XXI", "numero_int": 21, "texto": "XXI - as entidades associativas, quando expressamente autorizadas, têm legitimidade para representar seus filiados judicial ou extrajudicialmente;", "ordem": 40}, {"id": 41, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XXII", "numero_int": 22, "texto": "XXII - é garantido o direito de propriedade;", "ordem": 41}, {"id": 42, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XXIII", "numero_int": 23, "texto": "XXIII - a propriedade atenderá a sua função social;", "ordem": 42}, {"id": 43, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XXIV", "numero_int": 24, "texto": "XXIV - a lei estabelecerá o procedimento para desapropriação por necessidade ou utilidade pública, ou por interesse social, mediante justa e prévia indenização em dinheiro, ressalvados os casos previstos nesta Constituição;", "ordem": 43}, {"id": 44, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XXV", "numero_int": 25, "texto": "XXV - no caso de iminente perigo público, a autoridade competente poderá usar de propriedade particular, assegurada ao proprietário indenização ulterior, se houver dano;", "ordem": 44}, {"id": 45, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XXVI", "numero_int": 26, "texto": "XXVI - a pequena propriedade rural, assim definida em lei, desde que trabalhada pela família, não será objeto de penhora para pagamento de débitos decorrentes de sua atividade produtiva, dispondo a lei sobre os meios de financiar o seu desenvolvimento;", "ordem": 45}, {"id": 46, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XXVII", "numero_int": 27, "texto": "XXVII - aos autores pertence o direito exclusivo de utilização, publicação ou reprodução de suas obras, transmissível aos herdeiros pelo tempo que a lei fixar;", "ordem": 46}, {"id": 47, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XXVIII", "numero_int": 28, "texto": "XXVIII - são assegurados, nos termos da lei:", "ordem": 47}, {"id": 48, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XXIX", "numero_int": 29, "texto": "XXIX - a lei assegurará aos autores de inventos industriais privilégio temporário para sua utilização, bem como proteção às criações industriais, à propriedade das marcas, aos nomes de empresas e a outros signos distintivos, tendo em vista o interesse social e o desenvolvimento tecnológico e econômico do País;", "ordem": 48}, {"id": 49, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XXX", "numero_int": 30, "texto": "XXX - é garantido o direito de herança;", "ordem": 49}, {"id": 50, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XXXI", "numero_int": 31, "texto": "XXXI - a sucessão de bens de estrangeiros situados no País será regulada pela lei brasileira em benefício do cônjuge ou dos filhos brasileiros, sempre que não lhes seja mais favorável a lei pessoal do \"de cujus\";", "ordem": 50}, {"id": 51, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XXXII", "numero_int": 32, "texto": "XXXII - o Estado promoverá, na forma da lei, a defesa do consumidor;", "ordem": 51}, {"id": 52, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XXXIII", "numero_int": 33, "texto": "XXXIII - todos têm direito a receber dos órgãos públicos informações de seu interesse particular, ou de interesse coletivo ou geral, que serão prestadas no prazo da lei, sob pena de responsabilidade, ressalvadas aquelas cujo sigilo seja imprescindível à segurança da sociedade e do Estado; (Regulamento)", "ordem": 52}, {"id": 53, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XXXIV", "numero_int": 34, "texto": "XXXIV - são a todos assegurados, independentemente do pagamento de taxas:", "ordem": 53}, {"id": 54, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XXXV", "numero_int": 35, "texto": "XXXV - a lei não excluirá da apreciação do Poder Judiciário lesão ou ameaça a direito;", "ordem": 54}, {"id": 55, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XXXVI", "numero_int": 36, "texto": "XXXVI - a lei não prejudicará o direito adquirido, o ato jurídico perfeito e a coisa julgada;", "ordem": 55}, {"id": 56, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XXXVII", "numero_int": 37, "texto": "XXXVII - não haverá juízo ou tribunal de exceção;", "ordem": 56}, {"id": 57, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XXXVIII", "numero_int": 38, "texto": "XXXVIII - é reconhecida a instituição do júri, com a organização que lhe der a lei, assegurados:", "ordem": 57}, {"id": 58, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XXXIX", "numero_int": 39, "texto": "XXXIX - não há crime sem lei anterior que o defina, nem pena sem prévia cominação legal;", "ordem": 58}, {"id": 59, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XL", "numero_int": 40, "texto": "XL - a lei penal não retroagirá, salvo para beneficiar o réu;", "ordem": 59}, {"id": 60, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XLI", "numero_int": 41, "texto": "XLI - a lei punirá qualquer discriminação atentatória dos direitos e liberdades fundamentais;", "ordem": 60}, {"id": 61, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XLII", "numero_int": 42, "texto": "XLII - a prática do racismo constitui crime inafiançável e imprescritível, sujeito à pena de reclusão, nos termos da lei;", "ordem": 61}, {"id": 62, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XLIII", "numero_int": 43, "texto": "XLIII - a lei considerará crimes inafiançáveis e insuscetíveis de graça ou anistia a prática da tortura , o tráfico ilícito de entorpecentes e drogas afins, o terrorismo e os definidos como crimes hediondos, por eles respondendo os mandantes, os executores e os que, podendo evitá-los, se omitirem; (Regulamento)", "ordem": 62}, {"id": 63, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XLIV", "numero_int": 44, "texto": "XLIV - constitui crime inafiançável e imprescritível a ação de grupos armados, civis ou militares, contra a ordem constitucional e o Estado Democrático;", "ordem": 63}, {"id": 64, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XLV", "numero_int": 45, "texto": "XLV - nenhuma pena passará da pessoa do condenado, podendo a obrigação de reparar o dano e a decretação do perdimento de bens ser, nos termos da lei, estendidas aos sucessores e contra eles executadas, até o limite do valor do patrimônio transferido;", "ordem": 64}, {"id": 65, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XLVI", "numero_int": 46, "texto": "XLVI - a lei regulará a individualização da pena e adotará, entre outras, as seguintes:", "ordem": 65}, {"id": 66, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XLVII", "numero_int": 47, "texto": "XLVII - não haverá penas:", "ordem": 66}, {"id": 67, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XLVIII", "numero_int": 48, "texto": "XLVIII - a pena será cumprida em estabelecimentos distintos, de acordo com a natureza do delito, a idade e o sexo do apenado;", "ordem": 67}, {"id": 68, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "XLIX", "numero_int": 49, "texto": "XLIX - é assegurado aos presos o respeito à integridade física e moral;", "ordem": 68}, {"id": 69, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "L", "numero_int": 50, "texto": "L - às presidiárias serão asseguradas condições para que possam permanecer com seus filhos durante o período de amamentação;", "ordem": 69}, {"id": 70, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LI", "numero_int": 51, "texto": "LI - nenhum brasileiro será extraditado, salvo o naturalizado, em caso de crime comum, praticado antes da naturalização, ou de comprovado envolvimento em tráfico ilícito de entorpecentes e drogas afins, na forma da lei;", "ordem": 70}, {"id": 71, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LII", "numero_int": 52, "texto": "LII - não será concedida extradição de estrangeiro por crime político ou de opinião;", "ordem": 71}, {"id": 72, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LIII", "numero_int": 53, "texto": "LIII - ninguém será processado nem sentenciado senão pela autoridade competente;", "ordem": 72}, {"id": 73, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LIV", "numero_int": 54, "texto": "LIV - ninguém será privado da liberdade ou de seus bens sem o devido processo legal;", "ordem": 73}, {"id": 74, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LV", "numero_int": 55, "texto": "LV - aos litigantes, em processo judicial ou administrativo, e aos acusados em geral são assegurados o contraditório e ampla defesa, com os meios e recursos a ela inerentes;", "ordem": 74}, {"id": 75, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LVI", "numero_int": 56, "texto": "LVI - são inadmissíveis, no processo, as provas obtidas por meios ilícitos;", "ordem": 75}, {"id": 76, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LVII", "numero_int": 57, "texto": "LVII - ninguém será considerado culpado até o trânsito em julgado de sentença penal condenatória;", "ordem": 76}, {"id": 77, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LVIII", "numero_int": 58, "texto": "LVIII - o civilmente identificado não será submetido a identificação criminal, salvo nas hipóteses previstas em lei; (Regulamento)", "ordem": 77}, {"id": 78, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LIX", "numero_int": 59, "texto": "LIX - será admitida ação privada nos crimes de ação pública, se esta não for intentada no prazo legal;", "ordem": 78}, {"id": 79, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LX", "numero_int": 60, "texto": "LX - a lei só poderá restringir a publicidade dos atos processuais quando a defesa da intimidade ou o interesse social o exigirem;", "ordem": 79}, {"id": 80, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LXI", "numero_int": 61, "texto": "LXI - ninguém será preso senão em flagrante delito ou por ordem escrita e fundamentada de autoridade judiciária competente, salvo nos casos de transgressão militar ou crime propriamente militar, definidos em lei;", "ordem": 80}, {"id": 81, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LXII", "numero_int": 62, "texto": "LXII - a prisão de qualquer pessoa e o local onde se encontre serão comunicados imediatamente ao juiz competente e à família do preso ou à pessoa por ele indicada;", "ordem": 81}, {"id": 82, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LXIII", "numero_int": 63, "texto": "LXIII - o preso será informado de seus direitos, entre os quais o de permanecer calado, sendo-lhe assegurada a assistência da família e de advogado;", "ordem": 82}, {"id": 83, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LXIV", "numero_int": 64, "texto": "LXIV - o preso tem direito à identificação dos responsáveis por sua prisão ou por seu interrogatório policial;", "ordem": 83}, {"id": 84, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LXV", "numero_int": 65, "texto": "LXV - a prisão ilegal será imediatamente relaxada pela autoridade judiciária;", "ordem": 84}, {"id": 85, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LXVI", "numero_int": 66, "texto": "LXVI - ninguém será levado à prisão ou nela mantido, quando a lei admitir a liberdade provisória, com ou sem fiança;", "ordem": 85}, {"id": 86, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LXVII", "numero_int": 67, "texto": "LXVII - não haverá prisão civil por dívida, salvo a do responsável pelo inadimplemento voluntário e inescusável de obrigação alimentícia e a do depositário infiel;", "ordem": 86}, {"id": 87, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LXVIII", "numero_int": 68, "texto": "LXVIII - conceder-se-á \"habeas-corpus\" sempre que alguém sofrer ou se achar ameaçado de sofrer violência ou coação em sua liberdade de locomoção, por ilegalidade ou abuso de poder;", "ordem": 87}, {"id": 88, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LXIX", "numero_int": 69, "texto": "LXIX - conceder-se-á mandado de segurança para proteger direito líquido e certo, não amparado por \"habeas-corpus\" ou \"habeas-data\", quando o responsável pela ilegalidade ou abuso de poder for autoridade pública ou agente de pessoa jurídica no exercício de atribuições do Poder Público;", "ordem": 88}, {"id": 89, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LXX", "numero_int": 70, "texto": "LXX - o mandado de segurança coletivo pode ser impetrado por:", "ordem": 89}, {"id": 90, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LXXI", "numero_int": 71, "texto": "LXXI - conceder-se-á mandado de injunção sempre que a falta de norma regulamentadora torne inviável o exercício dos direitos e liberdades constitucionais e das prerrogativas inerentes à nacionalidade, à soberania e à cidadania;", "ordem": 90}, {"id": 91, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LXXII", "numero_int": 72, "texto": "LXXII - conceder-se-á \"habeas-data\":", "ordem": 91}, {"id": 92, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LXXIII", "numero_int": 73, "texto": "LXXIII - qualquer cidadão é parte legítima para propor ação popular que vise a anular ato lesivo ao patrimônio público ou de entidade de que o Estado participe, à moralidade administrativa, ao meio ambiente e ao patrimônio histórico e cultural, ficando o autor, salvo comprovada má-fé, isento de custas judiciais e do ônus da sucumbência;", "ordem": 92}, {"id": 93, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LXXIV", "numero_int": 74, "texto": "LXXIV - o Estado prestará assistência jurídica integral e gratuita aos que comprovarem insuficiência de recursos;", "ordem": 93}, {"id": 94, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LXXV", "numero_int": 75, "texto": "LXXV - o Estado indenizará o condenado por erro judiciário, assim como o que ficar preso além do tempo fixado na sentença;", "ordem": 94}, {"id": 95, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LXXVI", "numero_int": 76, "texto": "LXXVI - são gratuitos para os reconhecidamente pobres, na forma da lei:", "ordem": 95}, {"id": 96, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LXXVII", "numero_int": 77, "texto": "LXXVII - são gratuitas as ações de \"habeas-corpus\" e \"habeas-data\", e, na forma da lei, os atos necessários ao exercício da cidadania. (Regulamento)", "ordem": 96}, {"id": 97, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LXXVIII", "numero_int": 78, "texto": "LXXVIII - a todos, no âmbito judicial e administrativo, são assegurados a razoável duração do processo e os meios que garantam a celeridade de sua tramitação.", "ordem": 97}, {"id": 98, "artigo_id": 5, "paragrafo_id": null, "numero_romano": "LXXIX", "numero_int": 79, "texto": "LXXIX - é assegurado, nos termos da lei, o direito à proteção dos dados pessoais, inclusive nos meios digitais.", "ordem": 98}, {"id": 99, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - relação de emprego protegida contra despedida arbitrária ou sem justa causa, nos termos de lei complementar, que preverá indenização compensatória, dentre outros direitos;", "ordem": 99}, {"id": 100, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - seguro-desemprego, em caso de desemprego involuntário;", "ordem": 100}, {"id": 101, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - fundo de garantia do tempo de serviço;", "ordem": 101}, {"id": 102, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - salário mínimo, fixado em lei, nacionalmente unificado, capaz de atender a suas necessidades vitais básicas e às de sua família com moradia, alimentação, educação, saúde, lazer, vestuário, higiene, transporte e previdência social, com reajustes periódicos que lhe preservem o poder aquisitivo, sendo vedada sua vinculação para qualquer fim;", "ordem": 102}, {"id": 103, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - piso salarial proporcional à extensão e à complexidade do trabalho;", "ordem": 103}, {"id": 104, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - irredutibilidade do salário, salvo o disposto em convenção ou acordo coletivo;", "ordem": 104}, {"id": 105, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - garantia de salário, nunca inferior ao mínimo, para os que percebem remuneração variável;", "ordem": 105}, {"id": 106, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - décimo terceiro salário com base na remuneração integral ou no valor da aposentadoria;", "ordem": 106}, {"id": 107, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - remuneração do trabalho noturno superior à do diurno;", "ordem": 107}, {"id": 108, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "X", "numero_int": 10, "texto": "X - proteção do salário na forma da lei, constituindo crime sua retenção dolosa;", "ordem": 108}, {"id": 109, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "XI", "numero_int": 11, "texto": "XI - participação nos lucros, ou resultados, desvinculada da remuneração, e, excepcionalmente, participação na gestão da empresa, conforme definido em lei;", "ordem": 109}, {"id": 110, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "XII", "numero_int": 12, "texto": "XII - salário-família pago em razão do dependente do trabalhador de baixa renda nos termos da lei;", "ordem": 110}, {"id": 111, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "XIII", "numero_int": 13, "texto": "XIII - duração do trabalho normal não superior a oito horas diárias e quarenta e quatro semanais, facultada a compensação de horários e a redução da jornada, mediante acordo ou convenção coletiva de trabalho;", "ordem": 111}, {"id": 112, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "XIV", "numero_int": 14, "texto": "XIV - jornada de seis horas para o trabalho realizado em turnos ininterruptos de revezamento, salvo negociação coletiva;", "ordem": 112}, {"id": 113, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "XV", "numero_int": 15, "texto": "XV - repouso semanal remunerado, preferencialmente aos domingos;", "ordem": 113}, {"id": 114, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "XVI", "numero_int": 16, "texto": "XVI - remuneração do serviço extraordinário superior, no mínimo, em cinqüenta por cento à do normal;", "ordem": 114}, {"id": 115, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "XVII", "numero_int": 17, "texto": "XVII - gozo de férias anuais remuneradas com, pelo menos, um terço a mais do que o salário normal;", "ordem": 115}, {"id": 116, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "XVIII", "numero_int": 18, "texto": "XVIII - licença à gestante, sem prejuízo do emprego e do salário, com a duração de cento e vinte dias;", "ordem": 116}, {"id": 117, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "XIX", "numero_int": 19, "texto": "XIX - licença-paternidade, nos termos fixados em lei;", "ordem": 117}, {"id": 118, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "XX", "numero_int": 20, "texto": "XX - proteção do mercado de trabalho da mulher, mediante incentivos específicos, nos termos da lei;", "ordem": 118}, {"id": 119, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "XXI", "numero_int": 21, "texto": "XXI - aviso prévio proporcional ao tempo de serviço, sendo no mínimo de trinta dias, nos termos da lei;", "ordem": 119}, {"id": 120, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "XXII", "numero_int": 22, "texto": "XXII - redução dos riscos inerentes ao trabalho, por meio de normas de saúde, higiene e segurança;", "ordem": 120}, {"id": 121, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "XXIII", "numero_int": 23, "texto": "XXIII - adicional de remuneração para as atividades penosas, insalubres ou perigosas, na forma da lei;", "ordem": 121}, {"id": 122, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "XXIV", "numero_int": 24, "texto": "XXIV - aposentadoria;", "ordem": 122}, {"id": 123, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "XXV", "numero_int": 25, "texto": "XXV - assistência gratuita aos filhos e dependentes desde o nascimento até 5 (cinco) anos de idade em creches e pré-escolas;", "ordem": 123}, {"id": 124, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "XXVI", "numero_int": 26, "texto": "XXVI - reconhecimento das convenções e acordos coletivos de trabalho;", "ordem": 124}, {"id": 125, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "XXVII", "numero_int": 27, "texto": "XXVII - proteção em face da automação, na forma da lei;", "ordem": 125}, {"id": 126, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "XXVIII", "numero_int": 28, "texto": "XXVIII - seguro contra acidentes de trabalho, a cargo do empregador, sem excluir a indenização a que este está obrigado, quando incorrer em dolo ou culpa;", "ordem": 126}, {"id": 127, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "XXIX", "numero_int": 29, "texto": "XXIX - ação, quanto aos créditos resultantes das relações de trabalho, com prazo prescricional de cinco anos para os trabalhadores urbanos e rurais, até o limite de dois anos após a extinção do contrato de trabalho;", "ordem": 127}, {"id": 128, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "XXX", "numero_int": 30, "texto": "XXX - proibição de diferença de salários, de exercício de funções e de critério de admissão por motivo de sexo, idade, cor ou estado civil;", "ordem": 128}, {"id": 129, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "XXXI", "numero_int": 31, "texto": "XXXI - proibição de qualquer discriminação no tocante a salário e critérios de admissão do trabalhador portador de deficiência;", "ordem": 129}, {"id": 130, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "XXXII", "numero_int": 32, "texto": "XXXII - proibição de distinção entre trabalho manual, técnico e intelectual ou entre os profissionais respectivos;", "ordem": 130}, {"id": 131, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "XXXIII", "numero_int": 33, "texto": "XXXIII - proibição de trabalho noturno, perigoso ou insalubre a menores de dezoito e de qualquer trabalho a menores de dezesseis anos, salvo na condição de aprendiz, a partir de quatorze anos;", "ordem": 131}, {"id": 132, "artigo_id": 7, "paragrafo_id": null, "numero_romano": "XXXIV", "numero_int": 34, "texto": "XXXIV - igualdade de direitos entre o trabalhador com vínculo empregatício permanente e o trabalhador avulso", "ordem": 132}, {"id": 133, "artigo_id": 8, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - a lei não poderá exigir autorização do Estado para a fundação de sindicato, ressalvado o registro no órgão competente, vedadas ao Poder Público a interferência e a intervenção na organização sindical;", "ordem": 133}, {"id": 134, "artigo_id": 8, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - é vedada a criação de mais de uma organização sindical, em qualquer grau, representativa de categoria profissional ou econômica, na mesma base territorial, que será definida pelos trabalhadores ou empregadores interessados, não podendo ser inferior à área de um Município;", "ordem": 134}, {"id": 135, "artigo_id": 8, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - ao sindicato cabe a defesa dos direitos e interesses coletivos ou individuais da categoria, inclusive em questões judiciais ou administrativas;", "ordem": 135}, {"id": 136, "artigo_id": 8, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - a assembléia geral fixará a contribuição que, em se tratando de categoria profissional, será descontada em folha, para custeio do sistema confederativo da representação sindical respectiva, independentemente da contribuição prevista em lei;", "ordem": 136}, {"id": 137, "artigo_id": 8, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - ninguém será obrigado a filiar-se ou a manter-se filiado a sindicato;", "ordem": 137}, {"id": 138, "artigo_id": 8, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - é obrigatória a participação dos sindicatos nas negociações coletivas de trabalho;", "ordem": 138}, {"id": 139, "artigo_id": 8, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - o aposentado filiado tem direito a votar e ser votado nas organizações sindicais;", "ordem": 139}, {"id": 140, "artigo_id": 8, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - é vedada a dispensa do empregado sindicalizado a partir do registro da candidatura a cargo de direção ou representação sindical e, se eleito, ainda que suplente, até um ano após o final do mandato, salvo se cometer falta grave nos termos da lei.", "ordem": 140}, {"id": 141, "artigo_id": 12, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - natos:", "ordem": 141}, {"id": 142, "artigo_id": 12, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - naturalizados:", "ordem": 142}, {"id": 143, "artigo_id": 12, "paragrafo_id": 14, "numero_romano": "I", "numero_int": 1, "texto": "I - de Presidente e Vice-Presidente da República;", "ordem": 143}, {"id": 144, "artigo_id": 12, "paragrafo_id": 14, "numero_romano": "II", "numero_int": 2, "texto": "II - de Presidente da Câmara dos Deputados;", "ordem": 144}, {"id": 145, "artigo_id": 12, "paragrafo_id": 14, "numero_romano": "III", "numero_int": 3, "texto": "III - de Presidente do Senado Federal;", "ordem": 145}, {"id": 146, "artigo_id": 12, "paragrafo_id": 14, "numero_romano": "IV", "numero_int": 4, "texto": "IV - de Ministro do Supremo Tribunal Federal;", "ordem": 146}, {"id": 147, "artigo_id": 12, "paragrafo_id": 14, "numero_romano": "V", "numero_int": 5, "texto": "V - da carreira diplomática;", "ordem": 147}, {"id": 148, "artigo_id": 12, "paragrafo_id": 14, "numero_romano": "VI", "numero_int": 6, "texto": "VI - de oficial das Forças Armadas.", "ordem": 148}, {"id": 149, "artigo_id": 12, "paragrafo_id": 14, "numero_romano": "VII", "numero_int": 7, "texto": "VII - de Ministro de Estado da Defesa.", "ordem": 149}, {"id": 150, "artigo_id": 12, "paragrafo_id": 15, "numero_romano": "I", "numero_int": 1, "texto": "I - tiver cancelada sua naturalização, por sentença judicial, em virtude de fraude relacionada ao processo de naturalização ou de atentado contra a ordem constitucional e o Estado Democrático;", "ordem": 150}, {"id": 151, "artigo_id": 12, "paragrafo_id": 15, "numero_romano": "II", "numero_int": 2, "texto": "II - fizer pedido expresso de perda da nacionalidade brasileira perante autoridade brasileira competente, ressalvadas situações que acarretem apatridia.", "ordem": 151}, {"id": 152, "artigo_id": 14, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - plebiscito;", "ordem": 152}, {"id": 153, "artigo_id": 14, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - referendo;", "ordem": 153}, {"id": 154, "artigo_id": 14, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - iniciativa popular.", "ordem": 154}, {"id": 155, "artigo_id": 14, "paragrafo_id": 19, "numero_romano": "I", "numero_int": 1, "texto": "I - obrigatórios para os maiores de dezoito anos;", "ordem": 155}, {"id": 156, "artigo_id": 14, "paragrafo_id": 19, "numero_romano": "II", "numero_int": 2, "texto": "II - facultativos para:", "ordem": 156}, {"id": 157, "artigo_id": 14, "paragrafo_id": 21, "numero_romano": "I", "numero_int": 1, "texto": "I - a nacionalidade brasileira;", "ordem": 157}, {"id": 158, "artigo_id": 14, "paragrafo_id": 21, "numero_romano": "II", "numero_int": 2, "texto": "II - o pleno exercício dos direitos políticos;", "ordem": 158}, {"id": 159, "artigo_id": 14, "paragrafo_id": 21, "numero_romano": "III", "numero_int": 3, "texto": "III - o alistamento eleitoral;", "ordem": 159}, {"id": 160, "artigo_id": 14, "paragrafo_id": 21, "numero_romano": "IV", "numero_int": 4, "texto": "IV - o domicílio eleitoral na circunscrição;", "ordem": 160}, {"id": 161, "artigo_id": 14, "paragrafo_id": 21, "numero_romano": "V", "numero_int": 5, "texto": "V - a filiação partidária; Regulamento", "ordem": 161}, {"id": 162, "artigo_id": 14, "paragrafo_id": 21, "numero_romano": "VI", "numero_int": 6, "texto": "VI - a idade mínima de:", "ordem": 162}, {"id": 163, "artigo_id": 14, "paragrafo_id": 26, "numero_romano": "I", "numero_int": 1, "texto": "I - se contar menos de dez anos de serviço, deverá afastar-se da atividade;", "ordem": 163}, {"id": 164, "artigo_id": 14, "paragrafo_id": 26, "numero_romano": "II", "numero_int": 2, "texto": "II - se contar mais de dez anos de serviço, será agregado pela autoridade superior e, se eleito, passará automaticamente, no ato da diplomação, para a inatividade.", "ordem": 164}, {"id": 165, "artigo_id": 15, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - cancelamento da naturalização por sentença transitada em julgado;", "ordem": 165}, {"id": 166, "artigo_id": 15, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - incapacidade civil absoluta;", "ordem": 166}, {"id": 167, "artigo_id": 15, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - condenação criminal transitada em julgado, enquanto durarem seus efeitos;", "ordem": 167}, {"id": 168, "artigo_id": 15, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - recusa de cumprir obrigação a todos imposta ou prestação alternativa, nos termos do art. 5º, VIII;", "ordem": 168}, {"id": 169, "artigo_id": 15, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - improbidade administrativa, nos termos do art. 37, § 4º.", "ordem": 169}, {"id": 170, "artigo_id": 17, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - caráter nacional;", "ordem": 170}, {"id": 171, "artigo_id": 17, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - proibição de recebimento de recursos financeiros de entidade ou governo estrangeiros ou de subordinação a estes;", "ordem": 171}, {"id": 172, "artigo_id": 17, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - prestação de contas à Justiça Eleitoral;", "ordem": 172}, {"id": 173, "artigo_id": 17, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - funcionamento parlamentar de acordo com a lei.", "ordem": 173}, {"id": 174, "artigo_id": 17, "paragrafo_id": 32, "numero_romano": "I", "numero_int": 1, "texto": "I - obtiverem, nas eleições para a Câmara dos Deputados, no mínimo, 3% (três por cento) dos votos válidos, distribuídos em pelo menos um terço das unidades da Federação, com um mínimo de 2% (dois por cento) dos votos válidos em cada uma delas; ou", "ordem": 174}, {"id": 175, "artigo_id": 17, "paragrafo_id": 32, "numero_romano": "II", "numero_int": 2, "texto": "II - tiverem elegido pelo menos quinze Deputados Federais distribuídos em pelo menos um terço das unidades da Federação.", "ordem": 175}, {"id": 176, "artigo_id": 19, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - estabelecer cultos religiosos ou igrejas, subvencioná-los, embaraçar-lhes o funcionamento ou manter com eles ou seus representantes relações de dependência ou aliança, ressalvada, na forma da lei, a colaboração de interesse público;", "ordem": 176}, {"id": 177, "artigo_id": 19, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - recusar fé aos documentos públicos;", "ordem": 177}, {"id": 178, "artigo_id": 19, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - criar distinções entre brasileiros ou preferências entre si.", "ordem": 178}, {"id": 179, "artigo_id": 20, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - os que atualmente lhe pertencem e os que lhe vierem a ser atribuídos;", "ordem": 179}, {"id": 180, "artigo_id": 20, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - as terras devolutas indispensáveis à defesa das fronteiras, das fortificações e construções militares, das vias federais de comunicação e à preservação ambiental, definidas em lei;", "ordem": 180}, {"id": 181, "artigo_id": 20, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - os lagos, rios e quaisquer correntes de água em terrenos de seu domínio, ou que banhem mais de um Estado, sirvam de limites com outros países, ou se estendam a território estrangeiro ou dele provenham, bem como os terrenos marginais e as praias fluviais;", "ordem": 181}, {"id": 182, "artigo_id": 20, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - os recursos naturais da plataforma continental e da zona econômica exclusiva;", "ordem": 182}, {"id": 183, "artigo_id": 20, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - o mar territorial;", "ordem": 183}, {"id": 184, "artigo_id": 20, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - os terrenos de marinha e seus acrescidos;", "ordem": 184}, {"id": 185, "artigo_id": 20, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - os potenciais de energia hidráulica;", "ordem": 185}, {"id": 186, "artigo_id": 20, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - os recursos minerais, inclusive os do subsolo;", "ordem": 186}, {"id": 187, "artigo_id": 20, "paragrafo_id": null, "numero_romano": "X", "numero_int": 10, "texto": "X - as cavidades naturais subterrâneas e os sítios arqueológicos e pré-históricos;", "ordem": 187}, {"id": 188, "artigo_id": 20, "paragrafo_id": null, "numero_romano": "XI", "numero_int": 11, "texto": "XI - as terras tradicionalmente ocupadas pelos índios.", "ordem": 188}, {"id": 189, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - manter relações com Estados estrangeiros e participar de organizações internacionais;", "ordem": 189}, {"id": 190, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - declarar a guerra e celebrar a paz;", "ordem": 190}, {"id": 191, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - assegurar a defesa nacional;", "ordem": 191}, {"id": 192, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - permitir, nos casos previstos em lei complementar, que forças estrangeiras transitem pelo território nacional ou nele permaneçam temporariamente;", "ordem": 192}, {"id": 193, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - decretar o estado de sítio, o estado de defesa e a intervenção federal;", "ordem": 193}, {"id": 194, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - autorizar e fiscalizar a produção e o comércio de material bélico;", "ordem": 194}, {"id": 195, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - emitir moeda;", "ordem": 195}, {"id": 196, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - administrar as reservas cambiais do País e fiscalizar as operações de natureza financeira, especialmente as de crédito, câmbio e capitalização, bem como as de seguros e de previdência privada;", "ordem": 196}, {"id": 197, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - elaborar e executar planos nacionais e regionais de ordenação do território e de desenvolvimento econômico e social;", "ordem": 197}, {"id": 198, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "X", "numero_int": 10, "texto": "X - manter o serviço postal e o correio aéreo nacional;", "ordem": 198}, {"id": 199, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "XI", "numero_int": 11, "texto": "XI - explorar, diretamente ou mediante autorização, concessão ou permissão, os serviços de telecomunicações, nos termos da lei, que disporá sobre a organização dos serviços, a criação de um órgão regulador e outros aspectos institucionais;", "ordem": 199}, {"id": 200, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "XII", "numero_int": 12, "texto": "XII - explorar, diretamente ou mediante autorização, concessão ou permissão:", "ordem": 200}, {"id": 201, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "XIII", "numero_int": 13, "texto": "XIII - organizar e manter o Poder Judiciário, o Ministério Público do Distrito Federal e dos Territórios e a Defensoria Pública dos Territórios; (Produção de efeito)", "ordem": 201}, {"id": 202, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "XIV", "numero_int": 14, "texto": "XIV - organizar e manter a polícia civil, a polícia penal, a polícia militar e o corpo de bombeiros militar do Distrito Federal, bem como prestar assistência financeira ao Distrito Federal para a execução de serviços públicos, por meio de fundo próprio;", "ordem": 202}, {"id": 203, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "XV", "numero_int": 15, "texto": "XV - organizar e manter os serviços oficiais de estatística, geografia, geologia e cartografia de âmbito nacional;", "ordem": 203}, {"id": 204, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "XVI", "numero_int": 16, "texto": "XVI - exercer a classificação, para efeito indicativo, de diversões públicas e de programas de rádio e televisão;", "ordem": 204}, {"id": 205, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "XVII", "numero_int": 17, "texto": "XVII - conceder anistia;", "ordem": 205}, {"id": 206, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "XVIII", "numero_int": 18, "texto": "XVIII - planejar e promover a defesa permanente contra as calamidades públicas, especialmente as secas e as inundações;", "ordem": 206}, {"id": 207, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "XIX", "numero_int": 19, "texto": "XIX - instituir sistema nacional de gerenciamento de recursos hídricos e definir critérios de outorga de direitos de seu uso; ( Regulamento )", "ordem": 207}, {"id": 208, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "XX", "numero_int": 20, "texto": "XX - instituir diretrizes para o desenvolvimento urbano, inclusive habitação, saneamento básico e transportes urbanos;", "ordem": 208}, {"id": 209, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "XXI", "numero_int": 21, "texto": "XXI - estabelecer princípios e diretrizes para o sistema nacional de viação;", "ordem": 209}, {"id": 210, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "XXII", "numero_int": 22, "texto": "XXII - executar os serviços de polícia marítima, aeroportuária e de fronteiras;", "ordem": 210}, {"id": 211, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "XXIII", "numero_int": 23, "texto": "XXIII - explorar os serviços e instalações nucleares de qualquer natureza e exercer monopólio estatal sobre a pesquisa, a lavra, o enriquecimento e reprocessamento, a industrialização e o comércio de minérios nucleares e seus derivados, atendidos os seguintes princípios e condições:", "ordem": 211}, {"id": 212, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "XXIV", "numero_int": 24, "texto": "XXIV - organizar, manter e executar a inspeção do trabalho;", "ordem": 212}, {"id": 213, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "XXV", "numero_int": 25, "texto": "XXV - estabelecer as áreas e as condições para o exercício da atividade de garimpagem, em forma associativa.", "ordem": 213}, {"id": 214, "artigo_id": 21, "paragrafo_id": null, "numero_romano": "XXVI", "numero_int": 26, "texto": "XXVI - organizar e fiscalizar a proteção e o tratamento de dados pessoais, nos termos da lei.", "ordem": 214}, {"id": 215, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - direito civil, comercial, penal, processual, eleitoral, agrário, marítimo, aeronáutico, espacial e do trabalho;", "ordem": 215}, {"id": 216, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - desapropriação;", "ordem": 216}, {"id": 217, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - requisições civis e militares, em caso de iminente perigo e em tempo de guerra;", "ordem": 217}, {"id": 218, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - águas, energia, informática, telecomunicações e radiodifusão;", "ordem": 218}, {"id": 219, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - serviço postal;", "ordem": 219}, {"id": 220, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - sistema monetário e de medidas, títulos e garantias dos metais;", "ordem": 220}, {"id": 221, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - política de crédito, câmbio, seguros e transferência de valores;", "ordem": 221}, {"id": 222, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - comércio exterior e interestadual;", "ordem": 222}, {"id": 223, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - diretrizes da política nacional de transportes;", "ordem": 223}, {"id": 224, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "X", "numero_int": 10, "texto": "X - regime dos portos, navegação lacustre, fluvial, marítima, aérea e aeroespacial;", "ordem": 224}, {"id": 225, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "XI", "numero_int": 11, "texto": "XI - trânsito e transporte;", "ordem": 225}, {"id": 226, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "XII", "numero_int": 12, "texto": "XII - jazidas, minas, outros recursos minerais e metalurgia;", "ordem": 226}, {"id": 227, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "XIII", "numero_int": 13, "texto": "XIII - nacionalidade, cidadania e naturalização;", "ordem": 227}, {"id": 228, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "XIV", "numero_int": 14, "texto": "XIV - populações indígenas;", "ordem": 228}, {"id": 229, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "XV", "numero_int": 15, "texto": "XV - emigração e imigração, entrada, extradição e expulsão de estrangeiros;", "ordem": 229}, {"id": 230, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "XVI", "numero_int": 16, "texto": "XVI - organização do sistema nacional de emprego e condições para o exercício de profissões;", "ordem": 230}, {"id": 231, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "XVII", "numero_int": 17, "texto": "XVII - organização judiciária, do Ministério Público do Distrito Federal e dos Territórios e da Defensoria Pública dos Territórios, bem como organização administrativa destes; (Produção de efeito)", "ordem": 231}, {"id": 232, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "XVIII", "numero_int": 18, "texto": "XVIII - sistema estatístico, sistema cartográfico e de geologia nacionais;", "ordem": 232}, {"id": 233, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "XIX", "numero_int": 19, "texto": "XIX - sistemas de poupança, captação e garantia da poupança popular;", "ordem": 233}, {"id": 234, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "XX", "numero_int": 20, "texto": "XX - sistemas de consórcios e sorteios;", "ordem": 234}, {"id": 235, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "XXI", "numero_int": 21, "texto": "XXI - normas gerais de organização, efetivos, material bélico, garantias, convocação, mobilização, inatividades e pensões das polícias militares e dos corpos de bombeiros militares;", "ordem": 235}, {"id": 236, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "XXII", "numero_int": 22, "texto": "XXII - competência da polícia federal e das polícias rodoviária e ferroviária federais;", "ordem": 236}, {"id": 237, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "XXIII", "numero_int": 23, "texto": "XXIII - seguridade social;", "ordem": 237}, {"id": 238, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "XXIV", "numero_int": 24, "texto": "XXIV - diretrizes e bases da educação nacional;", "ordem": 238}, {"id": 239, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "XXV", "numero_int": 25, "texto": "XXV - registros públicos;", "ordem": 239}, {"id": 240, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "XXVI", "numero_int": 26, "texto": "XXVI - atividades nucleares de qualquer natureza;", "ordem": 240}, {"id": 241, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "XXVII", "numero_int": 27, "texto": "XXVII - normas gerais de licitação e contratação, em todas as modalidades, para as administrações públicas diretas, autárquicas e fundacionais da União, Estados, Distrito Federal e Municípios, obedecido o disposto no art. 37, XXI, e para as empresas públicas e sociedades de economia mista, nos termos do art. 173, § 1°, III;", "ordem": 241}, {"id": 242, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "XXVIII", "numero_int": 28, "texto": "XXVIII - defesa territorial, defesa aeroespacial, defesa marítima, defesa civil e mobilização nacional;", "ordem": 242}, {"id": 243, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "XXIX", "numero_int": 29, "texto": "XXIX - propaganda comercial.", "ordem": 243}, {"id": 244, "artigo_id": 22, "paragrafo_id": null, "numero_romano": "XXX", "numero_int": 30, "texto": "XXX - proteção e tratamento de dados pessoais.", "ordem": 244}, {"id": 245, "artigo_id": 23, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - zelar pela guarda da Constituição, das leis e das instituições democráticas e conservar o patrimônio público;", "ordem": 245}, {"id": 246, "artigo_id": 23, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - cuidar da saúde e assistência pública, da proteção e garantia das pessoas portadoras de deficiência;", "ordem": 246}, {"id": 247, "artigo_id": 23, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - proteger os documentos, as obras e outros bens de valor histórico, artístico e cultural, os monumentos, as paisagens naturais notáveis e os sítios arqueológicos;", "ordem": 247}, {"id": 248, "artigo_id": 23, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - impedir a evasão, a destruição e a descaracterização de obras de arte e de outros bens de valor histórico, artístico ou cultural;", "ordem": 248}, {"id": 249, "artigo_id": 23, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - proporcionar os meios de acesso à cultura, à educação, à ciência, à tecnologia, à pesquisa e à inovação;", "ordem": 249}, {"id": 250, "artigo_id": 23, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - proteger o meio ambiente e combater a poluição em qualquer de suas formas;", "ordem": 250}, {"id": 251, "artigo_id": 23, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - preservar as florestas, a fauna e a flora;", "ordem": 251}, {"id": 252, "artigo_id": 23, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - fomentar a produção agropecuária e organizar o abastecimento alimentar;", "ordem": 252}, {"id": 253, "artigo_id": 23, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - promover programas de construção de moradias e a melhoria das condições habitacionais e de saneamento básico;", "ordem": 253}, {"id": 254, "artigo_id": 23, "paragrafo_id": null, "numero_romano": "X", "numero_int": 10, "texto": "X - combater as causas da pobreza e os fatores de marginalização, promovendo a integração social dos setores desfavorecidos;", "ordem": 254}, {"id": 255, "artigo_id": 23, "paragrafo_id": null, "numero_romano": "XI", "numero_int": 11, "texto": "XI - registrar, acompanhar e fiscalizar as concessões de direitos de pesquisa e exploração de recursos hídricos e minerais em seus territórios;", "ordem": 255}, {"id": 256, "artigo_id": 23, "paragrafo_id": null, "numero_romano": "XII", "numero_int": 12, "texto": "XII - estabelecer e implantar política de educação para a segurança do trânsito.", "ordem": 256}, {"id": 257, "artigo_id": 24, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - direito tributário, financeiro, penitenciário, econômico e urbanístico;", "ordem": 257}, {"id": 258, "artigo_id": 24, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - orçamento;", "ordem": 258}, {"id": 259, "artigo_id": 24, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - juntas comerciais;", "ordem": 259}, {"id": 260, "artigo_id": 24, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - custas dos serviços forenses;", "ordem": 260}, {"id": 261, "artigo_id": 24, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - produção e consumo;", "ordem": 261}, {"id": 262, "artigo_id": 24, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - florestas, caça, pesca, fauna, conservação da natureza, defesa do solo e dos recursos naturais, proteção do meio ambiente e controle da poluição;", "ordem": 262}, {"id": 263, "artigo_id": 24, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - proteção ao patrimônio histórico, cultural, artístico, turístico e paisagístico;", "ordem": 263}, {"id": 264, "artigo_id": 24, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - responsabilidade por dano ao meio ambiente, ao consumidor, a bens e direitos de valor artístico, estético, histórico, turístico e paisagístico;", "ordem": 264}, {"id": 265, "artigo_id": 24, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - educação, cultura, ensino, desporto, ciência, tecnologia, pesquisa, desenvolvimento e inovação;", "ordem": 265}, {"id": 266, "artigo_id": 24, "paragrafo_id": null, "numero_romano": "X", "numero_int": 10, "texto": "X - criação, funcionamento e processo do juizado de pequenas causas;", "ordem": 266}, {"id": 267, "artigo_id": 24, "paragrafo_id": null, "numero_romano": "XI", "numero_int": 11, "texto": "XI - procedimentos em matéria processual;", "ordem": 267}, {"id": 268, "artigo_id": 24, "paragrafo_id": null, "numero_romano": "XII", "numero_int": 12, "texto": "XII - previdência social, proteção e defesa da saúde;", "ordem": 268}, {"id": 269, "artigo_id": 24, "paragrafo_id": null, "numero_romano": "XIII", "numero_int": 13, "texto": "XIII - assistência jurídica e Defensoria pública;", "ordem": 269}, {"id": 270, "artigo_id": 24, "paragrafo_id": null, "numero_romano": "XIV", "numero_int": 14, "texto": "XIV - proteção e integração social das pessoas portadoras de deficiência;", "ordem": 270}, {"id": 271, "artigo_id": 24, "paragrafo_id": null, "numero_romano": "XV", "numero_int": 15, "texto": "XV - proteção à infância e à juventude;", "ordem": 271}, {"id": 272, "artigo_id": 24, "paragrafo_id": null, "numero_romano": "XVI", "numero_int": 16, "texto": "XVI - organização, garantias, direitos e deveres das polícias civis.", "ordem": 272}, {"id": 273, "artigo_id": 26, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - as águas superficiais ou subterrâneas, fluentes, emergentes e em depósito, ressalvadas, neste caso, na forma da lei, as decorrentes de obras da União;", "ordem": 273}, {"id": 274, "artigo_id": 26, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - as áreas, nas ilhas oceânicas e costeiras, que estiverem no seu domínio, excluídas aquelas sob domínio da União, Municípios ou terceiros;", "ordem": 274}, {"id": 275, "artigo_id": 26, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - as ilhas fluviais e lacustres não pertencentes à União;", "ordem": 275}, {"id": 276, "artigo_id": 26, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - as terras devolutas não compreendidas entre as da União.", "ordem": 276}, {"id": 277, "artigo_id": 29, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - eleição do Prefeito, do Vice-Prefeito e dos Vereadores, para mandato de quatro anos, mediante pleito direto e simultâneo realizado em todo o País;", "ordem": 277}, {"id": 278, "artigo_id": 29, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - eleição do Prefeito e do Vice-Prefeito realizada no primeiro domingo de outubro do ano anterior ao término do mandato dos que devam suceder, aplicadas as regras do art. 77, no caso de Municípios com mais de duzentos mil eleitores;", "ordem": 278}, {"id": 279, "artigo_id": 29, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - posse do Prefeito e do Vice-Prefeito no dia 1º de janeiro do ano subseqüente ao da eleição;", "ordem": 279}, {"id": 280, "artigo_id": 29, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - para a composição das Câmaras Municipais, será observado o limite máximo de: (Produção de efeito)", "ordem": 280}, {"id": 281, "artigo_id": 29, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - subsídios do Prefeito, do Vice-Prefeito e dos Secretários Municipais fixados por lei de iniciativa da Câmara Municipal, observado o que dispõem os arts. 37, XI, 39, § 4º, 150, II, 153, III, e 153, § 2º, I;", "ordem": 281}, {"id": 282, "artigo_id": 29, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - o subsídio dos Vereadores será fixado pelas respectivas Câmaras Municipais em cada legislatura para a subseqüente, observado o que dispõe esta Constituição, observados os critérios estabelecidos na respectiva Lei Orgânica e os seguintes limites máximos:", "ordem": 282}, {"id": 283, "artigo_id": 29, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - o total da despesa com a remuneração dos Vereadores não poderá ultrapassar o montante de cinco por cento da receita do Município;", "ordem": 283}, {"id": 284, "artigo_id": 29, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - inviolabilidade dos Vereadores por suas opiniões, palavras e votos no exercício do mandato e na circunscrição do Município; (Renumerado do inciso VI, pela Emenda Constitucional nº 1, de 1992)", "ordem": 284}, {"id": 285, "artigo_id": 29, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - proibições e incompatibilidades, no exercício da vereança, similares, no que couber, ao disposto nesta Constituição para os membros do Congresso Nacional e na Constituição do respectivo Estado para os membros da Assembléia Legislativa; (Renumerado do inciso VII, pela Emenda Constitucional nº 1, de 1992)", "ordem": 285}, {"id": 286, "artigo_id": 29, "paragrafo_id": null, "numero_romano": "X", "numero_int": 10, "texto": "X - julgamento do Prefeito perante o Tribunal de Justiça; (Renumerado do inciso VIII, pela Emenda Constitucional nº 1, de 1992)", "ordem": 286}, {"id": 287, "artigo_id": 29, "paragrafo_id": null, "numero_romano": "XI", "numero_int": 11, "texto": "XI - organização das funções legislativas e fiscalizadoras da Câmara Municipal; (Renumerado do inciso IX, pela Emenda Constitucional nº 1, de 1992)", "ordem": 287}, {"id": 288, "artigo_id": 29, "paragrafo_id": null, "numero_romano": "XII", "numero_int": 12, "texto": "XII - cooperação das associações representativas no planejamento municipal; (Renumerado do inciso X, pela Emenda Constitucional nº 1, de 1992)", "ordem": 288}, {"id": 289, "artigo_id": 29, "paragrafo_id": null, "numero_romano": "XIII", "numero_int": 13, "texto": "XIII - iniciativa popular de projetos de lei de interesse específico do Município, da cidade ou de bairros, através de manifestação de, pelo menos, cinco por cento do eleitorado; (Renumerado do inciso XI, pela Emenda Constitucional nº 1, de 1992)", "ordem": 289}, {"id": 290, "artigo_id": 29, "paragrafo_id": null, "numero_romano": "XIV", "numero_int": 14, "texto": "XIV - perda do mandato do Prefeito, nos termos do art. 28, parágrafo único . (Renumerado do inciso XII, pela Emenda Constitucional nº 1, de 1992)", "ordem": 290}, {"id": 291, "artigo_id": 29, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - 7% (sete por cento) para Municípios com população de até 100.000 (cem mil) habitantes; (Produção de efeito)", "ordem": 291}, {"id": 292, "artigo_id": 29, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - 6% (seis por cento) para Municípios com população entre 100.000 (cem mil) e 300.000 (trezentos mil) habitantes;", "ordem": 292}, {"id": 293, "artigo_id": 29, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - 5% (cinco por cento) para Municípios com população entre 300.001 (trezentos mil e um) e 500.000 (quinhentos mil) habitantes;", "ordem": 293}, {"id": 294, "artigo_id": 29, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - 4,5% (quatro inteiros e cinco décimos por cento) para Municípios com população entre 500.001 (quinhentos mil e um) e 3.000.000 (três milhões) de habitantes;", "ordem": 294}, {"id": 295, "artigo_id": 29, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - 4% (quatro por cento) para Municípios com população entre 3.000.001 (três milhões e um) e 8.000.000 (oito milhões) de habitantes;", "ordem": 295}, {"id": 296, "artigo_id": 29, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - 3,5% (três inteiros e cinco décimos por cento) para Municípios com população acima de 8.000.001 (oito milhões e um) habitantes.", "ordem": 296}, {"id": 297, "artigo_id": 29, "paragrafo_id": 61, "numero_romano": "I", "numero_int": 1, "texto": "I - efetuar repasse que supere os limites definidos neste artigo;", "ordem": 297}, {"id": 298, "artigo_id": 29, "paragrafo_id": 61, "numero_romano": "II", "numero_int": 2, "texto": "II - não enviar o repasse até o dia vinte de cada mês; ou", "ordem": 298}, {"id": 299, "artigo_id": 29, "paragrafo_id": 61, "numero_romano": "III", "numero_int": 3, "texto": "III - enviá-lo a menor em relação à proporção fixada na Lei Orçamentária.", "ordem": 299}, {"id": 300, "artigo_id": 30, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - legislar sobre assuntos de interesse local;", "ordem": 300}, {"id": 301, "artigo_id": 30, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - suplementar a legislação federal e a estadual no que couber;", "ordem": 301}, {"id": 302, "artigo_id": 30, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - instituir e arrecadar os tributos de sua competência, bem como aplicar suas rendas, sem prejuízo da obrigatoriedade de prestar contas e publicar balancetes nos prazos fixados em lei;", "ordem": 302}, {"id": 303, "artigo_id": 30, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - criar, organizar e suprimir distritos, observada a legislação estadual;", "ordem": 303}, {"id": 304, "artigo_id": 30, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - organizar e prestar, diretamente ou sob regime de concessão ou permissão, os serviços públicos de interesse local, incluído o de transporte coletivo, que tem caráter essencial;", "ordem": 304}, {"id": 305, "artigo_id": 30, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - manter, com a cooperação técnica e financeira da União e do Estado, programas de educação infantil e de ensino fundamental;", "ordem": 305}, {"id": 306, "artigo_id": 30, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - prestar, com a cooperação técnica e financeira da União e do Estado, serviços de atendimento à saúde da população;", "ordem": 306}, {"id": 307, "artigo_id": 30, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - promover, no que couber, adequado ordenamento territorial, mediante planejamento e controle do uso, do parcelamento e da ocupação do solo urbano;", "ordem": 307}, {"id": 308, "artigo_id": 30, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - promover a proteção do patrimônio histórico-cultural local, observada a legislação e a ação fiscalizadora federal e estadual.", "ordem": 308}, {"id": 309, "artigo_id": 34, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - manter a integridade nacional;", "ordem": 309}, {"id": 310, "artigo_id": 34, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - repelir invasão estrangeira ou de uma unidade da Federação em outra;", "ordem": 310}, {"id": 311, "artigo_id": 34, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - pôr termo a grave comprometimento da ordem pública;", "ordem": 311}, {"id": 312, "artigo_id": 34, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - garantir o livre exercício de qualquer dos Poderes nas unidades da Federação;", "ordem": 312}, {"id": 313, "artigo_id": 34, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - reorganizar as finanças da unidade da Federação que:", "ordem": 313}, {"id": 314, "artigo_id": 34, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - prover a execução de lei federal, ordem ou decisão judicial;", "ordem": 314}, {"id": 315, "artigo_id": 34, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - assegurar a observância dos seguintes princípios constitucionais:", "ordem": 315}, {"id": 316, "artigo_id": 35, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - deixar de ser paga, sem motivo de força maior, por dois anos consecutivos, a dívida fundada;", "ordem": 316}, {"id": 317, "artigo_id": 35, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - não forem prestadas contas devidas, na forma da lei;", "ordem": 317}, {"id": 318, "artigo_id": 35, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - não tiver sido aplicado o mínimo exigido da receita municipal na manutenção e desenvolvimento do ensino e nas ações e serviços públicos de saúde;", "ordem": 318}, {"id": 319, "artigo_id": 35, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - o Tribunal de Justiça der provimento a representação para assegurar a observância de princípios indicados na Constituição Estadual, ou para prover a execução de lei, de ordem ou de decisão judicial.", "ordem": 319}, {"id": 320, "artigo_id": 36, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - no caso do art. 34, IV, de solicitação do Poder Legislativo ou do Poder Executivo coacto ou impedido, ou de requisição do Supremo Tribunal Federal, se a coação for exercida contra o Poder Judiciário;", "ordem": 320}, {"id": 321, "artigo_id": 36, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - no caso de desobediência a ordem ou decisão judiciária, de requisição do Supremo Tribunal Federal, do Superior Tribunal de Justiça ou do Tribunal Superior Eleitoral;", "ordem": 321}, {"id": 322, "artigo_id": 36, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - de provimento, pelo Supremo Tribunal Federal, de representação do Procurador-Geral da República, na hipótese do art. 34, VII, e no caso de recusa à execução de lei federal.", "ordem": 322}, {"id": 323, "artigo_id": 37, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - os cargos, empregos e funções públicas são acessíveis aos brasileiros que preencham os requisitos estabelecidos em lei, assim como aos estrangeiros, na forma da lei;", "ordem": 323}, {"id": 324, "artigo_id": 37, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - a investidura em cargo ou emprego público depende de aprovação prévia em concurso público de provas ou de provas e títulos, de acordo com a natureza e a complexidade do cargo ou emprego, na forma prevista em lei, ressalvadas as nomeações para cargo em comissão declarado em lei de livre nomeação e exoneração;", "ordem": 324}, {"id": 325, "artigo_id": 37, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - o prazo de validade do concurso público será de até dois anos, prorrogável uma vez, por igual período;", "ordem": 325}, {"id": 326, "artigo_id": 37, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - durante o prazo improrrogável previsto no edital de convocação, aquele aprovado em concurso público de provas ou de provas e títulos será convocado com prioridade sobre novos concursados para assumir cargo ou emprego, na carreira;", "ordem": 326}, {"id": 327, "artigo_id": 37, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - as funções de confiança, exercidas exclusivamente por servidores ocupantes de cargo efetivo, e os cargos em comissão, a serem preenchidos por servidores de carreira nos casos, condições e percentuais mínimos previstos em lei, destinam-se apenas às atribuições de direção, chefia e assessoramento;", "ordem": 327}, {"id": 328, "artigo_id": 37, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - é garantido ao servidor público civil o direito à livre associação sindical;", "ordem": 328}, {"id": 329, "artigo_id": 37, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - o direito de greve será exercido nos termos e nos limites definidos em lei específica;", "ordem": 329}, {"id": 330, "artigo_id": 37, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - a lei reservará percentual dos cargos e empregos públicos para as pessoas portadoras de deficiência e definirá os critérios de sua admissão;", "ordem": 330}, {"id": 331, "artigo_id": 37, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - a lei estabelecerá os casos de contratação por tempo determinado para atender a necessidade temporária de excepcional interesse público;", "ordem": 331}, {"id": 332, "artigo_id": 37, "paragrafo_id": null, "numero_romano": "X", "numero_int": 10, "texto": "X - a remuneração dos servidores públicos e o subsídio de que trata o § 4º do art. 39 somente poderão ser fixados ou alterados por lei específica, observada a iniciativa privativa em cada caso, assegurada revisão geral anual, sempre na mesma data e sem distinção de índices; (Regulamento)", "ordem": 332}, {"id": 333, "artigo_id": 37, "paragrafo_id": null, "numero_romano": "XII", "numero_int": 12, "texto": "XII - os vencimentos dos cargos do Poder Legislativo e do Poder Judiciário não poderão ser superiores aos pagos pelo Poder Executivo;", "ordem": 333}, {"id": 334, "artigo_id": 37, "paragrafo_id": null, "numero_romano": "XIII", "numero_int": 13, "texto": "XIII - é vedada a vinculação ou equiparação de quaisquer espécies remuneratórias para o efeito de remuneração de pessoal do serviço público;", "ordem": 334}, {"id": 335, "artigo_id": 37, "paragrafo_id": null, "numero_romano": "XIV", "numero_int": 14, "texto": "XIV - os acréscimos pecuniários percebidos por servidor público não serão computados nem acumulados para fins de concessão de acréscimos ulteriores;", "ordem": 335}, {"id": 336, "artigo_id": 37, "paragrafo_id": null, "numero_romano": "XV", "numero_int": 15, "texto": "XV - o subsídio e os vencimentos dos ocupantes de cargos e empregos públicos são irredutíveis, ressalvado o disposto nos incisos XI e XIV deste artigo e nos arts. 39, § 4º, 150, II, 153, III, e 153, § 2º, I;", "ordem": 336}, {"id": 337, "artigo_id": 37, "paragrafo_id": null, "numero_romano": "XVI", "numero_int": 16, "texto": "XVI - é vedada a acumulação remunerada de cargos públicos, exceto, quando houver compatibilidade de horários, observado em qualquer caso o disposto no inciso XI:", "ordem": 337}, {"id": 338, "artigo_id": 37, "paragrafo_id": null, "numero_romano": "XVII", "numero_int": 17, "texto": "XVII - a proibição de acumular estende-se a empregos e funções e abrange autarquias, fundações, empresas públicas, sociedades de economia mista, suas subsidiárias, e sociedades controladas, direta ou indiretamente, pelo poder público;", "ordem": 338}, {"id": 339, "artigo_id": 37, "paragrafo_id": null, "numero_romano": "XVIII", "numero_int": 18, "texto": "XVIII - a administração fazendária e seus servidores fiscais terão, dentro de suas áreas de competência e jurisdição, precedência sobre os demais setores administrativos, na forma da lei;", "ordem": 339}, {"id": 340, "artigo_id": 37, "paragrafo_id": null, "numero_romano": "XIX", "numero_int": 19, "texto": "XIX - somente por lei específica poderá ser criada autarquia e autorizada a instituição de empresa pública, de sociedade de economia mista e de fundação, cabendo à lei complementar, neste último caso, definir as áreas de sua atuação;", "ordem": 340}, {"id": 341, "artigo_id": 37, "paragrafo_id": null, "numero_romano": "XX", "numero_int": 20, "texto": "XX - depende de autorização legislativa, em cada caso, a criação de subsidiárias das entidades mencionadas no inciso anterior, assim como a participação de qualquer delas em empresa privada;", "ordem": 341}, {"id": 342, "artigo_id": 37, "paragrafo_id": null, "numero_romano": "XXI", "numero_int": 21, "texto": "XXI - ressalvados os casos especificados na legislação, as obras, serviços, compras e alienações serão contratados mediante processo de licitação pública que assegure igualdade de condições a todos os concorrentes, com cláusulas que estabeleçam obrigações de pagamento, mantidas as condições efetivas da proposta, nos termos da lei, o qual somente permitirá as exigências de qualificação técnica e econômica indispensáveis à garantia do cumprimento das obrigações. (Regulamento)", "ordem": 342}, {"id": 343, "artigo_id": 37, "paragrafo_id": null, "numero_romano": "XXII", "numero_int": 22, "texto": "XXII - as administrações tributárias da União, dos Estados, do Distrito Federal e dos Municípios, atividades essenciais ao funcionamento do Estado, exercidas por servidores de carreiras específicas, terão recursos prioritários para a realização de suas atividades e atuarão de forma integrada, inclusive com o compartilhamento de cadastros e de informações fiscais, na forma da lei ou convênio.", "ordem": 343}, {"id": 344, "artigo_id": 37, "paragrafo_id": 80, "numero_romano": "I", "numero_int": 1, "texto": "I - as reclamações relativas à prestação dos serviços públicos em geral, asseguradas a manutenção de serviços de atendimento ao usuário e a avaliação periódica, externa e interna, da qualidade dos serviços;", "ordem": 344}, {"id": 345, "artigo_id": 37, "paragrafo_id": 80, "numero_romano": "II", "numero_int": 2, "texto": "II - o acesso dos usuários a registros administrativos e a informações sobre atos de governo, observado o disposto no art. 5º, X e XXXIII;", "ordem": 345}, {"id": 346, "artigo_id": 37, "paragrafo_id": 80, "numero_romano": "III", "numero_int": 3, "texto": "III - a disciplina da representação contra o exercício negligente ou abusivo de cargo, emprego ou função na administração pública.", "ordem": 346}, {"id": 347, "artigo_id": 37, "paragrafo_id": 85, "numero_romano": "I", "numero_int": 1, "texto": "I - o prazo de duração do contrato;", "ordem": 347}, {"id": 348, "artigo_id": 37, "paragrafo_id": 85, "numero_romano": "II", "numero_int": 2, "texto": "II - os controles e critérios de avaliação de desempenho, direitos, obrigações e responsabilidade dos dirigentes;", "ordem": 348}, {"id": 349, "artigo_id": 37, "paragrafo_id": 85, "numero_romano": "III", "numero_int": 3, "texto": "III - a remuneração do pessoal.", "ordem": 349}, {"id": 350, "artigo_id": 38, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - tratando-se de mandato eletivo federal, estadual ou distrital, ficará afastado de seu cargo, emprego ou função;", "ordem": 350}, {"id": 351, "artigo_id": 38, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - investido no mandato de Prefeito, será afastado do cargo, emprego ou função, sendo-lhe facultado optar pela sua remuneração;", "ordem": 351}, {"id": 352, "artigo_id": 38, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - investido no mandato de Vereador, havendo compatibilidade de horários, perceberá as vantagens de seu cargo, emprego ou função, sem prejuízo da remuneração do cargo eletivo, e, não havendo compatibilidade, será aplicada a norma do inciso anterior;", "ordem": 352}, {"id": 353, "artigo_id": 38, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - em qualquer caso que exija o afastamento para o exercício de mandato eletivo, seu tempo de serviço será contado para todos os efeitos legais, exceto para promoção por merecimento;", "ordem": 353}, {"id": 354, "artigo_id": 38, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - na hipótese de ser segurado de regime próprio de previdência social, permanecerá filiado a esse regime, no ente federativo de origem.", "ordem": 354}, {"id": 355, "artigo_id": 39, "paragrafo_id": 87, "numero_romano": "I", "numero_int": 1, "texto": "I - a natureza, o grau de responsabilidade e a complexidade dos cargos componentes de cada carreira;", "ordem": 355}, {"id": 356, "artigo_id": 39, "paragrafo_id": 87, "numero_romano": "II", "numero_int": 2, "texto": "II - os requisitos para a investidura;", "ordem": 356}, {"id": 357, "artigo_id": 39, "paragrafo_id": 87, "numero_romano": "III", "numero_int": 3, "texto": "III - as peculiaridades dos cargos.", "ordem": 357}, {"id": 358, "artigo_id": 40, "paragrafo_id": 96, "numero_romano": "I", "numero_int": 1, "texto": "I - por incapacidade permanente para o trabalho, no cargo em que estiver investido, quando insuscetível de readaptação, hipótese em que será obrigatória a realização de avaliações periódicas para verificação da continuidade das condições que ensejaram a concessão da aposentadoria, na forma de lei do respectivo ente federativo;", "ordem": 358}, {"id": 359, "artigo_id": 40, "paragrafo_id": 96, "numero_romano": "II", "numero_int": 2, "texto": "II - compulsoriamente, com proventos proporcionais ao tempo de contribuição, aos 70 (setenta) anos de idade, ou aos 75 (setenta e cinco) anos de idade, na forma de lei complementar;", "ordem": 359}, {"id": 360, "artigo_id": 40, "paragrafo_id": 96, "numero_romano": "III", "numero_int": 3, "texto": "III - no âmbito da União, aos 62 (sessenta e dois) anos de idade, se mulher, e aos 65 (sessenta e cinco) anos de idade, se homem, e, no âmbito dos Estados, do Distrito Federal e dos Municípios, na idade mínima estabelecida mediante emenda às respectivas Constituições e Leis Orgânicas, observados o tempo de contribuição e os demais requisitos estabelecidos em lei complementar do respectivo ente federativo.", "ordem": 360}, {"id": 361, "artigo_id": 40, "paragrafo_id": 107, "numero_romano": "I", "numero_int": 1, "texto": "I - requisitos para sua extinção e consequente migração para o Regime Geral de Previdência Social;", "ordem": 361}, {"id": 362, "artigo_id": 40, "paragrafo_id": 107, "numero_romano": "II", "numero_int": 2, "texto": "II - modelo de arrecadação, de aplicação e de utilização dos recursos;", "ordem": 362}, {"id": 363, "artigo_id": 40, "paragrafo_id": 107, "numero_romano": "III", "numero_int": 3, "texto": "III - fiscalização pela União e controle externo e social;", "ordem": 363}, {"id": 364, "artigo_id": 40, "paragrafo_id": 107, "numero_romano": "IV", "numero_int": 4, "texto": "IV - definição de equilíbrio financeiro e atuarial;", "ordem": 364}, {"id": 365, "artigo_id": 40, "paragrafo_id": 107, "numero_romano": "V", "numero_int": 5, "texto": "V - condições para instituição do fundo com finalidade previdenciária de que trata o art. 249 e para vinculação a ele dos recursos provenientes de contribuições e dos bens, direitos e ativos de qualquer natureza;", "ordem": 365}, {"id": 366, "artigo_id": 40, "paragrafo_id": 107, "numero_romano": "VI", "numero_int": 6, "texto": "VI - mecanismos de equacionamento do deficit atuarial;", "ordem": 366}, {"id": 367, "artigo_id": 40, "paragrafo_id": 107, "numero_romano": "VII", "numero_int": 7, "texto": "VII - estruturação do órgão ou entidade gestora do regime, observados os princípios relacionados com governança, controle interno e transparência;", "ordem": 367}, {"id": 368, "artigo_id": 40, "paragrafo_id": 107, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - condições e hipóteses para responsabilização daqueles que desempenhem atribuições relacionadas, direta ou indiretamente, com a gestão do regime;", "ordem": 368}, {"id": 369, "artigo_id": 40, "paragrafo_id": 107, "numero_romano": "IX", "numero_int": 9, "texto": "IX - condições para adesão a consórcio público;", "ordem": 369}, {"id": 370, "artigo_id": 40, "paragrafo_id": 107, "numero_romano": "X", "numero_int": 10, "texto": "X - parâmetros para apuração da base de cálculo e definição de alíquota de contribuições ordinárias e extraordinárias.", "ordem": 370}, {"id": 371, "artigo_id": 41, "paragrafo_id": 108, "numero_romano": "I", "numero_int": 1, "texto": "I - em virtude de sentença judicial transitada em julgado;", "ordem": 371}, {"id": 372, "artigo_id": 41, "paragrafo_id": 108, "numero_romano": "II", "numero_int": 2, "texto": "II - mediante processo administrativo em que lhe seja assegurada ampla defesa;", "ordem": 372}, {"id": 373, "artigo_id": 41, "paragrafo_id": 108, "numero_romano": "III", "numero_int": 3, "texto": "III - mediante procedimento de avaliação periódica de desempenho, na forma de lei complementar, assegurada ampla defesa.", "ordem": 373}, {"id": 374, "artigo_id": 43, "paragrafo_id": 115, "numero_romano": "I", "numero_int": 1, "texto": "I - as condições para integração de regiões em desenvolvimento;", "ordem": 374}, {"id": 375, "artigo_id": 43, "paragrafo_id": 115, "numero_romano": "II", "numero_int": 2, "texto": "II - a composição dos organismos regionais que executarão, na forma da lei, os planos regionais, integrantes dos planos nacionais de desenvolvimento econômico e social, aprovados juntamente com estes.", "ordem": 375}, {"id": 376, "artigo_id": 43, "paragrafo_id": 116, "numero_romano": "I", "numero_int": 1, "texto": "I - igualdade de tarifas, fretes, seguros e outros itens de custos e preços de responsabilidade do Poder Público;", "ordem": 376}, {"id": 377, "artigo_id": 43, "paragrafo_id": 116, "numero_romano": "II", "numero_int": 2, "texto": "II - juros favorecidos para financiamento de atividades prioritárias;", "ordem": 377}, {"id": 378, "artigo_id": 43, "paragrafo_id": 116, "numero_romano": "III", "numero_int": 3, "texto": "III - isenções, reduções ou diferimento temporário de tributos federais devidos por pessoas físicas ou jurídicas;", "ordem": 378}, {"id": 379, "artigo_id": 43, "paragrafo_id": 116, "numero_romano": "IV", "numero_int": 4, "texto": "IV - prioridade para o aproveitamento econômico e social dos rios e das massas de água represadas ou represáveis nas regiões de baixa renda, sujeitas a secas periódicas.", "ordem": 379}, {"id": 380, "artigo_id": 48, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - sistema tributário, arrecadação e distribuição de rendas;", "ordem": 380}, {"id": 381, "artigo_id": 48, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - plano plurianual, diretrizes orçamentárias, orçamento anual, operações de crédito, dívida pública e emissões de curso forçado;", "ordem": 381}, {"id": 382, "artigo_id": 48, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - fixação e modificação do efetivo das Forças Armadas;", "ordem": 382}, {"id": 383, "artigo_id": 48, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - planos e programas nacionais, regionais e setoriais de desenvolvimento;", "ordem": 383}, {"id": 384, "artigo_id": 48, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - limites do território nacional, espaço aéreo e marítimo e bens do domínio da União;", "ordem": 384}, {"id": 385, "artigo_id": 48, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - incorporação, subdivisão ou desmembramento de áreas de Territórios ou Estados, ouvidas as respectivas Assembléias Legislativas;", "ordem": 385}, {"id": 386, "artigo_id": 48, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - transferência temporária da sede do Governo Federal;", "ordem": 386}, {"id": 387, "artigo_id": 48, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - concessão de anistia;", "ordem": 387}, {"id": 388, "artigo_id": 48, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - organização administrativa, judiciária, do Ministério Público e da Defensoria Pública da União e dos Territórios e organização judiciária e do Ministério Público do Distrito Federal; (Produção de efeito)", "ordem": 388}, {"id": 389, "artigo_id": 48, "paragrafo_id": null, "numero_romano": "X", "numero_int": 10, "texto": "X - criação, transformação e extinção de cargos, empregos e funções públicas, observado o que estabelece o art. 84, VI, b ;", "ordem": 389}, {"id": 390, "artigo_id": 48, "paragrafo_id": null, "numero_romano": "XI", "numero_int": 11, "texto": "XI - criação e extinção de Ministérios e órgãos da administração pública;", "ordem": 390}, {"id": 391, "artigo_id": 48, "paragrafo_id": null, "numero_romano": "XII", "numero_int": 12, "texto": "XII - telecomunicações e radiodifusão;", "ordem": 391}, {"id": 392, "artigo_id": 48, "paragrafo_id": null, "numero_romano": "XIII", "numero_int": 13, "texto": "XIII - matéria financeira, cambial e monetária, instituições financeiras e suas operações;", "ordem": 392}, {"id": 393, "artigo_id": 48, "paragrafo_id": null, "numero_romano": "XIV", "numero_int": 14, "texto": "XIV - moeda, seus limites de emissão, e montante da dívida mobiliária federal.", "ordem": 393}, {"id": 394, "artigo_id": 48, "paragrafo_id": null, "numero_romano": "XV", "numero_int": 15, "texto": "XV - fixação do subsídio dos Ministros do Supremo Tribunal Federal, observado o que dispõem os arts. 39, § 4º; 150, II; 153, III; e 153, § 2º, I.", "ordem": 394}, {"id": 395, "artigo_id": 49, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - resolver definitivamente sobre tratados, acordos ou atos internacionais que acarretem encargos ou compromissos gravosos ao patrimônio nacional;", "ordem": 395}, {"id": 396, "artigo_id": 49, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - autorizar o Presidente da República a declarar guerra, a celebrar a paz, a permitir que forças estrangeiras transitem pelo território nacional ou nele permaneçam temporariamente, ressalvados os casos previstos em lei complementar;", "ordem": 396}, {"id": 397, "artigo_id": 49, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - autorizar o Presidente e o Vice-Presidente da República a se ausentarem do País, quando a ausência exceder a quinze dias;", "ordem": 397}, {"id": 398, "artigo_id": 49, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - aprovar o estado de defesa e a intervenção federal, autorizar o estado de sítio, ou suspender qualquer uma dessas medidas;", "ordem": 398}, {"id": 399, "artigo_id": 49, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - sustar os atos normativos do Poder Executivo que exorbitem do poder regulamentar ou dos limites de delegação legislativa;", "ordem": 399}, {"id": 400, "artigo_id": 49, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - mudar temporariamente sua sede;", "ordem": 400}, {"id": 401, "artigo_id": 49, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - fixar idêntico subsídio para os Deputados Federais e os Senadores, observado o que dispõem os arts. 37, XI, 39, § 4º, 150, II, 153, III, e 153, § 2º, I;", "ordem": 401}, {"id": 402, "artigo_id": 49, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - fixar os subsídios do Presidente e do Vice-Presidente da República e dos Ministros de Estado, observado o que dispõem os arts. 37, XI, 39, § 4º, 150, II, 153, III, e 153, § 2º, I;", "ordem": 402}, {"id": 403, "artigo_id": 49, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - julgar anualmente as contas prestadas pelo Presidente da República e apreciar os relatórios sobre a execução dos planos de governo;", "ordem": 403}, {"id": 404, "artigo_id": 49, "paragrafo_id": null, "numero_romano": "X", "numero_int": 10, "texto": "X - fiscalizar e controlar, diretamente, ou por qualquer de suas Casas, os atos do Poder Executivo, incluídos os da administração indireta;", "ordem": 404}, {"id": 405, "artigo_id": 49, "paragrafo_id": null, "numero_romano": "XI", "numero_int": 11, "texto": "XI - zelar pela preservação de sua competência legislativa em face da atribuição normativa dos outros Poderes;", "ordem": 405}, {"id": 406, "artigo_id": 49, "paragrafo_id": null, "numero_romano": "XII", "numero_int": 12, "texto": "XII - apreciar os atos de concessão e renovação de concessão de emissoras de rádio e televisão;", "ordem": 406}, {"id": 407, "artigo_id": 49, "paragrafo_id": null, "numero_romano": "XIII", "numero_int": 13, "texto": "XIII - escolher dois terços dos membros do Tribunal de Contas da União;", "ordem": 407}, {"id": 408, "artigo_id": 49, "paragrafo_id": null, "numero_romano": "XIV", "numero_int": 14, "texto": "XIV - aprovar iniciativas do Poder Executivo referentes a atividades nucleares;", "ordem": 408}, {"id": 409, "artigo_id": 49, "paragrafo_id": null, "numero_romano": "XV", "numero_int": 15, "texto": "XV - autorizar referendo e convocar plebiscito;", "ordem": 409}, {"id": 410, "artigo_id": 49, "paragrafo_id": null, "numero_romano": "XVI", "numero_int": 16, "texto": "XVI - autorizar, em terras indígenas, a exploração e o aproveitamento de recursos hídricos e a pesquisa e lavra de riquezas minerais;", "ordem": 410}, {"id": 411, "artigo_id": 49, "paragrafo_id": null, "numero_romano": "XVII", "numero_int": 17, "texto": "XVII - aprovar, previamente, a alienação ou concessão de terras públicas com área superior a dois mil e quinhentos hectares.", "ordem": 411}, {"id": 412, "artigo_id": 49, "paragrafo_id": null, "numero_romano": "XVIII", "numero_int": 18, "texto": "XVIII - decretar o estado de calamidade pública de âmbito nacional previsto nos arts. 167-B, 167-C, 167-D, 167-E, 167-F e 167-G desta Constituição.", "ordem": 412}, {"id": 413, "artigo_id": 51, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - autorizar, por dois terços de seus membros, a instauração de processo contra o Presidente e o Vice-Presidente da República e os Ministros de Estado;", "ordem": 413}, {"id": 414, "artigo_id": 51, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - proceder à tomada de contas do Presidente da República, quando não apresentadas ao Congresso Nacional dentro de sessenta dias após a abertura da sessão legislativa;", "ordem": 414}, {"id": 415, "artigo_id": 51, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - elaborar seu regimento interno;", "ordem": 415}, {"id": 416, "artigo_id": 51, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - dispor sobre sua organização, funcionamento, polícia, criação, transformação ou extinção dos cargos, empregos e funções de seus serviços, e a iniciativa de lei para fixação da respectiva remuneração, observados os parâmetros estabelecidos na lei de diretrizes orçamentárias;", "ordem": 416}, {"id": 417, "artigo_id": 51, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - eleger membros do Conselho da República, nos termos do art. 89, VII.", "ordem": 417}, {"id": 418, "artigo_id": 52, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - processar e julgar o Presidente e o Vice-Presidente da República nos crimes de responsabilidade, bem como os Ministros de Estado e os Comandantes da Marinha, do Exército e da Aeronáutica nos crimes da mesma natureza conexos com aqueles;", "ordem": 418}, {"id": 419, "artigo_id": 52, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - aprovar previamente, por voto secreto, após argüição pública, a escolha de:", "ordem": 419}, {"id": 420, "artigo_id": 52, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - aprovar previamente, por voto secreto, após argüição em sessão secreta, a escolha dos chefes de missão diplomática de caráter permanente;", "ordem": 420}, {"id": 421, "artigo_id": 52, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - autorizar operações externas de natureza financeira, de interesse da União, dos Estados, do Distrito Federal, dos Territórios e dos Municípios;", "ordem": 421}, {"id": 422, "artigo_id": 52, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - fixar, por proposta do Presidente da República, limites globais para o montante da dívida consolidada da União, dos Estados, do Distrito Federal e dos Municípios;", "ordem": 422}, {"id": 423, "artigo_id": 52, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - dispor sobre limites globais e condições para as operações de crédito externo e interno da União, dos Estados, do Distrito Federal e dos Municípios, de suas autarquias e demais entidades controladas pelo Poder Público federal;", "ordem": 423}, {"id": 424, "artigo_id": 52, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - dispor sobre limites e condições para a concessão de garantia da União em operações de crédito externo e interno;", "ordem": 424}, {"id": 425, "artigo_id": 52, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - estabelecer limites globais e condições para o montante da dívida mobiliária dos Estados, do Distrito Federal e dos Municípios;", "ordem": 425}, {"id": 426, "artigo_id": 52, "paragrafo_id": null, "numero_romano": "X", "numero_int": 10, "texto": "X - suspender a execução, no todo ou em parte, de lei declarada inconstitucional por decisão definitiva do Supremo Tribunal Federal;", "ordem": 426}, {"id": 427, "artigo_id": 52, "paragrafo_id": null, "numero_romano": "XI", "numero_int": 11, "texto": "XI - aprovar, por maioria absoluta e por voto secreto, a exoneração, de ofício, do Procurador-Geral da República antes do término de seu mandato;", "ordem": 427}, {"id": 428, "artigo_id": 52, "paragrafo_id": null, "numero_romano": "XII", "numero_int": 12, "texto": "XII - elaborar seu regimento interno;", "ordem": 428}, {"id": 429, "artigo_id": 52, "paragrafo_id": null, "numero_romano": "XIII", "numero_int": 13, "texto": "XIII - dispor sobre sua organização, funcionamento, polícia, criação, transformação ou extinção dos cargos, empregos e funções de seus serviços, e a iniciativa de lei para fixação da respectiva remuneração, observados os parâmetros estabelecidos na lei de diretrizes orçamentárias;", "ordem": 429}, {"id": 430, "artigo_id": 52, "paragrafo_id": null, "numero_romano": "XIV", "numero_int": 14, "texto": "XIV - eleger membros do Conselho da República, nos termos do art. 89, VII.", "ordem": 430}, {"id": 431, "artigo_id": 52, "paragrafo_id": null, "numero_romano": "XV", "numero_int": 15, "texto": "XV - avaliar periodicamente a funcionalidade do Sistema Tributário Nacional, em sua estrutura e seus componentes, e o desempenho das administrações tributárias da União, dos Estados e do Distrito Federal e dos Municípios.", "ordem": 431}, {"id": 432, "artigo_id": 54, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - desde a expedição do diploma:", "ordem": 432}, {"id": 433, "artigo_id": 54, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - desde a posse:", "ordem": 433}, {"id": 434, "artigo_id": 55, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - que infringir qualquer das proibições estabelecidas no artigo anterior;", "ordem": 434}, {"id": 435, "artigo_id": 55, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - cujo procedimento for declarado incompatível com o decoro parlamentar;", "ordem": 435}, {"id": 436, "artigo_id": 55, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - que deixar de comparecer, em cada sessão legislativa, à terça parte das sessões ordinárias da Casa a que pertencer, salvo licença ou missão por esta autorizada;", "ordem": 436}, {"id": 437, "artigo_id": 55, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - que perder ou tiver suspensos os direitos políticos;", "ordem": 437}, {"id": 438, "artigo_id": 55, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - quando o decretar a Justiça Eleitoral, nos casos previstos nesta Constituição;", "ordem": 438}, {"id": 439, "artigo_id": 55, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - que sofrer condenação criminal em sentença transitada em julgado.", "ordem": 439}, {"id": 440, "artigo_id": 56, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - investido no cargo de Ministro de Estado, Governador de Território, Secretário de Estado, do Distrito Federal, de Território, de Prefeitura de Capital ou chefe de missão diplomática temporária;", "ordem": 440}, {"id": 441, "artigo_id": 56, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - licenciado pela respectiva Casa por motivo de doença, ou para tratar, sem remuneração, de interesse particular, desde que, neste caso, o afastamento não ultrapasse cento e vinte dias por sessão legislativa.", "ordem": 441}, {"id": 442, "artigo_id": 57, "paragrafo_id": 145, "numero_romano": "I", "numero_int": 1, "texto": "I - inaugurar a sessão legislativa;", "ordem": 442}, {"id": 443, "artigo_id": 57, "paragrafo_id": 145, "numero_romano": "II", "numero_int": 2, "texto": "II - elaborar o regimento comum e regular a criação de serviços comuns às duas Casas;", "ordem": 443}, {"id": 444, "artigo_id": 57, "paragrafo_id": 145, "numero_romano": "III", "numero_int": 3, "texto": "III - receber o compromisso do Presidente e do Vice-Presidente da República;", "ordem": 444}, {"id": 445, "artigo_id": 57, "paragrafo_id": 145, "numero_romano": "IV", "numero_int": 4, "texto": "IV - conhecer do veto e sobre ele deliberar.", "ordem": 445}, {"id": 446, "artigo_id": 57, "paragrafo_id": 148, "numero_romano": "I", "numero_int": 1, "texto": "I - pelo Presidente do Senado Federal, em caso de decretação de estado de defesa ou de intervenção federal, de pedido de autorização para a decretação de estado de sítio e para o compromisso e a posse do Presidente e do Vice-Presidente da República;", "ordem": 446}, {"id": 447, "artigo_id": 57, "paragrafo_id": 148, "numero_romano": "II", "numero_int": 2, "texto": "II - pelo Presidente da República, pelos Presidentes da Câmara dos Deputados e do Senado Federal ou a requerimento da maioria dos membros de ambas as Casas, em caso de urgência ou interesse público relevante, em todas as hipóteses deste inciso com a aprovação da maioria absoluta de cada uma das Casas do Congresso Nacional.", "ordem": 447}, {"id": 448, "artigo_id": 58, "paragrafo_id": 152, "numero_romano": "I", "numero_int": 1, "texto": "I - discutir e votar projeto de lei que dispensar, na forma do regimento, a competência do Plenário, salvo se houver recurso de um décimo dos membros da Casa;", "ordem": 448}, {"id": 449, "artigo_id": 58, "paragrafo_id": 152, "numero_romano": "II", "numero_int": 2, "texto": "II - realizar audiências públicas com entidades da sociedade civil;", "ordem": 449}, {"id": 450, "artigo_id": 58, "paragrafo_id": 152, "numero_romano": "III", "numero_int": 3, "texto": "III - convocar Ministros de Estado para prestar informações sobre assuntos inerentes a suas atribuições;", "ordem": 450}, {"id": 451, "artigo_id": 58, "paragrafo_id": 152, "numero_romano": "IV", "numero_int": 4, "texto": "IV - receber petições, reclamações, representações ou queixas de qualquer pessoa contra atos ou omissões das autoridades ou entidades públicas;", "ordem": 451}, {"id": 452, "artigo_id": 58, "paragrafo_id": 152, "numero_romano": "V", "numero_int": 5, "texto": "V - solicitar depoimento de qualquer autoridade ou cidadão;", "ordem": 452}, {"id": 453, "artigo_id": 58, "paragrafo_id": 152, "numero_romano": "VI", "numero_int": 6, "texto": "VI - apreciar programas de obras, planos nacionais, regionais e setoriais de desenvolvimento e sobre eles emitir parecer.", "ordem": 453}, {"id": 454, "artigo_id": 59, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - emendas à Constituição;", "ordem": 454}, {"id": 455, "artigo_id": 59, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - leis complementares;", "ordem": 455}, {"id": 456, "artigo_id": 59, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - leis ordinárias;", "ordem": 456}, {"id": 457, "artigo_id": 59, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - leis delegadas;", "ordem": 457}, {"id": 458, "artigo_id": 59, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - medidas provisórias;", "ordem": 458}, {"id": 459, "artigo_id": 59, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - decretos legislativos;", "ordem": 459}, {"id": 460, "artigo_id": 59, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - resoluções.", "ordem": 460}, {"id": 461, "artigo_id": 60, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - de um terço, no mínimo, dos membros da Câmara dos Deputados ou do Senado Federal;", "ordem": 461}, {"id": 462, "artigo_id": 60, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - do Presidente da República;", "ordem": 462}, {"id": 463, "artigo_id": 60, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - de mais da metade das Assembléias Legislativas das unidades da Federação, manifestando-se, cada uma delas, pela maioria relativa de seus membros.", "ordem": 463}, {"id": 464, "artigo_id": 60, "paragrafo_id": 159, "numero_romano": "I", "numero_int": 1, "texto": "I - a forma federativa de Estado;", "ordem": 464}, {"id": 465, "artigo_id": 60, "paragrafo_id": 159, "numero_romano": "II", "numero_int": 2, "texto": "II - o voto direto, secreto, universal e periódico;", "ordem": 465}, {"id": 466, "artigo_id": 60, "paragrafo_id": 159, "numero_romano": "III", "numero_int": 3, "texto": "III - a separação dos Poderes;", "ordem": 466}, {"id": 467, "artigo_id": 60, "paragrafo_id": 159, "numero_romano": "IV", "numero_int": 4, "texto": "IV - os direitos e garantias individuais.", "ordem": 467}, {"id": 468, "artigo_id": 61, "paragrafo_id": 161, "numero_romano": "I", "numero_int": 1, "texto": "I - fixem ou modifiquem os efetivos das Forças Armadas;", "ordem": 468}, {"id": 469, "artigo_id": 61, "paragrafo_id": 161, "numero_romano": "II", "numero_int": 2, "texto": "II - disponham sobre:", "ordem": 469}, {"id": 470, "artigo_id": 62, "paragrafo_id": 163, "numero_romano": "I", "numero_int": 1, "texto": "I - relativa a:", "ordem": 470}, {"id": 471, "artigo_id": 62, "paragrafo_id": 163, "numero_romano": "II", "numero_int": 2, "texto": "II - que vise a detenção ou seqüestro de bens, de poupança popular ou qualquer outro ativo financeiro;", "ordem": 471}, {"id": 472, "artigo_id": 62, "paragrafo_id": 163, "numero_romano": "III", "numero_int": 3, "texto": "III - reservada a lei complementar;", "ordem": 472}, {"id": 473, "artigo_id": 62, "paragrafo_id": 163, "numero_romano": "IV", "numero_int": 4, "texto": "IV - já disciplinada em projeto de lei aprovado pelo Congresso Nacional e pendente de sanção ou veto do Presidente da República.", "ordem": 473}, {"id": 474, "artigo_id": 63, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - nos projetos de iniciativa exclusiva do Presidente da República, ressalvado o disposto no art. 166, § 3º e § 4º;", "ordem": 474}, {"id": 475, "artigo_id": 63, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - nos projetos sobre organização dos serviços administrativos da Câmara dos Deputados, do Senado Federal, dos Tribunais Federais e do Ministério Público.", "ordem": 475}, {"id": 476, "artigo_id": 68, "paragrafo_id": 184, "numero_romano": "I", "numero_int": 1, "texto": "I - organização do Poder Judiciário e do Ministério Público, a carreira e a garantia de seus membros;", "ordem": 476}, {"id": 477, "artigo_id": 68, "paragrafo_id": 184, "numero_romano": "II", "numero_int": 2, "texto": "II - nacionalidade, cidadania, direitos individuais, políticos e eleitorais;", "ordem": 477}, {"id": 478, "artigo_id": 68, "paragrafo_id": 184, "numero_romano": "III", "numero_int": 3, "texto": "III - planos plurianuais, diretrizes orçamentárias e orçamentos.", "ordem": 478}, {"id": 479, "artigo_id": 71, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - apreciar as contas prestadas anualmente pelo Presidente da República, mediante parecer prévio que deverá ser elaborado em sessenta dias a contar de seu recebimento;", "ordem": 479}, {"id": 480, "artigo_id": 71, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - julgar as contas dos administradores e demais responsáveis por dinheiros, bens e valores públicos da administração direta e indireta, incluídas as fundações e sociedades instituídas e mantidas pelo Poder Público federal, e as contas daqueles que derem causa a perda, extravio ou outra irregularidade de que resulte prejuízo ao erário público;", "ordem": 480}, {"id": 481, "artigo_id": 71, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - apreciar, para fins de registro, a legalidade dos atos de admissão de pessoal, a qualquer título, na administração direta e indireta, incluídas as fundações instituídas e mantidas pelo Poder Público, excetuadas as nomeações para cargo de provimento em comissão, bem como a das concessões de aposentadorias, reformas e pensões, ressalvadas as melhorias posteriores que não alterem o fundamento legal do ato concessório;", "ordem": 481}, {"id": 482, "artigo_id": 71, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - realizar, por iniciativa própria, da Câmara dos Deputados, do Senado Federal, de Comissão técnica ou de inquérito, inspeções e auditorias de natureza contábil, financeira, orçamentária, operacional e patrimonial, nas unidades administrativas dos Poderes Legislativo, Executivo e Judiciário, e demais entidades referidas no inciso II;", "ordem": 482}, {"id": 483, "artigo_id": 71, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - fiscalizar as contas nacionais das empresas supranacionais de cujo capital social a União participe, de forma direta ou indireta, nos termos do tratado constitutivo;", "ordem": 483}, {"id": 484, "artigo_id": 71, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - fiscalizar a aplicação de quaisquer recursos repassados pela União mediante convênio, acordo, ajuste ou outros instrumentos congêneres, a Estado, ao Distrito Federal ou a Município;", "ordem": 484}, {"id": 485, "artigo_id": 71, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - prestar as informações solicitadas pelo Congresso Nacional, por qualquer de suas Casas, ou por qualquer das respectivas Comissões, sobre a fiscalização contábil, financeira, orçamentária, operacional e patrimonial e sobre resultados de auditorias e inspeções realizadas;", "ordem": 485}, {"id": 486, "artigo_id": 71, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - aplicar aos responsáveis, em caso de ilegalidade de despesa ou irregularidade de contas, as sanções previstas em lei, que estabelecerá, entre outras cominações, multa proporcional ao dano causado ao erário;", "ordem": 486}, {"id": 487, "artigo_id": 71, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - assinar prazo para que o órgão ou entidade adote as providências necessárias ao exato cumprimento da lei, se verificada ilegalidade;", "ordem": 487}, {"id": 488, "artigo_id": 71, "paragrafo_id": null, "numero_romano": "X", "numero_int": 10, "texto": "X - sustar, se não atendido, a execução do ato impugnado, comunicando a decisão à Câmara dos Deputados e ao Senado Federal;", "ordem": 488}, {"id": 489, "artigo_id": 71, "paragrafo_id": null, "numero_romano": "XI", "numero_int": 11, "texto": "XI - representar ao Poder competente sobre irregularidades ou abusos apurados.", "ordem": 489}, {"id": 490, "artigo_id": 73, "paragrafo_id": 194, "numero_romano": "I", "numero_int": 1, "texto": "I - mais de trinta e cinco e menos de setenta anos de idade;", "ordem": 490}, {"id": 491, "artigo_id": 73, "paragrafo_id": 194, "numero_romano": "II", "numero_int": 2, "texto": "II - idoneidade moral e reputação ilibada;", "ordem": 491}, {"id": 492, "artigo_id": 73, "paragrafo_id": 194, "numero_romano": "III", "numero_int": 3, "texto": "III - notórios conhecimentos jurídicos, contábeis, econômicos e financeiros ou de administração pública;", "ordem": 492}, {"id": 493, "artigo_id": 73, "paragrafo_id": 194, "numero_romano": "IV", "numero_int": 4, "texto": "IV - mais de dez anos de exercício de função ou de efetiva atividade profissional que exija os conhecimentos mencionados no inciso anterior.", "ordem": 493}, {"id": 494, "artigo_id": 73, "paragrafo_id": 195, "numero_romano": "I", "numero_int": 1, "texto": "I - um terço pelo Presidente da República, com aprovação do Senado Federal, sendo dois alternadamente dentre auditores e membros do Ministério Público junto ao Tribunal, indicados em lista tríplice pelo Tribunal, segundo os critérios de antigüidade e merecimento;", "ordem": 494}, {"id": 495, "artigo_id": 73, "paragrafo_id": 195, "numero_romano": "II", "numero_int": 2, "texto": "II - dois terços pelo Congresso Nacional.", "ordem": 495}, {"id": 496, "artigo_id": 74, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - avaliar o cumprimento das metas previstas no plano plurianual, a execução dos programas de governo e dos orçamentos da União;", "ordem": 496}, {"id": 497, "artigo_id": 74, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - comprovar a legalidade e avaliar os resultados, quanto à eficácia e eficiência, da gestão orçamentária, financeira e patrimonial nos órgãos e entidades da administração federal, bem como da aplicação de recursos públicos por entidades de direito privado;", "ordem": 497}, {"id": 498, "artigo_id": 74, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - exercer o controle das operações de crédito, avais e garantias, bem como dos direitos e haveres da União;", "ordem": 498}, {"id": 499, "artigo_id": 74, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - apoiar o controle externo no exercício de sua missão institucional.", "ordem": 499}, {"id": 500, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - nomear e exonerar os Ministros de Estado;", "ordem": 500}, {"id": 501, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - exercer, com o auxílio dos Ministros de Estado, a direção superior da administração federal;", "ordem": 501}, {"id": 502, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - iniciar o processo legislativo, na forma e nos casos previstos nesta Constituição;", "ordem": 502}, {"id": 503, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - sancionar, promulgar e fazer publicar as leis, bem como expedir decretos e regulamentos para sua fiel execução;", "ordem": 503}, {"id": 504, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - vetar projetos de lei, total ou parcialmente;", "ordem": 504}, {"id": 505, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - dispor, mediante decreto, sobre:", "ordem": 505}, {"id": 506, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - manter relações com Estados estrangeiros e acreditar seus representantes diplomáticos;", "ordem": 506}, {"id": 507, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - celebrar tratados, convenções e atos internacionais, sujeitos a referendo do Congresso Nacional;", "ordem": 507}, {"id": 508, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - decretar o estado de defesa e o estado de sítio;", "ordem": 508}, {"id": 509, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "X", "numero_int": 10, "texto": "X - decretar e executar a intervenção federal;", "ordem": 509}, {"id": 510, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "XI", "numero_int": 11, "texto": "XI - remeter mensagem e plano de governo ao Congresso Nacional por ocasião da abertura da sessão legislativa, expondo a situação do País e solicitando as providências que julgar necessárias;", "ordem": 510}, {"id": 511, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "XII", "numero_int": 12, "texto": "XII - conceder indulto e comutar penas, com audiência, se necessário, dos órgãos instituídos em lei;", "ordem": 511}, {"id": 512, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "XIII", "numero_int": 13, "texto": "XIII - exercer o comando supremo das Forças Armadas, nomear os Comandantes da Marinha, do Exército e da Aeronáutica, promover seus oficiais-generais e nomeá-los para os cargos que lhes são privativos;", "ordem": 512}, {"id": 513, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "XIV", "numero_int": 14, "texto": "XIV - nomear, após aprovação pelo Senado Federal, os Ministros do Supremo Tribunal Federal e dos Tribunais Superiores, os Governadores de Territórios, o Procurador-Geral da República, o presidente e os diretores do banco central e outros servidores, quando determinado em lei;", "ordem": 513}, {"id": 514, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "XV", "numero_int": 15, "texto": "XV - nomear, observado o disposto no art. 73, os Ministros do Tribunal de Contas da União;", "ordem": 514}, {"id": 515, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "XVI", "numero_int": 16, "texto": "XVI - nomear os magistrados, nos casos previstos nesta Constituição, e o Advogado-Geral da União;", "ordem": 515}, {"id": 516, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "XVII", "numero_int": 17, "texto": "XVII - nomear membros do Conselho da República, nos termos do art. 89, VII;", "ordem": 516}, {"id": 517, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "XVIII", "numero_int": 18, "texto": "XVIII - convocar e presidir o Conselho da República e o Conselho de Defesa Nacional;", "ordem": 517}, {"id": 518, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "XIX", "numero_int": 19, "texto": "XIX - declarar guerra, no caso de agressão estrangeira, autorizado pelo Congresso Nacional ou referendado por ele, quando ocorrida no intervalo das sessões legislativas, e, nas mesmas condições, decretar, total ou parcialmente, a mobilização nacional;", "ordem": 518}, {"id": 519, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "XX", "numero_int": 20, "texto": "XX - celebrar a paz, autorizado ou com o referendo do Congresso Nacional;", "ordem": 519}, {"id": 520, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "XXI", "numero_int": 21, "texto": "XXI - conferir condecorações e distinções honoríficas;", "ordem": 520}, {"id": 521, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "XXII", "numero_int": 22, "texto": "XXII - permitir, nos casos previstos em lei complementar, que forças estrangeiras transitem pelo território nacional ou nele permaneçam temporariamente;", "ordem": 521}, {"id": 522, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "XXIII", "numero_int": 23, "texto": "XXIII - enviar ao Congresso Nacional o plano plurianual, o projeto de lei de diretrizes orçamentárias e as propostas de orçamento previstos nesta Constituição;", "ordem": 522}, {"id": 523, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "XXIV", "numero_int": 24, "texto": "XXIV - prestar, anualmente, ao Congresso Nacional, dentro de sessenta dias após a abertura da sessão legislativa, as contas referentes ao exercício anterior;", "ordem": 523}, {"id": 524, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "XXV", "numero_int": 25, "texto": "XXV - prover e extinguir os cargos públicos federais, na forma da lei;", "ordem": 524}, {"id": 525, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "XXVI", "numero_int": 26, "texto": "XXVI - editar medidas provisórias com força de lei, nos termos do art. 62;", "ordem": 525}, {"id": 526, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "XXVII", "numero_int": 27, "texto": "XXVII - exercer outras atribuições previstas nesta Constituição.", "ordem": 526}, {"id": 527, "artigo_id": 84, "paragrafo_id": null, "numero_romano": "XXVIII", "numero_int": 28, "texto": "XXVIII - propor ao Congresso Nacional a decretação do estado de calamidade pública de âmbito nacional previsto nos arts. 167-B, 167-C, 167-D, 167-E, 167-F e 167-G desta Constituição.", "ordem": 527}, {"id": 528, "artigo_id": 85, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - a existência da União;", "ordem": 528}, {"id": 529, "artigo_id": 85, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - o livre exercício do Poder Legislativo, do Poder Judiciário, do Ministério Público e dos Poderes constitucionais das unidades da Federação;", "ordem": 529}, {"id": 530, "artigo_id": 85, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - o exercício dos direitos políticos, individuais e sociais;", "ordem": 530}, {"id": 531, "artigo_id": 85, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - a segurança interna do País;", "ordem": 531}, {"id": 532, "artigo_id": 85, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - a probidade na administração;", "ordem": 532}, {"id": 533, "artigo_id": 85, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - a lei orçamentária;", "ordem": 533}, {"id": 534, "artigo_id": 85, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - o cumprimento das leis e das decisões judiciais.", "ordem": 534}, {"id": 535, "artigo_id": 86, "paragrafo_id": 212, "numero_romano": "I", "numero_int": 1, "texto": "I - nas infrações penais comuns, se recebida a denúncia ou queixa-crime pelo Supremo Tribunal Federal;", "ordem": 535}, {"id": 536, "artigo_id": 86, "paragrafo_id": 212, "numero_romano": "II", "numero_int": 2, "texto": "II - nos crimes de responsabilidade, após a instauração do processo pelo Senado Federal.", "ordem": 536}, {"id": 537, "artigo_id": 87, "paragrafo_id": 216, "numero_romano": "I", "numero_int": 1, "texto": "I - exercer a orientação, coordenação e supervisão dos órgãos e entidades da administração federal na área de sua competência e referendar os atos e decretos assinados pelo Presidente da República;", "ordem": 537}, {"id": 538, "artigo_id": 87, "paragrafo_id": 216, "numero_romano": "II", "numero_int": 2, "texto": "II - expedir instruções para a execução das leis, decretos e regulamentos;", "ordem": 538}, {"id": 539, "artigo_id": 87, "paragrafo_id": 216, "numero_romano": "III", "numero_int": 3, "texto": "III - apresentar ao Presidente da República relatório anual de sua gestão no Ministério;", "ordem": 539}, {"id": 540, "artigo_id": 87, "paragrafo_id": 216, "numero_romano": "IV", "numero_int": 4, "texto": "IV - praticar os atos pertinentes às atribuições que lhe forem outorgadas ou delegadas pelo Presidente da República.", "ordem": 540}, {"id": 541, "artigo_id": 89, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - o Vice-Presidente da República;", "ordem": 541}, {"id": 542, "artigo_id": 89, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - o Presidente da Câmara dos Deputados;", "ordem": 542}, {"id": 543, "artigo_id": 89, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - o Presidente do Senado Federal;", "ordem": 543}, {"id": 544, "artigo_id": 89, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - os líderes da maioria e da minoria na Câmara dos Deputados;", "ordem": 544}, {"id": 545, "artigo_id": 89, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - os líderes da maioria e da minoria no Senado Federal;", "ordem": 545}, {"id": 546, "artigo_id": 89, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - o Ministro da Justiça;", "ordem": 546}, {"id": 547, "artigo_id": 89, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - seis cidadãos brasileiros natos, com mais de trinta e cinco anos de idade, sendo dois nomeados pelo Presidente da República, dois eleitos pelo Senado Federal e dois eleitos pela Câmara dos Deputados, todos com mandato de três anos, vedada a recondução.", "ordem": 547}, {"id": 548, "artigo_id": 90, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - intervenção federal, estado de defesa e estado de sítio;", "ordem": 548}, {"id": 549, "artigo_id": 90, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - as questões relevantes para a estabilidade das instituições democráticas.", "ordem": 549}, {"id": 550, "artigo_id": 91, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - o Vice-Presidente da República;", "ordem": 550}, {"id": 551, "artigo_id": 91, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - o Presidente da Câmara dos Deputados;", "ordem": 551}, {"id": 552, "artigo_id": 91, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - o Presidente do Senado Federal;", "ordem": 552}, {"id": 553, "artigo_id": 91, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - o Ministro da Justiça;", "ordem": 553}, {"id": 554, "artigo_id": 91, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - o Ministro de Estado da Defesa;", "ordem": 554}, {"id": 555, "artigo_id": 91, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - o Ministro das Relações Exteriores;", "ordem": 555}, {"id": 556, "artigo_id": 91, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - o Ministro do Planejamento.", "ordem": 556}, {"id": 557, "artigo_id": 91, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - os Comandantes da Marinha, do Exército e da Aeronáutica.", "ordem": 557}, {"id": 558, "artigo_id": 91, "paragrafo_id": 219, "numero_romano": "I", "numero_int": 1, "texto": "I - opinar nas hipóteses de declaração de guerra e de celebração da paz, nos termos desta Constituição;", "ordem": 558}, {"id": 559, "artigo_id": 91, "paragrafo_id": 219, "numero_romano": "II", "numero_int": 2, "texto": "II - opinar sobre a decretação do estado de defesa, do estado de sítio e da intervenção federal;", "ordem": 559}, {"id": 560, "artigo_id": 91, "paragrafo_id": 219, "numero_romano": "III", "numero_int": 3, "texto": "III - propor os critérios e condições de utilização de áreas indispensáveis à segurança do território nacional e opinar sobre seu efetivo uso, especialmente na faixa de fronteira e nas relacionadas com a preservação e a exploração dos recursos naturais de qualquer tipo;", "ordem": 560}, {"id": 561, "artigo_id": 91, "paragrafo_id": 219, "numero_romano": "IV", "numero_int": 4, "texto": "IV - estudar, propor e acompanhar o desenvolvimento de iniciativas necessárias a garantir a independência nacional e a defesa do Estado democrático.", "ordem": 561}, {"id": 562, "artigo_id": 92, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - o Supremo Tribunal Federal;", "ordem": 562}, {"id": 563, "artigo_id": 92, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - o Superior Tribunal de Justiça;", "ordem": 563}, {"id": 564, "artigo_id": 92, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - os Tribunais Regionais Federais e Juízes Federais;", "ordem": 564}, {"id": 565, "artigo_id": 92, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - os Tribunais e Juízes do Trabalho;", "ordem": 565}, {"id": 566, "artigo_id": 92, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - os Tribunais e Juízes Eleitorais;", "ordem": 566}, {"id": 567, "artigo_id": 92, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - os Tribunais e Juízes Militares;", "ordem": 567}, {"id": 568, "artigo_id": 92, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - os Tribunais e Juízes dos Estados e do Distrito Federal e Territórios.", "ordem": 568}, {"id": 569, "artigo_id": 93, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - ingresso na carreira, cujo cargo inicial será o de juiz substituto, mediante concurso público de provas e títulos, com a participação da Ordem dos Advogados do Brasil em todas as fases, exigindo-se do bacharel em direito, no mínimo, três anos de atividade jurídica e obedecendo-se, nas nomeações, à ordem de classificação;", "ordem": 569}, {"id": 570, "artigo_id": 93, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - promoção de entrância para entrância, alternadamente, por antigüidade e merecimento, atendidas as seguintes normas:", "ordem": 570}, {"id": 571, "artigo_id": 93, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - a aposentadoria dos magistrados e a pensão de seus dependentes observarão o disposto no art. 40;", "ordem": 571}, {"id": 572, "artigo_id": 93, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - o ato de remoção ou de disponibilidade do magistrado, por interesse público, fundar-se-á em decisão por voto da maioria absoluta do respectivo tribunal ou do Conselho Nacional de Justiça, assegurada ampla defesa;", "ordem": 572}, {"id": 573, "artigo_id": 95, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - vitaliciedade, que, no primeiro grau, só será adquirida após dois anos de exercício, dependendo a perda do cargo, nesse período, de deliberação do tribunal a que o juiz estiver vinculado, e, nos demais casos, de sentença judicial transitada em julgado;", "ordem": 573}, {"id": 574, "artigo_id": 95, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - inamovibilidade, salvo por motivo de interesse público, na forma do art. 93, VIII;", "ordem": 574}, {"id": 575, "artigo_id": 95, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - irredutibilidade de subsídio, ressalvado o disposto nos arts. 37, X e XI, 39, § 4º, 150, II, 153, III, e 153, § 2º, I.", "ordem": 575}, {"id": 576, "artigo_id": 95, "paragrafo_id": 224, "numero_romano": "I", "numero_int": 1, "texto": "I - exercer, ainda que em disponibilidade, outro cargo ou função, salvo uma de magistério;", "ordem": 576}, {"id": 577, "artigo_id": 95, "paragrafo_id": 224, "numero_romano": "II", "numero_int": 2, "texto": "II - receber, a qualquer título ou pretexto, custas ou participação em processo;", "ordem": 577}, {"id": 578, "artigo_id": 95, "paragrafo_id": 224, "numero_romano": "III", "numero_int": 3, "texto": "III - dedicar-se à atividade político-partidária.", "ordem": 578}, {"id": 579, "artigo_id": 95, "paragrafo_id": 224, "numero_romano": "IV", "numero_int": 4, "texto": "IV - receber, a qualquer título ou pretexto, auxílios ou contribuições de pessoas físicas, entidades públicas ou privadas, ressalvadas as exceções previstas em lei;", "ordem": 579}, {"id": 580, "artigo_id": 95, "paragrafo_id": 224, "numero_romano": "V", "numero_int": 5, "texto": "V - exercer a advocacia no juízo ou tribunal do qual se afastou, antes de decorridos três anos do afastamento do cargo por aposentadoria ou exoneração.", "ordem": 580}, {"id": 581, "artigo_id": 96, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - aos tribunais:", "ordem": 581}, {"id": 582, "artigo_id": 96, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - ao Supremo Tribunal Federal, aos Tribunais Superiores e aos Tribunais de Justiça propor ao Poder Legislativo respectivo, observado o disposto no art. 169:", "ordem": 582}, {"id": 583, "artigo_id": 96, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - aos Tribunais de Justiça julgar os juízes estaduais e do Distrito Federal e Territórios, bem como os membros do Ministério Público, nos crimes comuns e de responsabilidade, ressalvada a competência da Justiça Eleitoral.", "ordem": 583}, {"id": 584, "artigo_id": 98, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - juizados especiais, providos por juízes togados, ou togados e leigos, competentes para a conciliação, o julgamento e a execução de causas cíveis de menor complexidade e infrações penais de menor potencial ofensivo, mediante os procedimentos oral e sumaríssimo , permitidos, nas hipóteses previstas em lei, a transação e o julgamento de recursos por turmas de juízes de primeiro grau;", "ordem": 584}, {"id": 585, "artigo_id": 98, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - justiça de paz, remunerada, composta de cidadãos eleitos pelo voto direto, universal e secreto, com mandato de quatro anos e competência para, na forma da lei, celebrar casamentos, verificar, de ofício ou em face de impugnação apresentada, o processo de habilitação e exercer atribuições conciliatórias, sem caráter jurisdicional, além de outras previstas na legislação.", "ordem": 585}, {"id": 586, "artigo_id": 99, "paragrafo_id": 229, "numero_romano": "I", "numero_int": 1, "texto": "I - no âmbito da União, aos Presidentes do Supremo Tribunal Federal e dos Tribunais Superiores, com a aprovação dos respectivos tribunais;", "ordem": 586}, {"id": 587, "artigo_id": 99, "paragrafo_id": 229, "numero_romano": "II", "numero_int": 2, "texto": "II - no âmbito dos Estados e no do Distrito Federal e Territórios, aos Presidentes dos Tribunais de Justiça, com a aprovação dos respectivos tribunais.", "ordem": 587}, {"id": 588, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "I", "numero_int": 1, "texto": "I - quitação de débitos parcelados ou débitos inscritos em dívida ativa do ente federativo devedor, inclusive em transação resolutiva de litígio, e, subsidiariamente, débitos com a administração autárquica e fundacional do mesmo ente;", "ordem": 588}, {"id": 589, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "II", "numero_int": 2, "texto": "II - compra de imóveis públicos de propriedade do mesmo ente disponibilizados para venda;", "ordem": 589}, {"id": 590, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "III", "numero_int": 3, "texto": "III - pagamento de outorga de delegações de serviços públicos e demais espécies de concessão negocial promovidas pelo mesmo ente;", "ordem": 590}, {"id": 591, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "IV", "numero_int": 4, "texto": "IV - aquisição, inclusive minoritária, de participação societária, disponibilizada para venda, do respectivo ente federativo; ou", "ordem": 591}, {"id": 592, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "V", "numero_int": 5, "texto": "V - compra de direitos, disponibilizados para cessão, do respectivo ente federativo, inclusive, no caso da União, da antecipação de valores a serem recebidos a título do excedente em óleo em contratos de partilha de petróleo.", "ordem": 592}, {"id": 593, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "I", "numero_int": 1, "texto": "I - na União, as parcelas entregues aos Estados, ao Distrito Federal e aos Municípios por determinação constitucional;", "ordem": 593}, {"id": 594, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "II", "numero_int": 2, "texto": "II - nos Estados, as parcelas entregues aos Municípios por determinação constitucional;", "ordem": 594}, {"id": 595, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "III", "numero_int": 3, "texto": "III - na União, nos Estados, no Distrito Federal e nos Municípios, a contribuição dos servidores para custeio de seu sistema de previdência e assistência social e as receitas provenientes da compensação financeira referida no § 9º do art. 201 da Constituição Federal.", "ordem": 595}, {"id": 596, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "I", "numero_int": 1, "texto": "I - nos contratos de refinanciamento cujos créditos sejam detidos pelo ente federativo que figure como devedor na sentença de que trata o caput deste artigo;", "ordem": 596}, {"id": 597, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "II", "numero_int": 2, "texto": "II - nos contratos em que houve prestação de garantia a outro ente federativo;", "ordem": 597}, {"id": 598, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "III", "numero_int": 3, "texto": "III - nos parcelamentos de tributos ou de contribuições sociais; e", "ordem": 598}, {"id": 599, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "IV", "numero_int": 4, "texto": "IV - nas obrigações decorrentes do descumprimento de prestação de contas ou de desvio de recursos.", "ordem": 599}, {"id": 600, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "I", "numero_int": 1, "texto": "I - nas obrigações vencidas, será imputada primeiramente às parcelas mais antigas;", "ordem": 600}, {"id": 601, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "II", "numero_int": 2, "texto": "II - nas obrigações vincendas, reduzirá uniformemente o valor de cada parcela devida, mantida a duração original do respectivo contrato ou parcelamento.", "ordem": 601}, {"id": 602, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "I", "numero_int": 1, "texto": "I - 1% (um por cento) da receita corrente líquida apurada no exercício financeiro anterior, para os entes federativos que não possuam estoque e para os entes federativos cujo estoque de precatórios em mora, atualizados monetariamente e acrescidos de juros moratórios, em 1º de janeiro, não superar 15% (quinze por cento) desse valor;", "ordem": 602}, {"id": 603, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "II", "numero_int": 2, "texto": "II - 1,5% (um inteiro e cinco décimos por cento) da receita corrente líquida apurada no exercício financeiro anterior, se o estoque de precatórios em mora, atualizados monetariamente e acrescidos de juros moratórios, em 1º de janeiro, for superior a 15% (quinze por cento) e inferior ou igual a 25% (vinte e cinco por cento) desse valor;", "ordem": 603}, {"id": 604, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "III", "numero_int": 3, "texto": "III - 2% (dois por cento) da receita corrente líquida apurada no exercício financeiro anterior, se o estoque de precatórios em mora, atualizados monetariamente e acrescidos de juros moratórios, em 1º de janeiro, for superior a 25% (vinte e cinco por cento) e inferior ou igual a 35% (trinta e cinco por cento) desse valor;", "ordem": 604}, {"id": 605, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "IV", "numero_int": 4, "texto": "IV - 2,5% (dois inteiros e cinco décimos por cento) da receita corrente líquida apurada no exercício financeiro anterior, se o estoque de precatórios em mora, atualizados monetariamente e acrescidos de juros moratórios, em 1º de janeiro, for superior a 35% (trinta e cinco por cento) e inferior ou igual a 45% (quarenta e cinco por cento) desse valor;", "ordem": 605}, {"id": 606, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "V", "numero_int": 5, "texto": "V - 3% (três por cento) da receita corrente líquida apurada no exercício financeiro anterior, se o estoque de precatórios em mora, atualizados monetariamente e acrescidos de juros moratórios, em 1º de janeiro, for superior a 45% (quarenta e cinco por cento) e inferior ou igual a 55% (cinquenta e cinco por cento) desse valor;", "ordem": 606}, {"id": 607, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "VI", "numero_int": 6, "texto": "VI - 3,5% (três inteiros e cinco décimos por cento) da receita corrente líquida apurada no exercício financeiro anterior, se o estoque de precatórios em mora, atualizados monetariamente e acrescidos de juros moratórios, em 1º de janeiro, for superior a 55% (cinquenta e cinco por cento) e inferior ou igual a 65% (sessenta e cinco por cento) desse valor;", "ordem": 607}, {"id": 608, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "VII", "numero_int": 7, "texto": "VII - 4% (quatro por cento) da receita corrente líquida apurada no exercício financeiro anterior, se o estoque de precatórios em mora, atualizados monetariamente e acrescidos de juros moratórios, em 1º de janeiro, for superior a 65% (sessenta e cinco por cento) e inferior ou igual a 75% (setenta e cinco por cento) desse valor;", "ordem": 608}, {"id": 609, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - 4,5% (quatro inteiros e cinco décimos por cento) da receita corrente líquida apurada no exercício financeiro anterior, se o estoque de precatórios em mora, atualizados monetariamente e acrescidos de juros moratórios, em 1º de janeiro, for superior a 75% (setenta e cinco por cento) e inferior ou igual a 85% (oitenta e cinco por cento) desse valor;", "ordem": 609}, {"id": 610, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "IX", "numero_int": 9, "texto": "IX - 5% (cinco por cento) da receita corrente líquida apurada no exercício financeiro anterior, se o estoque de precatórios em mora, atualizados monetariamente e acrescidos de juros moratórios, em 1º de janeiro, for superior a 85% (oitenta e cinco por cento) desse valor.", "ordem": 610}, {"id": 611, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "I", "numero_int": 1, "texto": "I - os limites de que trata o § 23 deste artigo serão suspensos;", "ordem": 611}, {"id": 612, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "II", "numero_int": 2, "texto": "II - o Presidente do Tribunal de Justiça local determinará o sequestro, até o limite do valor devido, das contas municipais, estaduais ou distrital do ente federativo inadimplente para fins de pagamento de precatórios;", "ordem": 612}, {"id": 613, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "III", "numero_int": 3, "texto": "III - o Governador do Estado ou do Distrito Federal ou o Prefeito do Município inadimplente responderá na forma da legislação de responsabilidade fiscal e de improbidade administrativa;", "ordem": 613}, {"id": 614, "artigo_id": 100, "paragrafo_id": 241, "numero_romano": "IV", "numero_int": 4, "texto": "IV - o Estado, o Distrito Federal ou o Município ficará impedido de receber transferências voluntárias, enquanto perdurar a omissão.", "ordem": 614}, {"id": 615, "artigo_id": 102, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - processar e julgar, originariamente:", "ordem": 615}, {"id": 616, "artigo_id": 102, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - julgar, em recurso ordinário:", "ordem": 616}, {"id": 617, "artigo_id": 102, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - julgar, mediante recurso extraordinário, as causas decididas em única ou última instância, quando a decisão recorrida:", "ordem": 617}, {"id": 618, "artigo_id": 103, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - o Presidente da República;", "ordem": 618}, {"id": 619, "artigo_id": 103, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - a Mesa do Senado Federal;", "ordem": 619}, {"id": 620, "artigo_id": 103, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - a Mesa da Câmara dos Deputados;", "ordem": 620}, {"id": 621, "artigo_id": 103, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - a Mesa de Assembléia Legislativa ou da Câmara Legislativa do Distrito Federal;", "ordem": 621}, {"id": 622, "artigo_id": 103, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - o Governador de Estado ou do Distrito Federal;", "ordem": 622}, {"id": 623, "artigo_id": 103, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - o Procurador-Geral da República;", "ordem": 623}, {"id": 624, "artigo_id": 103, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - o Conselho Federal da Ordem dos Advogados do Brasil;", "ordem": 624}, {"id": 625, "artigo_id": 103, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - partido político com representação no Congresso Nacional;", "ordem": 625}, {"id": 626, "artigo_id": 103, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - confederação sindical ou entidade de classe de âmbito nacional.", "ordem": 626}, {"id": 627, "artigo_id": 103, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - o Presidente do Supremo Tribunal Federal;", "ordem": 627}, {"id": 628, "artigo_id": 103, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - um Ministro do Superior Tribunal de Justiça, indicado pelo respectivo tribunal;", "ordem": 628}, {"id": 629, "artigo_id": 103, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - um Ministro do Tribunal Superior do Trabalho, indicado pelo respectivo tribunal;", "ordem": 629}, {"id": 630, "artigo_id": 103, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - um desembargador de Tribunal de Justiça, indicado pelo Supremo Tribunal Federal;", "ordem": 630}, {"id": 631, "artigo_id": 103, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - um juiz estadual, indicado pelo Supremo Tribunal Federal;", "ordem": 631}, {"id": 632, "artigo_id": 103, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - um juiz de Tribunal Regional Federal, indicado pelo Superior Tribunal de Justiça;", "ordem": 632}, {"id": 633, "artigo_id": 103, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - um juiz federal, indicado pelo Superior Tribunal de Justiça;", "ordem": 633}, {"id": 634, "artigo_id": 103, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - um juiz de Tribunal Regional do Trabalho, indicado pelo Tribunal Superior do Trabalho;", "ordem": 634}, {"id": 635, "artigo_id": 103, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - um juiz do trabalho, indicado pelo Tribunal Superior do Trabalho;", "ordem": 635}, {"id": 636, "artigo_id": 103, "paragrafo_id": null, "numero_romano": "X", "numero_int": 10, "texto": "X - um membro do Ministério Público da União, indicado pelo Procurador-Geral da República;", "ordem": 636}, {"id": 637, "artigo_id": 103, "paragrafo_id": null, "numero_romano": "XII", "numero_int": 12, "texto": "XII - dois advogados, indicados pelo Conselho Federal da Ordem dos Advogados do Brasil;", "ordem": 637}, {"id": 638, "artigo_id": 103, "paragrafo_id": null, "numero_romano": "XIII", "numero_int": 13, "texto": "XIII - dois cidadãos, de notável saber jurídico e reputação ilibada, indicados um pela Câmara dos Deputados e outro pelo Senado Federal.", "ordem": 638}, {"id": 639, "artigo_id": 103, "paragrafo_id": 255, "numero_romano": "I", "numero_int": 1, "texto": "I - zelar pela autonomia do Poder Judiciário e pelo cumprimento do Estatuto da Magistratura, podendo expedir atos regulamentares, no âmbito de sua competência, ou recomendar providências;", "ordem": 639}, {"id": 640, "artigo_id": 103, "paragrafo_id": 255, "numero_romano": "II", "numero_int": 2, "texto": "II - zelar pela observância do art. 37 e apreciar, de ofício ou mediante provocação, a legalidade dos atos administrativos praticados por membros ou órgãos do Poder Judiciário, podendo desconstituí-los, revê-los ou fixar prazo para que se adotem as providências necessárias ao exato cumprimento da lei, sem prejuízo da competência do Tribunal de Contas da União;", "ordem": 640}, {"id": 641, "artigo_id": 103, "paragrafo_id": 255, "numero_romano": "III", "numero_int": 3, "texto": "III - receber e conhecer das reclamações contra membros ou órgãos do Poder Judiciário, inclusive contra seus serviços auxiliares, serventias e órgãos prestadores de serviços notariais e de registro que atuem por delegação do poder público ou oficializados, sem prejuízo da competência disciplinar e correicional dos tribunais, podendo avocar processos disciplinares em curso, determinar a remoção ou a disponibilidade e aplicar outras sanções administrativas, assegurada ampla defesa;", "ordem": 641}, {"id": 642, "artigo_id": 103, "paragrafo_id": 255, "numero_romano": "IV", "numero_int": 4, "texto": "IV - representar ao Ministério Público, no caso de crime contra a administração pública ou de abuso de autoridade;", "ordem": 642}, {"id": 643, "artigo_id": 103, "paragrafo_id": 255, "numero_romano": "V", "numero_int": 5, "texto": "V - rever, de ofício ou mediante provocação, os processos disciplinares de juízes e membros de tribunais julgados há menos de um ano;", "ordem": 643}, {"id": 644, "artigo_id": 103, "paragrafo_id": 255, "numero_romano": "VI", "numero_int": 6, "texto": "VI - elaborar semestralmente relatório estatístico sobre processos e sentenças prolatadas, por unidade da Federação, nos diferentes órgãos do Poder Judiciário;", "ordem": 644}, {"id": 645, "artigo_id": 103, "paragrafo_id": 255, "numero_romano": "VII", "numero_int": 7, "texto": "VII - elaborar relatório anual, propondo as providências que julgar necessárias, sobre a situação do Poder Judiciário no País e as atividades do Conselho, o qual deve integrar mensagem do Presidente do Supremo Tribunal Federal a ser remetida ao Congresso Nacional, por ocasião da abertura da sessão legislativa.", "ordem": 645}, {"id": 646, "artigo_id": 104, "paragrafo_id": 259, "numero_romano": "I", "numero_int": 1, "texto": "I - um terço dentre juízes dos Tribunais Regionais Federais e um terço dentre desembargadores dos Tribunais de Justiça, indicados em lista tríplice elaborada pelo próprio Tribunal;", "ordem": 646}, {"id": 647, "artigo_id": 104, "paragrafo_id": 259, "numero_romano": "II", "numero_int": 2, "texto": "II - um terço, em partes iguais, dentre advogados e membros do Ministério Público Federal, Estadual, do Distrito Federal e Territórios, alternadamente, indicados na forma do art. 94.", "ordem": 647}, {"id": 648, "artigo_id": 105, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - processar e julgar, originariamente:", "ordem": 648}, {"id": 649, "artigo_id": 105, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - julgar, em recurso ordinário:", "ordem": 649}, {"id": 650, "artigo_id": 105, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - julgar, em recurso especial, as causas decididas, em única ou última instância, pelos Tribunais Regionais Federais ou pelos tribunais dos Estados, do Distrito Federal e Territórios, quando a decisão recorrida:", "ordem": 650}, {"id": 651, "artigo_id": 105, "paragrafo_id": 260, "numero_romano": "I", "numero_int": 1, "texto": "I - a Escola Nacional de Formação e Aperfeiçoamento de Magistrados, cabendo-lhe, dentre outras funções, regulamentar os cursos oficiais para o ingresso e promoção na carreira;", "ordem": 651}, {"id": 652, "artigo_id": 105, "paragrafo_id": 260, "numero_romano": "II", "numero_int": 2, "texto": "II - o Conselho da Justiça Federal, cabendo-lhe exercer, na forma da lei, a supervisão administrativa e orçamentária da Justiça Federal de primeiro e segundo graus, como órgão central do sistema e com poderes correicionais, cujas decisões terão caráter vinculante.", "ordem": 652}, {"id": 653, "artigo_id": 105, "paragrafo_id": 262, "numero_romano": "I", "numero_int": 1, "texto": "I - ações penais;", "ordem": 653}, {"id": 654, "artigo_id": 105, "paragrafo_id": 262, "numero_romano": "II", "numero_int": 2, "texto": "II - ações de improbidade administrativa;", "ordem": 654}, {"id": 655, "artigo_id": 105, "paragrafo_id": 262, "numero_romano": "III", "numero_int": 3, "texto": "III - ações cujo valor da causa ultrapasse 500 (quinhentos) salários mínimos;", "ordem": 655}, {"id": 656, "artigo_id": 105, "paragrafo_id": 262, "numero_romano": "IV", "numero_int": 4, "texto": "IV - ações que possam gerar inelegibilidade;", "ordem": 656}, {"id": 657, "artigo_id": 105, "paragrafo_id": 262, "numero_romano": "V", "numero_int": 5, "texto": "V - hipóteses em que o acórdão recorrido contrariar jurisprudência dominante do Superior Tribunal de Justiça;", "ordem": 657}, {"id": 658, "artigo_id": 105, "paragrafo_id": 262, "numero_romano": "VI", "numero_int": 6, "texto": "VI - outras hipóteses previstas em lei.", "ordem": 658}, {"id": 659, "artigo_id": 106, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - os Tribunais Regionais Federais;", "ordem": 659}, {"id": 660, "artigo_id": 106, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - os Juízes Federais.", "ordem": 660}, {"id": 661, "artigo_id": 107, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - um quinto dentre advogados com mais de dez anos de efetiva atividade profissional e membros do Ministério Público Federal com mais de dez anos de carreira;", "ordem": 661}, {"id": 662, "artigo_id": 107, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - os demais, mediante promoção de juízes federais com mais de cinco anos de exercício, por antigüidade e merecimento, alternadamente.", "ordem": 662}, {"id": 663, "artigo_id": 108, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - processar e julgar, originariamente:", "ordem": 663}, {"id": 664, "artigo_id": 108, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - julgar, em grau de recurso, as causas decididas pelos juízes federais e pelos juízes estaduais no exercício da competência federal da área de sua jurisdição.", "ordem": 664}, {"id": 665, "artigo_id": 109, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - as causas em que a União, entidade autárquica ou empresa pública federal forem interessadas na condição de autoras, rés, assistentes ou oponentes, exceto as de falência, as de acidentes de trabalho e as sujeitas à Justiça Eleitoral e à Justiça do Trabalho;", "ordem": 665}, {"id": 666, "artigo_id": 109, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - as causas entre Estado estrangeiro ou organismo internacional e Município ou pessoa domiciliada ou residente no País;", "ordem": 666}, {"id": 667, "artigo_id": 109, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - as causas fundadas em tratado ou contrato da União com Estado estrangeiro ou organismo internacional;", "ordem": 667}, {"id": 668, "artigo_id": 109, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - os crimes políticos e as infrações penais praticadas em detrimento de bens, serviços ou interesse da União ou de suas entidades autárquicas ou empresas públicas, excluídas as contravenções e ressalvada a competência da Justiça Militar e da Justiça Eleitoral;", "ordem": 668}, {"id": 669, "artigo_id": 109, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - os crimes previstos em tratado ou convenção internacional, quando, iniciada a execução no País, o resultado tenha ou devesse ter ocorrido no estrangeiro, ou reciprocamente;", "ordem": 669}, {"id": 670, "artigo_id": 109, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - os crimes contra a organização do trabalho e, nos casos determinados por lei, contra o sistema financeiro e a ordem econômico-financeira;", "ordem": 670}, {"id": 671, "artigo_id": 109, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - os habeas corpus , em matéria criminal de sua competência ou quando o constrangimento provier de autoridade cujos atos não estejam diretamente sujeitos a outra jurisdição;", "ordem": 671}, {"id": 672, "artigo_id": 109, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - os mandados de segurança e os habeas data contra ato de autoridade federal, excetuados os casos de competência dos tribunais federais;", "ordem": 672}, {"id": 673, "artigo_id": 109, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - os crimes cometidos a bordo de navios ou aeronaves, ressalvada a competência da Justiça Militar;", "ordem": 673}, {"id": 674, "artigo_id": 109, "paragrafo_id": null, "numero_romano": "X", "numero_int": 10, "texto": "X - os crimes de ingresso ou permanência irregular de estrangeiro, a execução de carta rogatória, após o \"exequatur\", e de sentença estrangeira, após a homologação, as causas referentes à nacionalidade, inclusive a respectiva opção, e à naturalização;", "ordem": 674}, {"id": 675, "artigo_id": 109, "paragrafo_id": null, "numero_romano": "XI", "numero_int": 11, "texto": "XI - a disputa sobre direitos indígenas.", "ordem": 675}, {"id": 676, "artigo_id": 111, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - o Tribunal Superior do Trabalho;", "ordem": 676}, {"id": 677, "artigo_id": 111, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - os Tribunais Regionais do Trabalho;", "ordem": 677}, {"id": 678, "artigo_id": 111, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - Juizes do Trabalho.", "ordem": 678}, {"id": 679, "artigo_id": 117, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - o Tribunal Superior Eleitoral;", "ordem": 679}, {"id": 680, "artigo_id": 117, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - os Tribunais Regionais Eleitorais;", "ordem": 680}, {"id": 681, "artigo_id": 117, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - os Juízes Eleitorais;", "ordem": 681}, {"id": 682, "artigo_id": 117, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - as Juntas Eleitorais.", "ordem": 682}, {"id": 683, "artigo_id": 118, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - mediante eleição, pelo voto secreto:", "ordem": 683}, {"id": 684, "artigo_id": 118, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - por nomeação do Presidente da República, dois juízes dentre seis advogados de notável saber jurídico e idoneidade moral, indicados pelo Supremo Tribunal Federal.", "ordem": 684}, {"id": 685, "artigo_id": 119, "paragrafo_id": 281, "numero_romano": "I", "numero_int": 1, "texto": "I - mediante eleição, pelo voto secreto:", "ordem": 685}, {"id": 686, "artigo_id": 119, "paragrafo_id": 281, "numero_romano": "II", "numero_int": 2, "texto": "II - de um juiz do Tribunal Regional Federal com sede na Capital do Estado ou no Distrito Federal, ou, não havendo, de juiz federal, escolhido, em qualquer caso, pelo Tribunal Regional Federal respectivo;", "ordem": 686}, {"id": 687, "artigo_id": 119, "paragrafo_id": 281, "numero_romano": "III", "numero_int": 3, "texto": "III - por nomeação, pelo Presidente da República, de dois juízes dentre seis advogados de notável saber jurídico e idoneidade moral, indicados pelo Tribunal de Justiça.", "ordem": 687}, {"id": 688, "artigo_id": 120, "paragrafo_id": 286, "numero_romano": "I", "numero_int": 1, "texto": "I - forem proferidas contra disposição expressa desta Constituição ou de lei;", "ordem": 688}, {"id": 689, "artigo_id": 120, "paragrafo_id": 286, "numero_romano": "II", "numero_int": 2, "texto": "II - ocorrer divergência na interpretação de lei entre dois ou mais tribunais eleitorais;", "ordem": 689}, {"id": 690, "artigo_id": 120, "paragrafo_id": 286, "numero_romano": "III", "numero_int": 3, "texto": "III - versarem sobre inelegibilidade ou expedição de diplomas nas eleições federais ou estaduais;", "ordem": 690}, {"id": 691, "artigo_id": 120, "paragrafo_id": 286, "numero_romano": "IV", "numero_int": 4, "texto": "IV - anularem diplomas ou decretarem a perda de mandatos eletivos federais ou estaduais;", "ordem": 691}, {"id": 692, "artigo_id": 120, "paragrafo_id": 286, "numero_romano": "V", "numero_int": 5, "texto": "V - denegarem habeas corpus , mandado de segurança, habeas data ou mandado de injunção.", "ordem": 692}, {"id": 693, "artigo_id": 121, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - o Superior Tribunal Militar;", "ordem": 693}, {"id": 694, "artigo_id": 121, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - os Tribunais e Juízes Militares instituídos por lei.", "ordem": 694}, {"id": 695, "artigo_id": 122, "paragrafo_id": 287, "numero_romano": "I", "numero_int": 1, "texto": "I - três dentre advogados de notório saber jurídico e conduta ilibada, com mais de dez anos de efetiva atividade profissional;", "ordem": 695}, {"id": 696, "artigo_id": 122, "paragrafo_id": 287, "numero_romano": "II", "numero_int": 2, "texto": "II - dois, por escolha paritária, dentre juízes auditores e membros do Ministério Público da Justiça Militar.", "ordem": 696}, {"id": 697, "artigo_id": 127, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - o Ministério Público da União, que compreende:", "ordem": 697}, {"id": 698, "artigo_id": 127, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - os Ministérios Públicos dos Estados.", "ordem": 698}, {"id": 699, "artigo_id": 127, "paragrafo_id": 307, "numero_romano": "I", "numero_int": 1, "texto": "I - as seguintes garantias:", "ordem": 699}, {"id": 700, "artigo_id": 127, "paragrafo_id": 307, "numero_romano": "II", "numero_int": 2, "texto": "II - as seguintes vedações:", "ordem": 700}, {"id": 701, "artigo_id": 128, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - promover, privativamente, a ação penal pública, na forma da lei;", "ordem": 701}, {"id": 702, "artigo_id": 128, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - zelar pelo efetivo respeito dos Poderes Públicos e dos serviços de relevância pública aos direitos assegurados nesta Constituição, promovendo as medidas necessárias a sua garantia;", "ordem": 702}, {"id": 703, "artigo_id": 128, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - promover o inquérito civil e a ação civil pública, para a proteção do patrimônio público e social, do meio ambiente e de outros interesses difusos e coletivos;", "ordem": 703}, {"id": 704, "artigo_id": 128, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - promover a ação de inconstitucionalidade ou representação para fins de intervenção da União e dos Estados, nos casos previstos nesta Constituição;", "ordem": 704}, {"id": 705, "artigo_id": 128, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - defender judicialmente os direitos e interesses das populações indígenas;", "ordem": 705}, {"id": 706, "artigo_id": 128, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - expedir notificações nos procedimentos administrativos de sua competência, requisitando informações e documentos para instruí-los, na forma da lei complementar respectiva;", "ordem": 706}, {"id": 707, "artigo_id": 128, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - exercer o controle externo da atividade policial, na forma da lei complementar mencionada no artigo anterior;", "ordem": 707}, {"id": 708, "artigo_id": 128, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - requisitar diligências investigatórias e a instauração de inquérito policial, indicados os fundamentos jurídicos de suas manifestações processuais;", "ordem": 708}, {"id": 709, "artigo_id": 128, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - exercer outras funções que lhe forem conferidas, desde que compatíveis com sua finalidade, sendo-lhe vedada a representação judicial e a consultoria jurídica de entidades públicas.", "ordem": 709}, {"id": 710, "artigo_id": 129, "paragrafo_id": 315, "numero_romano": "III", "numero_int": 3, "texto": "III - receber e conhecer das reclamações contra membros ou órgãos do Ministério Público da União ou dos Estados, inclusive contra seus serviços auxiliares, sem prejuízo da competência disciplinar e correicional da instituição, podendo avocar processos disciplinares em curso, determinar a remoção ou a disponibilidade e aplicar outras sanções administrativas, assegurada ampla defesa;", "ordem": 710}, {"id": 711, "artigo_id": 135, "paragrafo_id": 327, "numero_romano": "I", "numero_int": 1, "texto": "I - restrições aos direitos de:", "ordem": 711}, {"id": 712, "artigo_id": 135, "paragrafo_id": 327, "numero_romano": "II", "numero_int": 2, "texto": "II - ocupação e uso temporário de bens e serviços públicos, na hipótese de calamidade pública, respondendo a União pelos danos e custos decorrentes.", "ordem": 712}, {"id": 713, "artigo_id": 135, "paragrafo_id": 329, "numero_romano": "I", "numero_int": 1, "texto": "I - a prisão por crime contra o Estado, determinada pelo executor da medida, será por este comunicada imediatamente ao juiz competente, que a relaxará, se não for legal, facultado ao preso requerer exame de corpo de delito à autoridade policial;", "ordem": 713}, {"id": 714, "artigo_id": 135, "paragrafo_id": 329, "numero_romano": "II", "numero_int": 2, "texto": "II - a comunicação será acompanhada de declaração, pela autoridade, do estado físico e mental do detido no momento de sua autuação;", "ordem": 714}, {"id": 715, "artigo_id": 135, "paragrafo_id": 329, "numero_romano": "III", "numero_int": 3, "texto": "III - a prisão ou detenção de qualquer pessoa não poderá ser superior a dez dias, salvo quando autorizada pelo Poder Judiciário;", "ordem": 715}, {"id": 716, "artigo_id": 135, "paragrafo_id": 329, "numero_romano": "IV", "numero_int": 4, "texto": "IV - é vedada a incomunicabilidade do preso.", "ordem": 716}, {"id": 717, "artigo_id": 136, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - comoção grave de repercussão nacional ou ocorrência de fatos que comprovem a ineficácia de medida tomada durante o estado de defesa;", "ordem": 717}, {"id": 718, "artigo_id": 136, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - declaração de estado de guerra ou resposta a agressão armada estrangeira.", "ordem": 718}, {"id": 719, "artigo_id": 138, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - obrigação de permanência em localidade determinada;", "ordem": 719}, {"id": 720, "artigo_id": 138, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - detenção em edifício não destinado a acusados ou condenados por crimes comuns;", "ordem": 720}, {"id": 721, "artigo_id": 138, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - restrições relativas à inviolabilidade da correspondência, ao sigilo das comunicações, à prestação de informações e à liberdade de imprensa, radiodifusão e televisão, na forma da lei;", "ordem": 721}, {"id": 722, "artigo_id": 138, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - suspensão da liberdade de reunião;", "ordem": 722}, {"id": 723, "artigo_id": 138, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - busca e apreensão em domicílio;", "ordem": 723}, {"id": 724, "artigo_id": 138, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - intervenção nas empresas de serviços públicos;", "ordem": 724}, {"id": 725, "artigo_id": 138, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - requisição de bens.", "ordem": 725}, {"id": 726, "artigo_id": 141, "paragrafo_id": 342, "numero_romano": "I", "numero_int": 1, "texto": "I - as patentes, com prerrogativas, direitos e deveres a elas inerentes, são conferidas pelo Presidente da República e asseguradas em plenitude aos oficiais da ativa, da reserva ou reformados, sendo-lhes privativos os títulos e postos militares e, juntamente com os demais membros, o uso dos uniformes das Forças Armadas;", "ordem": 726}, {"id": 727, "artigo_id": 141, "paragrafo_id": 342, "numero_romano": "II", "numero_int": 2, "texto": "II - o militar em atividade que tomar posse em cargo ou emprego público civil permanente, ressalvada a hipótese prevista no art. 37, inciso XVI, alínea \"c\", será transferido para a reserva, nos termos da lei;", "ordem": 727}, {"id": 728, "artigo_id": 141, "paragrafo_id": 342, "numero_romano": "III", "numero_int": 3, "texto": "III - o militar da ativa que, de acordo com a lei, tomar posse em cargo, emprego ou função pública civil temporária, não eletiva, ainda que da administração indireta, ressalvada a hipótese prevista no art. 37, inciso XVI, alínea \"c\", ficará agregado ao respectivo quadro e somente poderá, enquanto permanecer nessa situação, ser promovido por antiguidade, contando-se-lhe o tempo de serviço apenas para aquela promoção e transferência para a reserva, sendo depois de dois anos de afastamento, contínuos ou não, transferido para a reserva, nos termos da lei;", "ordem": 728}, {"id": 729, "artigo_id": 141, "paragrafo_id": 342, "numero_romano": "IV", "numero_int": 4, "texto": "IV - ao militar são proibidas a sindicalização e a greve;", "ordem": 729}, {"id": 730, "artigo_id": 141, "paragrafo_id": 342, "numero_romano": "V", "numero_int": 5, "texto": "V - o militar, enquanto em serviço ativo, não pode estar filiado a partidos políticos;", "ordem": 730}, {"id": 731, "artigo_id": 141, "paragrafo_id": 342, "numero_romano": "VI", "numero_int": 6, "texto": "VI - o oficial só perderá o posto e a patente se for julgado indigno do oficialato ou com ele incompatível, por decisão de tribunal militar de caráter permanente, em tempo de paz, ou de tribunal especial, em tempo de guerra;", "ordem": 731}, {"id": 732, "artigo_id": 141, "paragrafo_id": 342, "numero_romano": "VII", "numero_int": 7, "texto": "VII - o oficial condenado na justiça comum ou militar a pena privativa de liberdade superior a dois anos, por sentença transitada em julgado, será submetido ao julgamento previsto no inciso anterior;", "ordem": 732}, {"id": 733, "artigo_id": 141, "paragrafo_id": 342, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - aplica-se aos militares o disposto no art. 7º, incisos VIII, XII, XVII, XVIII, XIX e XXV, e no art. 37, incisos XI, XIII, XIV e XV, bem como, na forma da lei e com prevalência da atividade militar, no art. 37, inciso XVI, alínea \"c\";", "ordem": 733}, {"id": 734, "artigo_id": 141, "paragrafo_id": 342, "numero_romano": "X", "numero_int": 10, "texto": "X - a lei disporá sobre o ingresso nas Forças Armadas, os limites de idade, a estabilidade e outras condições de transferência do militar para a inatividade, os direitos, os deveres, a remuneração, as prerrogativas e outras situações especiais dos militares, consideradas as peculiaridades de suas atividades, inclusive aquelas cumpridas por força de compromissos internacionais e de guerra.", "ordem": 734}, {"id": 735, "artigo_id": 143, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - polícia federal;", "ordem": 735}, {"id": 736, "artigo_id": 143, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - polícia rodoviária federal;", "ordem": 736}, {"id": 737, "artigo_id": 143, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - polícia ferroviária federal;", "ordem": 737}, {"id": 738, "artigo_id": 143, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - polícias civis;", "ordem": 738}, {"id": 739, "artigo_id": 143, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - polícias militares e corpos de bombeiros militares.", "ordem": 739}, {"id": 740, "artigo_id": 143, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - polícias penais federal, estaduais e distrital.", "ordem": 740}, {"id": 741, "artigo_id": 143, "paragrafo_id": 345, "numero_romano": "I", "numero_int": 1, "texto": "I - apurar infrações penais contra a ordem política e social ou em detrimento de bens, serviços e interesses da União ou de suas entidades autárquicas e empresas públicas, assim como outras infrações cuja prática tenha repercussão interestadual ou internacional e exija repressão uniforme, segundo se dispuser em lei;", "ordem": 741}, {"id": 742, "artigo_id": 143, "paragrafo_id": 345, "numero_romano": "II", "numero_int": 2, "texto": "II - prevenir e reprimir o tráfico ilícito de entorpecentes e drogas afins, o contrabando e o descaminho, sem prejuízo da ação fazendária e de outros órgãos públicos nas respectivas áreas de competência;", "ordem": 742}, {"id": 743, "artigo_id": 143, "paragrafo_id": 345, "numero_romano": "III", "numero_int": 3, "texto": "III - exercer as funções de polícia marítima, aeroportuária e de fronteiras;", "ordem": 743}, {"id": 744, "artigo_id": 143, "paragrafo_id": 345, "numero_romano": "IV", "numero_int": 4, "texto": "IV - exercer, com exclusividade, as funções de polícia judiciária da União.", "ordem": 744}, {"id": 745, "artigo_id": 143, "paragrafo_id": 353, "numero_romano": "I", "numero_int": 1, "texto": "I - compreende a educação, engenharia e fiscalização de trânsito, além de outras atividades previstas em lei, que assegurem ao cidadão o direito à mobilidade urbana eficiente; e", "ordem": 745}, {"id": 746, "artigo_id": 143, "paragrafo_id": 353, "numero_romano": "II", "numero_int": 2, "texto": "II - compete, no âmbito dos Estados, do Distrito Federal e dos Municípios, aos respectivos órgãos ou entidades executivos e seus agentes de trânsito, estruturados em Carreira, na forma da lei.", "ordem": 746}, {"id": 747, "artigo_id": 144, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - impostos;", "ordem": 747}, {"id": 748, "artigo_id": 144, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - taxas, em razão do exercício do poder de polícia ou pela utilização, efetiva ou potencial, de serviços públicos específicos e divisíveis, prestados ao contribuinte ou postos a sua disposição;", "ordem": 748}, {"id": 749, "artigo_id": 144, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - contribuição de melhoria, decorrente de obras públicas.", "ordem": 749}, {"id": 750, "artigo_id": 145, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - dispor sobre conflitos de competência, em matéria tributária, entre a União, os Estados, o Distrito Federal e os Municípios;", "ordem": 750}, {"id": 751, "artigo_id": 145, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - regular as limitações constitucionais ao poder de tributar;", "ordem": 751}, {"id": 752, "artigo_id": 145, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - estabelecer normas gerais em matéria de legislação tributária, especialmente sobre:", "ordem": 752}, {"id": 753, "artigo_id": 145, "paragrafo_id": 358, "numero_romano": "I", "numero_int": 1, "texto": "I - será opcional para o contribuinte;", "ordem": 753}, {"id": 754, "artigo_id": 145, "paragrafo_id": 358, "numero_romano": "II", "numero_int": 2, "texto": "II - poderão ser estabelecidas condições de enquadramento diferenciadas por Estado;", "ordem": 754}, {"id": 755, "artigo_id": 145, "paragrafo_id": 358, "numero_romano": "III", "numero_int": 3, "texto": "III - o recolhimento será unificado e centralizado e a distribuição da parcela de recursos pertencentes aos respectivos entes federados será imediata, vedada qualquer retenção ou condicionamento;", "ordem": 755}, {"id": 756, "artigo_id": 145, "paragrafo_id": 358, "numero_romano": "IV", "numero_int": 4, "texto": "IV - a arrecadação, a fiscalização e a cobrança poderão ser compartilhadas pelos entes federados, adotado cadastro nacional único de contribuintes.", "ordem": 756}, {"id": 757, "artigo_id": 145, "paragrafo_id": 360, "numero_romano": "I", "numero_int": 1, "texto": "I - não será permitida a apropriação de créditos dos tributos previstos nos arts. 156-A e 195, V, pelo contribuinte optante pelo regime único; e", "ordem": 757}, {"id": 758, "artigo_id": 145, "paragrafo_id": 360, "numero_romano": "II", "numero_int": 2, "texto": "II - será permitida a apropriação de créditos dos tributos previstos nos arts. 156-A e 195, V, pelo adquirente não optante pelo regime único de que trata o § 1º de bens materiais ou imateriais, inclusive direitos, e de serviços do optante, em montante equivalente ao cobrado por meio do regime único.", "ordem": 758}, {"id": 759, "artigo_id": 147, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - para atender a despesas extraordinárias, decorrentes de calamidade pública, de guerra externa ou sua iminência;", "ordem": 759}, {"id": 760, "artigo_id": 147, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - no caso de investimento público de caráter urgente e de relevante interesse nacional, observado o disposto no art. 150, III, \"b\".", "ordem": 760}, {"id": 761, "artigo_id": 148, "paragrafo_id": 363, "numero_romano": "I", "numero_int": 1, "texto": "I - não incidirão sobre as receitas decorrentes de exportação;", "ordem": 761}, {"id": 762, "artigo_id": 148, "paragrafo_id": 363, "numero_romano": "II", "numero_int": 2, "texto": "II - incidirão também sobre a importação de produtos estrangeiros ou serviços;", "ordem": 762}, {"id": 763, "artigo_id": 148, "paragrafo_id": 363, "numero_romano": "III", "numero_int": 3, "texto": "III - poderão ter alíquotas:", "ordem": 763}, {"id": 764, "artigo_id": 148, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - fatos geradores, bases de cálculo, hipóteses de não incidência e sujeitos passivos;", "ordem": 764}, {"id": 765, "artigo_id": 148, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - imunidades;", "ordem": 765}, {"id": 766, "artigo_id": 148, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - regimes específicos, diferenciados ou favorecidos de tributação;", "ordem": 766}, {"id": 767, "artigo_id": 148, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - regras de não cumulatividade e de creditamento.", "ordem": 767}, {"id": 768, "artigo_id": 149, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - exigir ou aumentar tributo sem lei que o estabeleça;", "ordem": 768}, {"id": 769, "artigo_id": 149, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - instituir tratamento desigual entre contribuintes que se encontrem em situação equivalente, proibida qualquer distinção em razão de ocupação profissional ou função por eles exercida, independentemente da denominação jurídica dos rendimentos, títulos ou direitos;", "ordem": 769}, {"id": 770, "artigo_id": 149, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - cobrar tributos:", "ordem": 770}, {"id": 771, "artigo_id": 149, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - utilizar tributo com efeito de confisco;", "ordem": 771}, {"id": 772, "artigo_id": 149, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - estabelecer limitações ao tráfego de pessoas ou bens, por meio de tributos interestaduais ou intermunicipais, ressalvada a cobrança de pedágio pela utilização de vias conservadas pelo Poder Público;", "ordem": 772}, {"id": 773, "artigo_id": 149, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - instituir impostos sobre:", "ordem": 773}, {"id": 774, "artigo_id": 150, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - instituir tributo que não seja uniforme em todo o território nacional ou que implique distinção ou preferência em relação a Estado, ao Distrito Federal ou a Município, em detrimento de outro, admitida a concessão de incentivos fiscais destinados a promover o equilíbrio do desenvolvimento sócio-econômico entre as diferentes regiões do País;", "ordem": 774}, {"id": 775, "artigo_id": 150, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - tributar a renda das obrigações da dívida pública dos Estados, do Distrito Federal e dos Municípios, bem como a remuneração e os proventos dos respectivos agentes públicos, em níveis superiores aos que fixar para suas obrigações e para seus agentes;", "ordem": 775}, {"id": 776, "artigo_id": 150, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - instituir isenções de tributos da competência dos Estados, do Distrito Federal ou dos Municípios.", "ordem": 776}, {"id": 777, "artigo_id": 152, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - importação de produtos estrangeiros;", "ordem": 777}, {"id": 778, "artigo_id": 152, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - exportação, para o exterior, de produtos nacionais ou nacionalizados;", "ordem": 778}, {"id": 779, "artigo_id": 152, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - renda e proventos de qualquer natureza;", "ordem": 779}, {"id": 780, "artigo_id": 152, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - produtos industrializados;", "ordem": 780}, {"id": 781, "artigo_id": 152, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - operações de crédito, câmbio e seguro, ou relativas a títulos ou valores mobiliários;", "ordem": 781}, {"id": 782, "artigo_id": 152, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - propriedade territorial rural;", "ordem": 782}, {"id": 783, "artigo_id": 152, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - grandes fortunas, nos termos de lei complementar.", "ordem": 783}, {"id": 784, "artigo_id": 152, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - produção, extração, comercialização ou importação de bens e serviços prejudiciais à saúde ou ao meio ambiente, nos termos de lei complementar.", "ordem": 784}, {"id": 785, "artigo_id": 152, "paragrafo_id": 379, "numero_romano": "I", "numero_int": 1, "texto": "I - será informado pelos critérios da generalidade, da universalidade e da progressividade, na forma da lei;", "ordem": 785}, {"id": 786, "artigo_id": 152, "paragrafo_id": 380, "numero_romano": "I", "numero_int": 1, "texto": "I - será seletivo, em função da essencialidade do produto;", "ordem": 786}, {"id": 787, "artigo_id": 152, "paragrafo_id": 380, "numero_romano": "II", "numero_int": 2, "texto": "II - será não-cumulativo, compensando-se o que for devido em cada operação com o montante cobrado nas anteriores;", "ordem": 787}, {"id": 788, "artigo_id": 152, "paragrafo_id": 380, "numero_romano": "III", "numero_int": 3, "texto": "III - não incidirá sobre produtos industrializados destinados ao exterior.", "ordem": 788}, {"id": 789, "artigo_id": 152, "paragrafo_id": 380, "numero_romano": "IV", "numero_int": 4, "texto": "IV - terá reduzido seu impacto sobre a aquisição de bens de capital pelo contribuinte do imposto, na forma da lei.", "ordem": 789}, {"id": 790, "artigo_id": 152, "paragrafo_id": 381, "numero_romano": "I", "numero_int": 1, "texto": "I - será progressivo e terá suas alíquotas fixadas de forma a desestimular a manutenção de propriedades improdutivas;", "ordem": 790}, {"id": 791, "artigo_id": 152, "paragrafo_id": 381, "numero_romano": "II", "numero_int": 2, "texto": "II - não incidirá sobre pequenas glebas rurais, definidas em lei, quando as explore o proprietário que não possua outro imóvel;", "ordem": 791}, {"id": 792, "artigo_id": 152, "paragrafo_id": 381, "numero_romano": "III", "numero_int": 3, "texto": "III - será fiscalizado e cobrado pelos Municípios que assim optarem, na forma da lei, desde que não implique redução do imposto ou qualquer outra forma de renúncia fiscal. (Regulamento)", "ordem": 792}, {"id": 793, "artigo_id": 152, "paragrafo_id": 382, "numero_romano": "I", "numero_int": 1, "texto": "I - trinta por cento para o Estado, o Distrito Federal ou o Território, conforme a origem;", "ordem": 793}, {"id": 794, "artigo_id": 152, "paragrafo_id": 382, "numero_romano": "II", "numero_int": 2, "texto": "II - setenta por cento para o Município de origem.", "ordem": 794}, {"id": 795, "artigo_id": 152, "paragrafo_id": 383, "numero_romano": "I", "numero_int": 1, "texto": "I - não incidirá sobre as exportações nem sobre as operações com energia elétrica e com telecomunicações;", "ordem": 795}, {"id": 796, "artigo_id": 152, "paragrafo_id": 383, "numero_romano": "II", "numero_int": 2, "texto": "II - incidirá uma única vez sobre o bem ou serviço;", "ordem": 796}, {"id": 797, "artigo_id": 152, "paragrafo_id": 383, "numero_romano": "III", "numero_int": 3, "texto": "III - não integrará sua própria base de cálculo;", "ordem": 797}, {"id": 798, "artigo_id": 152, "paragrafo_id": 383, "numero_romano": "IV", "numero_int": 4, "texto": "IV - integrará a base de cálculo dos tributos previstos nos arts. 155, II, 156, III, 156-A e 195, V;", "ordem": 798}, {"id": 799, "artigo_id": 152, "paragrafo_id": 383, "numero_romano": "V", "numero_int": 5, "texto": "V - poderá ter o mesmo fato gerador e base de cálculo de outros tributos;", "ordem": 799}, {"id": 800, "artigo_id": 152, "paragrafo_id": 383, "numero_romano": "VI", "numero_int": 6, "texto": "VI - terá suas alíquotas fixadas em lei ordinária, podendo ser específicas, por unidade de medida adotada, ou ad valorem;", "ordem": 800}, {"id": 801, "artigo_id": 152, "paragrafo_id": 383, "numero_romano": "VII", "numero_int": 7, "texto": "VII - na extração, o imposto será cobrado independentemente da destinação, caso em que a alíquota máxima corresponderá a 1% (um por cento) do valor de mercado do produto.", "ordem": 801}, {"id": 802, "artigo_id": 153, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - mediante lei complementar, impostos não previstos no artigo anterior, desde que sejam não-cumulativos e não tenham fato gerador ou base de cálculo próprios dos discriminados nesta Constituição;", "ordem": 802}, {"id": 803, "artigo_id": 153, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - na iminência ou no caso de guerra externa, impostos extraordinários, compreendidos ou não em sua competência tributária, os quais serão suprimidos, gradativamente, cessadas as causas de sua criação.", "ordem": 803}, {"id": 804, "artigo_id": 154, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - transmissão causa mortis e doação, de quaisquer bens ou direitos;", "ordem": 804}, {"id": 805, "artigo_id": 154, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - operações relativas à circulação de mercadorias e sobre prestações de serviços de transporte interestadual e intermunicipal e de comunicação, ainda que as operações e as prestações se iniciem no exterior; Vigência", "ordem": 805}, {"id": 806, "artigo_id": 154, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - propriedade de veículos automotores.", "ordem": 806}, {"id": 807, "artigo_id": 154, "paragrafo_id": 384, "numero_romano": "I", "numero_int": 1, "texto": "I - relativamente a bens imóveis e respectivos direitos, compete ao Estado da situação do bem, ou ao Distrito Federal", "ordem": 807}, {"id": 808, "artigo_id": 154, "paragrafo_id": 384, "numero_romano": "II", "numero_int": 2, "texto": "II - relativamente a bens móveis, títulos e créditos, compete ao Estado onde era domiciliado ode cujus, ou tiver domicílio o doador, ou ao Distrito Federal;", "ordem": 808}, {"id": 809, "artigo_id": 154, "paragrafo_id": 384, "numero_romano": "III", "numero_int": 3, "texto": "III - terá competência para sua instituição regulada por lei complementar:", "ordem": 809}, {"id": 810, "artigo_id": 154, "paragrafo_id": 384, "numero_romano": "IV", "numero_int": 4, "texto": "IV - terá suas alíquotas máximas fixadas pelo Senado Federal;", "ordem": 810}, {"id": 811, "artigo_id": 154, "paragrafo_id": 384, "numero_romano": "V", "numero_int": 5, "texto": "V - não incidirá sobre as doações destinadas, no âmbito do Poder Executivo da União, a projetos socioambientais ou destinados a mitigar os efeitos das mudanças climáticas e às instituições federais de ensino.", "ordem": 811}, {"id": 812, "artigo_id": 154, "paragrafo_id": 384, "numero_romano": "VI", "numero_int": 6, "texto": "VI - será progressivo em razão do valor do quinhão, do legado ou da doação;", "ordem": 812}, {"id": 813, "artigo_id": 154, "paragrafo_id": 384, "numero_romano": "VII", "numero_int": 7, "texto": "VII - não incidirá sobre as transmissões e as doações para as instituições sem fins lucrativos com finalidade de relevância pública e social, inclusive as organizações assistenciais e beneficentes de entidades religiosas e institutos científicos e tecnológicos, e por elas realizadas na consecução dos seus objetivos sociais, observadas as condições estabelecidas em lei complementar.", "ordem": 813}, {"id": 814, "artigo_id": 154, "paragrafo_id": 385, "numero_romano": "I", "numero_int": 1, "texto": "I - será não-cumulativo, compensando-se o que for devido em cada operação relativa à circulação de mercadorias ou prestação de serviços com o montante cobrado nas anteriores pelo mesmo ou outro Estado ou pelo Distrito Federal;", "ordem": 814}, {"id": 815, "artigo_id": 154, "paragrafo_id": 385, "numero_romano": "II", "numero_int": 2, "texto": "II - a isenção ou não-incidência, salvo determinação em contrário da legislação:", "ordem": 815}, {"id": 816, "artigo_id": 154, "paragrafo_id": 385, "numero_romano": "III", "numero_int": 3, "texto": "III - poderá ser seletivo, em função da essencialidade das mercadorias e dos serviços;", "ordem": 816}, {"id": 817, "artigo_id": 154, "paragrafo_id": 385, "numero_romano": "IV", "numero_int": 4, "texto": "IV - resolução do Senado Federal, de iniciativa do Presidente da República ou de um terço dos Senadores, aprovada pela maioria absoluta de seus membros, estabelecerá as alíquotas aplicáveis às operações e prestações, interestaduais e de exportação;", "ordem": 817}, {"id": 818, "artigo_id": 154, "paragrafo_id": 385, "numero_romano": "V", "numero_int": 5, "texto": "V - é facultado ao Senado Federal:", "ordem": 818}, {"id": 819, "artigo_id": 154, "paragrafo_id": 385, "numero_romano": "VI", "numero_int": 6, "texto": "VI - salvo deliberação em contrário dos Estados e do Distrito Federal, nos termos do disposto no inciso XII, \"g\", as alíquotas internas, nas operações relativas à circulação de mercadorias e nas prestações de serviços, não poderão ser inferiores às previstas para as operações interestaduais;", "ordem": 819}, {"id": 820, "artigo_id": 154, "paragrafo_id": 385, "numero_romano": "VII", "numero_int": 7, "texto": "VII - nas operações e prestações que destinem bens e serviços a consumidor final, contribuinte ou não do imposto, localizado em outro Estado, adotar-se-á a alíquota interestadual e caberá ao Estado de localização do destinatário o imposto correspondente à diferença entre a alíquota interna do Estado destinatário e a alíquota interestadual; (Produção de efeito)", "ordem": 820}, {"id": 821, "artigo_id": 154, "paragrafo_id": 385, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - a responsabilidade pelo recolhimento do imposto correspondente à diferença entre a alíquota interna e a interestadual de que trata o inciso VII será atribuída: (Produção de efeito)", "ordem": 821}, {"id": 822, "artigo_id": 154, "paragrafo_id": 385, "numero_romano": "IX", "numero_int": 9, "texto": "IX - incidirá também:", "ordem": 822}, {"id": 823, "artigo_id": 154, "paragrafo_id": 385, "numero_romano": "X", "numero_int": 10, "texto": "X - não incidirá:", "ordem": 823}, {"id": 824, "artigo_id": 154, "paragrafo_id": 385, "numero_romano": "XI", "numero_int": 11, "texto": "XI - não compreenderá, em sua base de cálculo, o montante do imposto sobre produtos industrializados, quando a operação, realizada entre contribuintes e relativa a produto destinado à industrialização ou à comercialização, configure fato gerador dos dois impostos;", "ordem": 824}, {"id": 825, "artigo_id": 154, "paragrafo_id": 385, "numero_romano": "XII", "numero_int": 12, "texto": "XII - cabe à lei complementar:", "ordem": 825}, {"id": 826, "artigo_id": 154, "paragrafo_id": 387, "numero_romano": "I", "numero_int": 1, "texto": "I - nas operações com os lubrificantes e combustíveis derivados de petróleo, o imposto caberá ao Estado onde ocorrer o consumo;", "ordem": 826}, {"id": 827, "artigo_id": 154, "paragrafo_id": 387, "numero_romano": "II", "numero_int": 2, "texto": "II - nas operações interestaduais, entre contribuintes, com gás natural e seus derivados, e lubrificantes e combustíveis não incluídos no inciso I deste parágrafo, o imposto será repartido entre os Estados de origem e de destino, mantendo-se a mesma proporcionalidade que ocorre nas operações com as demais mercadorias;", "ordem": 827}, {"id": 828, "artigo_id": 154, "paragrafo_id": 387, "numero_romano": "III", "numero_int": 3, "texto": "III - nas operações interestaduais com gás natural e seus derivados, e lubrificantes e combustíveis não incluídos no inciso I deste parágrafo, destinadas a não contribuinte, o imposto caberá ao Estado de origem;", "ordem": 828}, {"id": 829, "artigo_id": 154, "paragrafo_id": 387, "numero_romano": "IV", "numero_int": 4, "texto": "IV - as alíquotas do imposto serão definidas mediante deliberação dos Estados e Distrito Federal, nos termos do § 2º, XII, g , observando-se o seguinte:", "ordem": 829}, {"id": 830, "artigo_id": 154, "paragrafo_id": 389, "numero_romano": "I", "numero_int": 1, "texto": "I - terá alíquotas mínimas fixadas pelo Senado Federal;", "ordem": 830}, {"id": 831, "artigo_id": 154, "paragrafo_id": 389, "numero_romano": "II", "numero_int": 2, "texto": "II - poderá ter alíquotas diferenciadas em função do tipo, do valor, da utilização e do impacto ambiental;", "ordem": 831}, {"id": 832, "artigo_id": 154, "paragrafo_id": 389, "numero_romano": "III", "numero_int": 3, "texto": "III - incidirá sobre a propriedade de veículos automotores terrestres, aquáticos e aéreos, excetuados:", "ordem": 832}, {"id": 833, "artigo_id": 155, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - propriedade predial e territorial urbana;", "ordem": 833}, {"id": 834, "artigo_id": 155, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - transmissão \"inter vivos\", a qualquer título, por ato oneroso, de bens imóveis, por natureza ou acessão física, e de direitos reais sobre imóveis, exceto os de garantia, bem como cessão de direitos a sua aquisição;", "ordem": 834}, {"id": 835, "artigo_id": 155, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - serviços de qualquer natureza, não compreendidos no art. 155, II, definidos em lei complementar. Vigência", "ordem": 835}, {"id": 836, "artigo_id": 155, "paragrafo_id": 390, "numero_romano": "I", "numero_int": 1, "texto": "I - ser progressivo em razão do valor do imóvel; e", "ordem": 836}, {"id": 837, "artigo_id": 155, "paragrafo_id": 390, "numero_romano": "II", "numero_int": 2, "texto": "II - ter alíquotas diferentes de acordo com a localização e o uso do imóvel.", "ordem": 837}, {"id": 838, "artigo_id": 155, "paragrafo_id": 390, "numero_romano": "III", "numero_int": 3, "texto": "III - ter sua base de cálculo atualizada pelo Poder Executivo, conforme critérios estabelecidos em lei municipal.", "ordem": 838}, {"id": 839, "artigo_id": 155, "paragrafo_id": 391, "numero_romano": "I", "numero_int": 1, "texto": "I - não incide sobre a transmissão de bens ou direitos incorporados ao patrimônio de pessoa jurídica em realização de capital, nem sobre a transmissão de bens ou direitos decorrente de fusão, incorporação, cisão ou extinção de pessoa jurídica, salvo se, nesses casos, a atividade preponderante do adquirente for a compra e venda desses bens ou direitos, locação de bens imóveis ou arrendamento mercantil;", "ordem": 839}, {"id": 840, "artigo_id": 155, "paragrafo_id": 391, "numero_romano": "II", "numero_int": 2, "texto": "II - compete ao Município da situação do bem.", "ordem": 840}, {"id": 841, "artigo_id": 155, "paragrafo_id": 392, "numero_romano": "I", "numero_int": 1, "texto": "I - fixar as suas alíquotas máximas e mínimas;", "ordem": 841}, {"id": 842, "artigo_id": 155, "paragrafo_id": 392, "numero_romano": "II", "numero_int": 2, "texto": "II - excluir da sua incidência exportações de serviços para o exterior.", "ordem": 842}, {"id": 843, "artigo_id": 155, "paragrafo_id": 392, "numero_romano": "III", "numero_int": 3, "texto": "III - regular a forma e as condições como isenções, incentivos e benefícios fiscais serão concedidos e revogados.", "ordem": 843}, {"id": 844, "artigo_id": 155, "paragrafo_id": 393, "numero_romano": "I", "numero_int": 1, "texto": "I - incidirá sobre operações com bens materiais ou imateriais, inclusive direitos, ou com serviços;", "ordem": 844}, {"id": 845, "artigo_id": 155, "paragrafo_id": 393, "numero_romano": "II", "numero_int": 2, "texto": "II - incidirá também sobre a importação de bens materiais ou imateriais, inclusive direitos, ou de serviços realizada por pessoa física ou jurídica, ainda que não seja sujeito passivo habitual do imposto, qualquer que seja a sua finalidade;", "ordem": 845}, {"id": 846, "artigo_id": 155, "paragrafo_id": 393, "numero_romano": "III", "numero_int": 3, "texto": "III - não incidirá sobre as exportações, assegurados ao exportador a manutenção e o aproveitamento dos créditos relativos às operações nas quais seja adquirente de bem material ou imaterial, inclusive direitos, ou serviço, observado o disposto no § 5º, III;", "ordem": 846}, {"id": 847, "artigo_id": 155, "paragrafo_id": 393, "numero_romano": "IV", "numero_int": 4, "texto": "IV - terá legislação única e uniforme em todo o território nacional, ressalvado o disposto no inciso V;", "ordem": 847}, {"id": 848, "artigo_id": 155, "paragrafo_id": 393, "numero_romano": "V", "numero_int": 5, "texto": "V - cada ente federativo fixará sua alíquota própria por lei específica;", "ordem": 848}, {"id": 849, "artigo_id": 155, "paragrafo_id": 393, "numero_romano": "VI", "numero_int": 6, "texto": "VI - a alíquota fixada pelo ente federativo na forma do inciso V será a mesma para todas as operações com bens materiais ou imateriais, inclusive direitos, ou com serviços, ressalvadas as hipóteses previstas nesta Constituição;", "ordem": 849}, {"id": 850, "artigo_id": 155, "paragrafo_id": 393, "numero_romano": "VII", "numero_int": 7, "texto": "VII - será cobrado pelo somatório das alíquotas do Estado e do Município de destino da operação;", "ordem": 850}, {"id": 851, "artigo_id": 155, "paragrafo_id": 393, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - será não cumulativo, compensando-se o imposto devido pelo contribuinte com o montante cobrado sobre todas as operações nas quais seja adquirente de bem material ou imaterial, inclusive direito, ou de serviço, excetuadas exclusivamente as consideradas de uso ou consumo pessoal especificadas em lei complementar e as hipóteses previstas nesta Constituição;", "ordem": 851}, {"id": 852, "artigo_id": 155, "paragrafo_id": 393, "numero_romano": "IX", "numero_int": 9, "texto": "IX - não integrará sua própria base de cálculo nem a dos tributos previstos nos arts. 153, VIII, e 195, I, \"b\", IV e V, e da contribuição para o Programa de Integração Social de que trata o art. 239;", "ordem": 852}, {"id": 853, "artigo_id": 155, "paragrafo_id": 393, "numero_romano": "X", "numero_int": 10, "texto": "X - não será objeto de concessão de incentivos e benefícios financeiros ou fiscais relativos ao imposto ou de regimes específicos, diferenciados ou favorecidos de tributação, excetuadas as hipóteses previstas nesta Constituição;", "ordem": 853}, {"id": 854, "artigo_id": 155, "paragrafo_id": 393, "numero_romano": "XI", "numero_int": 11, "texto": "XI - não incidirá nas prestações de serviço de comunicação nas modalidades de radiodifusão sonora e de sons e imagens de recepção livre e gratuita;", "ordem": 854}, {"id": 855, "artigo_id": 155, "paragrafo_id": 393, "numero_romano": "XII", "numero_int": 12, "texto": "XII - resolução do Senado Federal fixará alíquota de referência do imposto para cada esfera federativa, nos termos de lei complementar, que será aplicada se outra não houver sido estabelecida pelo próprio ente federativo;", "ordem": 855}, {"id": 856, "artigo_id": 155, "paragrafo_id": 393, "numero_romano": "XIII", "numero_int": 13, "texto": "XIII - sempre que possível, terá seu valor informado, de forma específica, no respectivo documento fiscal.", "ordem": 856}, {"id": 857, "artigo_id": 155, "paragrafo_id": 396, "numero_romano": "I", "numero_int": 1, "texto": "I - reterá montante equivalente ao saldo acumulado de créditos do imposto não compensados pelos contribuintes e não ressarcidos ao final de cada período de apuração e aos valores decorrentes do cumprimento do § 5º, VIII;", "ordem": 857}, {"id": 858, "artigo_id": 155, "paragrafo_id": 396, "numero_romano": "II", "numero_int": 2, "texto": "II - distribuirá o produto da arrecadação do imposto, deduzida a retenção de que trata o inciso I deste parágrafo, ao ente federativo de destino das operações que não tenham gerado creditamento.", "ordem": 858}, {"id": 859, "artigo_id": 155, "paragrafo_id": 397, "numero_romano": "I", "numero_int": 1, "texto": "I - as regras para a distribuição do produto da arrecadação do imposto, disciplinando, entre outros aspectos:", "ordem": 859}, {"id": 860, "artigo_id": 155, "paragrafo_id": 397, "numero_romano": "II", "numero_int": 2, "texto": "II - o regime de compensação, podendo estabelecer hipóteses em que o aproveitamento do crédito ficará condicionado à verificação do efetivo recolhimento do imposto incidente sobre a operação com bens materiais ou imateriais, inclusive direitos, ou com serviços, desde que:", "ordem": 860}, {"id": 861, "artigo_id": 155, "paragrafo_id": 397, "numero_romano": "III", "numero_int": 3, "texto": "III - a forma e o prazo para ressarcimento de créditos acumulados pelo contribuinte;", "ordem": 861}, {"id": 862, "artigo_id": 155, "paragrafo_id": 397, "numero_romano": "IV", "numero_int": 4, "texto": "IV - os critérios para a definição do destino da operação, que poderá ser, inclusive, o local da entrega, da disponibilização ou da localização do bem, o da prestação ou da disponibilização do serviço ou o do domicílio ou da localização do adquirente ou destinatário do bem ou serviço, admitidas diferenciações em razão das características da operação;", "ordem": 862}, {"id": 863, "artigo_id": 155, "paragrafo_id": 397, "numero_romano": "V", "numero_int": 5, "texto": "V - a forma de desoneração da aquisição de bens de capital pelos contribuintes, que poderá ser implementada por meio de:", "ordem": 863}, {"id": 864, "artigo_id": 155, "paragrafo_id": 397, "numero_romano": "VI", "numero_int": 6, "texto": "VI - as hipóteses de diferimento e desoneração do imposto aplicáveis aos regimes aduaneiros especiais e às zonas de processamento de exportação;", "ordem": 864}, {"id": 865, "artigo_id": 155, "paragrafo_id": 397, "numero_romano": "VII", "numero_int": 7, "texto": "VII - o processo administrativo fiscal do imposto;", "ordem": 865}, {"id": 866, "artigo_id": 155, "paragrafo_id": 397, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - as hipóteses de devolução do imposto a pessoas físicas, inclusive os limites e os beneficiários, com o objetivo de reduzir as desigualdades de renda;", "ordem": 866}, {"id": 867, "artigo_id": 155, "paragrafo_id": 397, "numero_romano": "IX", "numero_int": 9, "texto": "IX - os critérios para as obrigações tributárias acessórias, visando à sua simplificação.", "ordem": 867}, {"id": 868, "artigo_id": 155, "paragrafo_id": 398, "numero_romano": "I", "numero_int": 1, "texto": "I - combustíveis e lubrificantes sobre os quais o imposto incidirá uma única vez, qualquer que seja a sua finalidade, hipótese em que:", "ordem": 868}, {"id": 869, "artigo_id": 155, "paragrafo_id": 398, "numero_romano": "II", "numero_int": 2, "texto": "II - serviços financeiros, operações com bens imóveis, planos de assistência à saúde e concursos de prognósticos, podendo prever:", "ordem": 869}, {"id": 870, "artigo_id": 155, "paragrafo_id": 398, "numero_romano": "III", "numero_int": 3, "texto": "III - sociedades cooperativas, que será optativo, com vistas a assegurar sua competitividade, observados os princípios da livre concorrência e da isonomia tributária, definindo, inclusive:", "ordem": 870}, {"id": 871, "artigo_id": 155, "paragrafo_id": 398, "numero_romano": "IV", "numero_int": 4, "texto": "IV - serviços de hotelaria, parques de diversão e parques temáticos, agências de viagens e de turismo, bares e restaurantes, atividade esportiva desenvolvida por Sociedade Anônima do Futebol e aviação regional, podendo prever hipóteses de alterações nas alíquotas, nas bases de cálculo e nas regras de creditamento, admitida a não aplicação do disposto no § 1º, V a VIII;", "ordem": 871}, {"id": 872, "artigo_id": 155, "paragrafo_id": 398, "numero_romano": "V", "numero_int": 5, "texto": "V - operações alcançadas por tratado ou convenção internacional, inclusive referentes a missões diplomáticas, repartições consulares, representações de organismos internacionais e respectivos funcionários acreditados;", "ordem": 872}, {"id": 873, "artigo_id": 155, "paragrafo_id": 398, "numero_romano": "VI", "numero_int": 6, "texto": "VI - serviços de transporte coletivo de passageiros rodoviário intermunicipal e interestadual, ferroviário e hidroviário, podendo prever hipóteses de alterações nas alíquotas e nas regras de creditamento, admitida a não aplicação do disposto no § 1º, V a VIII.", "ordem": 873}, {"id": 874, "artigo_id": 155, "paragrafo_id": 399, "numero_romano": "I", "numero_int": 1, "texto": "I - não implicarão crédito para compensação com o montante devido nas operações seguintes;", "ordem": 874}, {"id": 875, "artigo_id": 155, "paragrafo_id": 399, "numero_romano": "II", "numero_int": 2, "texto": "II - acarretarão a anulação do crédito relativo às operações anteriores, salvo, na hipótese da imunidade, inclusive em relação ao inciso XI do § 1º, quando determinado em contrário em lei complementar.", "ordem": 875}, {"id": 876, "artigo_id": 155, "paragrafo_id": 401, "numero_romano": "I", "numero_int": 1, "texto": "I - deverá ser compensada pela elevação ou redução, pelo Senado Federal, das alíquotas de referência de que trata o § 1º, XII, de modo a preservar a arrecadação das esferas federativas, nos termos de lei complementar;", "ordem": 876}, {"id": 877, "artigo_id": 155, "paragrafo_id": 401, "numero_romano": "II", "numero_int": 2, "texto": "II - somente entrará em vigor com o início da produção de efeitos do ajuste das alíquotas de referência de que trata o inciso I deste parágrafo.", "ordem": 877}, {"id": 878, "artigo_id": 155, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - editar regulamento único e uniformizar a interpretação e a aplicação da legislação do imposto;", "ordem": 878}, {"id": 879, "artigo_id": 155, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - arrecadar o imposto, efetuar as compensações e distribuir o produto da arrecadação entre Estados, Distrito Federal e Municípios;", "ordem": 879}, {"id": 880, "artigo_id": 155, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - decidir o contencioso administrativo.", "ordem": 880}, {"id": 881, "artigo_id": 155, "paragrafo_id": 403, "numero_romano": "I", "numero_int": 1, "texto": "I - os Estados, o Distrito Federal e os Municípios serão representados, de forma paritária, na instância máxima de deliberação do Comitê Gestor do Imposto sobre Bens e Serviços;", "ordem": 881}, {"id": 882, "artigo_id": 155, "paragrafo_id": 403, "numero_romano": "II", "numero_int": 2, "texto": "II - será assegurada a alternância na presidência do Comitê Gestor entre o conjunto dos Estados e o Distrito Federal e o conjunto dos Municípios e o Distrito Federal;", "ordem": 882}, {"id": 883, "artigo_id": 155, "paragrafo_id": 403, "numero_romano": "III", "numero_int": 3, "texto": "III - o Comitê Gestor será financiado por percentual do produto da arrecadação do imposto destinado a cada ente federativo;", "ordem": 883}, {"id": 884, "artigo_id": 155, "paragrafo_id": 403, "numero_romano": "IV", "numero_int": 4, "texto": "IV - o controle externo do Comitê Gestor será exercido pelos Estados, pelo Distrito Federal e pelos Municípios;", "ordem": 884}, {"id": 885, "artigo_id": 155, "paragrafo_id": 403, "numero_romano": "V", "numero_int": 5, "texto": "V - a fiscalização, o lançamento, a cobrança, a representação administrativa e a representação judicial relativos ao imposto serão realizados, no âmbito de suas respectivas competências, pelas administrações tributárias e procuradorias dos Estados, do Distrito Federal e dos Municípios, que poderão definir hipóteses de delegação ou de compartilhamento de competências, cabendo ao Comitê Gestor a coordenação dessas atividades administrativas com vistas à integração entre os entes federativos;", "ordem": 885}, {"id": 886, "artigo_id": 155, "paragrafo_id": 403, "numero_romano": "VI", "numero_int": 6, "texto": "VI - as competências exclusivas das carreiras da administração tributária e das procuradorias dos Estados, do Distrito Federal e dos Municípios serão exercidas, no Comitê Gestor e na representação deste, por servidores das referidas carreiras;", "ordem": 886}, {"id": 887, "artigo_id": 155, "paragrafo_id": 403, "numero_romano": "VII", "numero_int": 7, "texto": "VII - serão estabelecidas a estrutura e a gestão do Comitê Gestor, cabendo ao regimento interno dispor sobre sua organização e funcionamento.", "ordem": 887}, {"id": 888, "artigo_id": 155, "paragrafo_id": 404, "numero_romano": "I", "numero_int": 1, "texto": "I - 27 (vinte e sete) membros, representando cada Estado e o Distrito Federal;", "ordem": 888}, {"id": 889, "artigo_id": 155, "paragrafo_id": 404, "numero_romano": "II", "numero_int": 2, "texto": "II - 27 (vinte e sete) membros, representando o conjunto dos Municípios e do Distrito Federal, que serão eleitos nos seguintes termos:", "ordem": 889}, {"id": 890, "artigo_id": 155, "paragrafo_id": 405, "numero_romano": "I", "numero_int": 1, "texto": "I - em relação ao conjunto dos Estados e do Distrito Federal:", "ordem": 890}, {"id": 891, "artigo_id": 155, "paragrafo_id": 405, "numero_romano": "II", "numero_int": 2, "texto": "II - em relação ao conjunto dos Municípios e do Distrito Federal, da maioria absoluta de seus representantes.", "ordem": 891}, {"id": 892, "artigo_id": 156, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - o produto da arrecadação do imposto da União sobre renda e proventos de qualquer natureza, incidente na fonte, sobre rendimentos pagos, a qualquer título, por eles, suas autarquias e pelas fundações que instituírem e mantiverem;", "ordem": 892}, {"id": 893, "artigo_id": 156, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - vinte por cento do produto da arrecadação do imposto que a União instituir no exercício da competência que lhe é atribuída pelo art. 154, I.", "ordem": 893}, {"id": 894, "artigo_id": 157, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - o produto da arrecadação do imposto da União sobre renda e proventos de qualquer natureza, incidente na fonte, sobre rendimentos pagos, a qualquer título, por eles, suas autarquias e pelas fundações que instituírem e mantiverem;", "ordem": 894}, {"id": 895, "artigo_id": 157, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - cinqüenta por cento do produto da arrecadação do imposto da União sobre a propriedade territorial rural, relativamente aos imóveis neles situados, cabendo a totalidade na hipótese da opção a que se refere o art. 153, § 4º, III; (Regulamento)", "ordem": 895}, {"id": 896, "artigo_id": 157, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - 50% (cinquenta por cento) do produto da arrecadação do imposto do Estado sobre a propriedade de veículos automotores licenciados em seus territórios e, em relação a veículos aquáticos e aéreos, cujos proprietários sejam domiciliados em seus territórios;", "ordem": 896}, {"id": 897, "artigo_id": 157, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - 25% (vinte e cinco por cento):", "ordem": 897}, {"id": 898, "artigo_id": 157, "paragrafo_id": 410, "numero_romano": "I", "numero_int": 1, "texto": "I - 65% (sessenta e cinco por cento), no mínimo, na proporção do valor adicionado nas operações relativas à circulação de mercadorias e nas prestações de serviços, realizadas em seus territórios;", "ordem": 898}, {"id": 899, "artigo_id": 157, "paragrafo_id": 410, "numero_romano": "II", "numero_int": 2, "texto": "II - até 35% (trinta e cinco por cento), de acordo com o que dispuser lei estadual, observada, obrigatoriamente, a distribuição de, no mínimo, 10 (dez) pontos percentuais com base em indicadores de melhoria nos resultados de aprendizagem e de aumento da equidade, considerado o nível socioeconômico dos educandos.", "ordem": 899}, {"id": 900, "artigo_id": 157, "paragrafo_id": 411, "numero_romano": "I", "numero_int": 1, "texto": "I - 80% (oitenta por cento) na proporção da população;", "ordem": 900}, {"id": 901, "artigo_id": 157, "paragrafo_id": 411, "numero_romano": "II", "numero_int": 2, "texto": "II - 10% (dez por cento) com base em indicadores de melhoria nos resultados de aprendizagem e de aumento da equidade, considerado o nível socioeconômico dos educandos, de acordo com o que dispuser lei estadual;", "ordem": 901}, {"id": 902, "artigo_id": 157, "paragrafo_id": 411, "numero_romano": "III", "numero_int": 3, "texto": "III - 5% (cinco por cento) com base em indicadores de preservação ambiental, de acordo com o que dispuser lei estadual;", "ordem": 902}, {"id": 903, "artigo_id": 157, "paragrafo_id": 411, "numero_romano": "IV", "numero_int": 4, "texto": "IV - 5% (cinco por cento) em montantes iguais para todos os Municípios do Estado.", "ordem": 903}, {"id": 904, "artigo_id": 158, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - do produto da arrecadação dos impostos sobre renda e proventos de qualquer natureza e sobre produtos industrializados e do imposto previsto no art. 153, VIII, 50% (cinquenta por cento), da seguinte forma:", "ordem": 904}, {"id": 905, "artigo_id": 158, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - do produto da arrecadação do imposto sobre produtos industrializados e do imposto previsto no art. 153, VIII, 10% (dez por cento) aos Estados e ao Distrito Federal, proporcionalmente ao valor das respectivas exportações de produtos industrializados;", "ordem": 905}, {"id": 906, "artigo_id": 158, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - do produto da arrecadação da contribuição de intervenção no domínio econômico prevista no art. 177, § 4º, 29% (vinte e nove por cento) para os Estados e o Distrito Federal, distribuídos na forma da lei, observadas as destinações a que se referem as alíneas \"c\" e \"d\" do inciso II do referido parágrafo.", "ordem": 906}, {"id": 907, "artigo_id": 158, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - realização de estudos, projetos e obras de infraestrutura;", "ordem": 907}, {"id": 908, "artigo_id": 158, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - fomento a atividades produtivas com elevado potencial de geração de emprego e renda, incluindo a concessão de subvenções econômicas e financeiras; e", "ordem": 908}, {"id": 909, "artigo_id": 158, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - promoção de ações com vistas ao desenvolvimento científico e tecnológico e à inovação.", "ordem": 909}, {"id": 910, "artigo_id": 158, "paragrafo_id": 419, "numero_romano": "I", "numero_int": 1, "texto": "I - população do Estado ou do Distrito Federal, com peso de 30% (trinta por cento);", "ordem": 910}, {"id": 911, "artigo_id": 158, "paragrafo_id": 419, "numero_romano": "II", "numero_int": 2, "texto": "II - coeficiente individual de participação do Estado ou do Distrito Federal nos recursos de que trata o art. 159, I, \"a\", da Constituição Federal, com peso de 70% (setenta por cento).", "ordem": 911}, {"id": 912, "artigo_id": 159, "paragrafo_id": 421, "numero_romano": "I", "numero_int": 1, "texto": "I - ao pagamento de seus créditos, inclusive de suas autarquias;", "ordem": 912}, {"id": 913, "artigo_id": 159, "paragrafo_id": 421, "numero_romano": "II", "numero_int": 2, "texto": "II - ao cumprimento do disposto no art. 198, § 2º, incisos II e III.", "ordem": 913}, {"id": 914, "artigo_id": 160, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - definir valor adicionado para fins do disposto no art. 158, § 1º, I; Vigência", "ordem": 914}, {"id": 915, "artigo_id": 160, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - estabelecer normas sobre a entrega dos recursos de que trata o art. 159, especialmente sobre os critérios de rateio dos fundos previstos em seu inciso I, objetivando promover o equilíbrio sócio-econômico entre Estados e entre Municípios;", "ordem": 915}, {"id": 916, "artigo_id": 160, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - dispor sobre o acompanhamento, pelos beneficiários, do cálculo das quotas e da liberação das participações previstas nos arts. 157, 158 e 159.", "ordem": 916}, {"id": 917, "artigo_id": 162, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - finanças públicas;", "ordem": 917}, {"id": 918, "artigo_id": 162, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - dívida pública externa e interna, incluída a das autarquias, fundações e demais entidades controladas pelo Poder Público;", "ordem": 918}, {"id": 919, "artigo_id": 162, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - concessão de garantias pelas entidades públicas;", "ordem": 919}, {"id": 920, "artigo_id": 162, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - emissão e resgate de títulos da dívida pública;", "ordem": 920}, {"id": 921, "artigo_id": 162, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - fiscalização financeira da administração pública direta e indireta;", "ordem": 921}, {"id": 922, "artigo_id": 162, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - operações de câmbio realizadas por órgãos e entidades da União, dos Estados, do Distrito Federal e dos Municípios;", "ordem": 922}, {"id": 923, "artigo_id": 162, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - compatibilização das funções das instituições oficiais de crédito da União, resguardadas as características e condições operacionais plenas das voltadas ao desenvolvimento regional.", "ordem": 923}, {"id": 924, "artigo_id": 162, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - sustentabilidade da dívida, especificando:", "ordem": 924}, {"id": 925, "artigo_id": 162, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - condições e limites para concessão, ampliação ou prorrogação de incentivo ou benefício de natureza tributária.", "ordem": 925}, {"id": 926, "artigo_id": 164, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - o plano plurianual;", "ordem": 926}, {"id": 927, "artigo_id": 164, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - as diretrizes orçamentárias;", "ordem": 927}, {"id": 928, "artigo_id": 164, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - os orçamentos anuais.", "ordem": 928}, {"id": 929, "artigo_id": 164, "paragrafo_id": 434, "numero_romano": "I", "numero_int": 1, "texto": "I - o orçamento fiscal referente aos Poderes da União, seus fundos, órgãos e entidades da administração direta e indireta, inclusive fundações instituídas e mantidas pelo Poder Público;", "ordem": 929}, {"id": 930, "artigo_id": 164, "paragrafo_id": 434, "numero_romano": "II", "numero_int": 2, "texto": "II - o orçamento de investimento das empresas em que a União, direta ou indiretamente, detenha a maioria do capital social com direito a voto;", "ordem": 930}, {"id": 931, "artigo_id": 164, "paragrafo_id": 434, "numero_romano": "III", "numero_int": 3, "texto": "III - o orçamento da seguridade social, abrangendo todas as entidades e órgãos a ela vinculados, da administração direta ou indireta, bem como os fundos e fundações instituídos e mantidos pelo Poder Público.", "ordem": 931}, {"id": 932, "artigo_id": 164, "paragrafo_id": 438, "numero_romano": "I", "numero_int": 1, "texto": "I - dispor sobre o exercício financeiro, a vigência, os prazos, a elaboração e a organização do plano plurianual, da lei de diretrizes orçamentárias e da lei orçamentária anual;", "ordem": 932}, {"id": 933, "artigo_id": 164, "paragrafo_id": 438, "numero_romano": "II", "numero_int": 2, "texto": "II - estabelecer normas de gestão financeira e patrimonial da administração direta e indireta bem como condições para a instituição e funcionamento de fundos.", "ordem": 933}, {"id": 934, "artigo_id": 164, "paragrafo_id": 438, "numero_romano": "III", "numero_int": 3, "texto": "III - dispor sobre critérios para a execução equitativa, além de procedimentos que serão adotados quando houver impedimentos legais e técnicos, cumprimento de restos a pagar e limitação das programações de caráter obrigatório, para a realização do disposto nos §§ 11 e 12 do art. 166 . (Produção de efeito )", "ordem": 934}, {"id": 935, "artigo_id": 164, "paragrafo_id": 438, "numero_romano": "I", "numero_int": 1, "texto": "I - subordina-se ao cumprimento de dispositivos constitucionais e legais que estabeleçam metas fiscais ou limites de despesas e não impede o cancelamento necessário à abertura de créditos adicionais;", "ordem": 935}, {"id": 936, "artigo_id": 164, "paragrafo_id": 438, "numero_romano": "II", "numero_int": 2, "texto": "II - não se aplica nos casos de impedimentos de ordem técnica devidamente justificados;", "ordem": 936}, {"id": 937, "artigo_id": 164, "paragrafo_id": 438, "numero_romano": "III", "numero_int": 3, "texto": "III - aplica-se exclusivamente às despesas primárias discricionárias.", "ordem": 937}, {"id": 938, "artigo_id": 165, "paragrafo_id": 439, "numero_romano": "I", "numero_int": 1, "texto": "I - examinar e emitir parecer sobre os projetos referidos neste artigo e sobre as contas apresentadas anualmente pelo Presidente da República;", "ordem": 938}, {"id": 939, "artigo_id": 165, "paragrafo_id": 439, "numero_romano": "II", "numero_int": 2, "texto": "II - examinar e emitir parecer sobre os planos e programas nacionais, regionais e setoriais previstos nesta Constituição e exercer o acompanhamento e a fiscalização orçamentária, sem prejuízo da atuação das demais comissões do Congresso Nacional e de suas Casas, criadas de acordo com o art. 58.", "ordem": 939}, {"id": 940, "artigo_id": 165, "paragrafo_id": 441, "numero_romano": "I", "numero_int": 1, "texto": "I - sejam compatíveis com o plano plurianual e com a lei de diretrizes orçamentárias;", "ordem": 940}, {"id": 941, "artigo_id": 165, "paragrafo_id": 441, "numero_romano": "II", "numero_int": 2, "texto": "II - indiquem os recursos necessários, admitidos apenas os provenientes de anulação de despesa, excluídas as que incidam sobre:", "ordem": 941}, {"id": 942, "artigo_id": 165, "paragrafo_id": 441, "numero_romano": "III", "numero_int": 3, "texto": "III - sejam relacionadas:", "ordem": 942}, {"id": 943, "artigo_id": 165, "paragrafo_id": 447, "numero_romano": "I", "numero_int": 1, "texto": "I - (revogado); (Produção de efeito)", "ordem": 943}, {"id": 944, "artigo_id": 165, "paragrafo_id": 447, "numero_romano": "II", "numero_int": 2, "texto": "II - (revogado); (Produção de efeito)", "ordem": 944}, {"id": 945, "artigo_id": 165, "paragrafo_id": 447, "numero_romano": "III", "numero_int": 3, "texto": "III - (revogado); (Produção de efeito)", "ordem": 945}, {"id": 946, "artigo_id": 165, "paragrafo_id": 447, "numero_romano": "IV", "numero_int": 4, "texto": "IV - (revogado). (Produção de efeito)", "ordem": 946}, {"id": 947, "artigo_id": 165, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - transferência especial; ou", "ordem": 947}, {"id": 948, "artigo_id": 165, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - transferência com finalidade definida.", "ordem": 948}, {"id": 949, "artigo_id": 165, "paragrafo_id": 448, "numero_romano": "I", "numero_int": 1, "texto": "I - despesas com pessoal e encargos sociais relativas a ativos e inativos, e com pensionistas; e", "ordem": 949}, {"id": 950, "artigo_id": 165, "paragrafo_id": 448, "numero_romano": "II", "numero_int": 2, "texto": "II - encargos referentes ao serviço da dívida.", "ordem": 950}, {"id": 951, "artigo_id": 165, "paragrafo_id": 449, "numero_romano": "I", "numero_int": 1, "texto": "I - serão repassados diretamente ao ente federado beneficiado, independentemente de celebração de convênio ou de instrumento congênere;", "ordem": 951}, {"id": 952, "artigo_id": 165, "paragrafo_id": 449, "numero_romano": "II", "numero_int": 2, "texto": "II - pertencerão ao ente federado no ato da efetiva transferência financeira; e", "ordem": 952}, {"id": 953, "artigo_id": 165, "paragrafo_id": 449, "numero_romano": "III", "numero_int": 3, "texto": "III - serão aplicadas em programações finalísticas das áreas de competência do Poder Executivo do ente federado beneficiado, observado o disposto no § 5º deste artigo.", "ordem": 953}, {"id": 954, "artigo_id": 165, "paragrafo_id": 451, "numero_romano": "I", "numero_int": 1, "texto": "I - vinculados à programação estabelecida na emenda parlamentar; e", "ordem": 954}, {"id": 955, "artigo_id": 165, "paragrafo_id": 451, "numero_romano": "II", "numero_int": 2, "texto": "II - aplicados nas áreas de competência constitucional da União.", "ordem": 955}, {"id": 956, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - o início de programas ou projetos não incluídos na lei orçamentária anual;", "ordem": 956}, {"id": 957, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - a realização de despesas ou a assunção de obrigações diretas que excedam os créditos orçamentários ou adicionais;", "ordem": 957}, {"id": 958, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - a realização de operações de créditos que excedam o montante das despesas de capital, ressalvadas as autorizadas mediante créditos suplementares ou especiais com finalidade precisa, aprovados pelo Poder Legislativo por maioria absoluta;", "ordem": 958}, {"id": 959, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - a vinculação de receita de impostos a órgão, fundo ou despesa, ressalvadas a repartição do produto da arrecadação dos impostos a que se referem os arts. 158 e 159, a destinação de recursos para as ações e serviços públicos de saúde, para manutenção e desenvolvimento do ensino e para realização de atividades da administração tributária, como determinado, respectivamente, pelos arts. 198, § 2º, 212 e 37, XXII, e a prestação de garantias às operações de crédito por antecipação de receita, previstas no art. 165, § 8º, bem como o disposto no § 4º deste artigo;", "ordem": 959}, {"id": 960, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - a abertura de crédito suplementar ou especial sem prévia autorização legislativa e sem indicação dos recursos correspondentes;", "ordem": 960}, {"id": 961, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - a transposição, o remanejamento ou a transferência de recursos de uma categoria de programação para outra ou de um órgão para outro, sem prévia autorização legislativa;", "ordem": 961}, {"id": 962, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - a concessão ou utilização de créditos ilimitados;", "ordem": 962}, {"id": 963, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - a utilização, sem autorização legislativa específica, de recursos dos orçamentos fiscal e da seguridade social para suprir necessidade ou cobrir déficit de empresas, fundações e fundos, inclusive dos mencionados no art. 165, § 5º;", "ordem": 963}, {"id": 964, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - a instituição de fundos de qualquer natureza, sem prévia autorização legislativa.", "ordem": 964}, {"id": 965, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "X", "numero_int": 10, "texto": "X - a transferência voluntária de recursos e a concessão de empréstimos, inclusive por antecipação de receita, pelos Governos Federal e Estaduais e suas instituições financeiras, para pagamento de despesas com pessoal ativo, inativo e pensionista, dos Estados, do Distrito Federal e dos Municípios.", "ordem": 965}, {"id": 966, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "XI", "numero_int": 11, "texto": "XI - a utilização dos recursos provenientes das contribuições sociais de que trata o art. 195, I, a, e II, para a realização de despesas distintas do pagamento de benefícios do regime geral de previdência social de que trata o art. 201.", "ordem": 966}, {"id": 967, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "XII", "numero_int": 12, "texto": "XII - na forma estabelecida na lei complementar de que trata o § 22 do art. 40, a utilização de recursos de regime próprio de previdência social, incluídos os valores integrantes dos fundos previstos no art. 249, para a realização de despesas distintas do pagamento dos benefícios previdenciários do respectivo fundo vinculado àquele regime e das despesas necessárias à sua organização e ao seu funcionamento;", "ordem": 967}, {"id": 968, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "XIII", "numero_int": 13, "texto": "XIII - a transferência voluntária de recursos, a concessão de avais, as garantias e as subvenções pela União e a concessão de empréstimos e de financiamentos por instituições financeiras federais aos Estados, ao Distrito Federal e aos Municípios na hipótese de descumprimento das regras gerais de organização e de funcionamento de regime próprio de previdência social.", "ordem": 968}, {"id": 969, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "XIV", "numero_int": 14, "texto": "XIV - a criação de fundo público, quando seus objetivos puderem ser alcançados mediante a vinculação de receitas orçamentárias específicas ou mediante a execução direta por programação orçamentária e financeira de órgão ou entidade da administração pública.", "ordem": 969}, {"id": 970, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - concessão, a qualquer título, de vantagem, aumento, reajuste ou adequação de remuneração de membros de Poder ou de órgão, de servidores e empregados públicos e de militares, exceto dos derivados de sentença judicial transitada em julgado ou de determinação legal anterior ao início da aplicação das medidas de que trata este artigo;", "ordem": 970}, {"id": 971, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - criação de cargo, emprego ou função que implique aumento de despesa;", "ordem": 971}, {"id": 972, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - alteração de estrutura de carreira que implique aumento de despesa;", "ordem": 972}, {"id": 973, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - admissão ou contratação de pessoal, a qualquer título, ressalvadas:", "ordem": 973}, {"id": 974, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - realização de concurso público, exceto para as reposições de vacâncias previstas no inciso IV deste caput;", "ordem": 974}, {"id": 975, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - criação ou majoração de auxílios, vantagens, bônus, abonos, verbas de representação ou benefícios de qualquer natureza, inclusive os de cunho indenizatório, em favor de membros de Poder, do Ministério Público ou da Defensoria Pública e de servidores e empregados públicos e de militares, ou ainda de seus dependentes, exceto quando derivados de sentença judicial transitada em julgado ou de determinação legal anterior ao início da aplicação das medidas de que trata este artigo;", "ordem": 975}, {"id": 976, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - criação de despesa obrigatória;", "ordem": 976}, {"id": 977, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - adoção de medida que implique reajuste de despesa obrigatória acima da variação da inflação, observada a preservação do poder aquisitivo referida no inciso IV do caput do art. 7º desta Constituição;", "ordem": 977}, {"id": 978, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - criação ou expansão de programas e linhas de financiamento, bem como remissão, renegociação ou refinanciamento de dívidas que impliquem ampliação das despesas com subsídios e subvenções;", "ordem": 978}, {"id": 979, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "X", "numero_int": 10, "texto": "X - concessão ou ampliação de incentivo ou benefício de natureza tributária.", "ordem": 979}, {"id": 980, "artigo_id": 166, "paragrafo_id": 462, "numero_romano": "I", "numero_int": 1, "texto": "I - rejeitado pelo Poder Legislativo;", "ordem": 980}, {"id": 981, "artigo_id": 166, "paragrafo_id": 462, "numero_romano": "II", "numero_int": 2, "texto": "II - transcorrido o prazo de 180 (cento e oitenta) dias sem que se ultime a sua apreciação; ou", "ordem": 981}, {"id": 982, "artigo_id": 166, "paragrafo_id": 462, "numero_romano": "III", "numero_int": 3, "texto": "III - apurado que não mais se verifica a hipótese prevista no § 1º deste artigo, mesmo após a sua aprovação pelo Poder Legislativo.", "ordem": 982}, {"id": 983, "artigo_id": 166, "paragrafo_id": 464, "numero_romano": "I", "numero_int": 1, "texto": "I - não constituem obrigação de pagamento futuro pelo ente da Federação ou direitos de outrem sobre o erário;", "ordem": 983}, {"id": 984, "artigo_id": 166, "paragrafo_id": 464, "numero_romano": "II", "numero_int": 2, "texto": "II - não revogam, dispensam ou suspendem o cumprimento de dispositivos constitucionais e legais que disponham sobre metas fiscais ou limites máximos de despesas.", "ordem": 984}, {"id": 985, "artigo_id": 166, "paragrafo_id": 465, "numero_romano": "I", "numero_int": 1, "texto": "I - a concessão, por qualquer outro ente da Federação, de garantias ao ente envolvido;", "ordem": 985}, {"id": 986, "artigo_id": 166, "paragrafo_id": 465, "numero_romano": "II", "numero_int": 2, "texto": "II - a tomada de operação de crédito por parte do ente envolvido com outro ente da Federação, diretamente ou por intermédio de seus fundos, autarquias, fundações ou empresas estatais dependentes, ainda que sob a forma de novação, refinanciamento ou postergação de dívida contraída anteriormente, ressalvados os financiamentos destinados a projetos específicos celebrados na forma de operações típicas das agências financeiras oficiais de fomento.", "ordem": 986}, {"id": 987, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - são dispensados, durante a integralidade do exercício financeiro em que vigore a calamidade pública, os limites, as condições e demais restrições aplicáveis à União para a contratação de operações de crédito, bem como sua verificação;", "ordem": 987}, {"id": 988, "artigo_id": 166, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - o superávit financeiro apurado em 31 de dezembro do ano imediatamente anterior ao reconhecimento pode ser destinado à cobertura de despesas oriundas das medidas de combate à calamidade pública de âmbito nacional e ao pagamento da dívida pública.", "ordem": 988}, {"id": 989, "artigo_id": 166, "paragrafo_id": 468, "numero_romano": "I", "numero_int": 1, "texto": "I - decorrentes de repartição de receitas a Estados, ao Distrito Federal e a Municípios;", "ordem": 989}, {"id": 990, "artigo_id": 166, "paragrafo_id": 468, "numero_romano": "II", "numero_int": 2, "texto": "II - decorrentes das vinculações estabelecidas pelos arts. 195, 198, 201, 212, 212-A e 239 desta Constituição;", "ordem": 990}, {"id": 991, "artigo_id": 166, "paragrafo_id": 468, "numero_romano": "III", "numero_int": 3, "texto": "III - destinadas ao registro de receitas oriundas da arrecadação de doações ou de empréstimos compulsórios, de transferências recebidas para o atendimento de finalidades determinadas ou das receitas de capital produto de operações de financiamento celebradas com finalidades contratualmente determinadas.", "ordem": 991}, {"id": 992, "artigo_id": 168, "paragrafo_id": 474, "numero_romano": "I", "numero_int": 1, "texto": "I - se houver prévia dotação orçamentária suficiente para atender às projeções de despesa de pessoal e aos acréscimos dela decorrentes;", "ordem": 992}, {"id": 993, "artigo_id": 168, "paragrafo_id": 474, "numero_romano": "II", "numero_int": 2, "texto": "II - se houver autorização específica na lei de diretrizes orçamentárias, ressalvadas as empresas públicas e as sociedades de economia mista.", "ordem": 993}, {"id": 994, "artigo_id": 168, "paragrafo_id": 476, "numero_romano": "I", "numero_int": 1, "texto": "I - redução em pelo menos vinte por cento das despesas com cargos em comissão e funções de confiança;", "ordem": 994}, {"id": 995, "artigo_id": 168, "paragrafo_id": 476, "numero_romano": "II", "numero_int": 2, "texto": "II - exoneração dos servidores não estáveis.", "ordem": 995}, {"id": 996, "artigo_id": 169, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - soberania nacional;", "ordem": 996}, {"id": 997, "artigo_id": 169, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - propriedade privada;", "ordem": 997}, {"id": 998, "artigo_id": 169, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - função social da propriedade;", "ordem": 998}, {"id": 999, "artigo_id": 169, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - livre concorrência;", "ordem": 999}, {"id": 1000, "artigo_id": 169, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - defesa do consumidor;", "ordem": 1000}, {"id": 1001, "artigo_id": 169, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - defesa do meio ambiente, inclusive mediante tratamento diferenciado conforme o impacto ambiental dos produtos e serviços e de seus processos de elaboração e prestação;", "ordem": 1001}, {"id": 1002, "artigo_id": 169, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - redução das desigualdades regionais e sociais;", "ordem": 1002}, {"id": 1003, "artigo_id": 169, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - busca do pleno emprego;", "ordem": 1003}, {"id": 1004, "artigo_id": 169, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - tratamento favorecido para as empresas de pequeno porte constituídas sob as leis brasileiras e que tenham sua sede e administração no País.", "ordem": 1004}, {"id": 1005, "artigo_id": 171, "paragrafo_id": 482, "numero_romano": "I", "numero_int": 1, "texto": "I - sua função social e formas de fiscalização pelo Estado e pela sociedade;", "ordem": 1005}, {"id": 1006, "artigo_id": 171, "paragrafo_id": 482, "numero_romano": "II", "numero_int": 2, "texto": "II - a sujeição ao regime jurídico próprio das empresas privadas, inclusive quanto aos direitos e obrigações civis, comerciais, trabalhistas e tributários;", "ordem": 1006}, {"id": 1007, "artigo_id": 171, "paragrafo_id": 482, "numero_romano": "III", "numero_int": 3, "texto": "III - licitação e contratação de obras, serviços, compras e alienações, observados os princípios da administração pública;", "ordem": 1007}, {"id": 1008, "artigo_id": 171, "paragrafo_id": 482, "numero_romano": "IV", "numero_int": 4, "texto": "IV - a constituição e o funcionamento dos conselhos de administração e fiscal, com a participação de acionistas minoritários;", "ordem": 1008}, {"id": 1009, "artigo_id": 171, "paragrafo_id": 482, "numero_romano": "V", "numero_int": 5, "texto": "V - os mandatos, a avaliação de desempenho e a responsabilidade dos administradores.", "ordem": 1009}, {"id": 1010, "artigo_id": 173, "paragrafo_id": 491, "numero_romano": "I", "numero_int": 1, "texto": "I - o regime das empresas concessionárias e permissionárias de serviços públicos, o caráter especial de seu contrato e de sua prorrogação, bem como as condições de caducidade, fiscalização e rescisão da concessão ou permissão;", "ordem": 1010}, {"id": 1011, "artigo_id": 173, "paragrafo_id": 491, "numero_romano": "II", "numero_int": 2, "texto": "II - os direitos dos usuários;", "ordem": 1011}, {"id": 1012, "artigo_id": 173, "paragrafo_id": 491, "numero_romano": "III", "numero_int": 3, "texto": "III - política tarifária;", "ordem": 1012}, {"id": 1013, "artigo_id": 173, "paragrafo_id": 491, "numero_romano": "IV", "numero_int": 4, "texto": "IV - a obrigação de manter serviço adequado.", "ordem": 1013}, {"id": 1014, "artigo_id": 175, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - a pesquisa e a lavra das jazidas de petróleo e gás natural e outros hidrocarbonetos fluidos;", "ordem": 1014}, {"id": 1015, "artigo_id": 175, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - a refinação do petróleo nacional ou estrangeiro;", "ordem": 1015}, {"id": 1016, "artigo_id": 175, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - a importação e exportação dos produtos e derivados básicos resultantes das atividades previstas nos incisos anteriores;", "ordem": 1016}, {"id": 1017, "artigo_id": 175, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - o transporte marítimo do petróleo bruto de origem nacional ou de derivados básicos de petróleo produzidos no País, bem assim o transporte, por meio de conduto, de petróleo bruto, seus derivados e gás natural de qualquer origem;", "ordem": 1017}, {"id": 1018, "artigo_id": 175, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - a pesquisa, a lavra, o enriquecimento, o reprocessamento, a industrialização e o comércio de minérios e minerais nucleares e seus derivados, com exceção dos radioisótopos cuja produção, comercialização e utilização poderão ser autorizadas sob regime de permissão, conforme as alíneas b e c do inciso XXIII do caput do art. 21 desta Constituição Federal.", "ordem": 1018}, {"id": 1019, "artigo_id": 175, "paragrafo_id": 497, "numero_romano": "I", "numero_int": 1, "texto": "I - a garantia do fornecimento dos derivados de petróleo em todo o território nacional;", "ordem": 1019}, {"id": 1020, "artigo_id": 175, "paragrafo_id": 497, "numero_romano": "II", "numero_int": 2, "texto": "II - as condições de contratação;", "ordem": 1020}, {"id": 1021, "artigo_id": 175, "paragrafo_id": 497, "numero_romano": "III", "numero_int": 3, "texto": "III - a estrutura e atribuições do órgão regulador do monopólio da União;", "ordem": 1021}, {"id": 1022, "artigo_id": 175, "paragrafo_id": 499, "numero_romano": "I", "numero_int": 1, "texto": "I - a alíquota da contribuição poderá ser:", "ordem": 1022}, {"id": 1023, "artigo_id": 175, "paragrafo_id": 499, "numero_romano": "II", "numero_int": 2, "texto": "II - os recursos arrecadados serão destinados:", "ordem": 1023}, {"id": 1024, "artigo_id": 180, "paragrafo_id": 504, "numero_romano": "I", "numero_int": 1, "texto": "I - parcelamento ou edificação compulsórios;", "ordem": 1024}, {"id": 1025, "artigo_id": 180, "paragrafo_id": 504, "numero_romano": "II", "numero_int": 2, "texto": "II - imposto sobre a propriedade predial e territorial urbana progressivo no tempo;", "ordem": 1025}, {"id": 1026, "artigo_id": 180, "paragrafo_id": 504, "numero_romano": "III", "numero_int": 3, "texto": "III - desapropriação com pagamento mediante títulos da dívida pública de emissão previamente aprovada pelo Senado Federal, com prazo de resgate de até dez anos, em parcelas anuais, iguais e sucessivas, assegurados o valor real da indenização e os juros legais.", "ordem": 1026}, {"id": 1027, "artigo_id": 183, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - a pequena e média propriedade rural, assim definida em lei, desde que seu proprietário não possua outra;", "ordem": 1027}, {"id": 1028, "artigo_id": 183, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - a propriedade produtiva.", "ordem": 1028}, {"id": 1029, "artigo_id": 184, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - aproveitamento racional e adequado;", "ordem": 1029}, {"id": 1030, "artigo_id": 184, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - utilização adequada dos recursos naturais disponíveis e preservação do meio ambiente;", "ordem": 1030}, {"id": 1031, "artigo_id": 184, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - observância das disposições que regulam as relações de trabalho;", "ordem": 1031}, {"id": 1032, "artigo_id": 184, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - exploração que favoreça o bem-estar dos proprietários e dos trabalhadores.", "ordem": 1032}, {"id": 1033, "artigo_id": 185, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - os instrumentos creditícios e fiscais;", "ordem": 1033}, {"id": 1034, "artigo_id": 185, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - os preços compatíveis com os custos de produção e a garantia de comercialização;", "ordem": 1034}, {"id": 1035, "artigo_id": 185, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - o incentivo à pesquisa e à tecnologia;", "ordem": 1035}, {"id": 1036, "artigo_id": 185, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - a assistência técnica e extensão rural;", "ordem": 1036}, {"id": 1037, "artigo_id": 185, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - o seguro agrícola;", "ordem": 1037}, {"id": 1038, "artigo_id": 185, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - o cooperativismo;", "ordem": 1038}, {"id": 1039, "artigo_id": 185, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - a eletrificação rural e irrigação;", "ordem": 1039}, {"id": 1040, "artigo_id": 185, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - a habitação para o trabalhador rural.", "ordem": 1040}, {"id": 1041, "artigo_id": 192, "paragrafo_id": 521, "numero_romano": "I", "numero_int": 1, "texto": "I - universalidade da cobertura e do atendimento;", "ordem": 1041}, {"id": 1042, "artigo_id": 192, "paragrafo_id": 521, "numero_romano": "II", "numero_int": 2, "texto": "II - uniformidade e equivalência dos benefícios e serviços às populações urbanas e rurais;", "ordem": 1042}, {"id": 1043, "artigo_id": 192, "paragrafo_id": 521, "numero_romano": "III", "numero_int": 3, "texto": "III - seletividade e distributividade na prestação dos benefícios e serviços;", "ordem": 1043}, {"id": 1044, "artigo_id": 192, "paragrafo_id": 521, "numero_romano": "IV", "numero_int": 4, "texto": "IV - irredutibilidade do valor dos benefícios;", "ordem": 1044}, {"id": 1045, "artigo_id": 192, "paragrafo_id": 521, "numero_romano": "V", "numero_int": 5, "texto": "V - eqüidade na forma de participação no custeio;", "ordem": 1045}, {"id": 1046, "artigo_id": 192, "paragrafo_id": 521, "numero_romano": "VI", "numero_int": 6, "texto": "VI - diversidade da base de financiamento, identificando-se, em rubricas contábeis específicas para cada área, as receitas e as despesas vinculadas a ações de saúde, previdência e assistência social, preservado o caráter contributivo da previdência social;", "ordem": 1046}, {"id": 1047, "artigo_id": 192, "paragrafo_id": 521, "numero_romano": "VII", "numero_int": 7, "texto": "VII - caráter democrático e descentralizado da administração, mediante gestão quadripartite, com participação dos trabalhadores, dos empregadores, dos aposentados e do Governo nos órgãos colegiados.", "ordem": 1047}, {"id": 1048, "artigo_id": 193, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - do empregador, da empresa e da entidade a ela equiparada na forma da lei, incidentes sobre:", "ordem": 1048}, {"id": 1049, "artigo_id": 193, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - do trabalhador e dos demais segurados da previdência social, podendo ser adotadas alíquotas progressivas de acordo com o valor do salário de contribuição, não incidindo contribuição sobre aposentadoria e pensão concedidas pelo Regime Geral de Previdência Social;", "ordem": 1049}, {"id": 1050, "artigo_id": 193, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - sobre a receita de concursos de prognósticos.", "ordem": 1050}, {"id": 1051, "artigo_id": 193, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - do importador de bens ou serviços do exterior, ou de quem a lei a ele equiparar. Vigência", "ordem": 1051}, {"id": 1052, "artigo_id": 193, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - sobre bens e serviços, nos termos de lei complementar.", "ordem": 1052}, {"id": 1053, "artigo_id": 196, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - descentralização, com direção única em cada esfera de governo;", "ordem": 1053}, {"id": 1054, "artigo_id": 196, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - atendimento integral, com prioridade para as atividades preventivas, sem prejuízo dos serviços assistenciais;", "ordem": 1054}, {"id": 1055, "artigo_id": 196, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - participação da comunidade.", "ordem": 1055}, {"id": 1056, "artigo_id": 196, "paragrafo_id": 531, "numero_romano": "I", "numero_int": 1, "texto": "I - no caso da União, a receita corrente líquida do respectivo exercício financeiro, não podendo ser inferior a 15% (quinze por cento);", "ordem": 1056}, {"id": 1057, "artigo_id": 196, "paragrafo_id": 531, "numero_romano": "II", "numero_int": 2, "texto": "II - no caso dos Estados e do Distrito Federal, o produto da arrecadação dos impostos a que se referem os arts. 155 e 156-A e dos recursos de que tratam os arts. 157 e 159, I, \"a\", e II, deduzidas as parcelas que forem transferidas aos respectivos Municípios;", "ordem": 1057}, {"id": 1058, "artigo_id": 196, "paragrafo_id": 531, "numero_romano": "III", "numero_int": 3, "texto": "III - no caso dos Municípios e do Distrito Federal, o produto da arrecadação dos impostos a que se referem os arts. 156 e 156-A e dos recursos de que tratam os arts. 158 e 159, I, \"b\", e § 3º.", "ordem": 1058}, {"id": 1059, "artigo_id": 196, "paragrafo_id": 532, "numero_romano": "I", "numero_int": 1, "texto": "I - os percentuais de que tratam os incisos II e III do § 2º;", "ordem": 1059}, {"id": 1060, "artigo_id": 196, "paragrafo_id": 532, "numero_romano": "II", "numero_int": 2, "texto": "II - os critérios de rateio dos recursos da União vinculados à saúde destinados aos Estados, ao Distrito Federal e aos Municípios, e dos Estados destinados a seus respectivos Municípios, objetivando a progressiva redução das disparidades regionais;", "ordem": 1060}, {"id": 1061, "artigo_id": 196, "paragrafo_id": 532, "numero_romano": "III", "numero_int": 3, "texto": "III - as normas de fiscalização, avaliação e controle das despesas com saúde nas esferas federal, estadual, distrital e municipal;", "ordem": 1061}, {"id": 1062, "artigo_id": 196, "paragrafo_id": 532, "numero_romano": "IV", "numero_int": 4, "texto": "IV - (revogado) .", "ordem": 1062}, {"id": 1063, "artigo_id": 198, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - controlar e fiscalizar procedimentos, produtos e substâncias de interesse para a saúde e participar da produção de medicamentos, equipamentos, imunobiológicos, hemoderivados e outros insumos;", "ordem": 1063}, {"id": 1064, "artigo_id": 198, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - executar as ações de vigilância sanitária e epidemiológica, bem como as de saúde do trabalhador;", "ordem": 1064}, {"id": 1065, "artigo_id": 198, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - ordenar a formação de recursos humanos na área de saúde;", "ordem": 1065}, {"id": 1066, "artigo_id": 198, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - participar da formulação da política e da execução das ações de saneamento básico;", "ordem": 1066}, {"id": 1067, "artigo_id": 198, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - incrementar, em sua área de atuação, o desenvolvimento científico e tecnológico e a inovação;", "ordem": 1067}, {"id": 1068, "artigo_id": 198, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - fiscalizar e inspecionar alimentos, compreendido o controle de seu teor nutricional, bem como bebidas e águas para consumo humano;", "ordem": 1068}, {"id": 1069, "artigo_id": 198, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - participar do controle e fiscalização da produção, transporte, guarda e utilização de substâncias e produtos psicoativos, tóxicos e radioativos;", "ordem": 1069}, {"id": 1070, "artigo_id": 198, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - colaborar na proteção do meio ambiente, nele compreendido o do trabalho.", "ordem": 1070}, {"id": 1071, "artigo_id": 199, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - cobertura dos eventos de incapacidade temporária ou permanente para o trabalho e idade avançada;", "ordem": 1071}, {"id": 1072, "artigo_id": 199, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - proteção à maternidade, especialmente à gestante;", "ordem": 1072}, {"id": 1073, "artigo_id": 199, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - proteção ao trabalhador em situação de desemprego involuntário;", "ordem": 1073}, {"id": 1074, "artigo_id": 199, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - salário-família e auxílio-reclusão para os dependentes dos segurados de baixa renda;", "ordem": 1074}, {"id": 1075, "artigo_id": 199, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - pensão por morte do segurado, homem ou mulher, ao cônjuge ou companheiro e dependentes, observado o disposto no § 2º.", "ordem": 1075}, {"id": 1076, "artigo_id": 199, "paragrafo_id": 543, "numero_romano": "I", "numero_int": 1, "texto": "I - com deficiência, previamente submetidos a avaliação biopsicossocial realizada por equipe multiprofissional e interdisciplinar;", "ordem": 1076}, {"id": 1077, "artigo_id": 199, "paragrafo_id": 543, "numero_romano": "II", "numero_int": 2, "texto": "II - cujas atividades sejam exercidas com efetiva exposição a agentes químicos, físicos e biológicos prejudiciais à saúde, ou associação desses agentes, vedada a caracterização por categoria profissional ou ocupação.", "ordem": 1077}, {"id": 1078, "artigo_id": 199, "paragrafo_id": 549, "numero_romano": "I", "numero_int": 1, "texto": "I - 65 (sessenta e cinco) anos de idade, se homem, e 62 (sessenta e dois) anos de idade, se mulher, observado tempo mínimo de contribuição;", "ordem": 1078}, {"id": 1079, "artigo_id": 199, "paragrafo_id": 549, "numero_romano": "II", "numero_int": 2, "texto": "II - 60 (sessenta) anos de idade, se homem, e 55 (cinquenta e cinco) anos de idade, se mulher, para os trabalhadores rurais e para os que exerçam suas atividades em regime de economia familiar, nestes incluídos o produtor rural, o garimpeiro e o pescador artesanal.", "ordem": 1079}, {"id": 1080, "artigo_id": 201, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - a proteção à família, à maternidade, à infância, à adolescência e à velhice;", "ordem": 1080}, {"id": 1081, "artigo_id": 201, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - o amparo às crianças e adolescentes carentes;", "ordem": 1081}, {"id": 1082, "artigo_id": 201, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - a promoção da integração ao mercado de trabalho;", "ordem": 1082}, {"id": 1083, "artigo_id": 201, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - a habilitação e reabilitação das pessoas portadoras de deficiência e a promoção de sua integração à vida comunitária;", "ordem": 1083}, {"id": 1084, "artigo_id": 201, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - a garantia de um salário mínimo de benefício mensal à pessoa portadora de deficiência e ao idoso que comprovem não possuir meios de prover à própria manutenção ou de tê-la provida por sua família, conforme dispuser a lei.", "ordem": 1084}, {"id": 1085, "artigo_id": 201, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - a redução da vulnerabilidade socioeconômica de famílias em situação de pobreza ou de extrema pobreza.", "ordem": 1085}, {"id": 1086, "artigo_id": 202, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - descentralização político-administrativa, cabendo a coordenação e as normas gerais à esfera federal e a coordenação e a execução dos respectivos programas às esferas estadual e municipal, bem como a entidades beneficentes e de assistência social;", "ordem": 1086}, {"id": 1087, "artigo_id": 202, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - participação da população, por meio de organizações representativas, na formulação das políticas e no controle das ações em todos os níveis.", "ordem": 1087}, {"id": 1088, "artigo_id": 202, "paragrafo_id": 558, "numero_romano": "I", "numero_int": 1, "texto": "I - despesas com pessoal e encargos sociais;", "ordem": 1088}, {"id": 1089, "artigo_id": 202, "paragrafo_id": 558, "numero_romano": "II", "numero_int": 2, "texto": "II - serviço da dívida;", "ordem": 1089}, {"id": 1090, "artigo_id": 202, "paragrafo_id": 558, "numero_romano": "III", "numero_int": 3, "texto": "III - qualquer outra despesa corrente não vinculada diretamente aos investimentos ou ações apoiados.", "ordem": 1090}, {"id": 1091, "artigo_id": 204, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - igualdade de condições para o acesso e permanência na escola;", "ordem": 1091}, {"id": 1092, "artigo_id": 204, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - liberdade de aprender, ensinar, pesquisar e divulgar o pensamento, a arte e o saber;", "ordem": 1092}, {"id": 1093, "artigo_id": 204, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - pluralismo de idéias e de concepções pedagógicas, e coexistência de instituições públicas e privadas de ensino;", "ordem": 1093}, {"id": 1094, "artigo_id": 204, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - gratuidade do ensino público em estabelecimentos oficiais;", "ordem": 1094}, {"id": 1095, "artigo_id": 204, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - valorização dos profissionais da educação escolar, garantidos, na forma da lei, planos de carreira, com ingresso exclusivamente por concurso público de provas e títulos, aos das redes públicas;", "ordem": 1095}, {"id": 1096, "artigo_id": 204, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - gestão democrática do ensino público, na forma da lei;", "ordem": 1096}, {"id": 1097, "artigo_id": 204, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - garantia de padrão de qualidade.", "ordem": 1097}, {"id": 1098, "artigo_id": 204, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - piso salarial profissional nacional para os profissionais da educação escolar pública, nos termos de lei federal.", "ordem": 1098}, {"id": 1099, "artigo_id": 204, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - garantia do direito à educação e à aprendizagem ao longo da vida.", "ordem": 1099}, {"id": 1100, "artigo_id": 206, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - educação básica obrigatória e gratuita dos 4 (quatro) aos 17 (dezessete) anos de idade, assegurada inclusive sua oferta gratuita para todos os que a ela não tiveram acesso na idade própria;", "ordem": 1100}, {"id": 1101, "artigo_id": 206, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - progressiva universalização do ensino médio gratuito;", "ordem": 1101}, {"id": 1102, "artigo_id": 206, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - atendimento educacional especializado aos portadores de deficiência, preferencialmente na rede regular de ensino;", "ordem": 1102}, {"id": 1103, "artigo_id": 206, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - educação infantil, em creche e pré-escola, às crianças até 5 (cinco) anos de idade;", "ordem": 1103}, {"id": 1104, "artigo_id": 206, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - acesso aos níveis mais elevados do ensino, da pesquisa e da criação artística, segundo a capacidade de cada um;", "ordem": 1104}, {"id": 1105, "artigo_id": 206, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - oferta de ensino noturno regular, adequado às condições do educando;", "ordem": 1105}, {"id": 1106, "artigo_id": 206, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - atendimento ao educando, em todas as etapas da educação básica, por meio de programas suplementares de material didático-escolar, transporte, alimentação e assistência à saúde.", "ordem": 1106}, {"id": 1107, "artigo_id": 207, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - cumprimento das normas gerais da educação nacional;", "ordem": 1107}, {"id": 1108, "artigo_id": 207, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - autorização e avaliação de qualidade pelo Poder Público.", "ordem": 1108}, {"id": 1109, "artigo_id": 210, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - a distribuição dos recursos e de responsabilidades entre o Distrito Federal, os Estados e seus Municípios é assegurada mediante a instituição, no âmbito de cada Estado e do Distrito Federal, de um Fundo de Manutenção e Desenvolvimento da Educação Básica e de Valorização dos Profissionais da Educação (Fundeb), de natureza contábil;", "ordem": 1109}, {"id": 1110, "artigo_id": 210, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - os fundos referidos no inciso I do caput deste artigo serão constituídos por 20% (vinte por cento):", "ordem": 1110}, {"id": 1111, "artigo_id": 210, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - os recursos referidos no inciso II do caput deste artigo serão distribuídos entre cada Estado e seus Municípios, proporcionalmente ao número de alunos das diversas etapas e modalidades da educação básica presencial matriculados nas respectivas redes, nos âmbitos de atuação prioritária, conforme estabelecido nos §§ 2º e 3º do art. 211 desta Constituição, observadas as ponderações referidas na alínea \"a\" do inciso X do caput e no § 2º deste artigo;", "ordem": 1111}, {"id": 1112, "artigo_id": 210, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - a União complementará os recursos dos fundos a que se refere o inciso II do caput deste artigo;", "ordem": 1112}, {"id": 1113, "artigo_id": 210, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - a complementação da União será equivalente a, no mínimo, 23% (vinte e três por cento) do total de recursos a que se refere o inciso II do caput deste artigo, distribuída da seguinte forma:", "ordem": 1113}, {"id": 1114, "artigo_id": 210, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - o VAAT será calculado, na forma da lei de que trata o inciso X do caput deste artigo, com base nos recursos a que se refere o inciso II do caput deste artigo, acrescidos de outras receitas e de transferências vinculadas à educação, observado o disposto no § 1º e consideradas as matrículas nos termos do inciso III do caput deste artigo;", "ordem": 1114}, {"id": 1115, "artigo_id": 210, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - os recursos de que tratam os incisos II e IV do caput deste artigo serão aplicados pelos Estados e pelos Municípios exclusivamente nos respectivos âmbitos de atuação prioritária, conforme estabelecido nos §§ 2º e 3º do art. 211 desta Constituição;", "ordem": 1115}, {"id": 1116, "artigo_id": 210, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - a vinculação de recursos à manutenção e ao desenvolvimento do ensino estabelecida no art. 212 desta Constituição suportará, no máximo, 30% (trinta por cento) da complementação da União, considerados para os fins deste inciso os valores previstos no inciso V do caput deste artigo;", "ordem": 1116}, {"id": 1117, "artigo_id": 210, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - o disposto no caput do art. 160 desta Constituição aplica-se aos recursos referidos nos incisos II e IV do caput deste artigo, e seu descumprimento pela autoridade competente importará em crime de responsabilidade;", "ordem": 1117}, {"id": 1118, "artigo_id": 210, "paragrafo_id": null, "numero_romano": "X", "numero_int": 10, "texto": "X - a lei disporá, observadas as garantias estabelecidas nos incisos I, II, III e IV do caput e no § 1º do art. 208 e as metas pertinentes do plano nacional de educação, nos termos previstos no art. 214 desta Constituição, sobre:", "ordem": 1118}, {"id": 1119, "artigo_id": 210, "paragrafo_id": null, "numero_romano": "XI", "numero_int": 11, "texto": "XI - proporção não inferior a 70% (setenta por cento) de cada fundo referido no inciso I do caput deste artigo, excluídos os recursos de que trata a alínea \"c\" do inciso V do caput deste artigo, será destinada ao pagamento dos profissionais da educação básica em efetivo exercício, observado, em relação aos recursos previstos na alínea \"b\" do inciso V do caput deste artigo, o percentual mínimo de 15% (quinze por cento) para despesas de capital;", "ordem": 1119}, {"id": 1120, "artigo_id": 210, "paragrafo_id": null, "numero_romano": "XII", "numero_int": 12, "texto": "XII - lei específica disporá sobre o piso salarial profissional nacional para os profissionais do magistério da educação básica pública;", "ordem": 1120}, {"id": 1121, "artigo_id": 210, "paragrafo_id": null, "numero_romano": "XIII", "numero_int": 13, "texto": "XIII - a utilização dos recursos a que se refere o § 5º do art. 212 desta Constituição para a complementação da União ao Fundeb, referida no inciso V do caput deste artigo, é vedada.", "ordem": 1121}, {"id": 1122, "artigo_id": 210, "paragrafo_id": null, "numero_romano": "XIV", "numero_int": 14, "texto": "XIV - no exercício de 2025, da complementação de que trata o inciso V docaput, até 10% (dez por cento) dos valores de cada uma das modalidades referidas nesse dispositivo poderão ser repassados pela União para ações de fomento à criação de matrículas em tempo integral na educação básica pública, considerados indicadores de atendimento, melhoria da qualidade e redução de desigualdades, mantida a classificação orçamentária do repasse como Fundeb, não se aplicando, para fins deste inciso, os critérios de que tratam as alíneas \"a\", \"b\" e \"c\" do inciso V deste artigo;", "ordem": 1122}, {"id": 1123, "artigo_id": 210, "paragrafo_id": null, "numero_romano": "XV", "numero_int": 15, "texto": "XV - a partir do exercício de 2026, no mínimo 4% (quatro por cento) dos recursos dos fundos referidos no inciso I docaputdeste artigo serão destinados pelos Estados, pelo Distrito Federal e pelos Municípios à criação de matrículas em tempo integral na educação básica, conforme diretrizes pactuadas entre a União e demais entes da Federação, até o atingimento das metas de educação em tempo integral estabelecidas pelo Plano Nacional de Educação.", "ordem": 1123}, {"id": 1124, "artigo_id": 210, "paragrafo_id": 583, "numero_romano": "I", "numero_int": 1, "texto": "I - receitas de Estados, do Distrito Federal e de Municípios vinculadas à manutenção e ao desenvolvimento do ensino não integrantes dos fundos referidos no inciso I do caput deste artigo;", "ordem": 1124}, {"id": 1125, "artigo_id": 210, "paragrafo_id": 583, "numero_romano": "II", "numero_int": 2, "texto": "II - cotas estaduais e municipais da arrecadação do salário-educação de que trata o § 6º do art. 212 desta Constituição;", "ordem": 1125}, {"id": 1126, "artigo_id": 210, "paragrafo_id": 583, "numero_romano": "III", "numero_int": 3, "texto": "III - complementação da União transferida a Estados, ao Distrito Federal e a Municípios nos termos da alínea \"a\" do inciso V do caput deste artigo.", "ordem": 1126}, {"id": 1127, "artigo_id": 211, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - comprovem finalidade não-lucrativa e apliquem seus excedentes financeiros em educação;", "ordem": 1127}, {"id": 1128, "artigo_id": 211, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - assegurem a destinação de seu patrimônio a outra escola comunitária, filantrópica ou confessional, ou ao Poder Público, no caso de encerramento de suas atividades.", "ordem": 1128}, {"id": 1129, "artigo_id": 212, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - erradicação do analfabetismo;", "ordem": 1129}, {"id": 1130, "artigo_id": 212, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - universalização do atendimento escolar;", "ordem": 1130}, {"id": 1131, "artigo_id": 212, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - melhoria da qualidade do ensino;", "ordem": 1131}, {"id": 1132, "artigo_id": 212, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - formação para o trabalho;", "ordem": 1132}, {"id": 1133, "artigo_id": 212, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - promoção humanística, científica e tecnológica do País.", "ordem": 1133}, {"id": 1134, "artigo_id": 212, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - estabelecimento de meta de aplicação de recursos públicos em educação como proporção do produto interno bruto.", "ordem": 1134}, {"id": 1135, "artigo_id": 214, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - as formas de expressão;", "ordem": 1135}, {"id": 1136, "artigo_id": 214, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - os modos de criar, fazer e viver;", "ordem": 1136}, {"id": 1137, "artigo_id": 214, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - as criações científicas, artísticas e tecnológicas;", "ordem": 1137}, {"id": 1138, "artigo_id": 214, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - as obras, objetos, documentos, edificações e demais espaços destinados às manifestações artístico-culturais;", "ordem": 1138}, {"id": 1139, "artigo_id": 214, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - os conjuntos urbanos e sítios de valor histórico, paisagístico, artístico, arqueológico, paleontológico, ecológico e científico.", "ordem": 1139}, {"id": 1140, "artigo_id": 214, "paragrafo_id": 596, "numero_romano": "I", "numero_int": 1, "texto": "I - despesas com pessoal e encargos sociais;", "ordem": 1140}, {"id": 1141, "artigo_id": 214, "paragrafo_id": 596, "numero_romano": "II", "numero_int": 2, "texto": "II - serviço da dívida;", "ordem": 1141}, {"id": 1142, "artigo_id": 214, "paragrafo_id": 596, "numero_romano": "III", "numero_int": 3, "texto": "III - qualquer outra despesa corrente não vinculada diretamente aos investimentos ou ações apoiados.", "ordem": 1142}, {"id": 1143, "artigo_id": 214, "paragrafo_id": 597, "numero_romano": "I", "numero_int": 1, "texto": "I - diversidade das expressões culturais;", "ordem": 1143}, {"id": 1144, "artigo_id": 214, "paragrafo_id": 597, "numero_romano": "II", "numero_int": 2, "texto": "II - universalização do acesso aos bens e serviços culturais;", "ordem": 1144}, {"id": 1145, "artigo_id": 214, "paragrafo_id": 597, "numero_romano": "III", "numero_int": 3, "texto": "III - fomento à produção, difusão e circulação de conhecimento e bens culturais;", "ordem": 1145}, {"id": 1146, "artigo_id": 214, "paragrafo_id": 597, "numero_romano": "IV", "numero_int": 4, "texto": "IV - cooperação entre os entes federados, os agentes públicos e privados atuantes na área cultural;", "ordem": 1146}, {"id": 1147, "artigo_id": 214, "paragrafo_id": 597, "numero_romano": "V", "numero_int": 5, "texto": "V - integração e interação na execução das políticas, programas, projetos e ações desenvolvidas;", "ordem": 1147}, {"id": 1148, "artigo_id": 214, "paragrafo_id": 597, "numero_romano": "VI", "numero_int": 6, "texto": "VI - complementaridade nos papéis dos agentes culturais;", "ordem": 1148}, {"id": 1149, "artigo_id": 214, "paragrafo_id": 597, "numero_romano": "VII", "numero_int": 7, "texto": "VII - transversalidade das políticas culturais;", "ordem": 1149}, {"id": 1150, "artigo_id": 214, "paragrafo_id": 597, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - autonomia dos entes federados e das instituições da sociedade civil;", "ordem": 1150}, {"id": 1151, "artigo_id": 214, "paragrafo_id": 597, "numero_romano": "IX", "numero_int": 9, "texto": "IX - transparência e compartilhamento das informações;", "ordem": 1151}, {"id": 1152, "artigo_id": 214, "paragrafo_id": 597, "numero_romano": "X", "numero_int": 10, "texto": "X - democratização dos processos decisórios com participação e controle social;", "ordem": 1152}, {"id": 1153, "artigo_id": 214, "paragrafo_id": 597, "numero_romano": "XI", "numero_int": 11, "texto": "XI - descentralização articulada e pactuada da gestão, dos recursos e das ações;", "ordem": 1153}, {"id": 1154, "artigo_id": 214, "paragrafo_id": 597, "numero_romano": "XII", "numero_int": 12, "texto": "XII - ampliação progressiva dos recursos contidos nos orçamentos públicos para a cultura.", "ordem": 1154}, {"id": 1155, "artigo_id": 214, "paragrafo_id": 598, "numero_romano": "I", "numero_int": 1, "texto": "I - órgãos gestores da cultura;", "ordem": 1155}, {"id": 1156, "artigo_id": 214, "paragrafo_id": 598, "numero_romano": "II", "numero_int": 2, "texto": "II - conselhos de política cultural;", "ordem": 1156}, {"id": 1157, "artigo_id": 214, "paragrafo_id": 598, "numero_romano": "III", "numero_int": 3, "texto": "III - conferências de cultura;", "ordem": 1157}, {"id": 1158, "artigo_id": 214, "paragrafo_id": 598, "numero_romano": "IV", "numero_int": 4, "texto": "IV - comissões intergestores;", "ordem": 1158}, {"id": 1159, "artigo_id": 214, "paragrafo_id": 598, "numero_romano": "V", "numero_int": 5, "texto": "V - planos de cultura;", "ordem": 1159}, {"id": 1160, "artigo_id": 214, "paragrafo_id": 598, "numero_romano": "VI", "numero_int": 6, "texto": "VI - sistemas de financiamento à cultura;", "ordem": 1160}, {"id": 1161, "artigo_id": 214, "paragrafo_id": 598, "numero_romano": "VII", "numero_int": 7, "texto": "VII - sistemas de informações e indicadores culturais;", "ordem": 1161}, {"id": 1162, "artigo_id": 214, "paragrafo_id": 598, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - programas de formação na área da cultura; e", "ordem": 1162}, {"id": 1163, "artigo_id": 214, "paragrafo_id": 598, "numero_romano": "IX", "numero_int": 9, "texto": "IX - sistemas setoriais de cultura.", "ordem": 1163}, {"id": 1164, "artigo_id": 215, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - a autonomia das entidades desportivas dirigentes e associações, quanto a sua organização e funcionamento;", "ordem": 1164}, {"id": 1165, "artigo_id": 215, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - a destinação de recursos públicos para a promoção prioritária do desporto educacional e, em casos específicos, para a do desporto de alto rendimento;", "ordem": 1165}, {"id": 1166, "artigo_id": 215, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - o tratamento diferenciado para o desporto profissional e o não- profissional;", "ordem": 1166}, {"id": 1167, "artigo_id": 215, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - a proteção e o incentivo às manifestações desportivas de criação nacional.", "ordem": 1167}, {"id": 1168, "artigo_id": 218, "paragrafo_id": 616, "numero_romano": "I", "numero_int": 1, "texto": "I - regular as diversões e espetáculos públicos, cabendo ao Poder Público informar sobre a natureza deles, as faixas etárias a que não se recomendem, locais e horários em que sua apresentação se mostre inadequada;", "ordem": 1168}, {"id": 1169, "artigo_id": 218, "paragrafo_id": 616, "numero_romano": "II", "numero_int": 2, "texto": "II - estabelecer os meios legais que garantam à pessoa e à família a possibilidade de se defenderem de programas ou programações de rádio e televisão que contrariem o disposto no art. 221, bem como da propaganda de produtos, práticas e serviços que possam ser nocivos à saúde e ao meio ambiente.", "ordem": 1169}, {"id": 1170, "artigo_id": 219, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - preferência a finalidades educativas, artísticas, culturais e informativas;", "ordem": 1170}, {"id": 1171, "artigo_id": 219, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - promoção da cultura nacional e regional e estímulo à produção independente que objetive sua divulgação;", "ordem": 1171}, {"id": 1172, "artigo_id": 219, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - regionalização da produção cultural, artística e jornalística, conforme percentuais estabelecidos em lei;", "ordem": 1172}, {"id": 1173, "artigo_id": 219, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - respeito aos valores éticos e sociais da pessoa e da família.", "ordem": 1173}, {"id": 1174, "artigo_id": 223, "paragrafo_id": 630, "numero_romano": "I", "numero_int": 1, "texto": "I - preservar e restaurar os processos ecológicos essenciais e prover o manejo ecológico das espécies e ecossistemas; (Regulamento)", "ordem": 1174}, {"id": 1175, "artigo_id": 223, "paragrafo_id": 630, "numero_romano": "II", "numero_int": 2, "texto": "II - preservar a diversidade e a integridade do patrimônio genético do País e fiscalizar as entidades dedicadas à pesquisa e manipulação de material genético; (Regulamento) (Regulamento) (Regulamento) (Regulamento)", "ordem": 1175}, {"id": 1176, "artigo_id": 223, "paragrafo_id": 630, "numero_romano": "III", "numero_int": 3, "texto": "III - definir, em todas as unidades da Federação, espaços territoriais e seus componentes a serem especialmente protegidos, sendo a alteração e a supressão permitidas somente através de lei, vedada qualquer utilização que comprometa a integridade dos atributos que justifiquem sua proteção; (Regulamento)", "ordem": 1176}, {"id": 1177, "artigo_id": 223, "paragrafo_id": 630, "numero_romano": "IV", "numero_int": 4, "texto": "IV - exigir, na forma da lei, para instalação de obra ou atividade potencialmente causadora de significativa degradação do meio ambiente, estudo prévio de impacto ambiental, a que se dará publicidade; (Regulamento)", "ordem": 1177}, {"id": 1178, "artigo_id": 223, "paragrafo_id": 630, "numero_romano": "V", "numero_int": 5, "texto": "V - controlar a produção, a comercialização e o emprego de técnicas, métodos e substâncias que comportem risco para a vida, a qualidade de vida e o meio ambiente; (Regulamento)", "ordem": 1178}, {"id": 1179, "artigo_id": 223, "paragrafo_id": 630, "numero_romano": "VI", "numero_int": 6, "texto": "VI - promover a educação ambiental em todos os níveis de ensino e a conscientização pública para a preservação do meio ambiente;", "ordem": 1179}, {"id": 1180, "artigo_id": 223, "paragrafo_id": 630, "numero_romano": "VII", "numero_int": 7, "texto": "VII - proteger a fauna e a flora, vedadas, na forma da lei, as práticas que coloquem em risco sua função ecológica, provoquem a extinção de espécies ou submetam os animais a crueldade. (Regulamento)", "ordem": 1180}, {"id": 1181, "artigo_id": 223, "paragrafo_id": 630, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - manter regime fiscal favorecido para os biocombustíveis e para o hidrogênio de baixa emissão de carbono, na forma de lei complementar, a fim de assegurar-lhes tributação inferior à incidente sobre os combustíveis fósseis, capaz de garantir diferencial competitivo em relação a estes, especialmente em relação às contribuições de que tratam o art. 195, I, \"b\", IV e V, e o art. 239 e aos impostos a que se referem os arts. 155, II, e 156-A.", "ordem": 1181}, {"id": 1182, "artigo_id": 225, "paragrafo_id": 645, "numero_romano": "I", "numero_int": 1, "texto": "I - aplicação de percentual dos recursos públicos destinados à saúde na assistência materno-infantil;", "ordem": 1182}, {"id": 1183, "artigo_id": 225, "paragrafo_id": 645, "numero_romano": "II", "numero_int": 2, "texto": "II - criação de programas de prevenção e atendimento especializado para as pessoas portadoras de deficiência física, sensorial ou mental, bem como de integração social do adolescente e do jovem portador de deficiência, mediante o treinamento para o trabalho e a convivência, e a facilitação do acesso aos bens e serviços coletivos, com a eliminação de obstáculos arquitetônicos e de todas as formas de discriminação.", "ordem": 1183}, {"id": 1184, "artigo_id": 225, "paragrafo_id": 647, "numero_romano": "I", "numero_int": 1, "texto": "I - idade mínima de quatorze anos para admissão ao trabalho, observado o disposto no art. 7º, XXXIII;", "ordem": 1184}, {"id": 1185, "artigo_id": 225, "paragrafo_id": 647, "numero_romano": "II", "numero_int": 2, "texto": "II - garantia de direitos previdenciários e trabalhistas;", "ordem": 1185}, {"id": 1186, "artigo_id": 225, "paragrafo_id": 647, "numero_romano": "III", "numero_int": 3, "texto": "III - garantia de acesso do trabalhador adolescente e jovem à escola;", "ordem": 1186}, {"id": 1187, "artigo_id": 225, "paragrafo_id": 647, "numero_romano": "IV", "numero_int": 4, "texto": "IV - garantia de pleno e formal conhecimento da atribuição de ato infracional, igualdade na relação processual e defesa técnica por profissional habilitado, segundo dispuser a legislação tutelar específica;", "ordem": 1187}, {"id": 1188, "artigo_id": 225, "paragrafo_id": 647, "numero_romano": "V", "numero_int": 5, "texto": "V - obediência aos princípios de brevidade, excepcionalidade e respeito à condição peculiar de pessoa em desenvolvimento, quando da aplicação de qualquer medida privativa da liberdade;", "ordem": 1188}, {"id": 1189, "artigo_id": 225, "paragrafo_id": 647, "numero_romano": "VI", "numero_int": 6, "texto": "VI - estímulo do Poder Público, através de assistência jurídica, incentivos fiscais e subsídios, nos termos da lei, ao acolhimento, sob a forma de guarda, de criança ou adolescente órfão ou abandonado;", "ordem": 1189}, {"id": 1190, "artigo_id": 225, "paragrafo_id": 647, "numero_romano": "VII", "numero_int": 7, "texto": "VII - programas de prevenção e atendimento especializado à criança, ao adolescente e ao jovem dependente de entorpecentes e drogas afins.", "ordem": 1190}, {"id": 1191, "artigo_id": 225, "paragrafo_id": 652, "numero_romano": "I", "numero_int": 1, "texto": "I - o estatuto da juventude, destinado a regular os direitos dos jovens;", "ordem": 1191}, {"id": 1192, "artigo_id": 225, "paragrafo_id": 652, "numero_romano": "II", "numero_int": 2, "texto": "II - o plano nacional de juventude, de duração decenal, visando à articulação das várias esferas do poder público para a execução de políticas públicas.", "ordem": 1192}, {"id": 1193, "artigo_id": 232, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - a Assembléia Legislativa será composta de dezessete Deputados se a população do Estado for inferior a seiscentos mil habitantes, e de vinte e quatro, se igual ou superior a esse número, até um milhão e quinhentos mil;", "ordem": 1193}, {"id": 1194, "artigo_id": 232, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - o Governo terá no máximo dez Secretarias;", "ordem": 1194}, {"id": 1195, "artigo_id": 232, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - o Tribunal de Contas terá três membros, nomeados, pelo Governador eleito, dentre brasileiros de comprovada idoneidade e notório saber;", "ordem": 1195}, {"id": 1196, "artigo_id": 232, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - o Tribunal de Justiça terá sete Desembargadores;", "ordem": 1196}, {"id": 1197, "artigo_id": 232, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - os primeiros Desembargadores serão nomeados pelo Governador eleito, escolhidos da seguinte forma:", "ordem": 1197}, {"id": 1198, "artigo_id": 232, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - no caso de Estado proveniente de Território Federal, os cinco primeiros Desembargadores poderão ser escolhidos dentre juízes de direito de qualquer parte do País;", "ordem": 1198}, {"id": 1199, "artigo_id": 232, "paragrafo_id": null, "numero_romano": "VII", "numero_int": 7, "texto": "VII - em cada Comarca, o primeiro Juiz de Direito, o primeiro Promotor de Justiça e o primeiro Defensor Público serão nomeados pelo Governador eleito após concurso público de provas e títulos;", "ordem": 1199}, {"id": 1200, "artigo_id": 232, "paragrafo_id": null, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - até a promulgação da Constituição Estadual, responderão pela Procuradoria-Geral, pela Advocacia-Geral e pela Defensoria-Geral do Estado advogados de notório saber, com trinta e cinco anos de idade, no mínimo, nomeados pelo Governador eleito e demissíveis \"ad nutum\";", "ordem": 1200}, {"id": 1201, "artigo_id": 232, "paragrafo_id": null, "numero_romano": "IX", "numero_int": 9, "texto": "IX - se o novo Estado for resultado de transformação de Território Federal, a transferência de encargos financeiros da União para pagamento dos servidores optantes que pertenciam à Administração Federal ocorrerá da seguinte forma:", "ordem": 1201}, {"id": 1202, "artigo_id": 232, "paragrafo_id": null, "numero_romano": "X", "numero_int": 10, "texto": "X - as nomeações que se seguirem às primeiras, para os cargos mencionados neste artigo, serão disciplinadas na Constituição Estadual;", "ordem": 1202}, {"id": 1203, "artigo_id": 232, "paragrafo_id": null, "numero_romano": "XI", "numero_int": 11, "texto": "XI - as despesas orçamentárias com pessoal não poderão ultrapassar cinqüenta por cento da receita do Estado.", "ordem": 1203}, {"id": 1204, "artigo_id": 257, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - fica limitada a proteção nele referida ao aumento, para quatro vezes, da porcentagem prevista no art. 6º, \"caput\" e § 1º, da Lei nº 5.107, de 13 de setembro de 1966 ;", "ordem": 1204}, {"id": 1205, "artigo_id": 257, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - fica vedada a dispensa arbitrária ou sem justa causa:", "ordem": 1205}, {"id": 1206, "artigo_id": 260, "paragrafo_id": 704, "numero_romano": "I", "numero_int": 1, "texto": "I - o prazo de filiação partidária dos candidatos será encerrado setenta e cinco dias antes da data das eleições;", "ordem": 1206}, {"id": 1207, "artigo_id": 260, "paragrafo_id": 704, "numero_romano": "II", "numero_int": 2, "texto": "II - as datas das convenções regionais partidárias destinadas a deliberar sobre coligações e escolha de candidatos, de apresentação de requerimento de registro dos candidatos escolhidos e dos demais procedimentos legais serão fixadas, em calendário especial, pela Justiça Eleitoral;", "ordem": 1207}, {"id": 1208, "artigo_id": 260, "paragrafo_id": 704, "numero_romano": "III", "numero_int": 3, "texto": "III - são inelegíveis os ocupantes de cargos estaduais ou municipais que não se tenham deles afastado, em caráter definitivo, setenta e cinco dias antes da data das eleições previstas neste parágrafo;", "ordem": 1208}, {"id": 1209, "artigo_id": 260, "paragrafo_id": 704, "numero_romano": "IV", "numero_int": 4, "texto": "IV - ficam mantidos os atuais diretórios regionais dos partidos políticos do Estado de Goiás, cabendo às comissões executivas nacionais designar comissões provisórias no Estado do Tocantins, nos termos e para os fins previstos na lei.", "ordem": 1209}, {"id": 1210, "artigo_id": 272, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - ação normativa;", "ordem": 1210}, {"id": 1211, "artigo_id": 272, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - alocação ou transferência de recursos de qualquer espécie.", "ordem": 1211}, {"id": 1212, "artigo_id": 272, "paragrafo_id": 723, "numero_romano": "I", "numero_int": 1, "texto": "I - se editados até 2 de setembro de 1988, serão apreciados pelo Congresso Nacional no prazo de até cento e oitenta dias a contar da promulgação da Constituição, não computado o recesso parlamentar;", "ordem": 1212}, {"id": 1213, "artigo_id": 272, "paragrafo_id": 723, "numero_romano": "II", "numero_int": 2, "texto": "II - decorrido o prazo definido no inciso anterior, e não havendo apreciação, os decretos-lei alí mencionados serão considerados rejeitados;", "ordem": 1213}, {"id": 1214, "artigo_id": 272, "paragrafo_id": 723, "numero_romano": "III", "numero_int": 3, "texto": "III - nas hipóteses definidas nos incisos I e II, terão plena validade os atos praticados na vigência dos respectivos decretos-lei, podendo o Congresso Nacional, se necessário, legislar sobre os efeitos deles remanescentes.", "ordem": 1214}, {"id": 1215, "artigo_id": 274, "paragrafo_id": 728, "numero_romano": "I", "numero_int": 1, "texto": "I - pelo aproveitamento dos Ministros do Tribunal Federal de Recursos;", "ordem": 1215}, {"id": 1216, "artigo_id": 274, "paragrafo_id": 728, "numero_romano": "II", "numero_int": 2, "texto": "II - pela nomeação dos Ministros que sejam necessários para completar o número estabelecido na Constituição.", "ordem": 1216}, {"id": 1217, "artigo_id": 281, "paragrafo_id": 744, "numero_romano": "I", "numero_int": 1, "texto": "I - a partir da promulgação da Constituição, os percentuais serão, respectivamente, de dezoito por cento e de vinte por cento, calculados sobre o produto da arrecadação dos impostos referidos no art. 153, III e IV, mantidos os atuais critérios de rateio até a entrada em vigor da lei complementar a que se refere o art. 161, II;", "ordem": 1217}, {"id": 1218, "artigo_id": 281, "paragrafo_id": 744, "numero_romano": "II", "numero_int": 2, "texto": "II - o percentual relativo ao Fundo de Participação dos Estados e do Distrito Federal será acrescido de um ponto percentual no exercício financeiro de 1989 e, a partir de 1990, inclusive, à razão de meio ponto por exercício, até 1992, inclusive, atingindo em 1993 o percentual estabelecido no art. 159, I, \"a\";", "ordem": 1218}, {"id": 1219, "artigo_id": 281, "paragrafo_id": 744, "numero_romano": "III", "numero_int": 3, "texto": "III - o percentual relativo ao Fundo de Participação dos Municípios, a partir de 1989, inclusive, será elevado à razão de meio ponto percentual por exercício financeiro, até atingir o estabelecido no art. 159, I, \"b\".", "ordem": 1219}, {"id": 1220, "artigo_id": 281, "paragrafo_id": 751, "numero_romano": "I", "numero_int": 1, "texto": "I - seis décimos por cento na Região Norte, através do Banco da Amazônia S.A.;", "ordem": 1220}, {"id": 1221, "artigo_id": 281, "paragrafo_id": 751, "numero_romano": "II", "numero_int": 2, "texto": "II - um inteiro e oito décimos por cento na Região Nordeste, através do Banco do Nordeste do Brasil S.A.;", "ordem": 1221}, {"id": 1222, "artigo_id": 281, "paragrafo_id": 751, "numero_romano": "III", "numero_int": 3, "texto": "III - seis décimos por cento na Região Centro-Oeste, através do Banco do Brasil S.A.", "ordem": 1222}, {"id": 1223, "artigo_id": 282, "paragrafo_id": 752, "numero_romano": "I", "numero_int": 1, "texto": "I - aos projetos considerados prioritários no plano plurianual;", "ordem": 1223}, {"id": 1224, "artigo_id": 282, "paragrafo_id": 752, "numero_romano": "II", "numero_int": 2, "texto": "II - à segurança e defesa nacional;", "ordem": 1224}, {"id": 1225, "artigo_id": 282, "paragrafo_id": 752, "numero_romano": "III", "numero_int": 3, "texto": "III - à manutenção dos órgãos federais no Distrito Federal;", "ordem": 1225}, {"id": 1226, "artigo_id": 282, "paragrafo_id": 752, "numero_romano": "IV", "numero_int": 4, "texto": "IV - ao Congresso Nacional, ao Tribunal de Contas da União e ao Poder Judiciário;", "ordem": 1226}, {"id": 1227, "artigo_id": 282, "paragrafo_id": 752, "numero_romano": "V", "numero_int": 5, "texto": "V - ao serviço da dívida da administração direta e indireta da União, inclusive fundações instituídas e mantidas pelo Poder Público federal.", "ordem": 1227}, {"id": 1228, "artigo_id": 282, "paragrafo_id": 753, "numero_romano": "I", "numero_int": 1, "texto": "I - o projeto do plano plurianual, para vigência até o final do primeiro exercício financeiro do mandato presidencial subseqüente, será encaminhado até quatro meses antes do encerramento do primeiro exercício financeiro e devolvido para sanção até o encerramento da sessão legislativa;", "ordem": 1228}, {"id": 1229, "artigo_id": 282, "paragrafo_id": 753, "numero_romano": "II", "numero_int": 2, "texto": "II - o projeto de lei de diretrizes orçamentárias será encaminhado até oito meses e meio antes do encerramento do exercício financeiro e devolvido para sanção até o encerramento do primeiro período da sessão legislativa;", "ordem": 1229}, {"id": 1230, "artigo_id": 282, "paragrafo_id": 753, "numero_romano": "III", "numero_int": 3, "texto": "III - o projeto de lei orçamentária da União será encaminhado até quatro meses antes do encerramento do exercício financeiro e devolvido para sanção até o encerramento da sessão legislativa.", "ordem": 1230}, {"id": 1231, "artigo_id": 285, "paragrafo_id": 755, "numero_romano": "I", "numero_int": 1, "texto": "I - até o fim do exercício financeiro subsequente ao da publicação deste dispositivo, não serão contabilizadas para esses limites;", "ordem": 1231}, {"id": 1232, "artigo_id": 285, "paragrafo_id": 755, "numero_romano": "II", "numero_int": 2, "texto": "II - no segundo exercício financeiro subsequente ao da publicação deste dispositivo, serão deduzidas em 90% (noventa por cento) do seu valor;", "ordem": 1232}, {"id": 1233, "artigo_id": 285, "paragrafo_id": 755, "numero_romano": "III", "numero_int": 3, "texto": "III - entre o terceiro e o décimo segundo exercício financeiro subsequente ao da publicação deste dispositivo, a dedução de que trata o inciso II deste parágrafo será reduzida anualmente na proporção de 10% (dez por cento) de seu valor.", "ordem": 1233}, {"id": 1234, "artigo_id": 289, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - 20% (vinte por cento) na Região Centro-Oeste;", "ordem": 1234}, {"id": 1235, "artigo_id": 289, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - 50% (cinquenta por cento) na Região Nordeste, preferencialmente no Semiárido.", "ordem": 1235}, {"id": 1236, "artigo_id": 293, "paragrafo_id": 766, "numero_romano": "I", "numero_int": 1, "texto": "I - às operações realizadas posteriormente à decretação dos regimes referidos no \"caput\" deste artigo;", "ordem": 1236}, {"id": 1237, "artigo_id": 293, "paragrafo_id": 766, "numero_romano": "II", "numero_int": 2, "texto": "II - às operações de empréstimo, financiamento, refinanciamento, assistência financeira de liquidez, cessão ou sub-rogação de créditos ou cédulas hipotecárias, efetivação de garantia de depósitos do público ou de compra de obrigações passivas, inclusive as realizadas com recursos de fundos que tenham essas destinações;", "ordem": 1237}, {"id": 1238, "artigo_id": 293, "paragrafo_id": 766, "numero_romano": "III", "numero_int": 3, "texto": "III - aos créditos anteriores à promulgação da Constituição;", "ordem": 1238}, {"id": 1239, "artigo_id": 293, "paragrafo_id": 766, "numero_romano": "IV", "numero_int": 4, "texto": "IV - aos créditos das entidades da administração pública anteriores à promulgação da Constituição, não liquidados até 1 de janeiro de 1988.", "ordem": 1239}, {"id": 1240, "artigo_id": 294, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - aos micro e pequenos empresários ou seus estabelecimentos no período de 28 de fevereiro de 1986 a 28 de fevereiro de 1987;", "ordem": 1240}, {"id": 1241, "artigo_id": 294, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - ao mini, pequenos e médios produtores rurais no período de 28 de fevereiro de 1986 a 31 de dezembro de 1987, desde que relativos a crédito rural.", "ordem": 1241}, {"id": 1242, "artigo_id": 294, "paragrafo_id": 769, "numero_romano": "I", "numero_int": 1, "texto": "I - se a liquidação do débito inicial, acrescido de juros legais e taxas judiciais, vier a ser efetivada no prazo de noventa dias, a contar da data da promulgação da Constituição;", "ordem": 1242}, {"id": 1243, "artigo_id": 294, "paragrafo_id": 769, "numero_romano": "II", "numero_int": 2, "texto": "II - se a aplicação dos recursos não contrariar a finalidade do financiamento, cabendo o ônus da prova à instituição credora;", "ordem": 1243}, {"id": 1244, "artigo_id": 294, "paragrafo_id": 769, "numero_romano": "III", "numero_int": 3, "texto": "III - se não for demonstrado pela instituição credora que o mutuário dispõe de meios para o pagamento de seu débito, excluído desta demonstração seu estabelecimento, a casa de moradia e os instrumentos de trabalho e produção;", "ordem": 1244}, {"id": 1245, "artigo_id": 294, "paragrafo_id": 769, "numero_romano": "IV", "numero_int": 4, "texto": "IV - se o financiamento inicial não ultrapassar o limite de cinco mil Obrigações do Tesouro Nacional;", "ordem": 1245}, {"id": 1246, "artigo_id": 294, "paragrafo_id": 769, "numero_romano": "V", "numero_int": 5, "texto": "V - se o beneficiário não for proprietário de mais de cinco módulos rurais.", "ordem": 1246}, {"id": 1247, "artigo_id": 299, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - a instalação, no País, de novas agências de instituições financeiras domiciliadas no exterior;", "ordem": 1247}, {"id": 1248, "artigo_id": 299, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - o aumento do percentual de participação, no capital de instituições financeiras com sede no País, de pessoas físicas ou jurídicas residentes ou domiciliadas no exterior.", "ordem": 1248}, {"id": 1249, "artigo_id": 300, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - aproveitamento no serviço público, sem a exigência de concurso, com estabilidade;", "ordem": 1249}, {"id": 1250, "artigo_id": 300, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - pensão especial correspondente à deixada por segundo-tenente das Forças Armadas, que poderá ser requerida a qualquer tempo, sendo inacumulável com quaisquer rendimentos recebidos dos cofres públicos, exceto os benefícios previdenciários, ressalvado o direito de opção;", "ordem": 1250}, {"id": 1251, "artigo_id": 300, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - em caso de morte, pensão à viúva ou companheira ou dependente, de forma proporcional, de valor igual à do inciso anterior;", "ordem": 1251}, {"id": 1252, "artigo_id": 300, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - assistência médica, hospitalar e educacional gratuita, extensiva aos dependentes;", "ordem": 1252}, {"id": 1253, "artigo_id": 300, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - aposentadoria com proventos integrais aos vinte e cinco anos de serviço efetivo, em qualquer regime jurídico;", "ordem": 1253}, {"id": 1254, "artigo_id": 300, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - prioridade na aquisição da casa própria, para os que não a possuam ou para suas viúvas ou companheiras.", "ordem": 1254}, {"id": 1255, "artigo_id": 307, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - 12% (doze por cento), no primeiro ano;", "ordem": 1255}, {"id": 1256, "artigo_id": 307, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - 15% (quinze por cento), no segundo ano;", "ordem": 1256}, {"id": 1257, "artigo_id": 307, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - 17% (dezessete por cento), no terceiro ano;", "ordem": 1257}, {"id": 1258, "artigo_id": 307, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - 19% (dezenove por cento), no quarto ano;", "ordem": 1258}, {"id": 1259, "artigo_id": 307, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - 21% (vinte e um por cento), no quinto ano;", "ordem": 1259}, {"id": 1260, "artigo_id": 307, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - 23% (vinte e três por cento), no sexto ano.", "ordem": 1260}, {"id": 1261, "artigo_id": 307, "paragrafo_id": 792, "numero_romano": "I", "numero_int": 1, "texto": "I - 2 (dois) pontos percentuais, no primeiro ano;", "ordem": 1261}, {"id": 1262, "artigo_id": 307, "paragrafo_id": 792, "numero_romano": "II", "numero_int": 2, "texto": "II - 5 (cinco) pontos percentuais, no segundo ano;", "ordem": 1262}, {"id": 1263, "artigo_id": 307, "paragrafo_id": 792, "numero_romano": "III", "numero_int": 3, "texto": "III - 6,25 (seis inteiros e vinte e cinco centésimos) pontos percentuais, no terceiro ano;", "ordem": 1263}, {"id": 1264, "artigo_id": 307, "paragrafo_id": 792, "numero_romano": "IV", "numero_int": 4, "texto": "IV - 7,5 (sete inteiros e cinco décimos) pontos percentuais, no quarto ano;", "ordem": 1264}, {"id": 1265, "artigo_id": 307, "paragrafo_id": 792, "numero_romano": "V", "numero_int": 5, "texto": "V - 9 (nove) pontos percentuais, no quinto ano;", "ordem": 1265}, {"id": 1266, "artigo_id": 307, "paragrafo_id": 792, "numero_romano": "VI", "numero_int": 6, "texto": "VI - 10,5 (dez inteiros e cinco décimos) pontos percentuais, no sexto ano.", "ordem": 1266}, {"id": 1267, "artigo_id": 307, "paragrafo_id": 793, "numero_romano": "I", "numero_int": 1, "texto": "I - 0,75 (setenta e cinco centésimos) ponto percentual, no terceiro ano;", "ordem": 1267}, {"id": 1268, "artigo_id": 307, "paragrafo_id": 793, "numero_romano": "II", "numero_int": 2, "texto": "II - 1,5 (um inteiro e cinco décimos) ponto percentual, no quarto ano;", "ordem": 1268}, {"id": 1269, "artigo_id": 307, "paragrafo_id": 793, "numero_romano": "III", "numero_int": 3, "texto": "III - 2 (dois) pontos percentuais, no quinto ano;", "ordem": 1269}, {"id": 1270, "artigo_id": 307, "paragrafo_id": 793, "numero_romano": "IV", "numero_int": 4, "texto": "IV - 2,5 (dois inteiros e cinco décimos) pontos percentuais, no sexto ano.", "ordem": 1270}, {"id": 1271, "artigo_id": 319, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - o produto da arrecadação do imposto sobre renda e proventos de qualquer natureza incidente na fonte sobre pagamentos efetuados, a qualquer título, pela União, inclusive suas autarquias e fundações;", "ordem": 1271}, {"id": 1272, "artigo_id": 319, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - a parcela do produto da arrecadação do imposto sobre renda e proventos de qualquer natureza e do imposto sobre operações de crédito, câmbio e seguro, ou relativas a títulos e valores mobiliários, decorrente das alterações produzidas pela Lei nº 8.894, de 21 de junho de 1994 , e pelas Leis nºs 8.849 e 8.848, ambas de 28 de janeiro de 1994 , e modificações posteriores;", "ordem": 1272}, {"id": 1273, "artigo_id": 319, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - a parcela do produto da arrecadação resultante da elevação da alíquota da contribuição social sobre o lucro dos contribuintes a que se refere o § 1º do Art. 22 da Lei nº 8.212, de 24 de julho de 1991 , a qual, nos exercícios financeiros de 1994 e 1995, bem assim no período de 1º de janeiro de 1996 a 30 de junho de 1997, passa a ser de trinta por cento, sujeita a alteração por lei ordinária, mantidas as demais normas da Lei nº 7.689, de 15 de dezembro de 1988 ;", "ordem": 1273}, {"id": 1274, "artigo_id": 319, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - vinte por cento do produto da arrecadação de todos os impostos e contribuições da União, já instituídos ou a serem criados, excetuado o previsto nos incisos I, II e III, observado o disposto nos §§ 3º e 4º;", "ordem": 1274}, {"id": 1275, "artigo_id": 319, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - outras receitas previstas em lei específica.", "ordem": 1275}, {"id": 1276, "artigo_id": 323, "paragrafo_id": 813, "numero_romano": "I", "numero_int": 1, "texto": "I - recursos destinados ao financiamento das ações e serviços públicos de saúde e à manutenção e desenvolvimento do ensino de que tratam, respectivamente, os incisos II e III do § 2º do art. 198 e o art. 212 da Constituição Federal; Produção de efeitos", "ordem": 1276}, {"id": 1277, "artigo_id": 323, "paragrafo_id": 813, "numero_romano": "II", "numero_int": 2, "texto": "II - receitas que pertencem aos Municípios decorrentes de transferências previstas na Constituição Federal; Produção de efeitos", "ordem": 1277}, {"id": 1278, "artigo_id": 323, "paragrafo_id": 813, "numero_romano": "III", "numero_int": 3, "texto": "III - receitas de contribuições previdenciárias e de assistência à saúde dos servidores; Produção de efeitos", "ordem": 1278}, {"id": 1279, "artigo_id": 323, "paragrafo_id": 813, "numero_romano": "IV", "numero_int": 4, "texto": "IV - demais transferências obrigatórias e voluntárias entre entes da Federação com destinação especificada em lei; Produção de efeitos", "ordem": 1279}, {"id": 1280, "artigo_id": 323, "paragrafo_id": 813, "numero_romano": "V", "numero_int": 5, "texto": "V - fundos instituídos pelo Poder Judiciário, pelos Tribunais de Contas, pelo Ministério Público, pelas Defensorias Públicas e pelas Procuradorias-Gerais dos Estados e do Distrito Federal. Produção de efeitos", "ordem": 1280}, {"id": 1281, "artigo_id": 323, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - 50% (cinquenta por cento), até 31 de dezembro de 2026; e", "ordem": 1281}, {"id": 1282, "artigo_id": 323, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - 30% (trinta por cento), de 1º de janeiro de 2027 a 31 de dezembro de 2032.", "ordem": 1282}, {"id": 1283, "artigo_id": 323, "paragrafo_id": 814, "numero_romano": "I", "numero_int": 1, "texto": "I - recursos destinados ao financiamento das ações e serviços públicos de saúde e à manutenção e desenvolvimento do ensino de que tratam, respectivamente, o inciso III do § 2º do art. 198 e o art. 212 da Constituição Federal;", "ordem": 1283}, {"id": 1284, "artigo_id": 323, "paragrafo_id": 814, "numero_romano": "II", "numero_int": 2, "texto": "II - receitas de contribuições previdenciárias e de assistência à saúde dos servidores; Produção de efeitos", "ordem": 1284}, {"id": 1285, "artigo_id": 323, "paragrafo_id": 814, "numero_romano": "III", "numero_int": 3, "texto": "III - transferências obrigatórias e voluntárias entre entes da Federação com destinação especificada em lei; Produção de efeitos", "ordem": 1285}, {"id": 1286, "artigo_id": 323, "paragrafo_id": 814, "numero_romano": "IV", "numero_int": 4, "texto": "IV - fundos instituídos pelo Tribunal de Contas do Município. Produção de efeitos", "ordem": 1286}, {"id": 1287, "artigo_id": 324, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - no caso da União:", "ordem": 1287}, {"id": 1288, "artigo_id": 324, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - no caso dos Estados e do Distrito Federal, doze por cento do produto da arrecadação dos impostos a que se refere o art. 155 e dos recursos de que tratam os arts. 157 e 159, inciso I, alínea a , e inciso II, deduzidas as parcelas que forem transferidas aos respectivos Municípios; e", "ordem": 1288}, {"id": 1289, "artigo_id": 324, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - no caso dos Municípios e do Distrito Federal, quinze por cento do produto da arrecadação dos impostos a que se refere o art. 156 e dos recursos de que tratam os arts. 158 e 159, inciso I, alínea b e § 3º.", "ordem": 1289}, {"id": 1290, "artigo_id": 327, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - a parcela do produto da arrecadação correspondente a um adicional de oito centésimos por cento, aplicável de 18 de junho de 2000 a 17 de junho de 2002, na alíquota da contribuição social de que trata o art. 75 do Ato das Disposições Constitucionais Transitórias;", "ordem": 1290}, {"id": 1291, "artigo_id": 327, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - a parcela do produto da arrecadação correspondente a um adicional de cinco pontos percentuais na alíquota do Imposto sobre Produtos Industrializados - IPI, ou do imposto que vier a substituí-lo, incidente sobre produtos supérfluos e aplicável até a extinção do Fundo; Vigência", "ordem": 1291}, {"id": 1292, "artigo_id": 327, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - o produto da arrecadação do imposto de que trata o art. 153, inciso VII, da Constituição;", "ordem": 1292}, {"id": 1293, "artigo_id": 327, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - dotações orçamentárias;", "ordem": 1293}, {"id": 1294, "artigo_id": 327, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V- doações, de qualquer natureza, de pessoas físicas ou jurídicas do País ou do exterior;", "ordem": 1294}, {"id": 1295, "artigo_id": 327, "paragrafo_id": null, "numero_romano": "VI", "numero_int": 6, "texto": "VI - outras receitas, a serem definidas na regulamentação do referido Fundo.", "ordem": 1295}, {"id": 1296, "artigo_id": 331, "paragrafo_id": 833, "numero_romano": "I", "numero_int": 1, "texto": "I - vinte centésimos por cento ao Fundo Nacional de Saúde, para financiamento das ações e serviços de saúde;", "ordem": 1296}, {"id": 1297, "artigo_id": 331, "paragrafo_id": 833, "numero_romano": "II", "numero_int": 2, "texto": "II - dez centésimos por cento ao custeio da previdência social;", "ordem": 1297}, {"id": 1298, "artigo_id": 331, "paragrafo_id": 833, "numero_romano": "III", "numero_int": 3, "texto": "III - oito centésimos por cento ao Fundo de Combate e Erradicação da Pobreza, de que tratam os arts. 80 e 81 deste Ato das Disposições Constitucionais Transitórias.", "ordem": 1298}, {"id": 1299, "artigo_id": 331, "paragrafo_id": 834, "numero_romano": "I", "numero_int": 1, "texto": "I - trinta e oito centésimos por cento, nos exercícios financeiros de 2002 e 2003;", "ordem": 1299}, {"id": 1300, "artigo_id": 332, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - em contas correntes de depósito especialmente abertas e exclusivamente utilizadas para operações de:", "ordem": 1300}, {"id": 1301, "artigo_id": 332, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - em contas correntes de depósito, relativos a:", "ordem": 1301}, {"id": 1302, "artigo_id": 332, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - em contas de investidores estrangeiros, relativos a entradas no País e a remessas para o exterior de recursos financeiros empregados, exclusivamente, em operações e contratos referidos no inciso II deste artigo.", "ordem": 1302}, {"id": 1303, "artigo_id": 333, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - ter sido objeto de emissão de precatórios judiciários;", "ordem": 1303}, {"id": 1304, "artigo_id": 333, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - ter sido definidos como de pequeno valor pela lei de que trata o § 3º do art. 100 da Constituição Federal ou pelo art. 87 deste Ato das Disposições Constitucionais Transitórias;", "ordem": 1304}, {"id": 1305, "artigo_id": 333, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - estar, total ou parcialmente, pendentes de pagamento na data da publicação desta Emenda Constitucional.", "ordem": 1305}, {"id": 1306, "artigo_id": 334, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - quarenta salários-mínimos, perante a Fazenda dos Estados e do Distrito Federal;", "ordem": 1306}, {"id": 1307, "artigo_id": 334, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - trinta salários-mínimos, perante a Fazenda dos Municípios.", "ordem": 1307}, {"id": 1308, "artigo_id": 335, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - terá alíquota mínima de dois por cento, exceto para os serviços a que se referem os itens 32, 33 e 34 da Lista de Serviços anexa ao Decreto-Lei nº 406, de 31 de dezembro de 1968 ;", "ordem": 1308}, {"id": 1309, "artigo_id": 335, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - não será objeto de concessão de isenções, incentivos e benefícios fiscais, que resulte, direta ou indiretamente, na redução da alíquota mínima estabelecida no inciso I.", "ordem": 1309}, {"id": 1310, "artigo_id": 338, "paragrafo_id": 848, "numero_romano": "I", "numero_int": 1, "texto": "I - estabelecerá o montante mínimo de aporte anual de recursos ao Fundo, bem como os critérios para sua correção;", "ordem": 1310}, {"id": 1311, "artigo_id": 338, "paragrafo_id": 848, "numero_romano": "II", "numero_int": 2, "texto": "II - preverá a possibilidade de utilização dos recursos do Fundo para compensar eventual perda de receita do Estado do Amazonas em função das alterações no sistema tributário decorrentes da instituição dos tributos previstos nos arts. 156-A e 195, V, da Constituição Federal.", "ordem": 1311}, {"id": 1312, "artigo_id": 343, "paragrafo_id": 853, "numero_romano": "I", "numero_int": 1, "texto": "I - pelo depósito em conta especial do valor referido pelo § 2º deste artigo; ou", "ordem": 1312}, {"id": 1313, "artigo_id": 343, "paragrafo_id": 853, "numero_romano": "II", "numero_int": 2, "texto": "II - pela adoção do regime especial pelo prazo de até 15 (quinze) anos, caso em que o percentual a ser depositado na conta especial a que se refere o § 2º deste artigo corresponderá, anualmente, ao saldo total dos precatórios devidos, acrescido do índice oficial de remuneração básica da caderneta de poupança e de juros simples no mesmo percentual de juros incidentes sobre a caderneta de poupança para fins de compensação da mora, excluída a incidência de juros compensatórios, diminuído das amortizações e dividido pelo número de anos restantes no regime especial de pagamento.", "ordem": 1313}, {"id": 1314, "artigo_id": 343, "paragrafo_id": 854, "numero_romano": "I", "numero_int": 1, "texto": "I - para os Estados e para o Distrito Federal:", "ordem": 1314}, {"id": 1315, "artigo_id": 343, "paragrafo_id": 854, "numero_romano": "II", "numero_int": 2, "texto": "II - para Municípios:", "ordem": 1315}, {"id": 1316, "artigo_id": 343, "paragrafo_id": 855, "numero_romano": "I", "numero_int": 1, "texto": "I - nos Estados, as parcelas entregues aos Municípios por determinação constitucional;", "ordem": 1316}, {"id": 1317, "artigo_id": 343, "paragrafo_id": 855, "numero_romano": "II", "numero_int": 2, "texto": "II - nos Estados, no Distrito Federal e nos Municípios, a contribuição dos servidores para custeio do seu sistema de previdência e assistência social e as receitas provenientes da compensação financeira referida no § 9º do art. 201 da Constituição Federal.", "ordem": 1317}, {"id": 1318, "artigo_id": 343, "paragrafo_id": 860, "numero_romano": "I", "numero_int": 1, "texto": "I - destinados ao pagamento dos precatórios por meio do leilão;", "ordem": 1318}, {"id": 1319, "artigo_id": 343, "paragrafo_id": 860, "numero_romano": "II", "numero_int": 2, "texto": "II - destinados a pagamento a vista de precatórios não quitados na forma do § 6° e do inciso I, em ordem única e crescente de valor por precatório;", "ordem": 1319}, {"id": 1320, "artigo_id": 343, "paragrafo_id": 860, "numero_romano": "III", "numero_int": 3, "texto": "III - destinados a pagamento por acordo direto com os credores, na forma estabelecida por lei própria da entidade devedora, que poderá prever criação e forma de funcionamento de câmara de conciliação.", "ordem": 1320}, {"id": 1321, "artigo_id": 343, "paragrafo_id": 861, "numero_romano": "I", "numero_int": 1, "texto": "I - serão realizados por meio de sistema eletrônico administrado por entidade autorizada pela Comissão de Valores Mobiliários ou pelo Banco Central do Brasil;", "ordem": 1321}, {"id": 1322, "artigo_id": 343, "paragrafo_id": 861, "numero_romano": "III", "numero_int": 3, "texto": "III - ocorrerão por meio de oferta pública a todos os credores habilitados pelo respectivo ente federativo devedor;", "ordem": 1322}, {"id": 1323, "artigo_id": 343, "paragrafo_id": 861, "numero_romano": "IV", "numero_int": 4, "texto": "IV - considerarão automaticamente habilitado o credor que satisfaça o que consta no inciso II;", "ordem": 1323}, {"id": 1324, "artigo_id": 343, "paragrafo_id": 861, "numero_romano": "V", "numero_int": 5, "texto": "V - serão realizados tantas vezes quanto necessário em função do valor disponível;", "ordem": 1324}, {"id": 1325, "artigo_id": 343, "paragrafo_id": 861, "numero_romano": "VI", "numero_int": 6, "texto": "VI - a competição por parcela do valor total ocorrerá a critério do credor, com deságio sobre o valor desta;", "ordem": 1325}, {"id": 1326, "artigo_id": 343, "paragrafo_id": 861, "numero_romano": "VII", "numero_int": 7, "texto": "VII - ocorrerão na modalidade deságio, associado ao maior volume ofertado cumulado ou não com o maior percentual de deságio, pelo maior percentual de deságio, podendo ser fixado valor máximo por credor, ou por outro critério a ser definido em edital;", "ordem": 1326}, {"id": 1327, "artigo_id": 343, "paragrafo_id": 861, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - o mecanismo de formação de preço constará nos editais publicados para cada leilão;", "ordem": 1327}, {"id": 1328, "artigo_id": 343, "paragrafo_id": 861, "numero_romano": "IX", "numero_int": 9, "texto": "IX - a quitação parcial dos precatórios será homologada pelo respectivo Tribunal que o expediu.", "ordem": 1328}, {"id": 1329, "artigo_id": 343, "paragrafo_id": 861, "numero_romano": "I", "numero_int": 1, "texto": "I - haverá o sequestro de quantia nas contas de Estados, Distrito Federal e Municípios devedores, por ordem do Presidente do Tribunal referido no § 4º, até o limite do valor não liberado;", "ordem": 1329}, {"id": 1330, "artigo_id": 343, "paragrafo_id": 861, "numero_romano": "II", "numero_int": 2, "texto": "II - constituir-se-á, alternativamente, por ordem do Presidente do Tribunal requerido, em favor dos credores de precatórios, contra Estados, Distrito Federal e Municípios devedores, direito líquido e certo, autoaplicável e independentemente de regulamentação, à compensação automática com débitos líquidos lançados por esta contra aqueles, e, havendo saldo em favor do credor, o valor terá automaticamente poder liberatório do pagamento de tributos de Estados, Distrito Federal e Municípios devedores, até onde se compensarem;", "ordem": 1330}, {"id": 1331, "artigo_id": 343, "paragrafo_id": 861, "numero_romano": "III", "numero_int": 3, "texto": "III - o chefe do Poder Executivo responderá na forma da legislação de responsabilidade fiscal e de improbidade administrativa;", "ordem": 1331}, {"id": 1332, "artigo_id": 343, "paragrafo_id": 861, "numero_romano": "IV", "numero_int": 4, "texto": "IV - enquanto perdurar a omissão, a entidade devedora:", "ordem": 1332}, {"id": 1333, "artigo_id": 343, "paragrafo_id": 861, "numero_romano": "V", "numero_int": 5, "texto": "V - a União reterá os repasses relativos ao Fundo de Participação dos Estados e do Distrito Federal e ao Fundo de Participação dos Municípios, e os depositará nas contas especiais referidas no § 1º, devendo sua utilização obedecer ao que prescreve o § 5º, ambos deste artigo.", "ordem": 1333}, {"id": 1334, "artigo_id": 343, "paragrafo_id": 861, "numero_romano": "I", "numero_int": 1, "texto": "I - 40 (quarenta) salários mínimos para Estados e para o Distrito Federal;", "ordem": 1334}, {"id": 1335, "artigo_id": 343, "paragrafo_id": 861, "numero_romano": "II", "numero_int": 2, "texto": "II - 30 (trinta) salários mínimos para Municípios.", "ordem": 1335}, {"id": 1336, "artigo_id": 345, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - para o ano de 2015: 20% (vinte por cento) para o Estado de destino e 80% (oitenta por cento) para o Estado de origem;", "ordem": 1336}, {"id": 1337, "artigo_id": 345, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - para o ano de 2016: 40% (quarenta por cento) para o Estado de destino e 60% (sessenta por cento) para o Estado de origem;", "ordem": 1337}, {"id": 1338, "artigo_id": 345, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - para o ano de 2017: 60% (sessenta por cento) para o Estado de destino e 40% (quarenta por cento) para o Estado de origem;", "ordem": 1338}, {"id": 1339, "artigo_id": 345, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - para o ano de 2018: 80% (oitenta por cento) para o Estado de destino e 20% (vinte por cento) para o Estado de origem;", "ordem": 1339}, {"id": 1340, "artigo_id": 345, "paragrafo_id": null, "numero_romano": "V", "numero_int": 5, "texto": "V - a partir do ano de 2019: 100% (cem por cento) para o Estado de destino.", "ordem": 1340}, {"id": 1341, "artigo_id": 347, "paragrafo_id": 864, "numero_romano": "I", "numero_int": 1, "texto": "I - nos Estados, as parcelas entregues aos Municípios por determinação constitucional;", "ordem": 1341}, {"id": 1342, "artigo_id": 347, "paragrafo_id": 864, "numero_romano": "II", "numero_int": 2, "texto": "II - nos Estados, no Distrito Federal e nos Municípios, a contribuição dos servidores para custeio de seu sistema de previdência e assistência social e as receitas provenientes da compensação financeira referida no § 9º do art. 201 da Constituição Federal.", "ordem": 1342}, {"id": 1343, "artigo_id": 347, "paragrafo_id": 865, "numero_romano": "II", "numero_int": 2, "texto": "II - até 30% (trinta por cento) dos demais depósitos judiciais da localidade sob jurisdição do respectivo Tribunal de Justiça, mediante a instituição de fundo garantidor em montante equivalente aos recursos levantados, constituído pela parcela restante dos depósitos judiciais e remunerado pela taxa referencial do Sistema Especial de Liquidação e de Custódia (Selic) para títulos federais, nunca inferior aos índices e critérios aplicados aos depósitos levantados, destinando-se:", "ordem": 1343}, {"id": 1344, "artigo_id": 347, "paragrafo_id": 865, "numero_romano": "III", "numero_int": 3, "texto": "III - empréstimos, excetuados para esse fim os limites de endividamento de que tratam os incisos VI e VII do caput do art. 52 da Constituição Federal e quaisquer outros limites de endividamento previstos em lei, não se aplicando a esses empréstimos a vedação de vinculação de receita prevista no inciso IV do caput do art. 167 da Constituição Federal;", "ordem": 1344}, {"id": 1345, "artigo_id": 347, "paragrafo_id": 865, "numero_romano": "IV", "numero_int": 4, "texto": "IV - a totalidade dos depósitos em precatórios e requisições diretas de pagamento de obrigações de pequeno valor efetuados até 31 de dezembro de 2009 e ainda não levantados, com o cancelamento dos respectivos requisitórios e a baixa das obrigações, assegurada a revalidação dos requisitórios pelos juízos dos processos perante os Tribunais, a requerimento dos credores e após a oitiva da entidade devedora, mantidas a posição de ordem cronológica original e a remuneração de todo o período.", "ordem": 1345}, {"id": 1346, "artigo_id": 347, "paragrafo_id": 866, "numero_romano": "I", "numero_int": 1, "texto": "I - (revogado);", "ordem": 1346}, {"id": 1347, "artigo_id": 347, "paragrafo_id": 866, "numero_romano": "II", "numero_int": 2, "texto": "II - (revogado);", "ordem": 1347}, {"id": 1348, "artigo_id": 347, "paragrafo_id": 866, "numero_romano": "III", "numero_int": 3, "texto": "III - (revogado);", "ordem": 1348}, {"id": 1349, "artigo_id": 347, "paragrafo_id": 866, "numero_romano": "IV", "numero_int": 4, "texto": "IV - (revogado).", "ordem": 1349}, {"id": 1350, "artigo_id": 350, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - o Presidente do Tribunal de Justiça local determinará o sequestro, até o limite do valor não liberado, das contas do ente federado inadimplente;", "ordem": 1350}, {"id": 1351, "artigo_id": 350, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - o chefe do Poder Executivo do ente federado inadimplente responderá, na forma da legislação de responsabilidade fiscal e de improbidade administrativa;", "ordem": 1351}, {"id": 1352, "artigo_id": 350, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - a União reterá os recursos referentes aos repasses ao Fundo de Participação dos Estados e do Distrito Federal e ao Fundo de Participação dos Municípios e os depositará na conta especial referida no art. 101 deste Ato das Disposições Constitucionais Transitórias, para utilização como nele previsto;", "ordem": 1352}, {"id": 1353, "artigo_id": 350, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - os Estados e o Comitê Gestor do Imposto sobre Bens e Serviços reterão os repasses previstos, respectivamente, nos §§ 1º e 2º do art. 158 da Constituição Federal e os depositarão na conta especial referida no art. 101 deste Ato das Disposições Constitucionais Transitórias, para utilização como nele previsto.", "ordem": 1353}, {"id": 1354, "artigo_id": 352, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - no exercício de 2022, o espaço fiscal decorrente da diferença entre o valor dos precatórios expedidos e o limite estabelecido no caput deste artigo deverá ser destinado ao programa previsto no parágrafo único do art. 6º e à seguridade social, nos termos do art. 194, ambos da Constituição Federal;", "ordem": 1354}, {"id": 1355, "artigo_id": 352, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - no exercício de 2023, pela diferença entre o total de precatórios expedidos entre 2 de julho de 2021 e 2 de abril de 2022 e o limite de que trata o caput deste artigo válido para o exercício de 2023; e", "ordem": 1355}, {"id": 1356, "artigo_id": 352, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - nos exercícios de 2024 a 2026, pela diferença entre o total de precatórios expedidos entre 3 de abril de dois anos anteriores e 2 de abril do ano anterior ao exercício e o limite de que trata o caput deste artigo válido para o mesmo exercício.", "ordem": 1356}, {"id": 1357, "artigo_id": 352, "paragrafo_id": 883, "numero_romano": "I", "numero_int": 1, "texto": "I - obrigações definidas em lei como de pequeno valor, previstas no § 3º do art. 100 da Constituição Federal;", "ordem": 1357}, {"id": 1358, "artigo_id": 352, "paragrafo_id": 883, "numero_romano": "II", "numero_int": 2, "texto": "II - precatórios de natureza alimentícia cujos titulares, originários ou por sucessão hereditária, tenham no mínimo 60 (sessenta) anos de idade, ou sejam portadores de doença grave ou pessoas com deficiência, assim definidos na forma da lei, até o valor equivalente ao triplo do montante fixado em lei como obrigação de pequeno valor;", "ordem": 1358}, {"id": 1359, "artigo_id": 352, "paragrafo_id": 883, "numero_romano": "III", "numero_int": 3, "texto": "III - demais precatórios de natureza alimentícia até o valor equivalente ao triplo do montante fixado em lei como obrigação de pequeno valor;", "ordem": 1359}, {"id": 1360, "artigo_id": 352, "paragrafo_id": 883, "numero_romano": "IV", "numero_int": 4, "texto": "IV - demais precatórios de natureza alimentícia além do valor previsto no inciso III deste parágrafo;", "ordem": 1360}, {"id": 1361, "artigo_id": 352, "paragrafo_id": 883, "numero_romano": "V", "numero_int": 5, "texto": "V - demais precatórios.", "ordem": 1361}, {"id": 1362, "artigo_id": 354, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - adoção de regras de elegibilidade, de cálculo e de reajustamento dos benefícios que contemplem, nos termos previstos nos incisos I e III do § 1º e nos §§ 3º a 5º, 7º e 8º do art. 40 da Constituição Federal, regras assemelhadas às aplicáveis aos servidores públicos do regime próprio de previdência social da União e que contribuam efetivamente para o atingimento e a manutenção do equilíbrio financeiro e atuarial;", "ordem": 1362}, {"id": 1363, "artigo_id": 354, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - adequação do rol de benefícios ao disposto nos §§ 2º e 3º do art. 9º da Emenda Constitucional nº 103, de 12 de novembro de 2019;", "ordem": 1363}, {"id": 1364, "artigo_id": 354, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - adequação da alíquota de contribuição devida pelos servidores, nos termos do § 4º do art. 9º da Emenda Constitucional nº 103, de 12 de novembro de 2019; e", "ordem": 1364}, {"id": 1365, "artigo_id": 354, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - instituição do regime de previdência complementar e adequação do órgão ou entidade gestora do regime próprio de previdência social, nos termos do § 6º do art. 9º da Emenda Constitucional nº 103, de 12 de novembro de 2019.", "ordem": 1365}, {"id": 1366, "artigo_id": 355, "paragrafo_id": 889, "numero_romano": "I", "numero_int": 1, "texto": "I - atualização monetária pela variação do IPCA ou por índice que vier a substituí-lo;", "ordem": 1366}, {"id": 1367, "artigo_id": 355, "paragrafo_id": 889, "numero_romano": "II", "numero_int": 2, "texto": "II - juros reais de 0% a.a. (zero por cento ao ano) para os Municípios que, em até 18 (dezoito) meses após a promulgação deste inciso, quitarem, no mínimo, 20% (vinte por cento) da dívida de que trata este artigo;", "ordem": 1367}, {"id": 1368, "artigo_id": 355, "paragrafo_id": 889, "numero_romano": "III", "numero_int": 3, "texto": "III - juros reais de 1% a.a. (um por cento ao ano) para os Municípios que, em até 18 (dezoito) meses após a promulgação deste inciso, quitarem, no mínimo, 10% (dez por cento) da dívida consolidada de que trata este artigo;", "ordem": 1368}, {"id": 1369, "artigo_id": 355, "paragrafo_id": 889, "numero_romano": "IV", "numero_int": 4, "texto": "IV - juros reais de 2% a.a. (dois por cento ao ano) para os Municípios que, em até 18 (dezoito) meses após a promulgação deste inciso, quitarem, no mínimo, 5% (cinco por cento) da dívida de que trata este artigo;", "ordem": 1369}, {"id": 1370, "artigo_id": 355, "paragrafo_id": 889, "numero_romano": "V", "numero_int": 5, "texto": "V - juros reais de 4% a.a. (quatro por cento ao ano) para os Municípios que não se enquadrarem nos incisos II, III ou IV deste parágrafo.", "ordem": 1370}, {"id": 1371, "artigo_id": 355, "paragrafo_id": 895, "numero_romano": "I", "numero_int": 1, "texto": "I - transferência de valores em moeda corrente à conta única do Tesouro Nacional, a título de amortização extraordinária do saldo devedor;", "ordem": 1371}, {"id": 1372, "artigo_id": 355, "paragrafo_id": 895, "numero_romano": "II", "numero_int": 2, "texto": "II - transferência, para a União, de participações societárias em empresas de propriedade do Município, desde que a operação seja autorizada mediante leis específicas da União e do Município;", "ordem": 1372}, {"id": 1373, "artigo_id": 355, "paragrafo_id": 895, "numero_romano": "III", "numero_int": 3, "texto": "III - transferência de bens móveis ou imóveis do Município para a União, desde que haja manifestação de aceite por ambas as partes e a operação seja autorizada mediante lei específica do Município;", "ordem": 1373}, {"id": 1374, "artigo_id": 355, "paragrafo_id": 895, "numero_romano": "IV", "numero_int": 4, "texto": "IV - cessão de créditos líquidos e certos do Município para o setor privado, desde que previamente aceitos pela União;", "ordem": 1374}, {"id": 1375, "artigo_id": 355, "paragrafo_id": 895, "numero_romano": "V", "numero_int": 5, "texto": "V - transferência de créditos do Município com a União reconhecidos por ambas as partes;", "ordem": 1375}, {"id": 1376, "artigo_id": 355, "paragrafo_id": 895, "numero_romano": "VI", "numero_int": 6, "texto": "VI - cessão, para a União, dos recebíveis originados de créditos inscritos na dívida ativa da Fazenda Pública municipal confessados e considerados recuperáveis nos termos da legislação aplicável, nas seguintes condições:", "ordem": 1376}, {"id": 1377, "artigo_id": 355, "paragrafo_id": 895, "numero_romano": "VII", "numero_int": 7, "texto": "VII - cessão de outros ativos que, em comum acordo entre as partes, possam ser utilizados para pagamento das dívidas, nos termos de ato do Poder Executivo federal; e", "ordem": 1377}, {"id": 1378, "artigo_id": 355, "paragrafo_id": 895, "numero_romano": "VIII", "numero_int": 8, "texto": "VIII - cessão, para a União, dos recebíveis originados da compensação financeira advinda da exploração de petróleo ou gás natural, de recursos hídricos para fins de geração de energia elétrica ou de recursos minerais em seus respectivos territórios, plataformas continentais, mar territorial ou zona econômica exclusiva, conforme as Leis nºs 7.990, de 28 de dezembro de 1989, e 9.478, de 6 de agosto de 1997, de acordo com definição em ato do Poder Executivo federal.", "ordem": 1378}, {"id": 1379, "artigo_id": 356, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - a prestação de garantia ou de contra garantia à União ou os pagamentos de débitos em favor da União, na forma do § 4º do art. 167 da Constituição Federal;", "ordem": 1379}, {"id": 1380, "artigo_id": 356, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - as contribuições parceladas devidas ao Regime Geral de Previdência Social;", "ordem": 1380}, {"id": 1381, "artigo_id": 356, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - as contribuições parceladas devidas ao respectivo regime próprio de previdência social.", "ordem": 1381}, {"id": 1382, "artigo_id": 359, "paragrafo_id": 898, "numero_romano": "I", "numero_int": 1, "texto": "I - quanto às despesas:", "ordem": 1382}, {"id": 1383, "artigo_id": 359, "paragrafo_id": 898, "numero_romano": "II", "numero_int": 2, "texto": "II - a abertura do crédito extraordinário para seu atendimento dar-se-á independentemente da observância dos requisitos exigidos no § 3º do art. 167 da Constituição Federal; e", "ordem": 1383}, {"id": 1384, "artigo_id": 359, "paragrafo_id": 898, "numero_romano": "III", "numero_int": 3, "texto": "III - a dispensa das limitações legais, inclusive quanto à necessidade de compensação:", "ordem": 1384}, {"id": 1385, "artigo_id": 364, "paragrafo_id": 903, "numero_romano": "I", "numero_int": 1, "texto": "I - o financiamento do Comitê Gestor do Imposto sobre Bens e Serviços, nos termos do art. 156-B, § 2º, III, da Constituição Federal;", "ordem": 1385}, {"id": 1386, "artigo_id": 364, "paragrafo_id": 903, "numero_romano": "II", "numero_int": 2, "texto": "II - compor o Fundo de Compensação de Benefícios Fiscais ou Financeiro-Fiscais do imposto de que trata o art. 155, II, da Constituição Federal.", "ordem": 1386}, {"id": 1387, "artigo_id": 365, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - serão cobrados:", "ordem": 1387}, {"id": 1388, "artigo_id": 365, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - serão extintas as contribuições previstas no art. 195, I, \"b\", e IV, e a contribuição para o Programa de Integração Social de que trata o art. 239, todos da Constituição Federal, desde que instituída a contribuição referida na alínea \"a\" do inciso I;", "ordem": 1388}, {"id": 1389, "artigo_id": 365, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - o imposto previsto no art. 153, IV, da Constituição Federal:", "ordem": 1389}, {"id": 1390, "artigo_id": 367, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - 9/10 (nove décimos), em 2029;", "ordem": 1390}, {"id": 1391, "artigo_id": 367, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - 8/10 (oito décimos), em 2030;", "ordem": 1391}, {"id": 1392, "artigo_id": 367, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - 7/10 (sete décimos), em 2031;", "ordem": 1392}, {"id": 1393, "artigo_id": 367, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - 6/10 (seis décimos), em 2032.", "ordem": 1393}, {"id": 1394, "artigo_id": 369, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - de 2027 a 2033, que a receita da União com a contribuição prevista no art. 195, V, e com o imposto previsto no art. 153, VIII, todos da Constituição Federal, seja equivalente à redução da receita:", "ordem": 1394}, {"id": 1395, "artigo_id": 369, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - de 2029 a 2033, que a receita dos Estados e do Distrito Federal com o imposto previsto no art. 156-A da Constituição Federal seja equivalente à redução:", "ordem": 1395}, {"id": 1396, "artigo_id": 369, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - de 2029 a 2033, que a receita dos Municípios e do Distrito Federal com o imposto previsto no art. 156-A seja equivalente à redução da receita do imposto previsto no art. 156, III, ambos da Constituição Federal.", "ordem": 1396}, {"id": 1397, "artigo_id": 369, "paragrafo_id": 911, "numero_romano": "I", "numero_int": 1, "texto": "I - Teto de Referência da União: a média da receita no período de 2012 a 2021, apurada como proporção do PIB, do imposto previsto no art. 153, IV, das contribuições previstas no art. 195, I, \"b\", e IV, da contribuição para o Programa de Integração Social de que trata o art. 239 e do imposto previsto no art. 153, V, sobre operações de seguro, todos da Constituição Federal;", "ordem": 1397}, {"id": 1398, "artigo_id": 369, "paragrafo_id": 911, "numero_romano": "II", "numero_int": 2, "texto": "II - Teto de Referência Total: a média da receita no período de 2012 a 2021, apurada como proporção do PIB, dos impostos previstos nos arts. 153, IV, 155, II e 156, III, das contribuições previstas no art. 195, I, \"b\", e IV, da contribuição para o Programa de Integração Social de que trata o art. 239 e do imposto previsto no art. 153, V, sobre operações de seguro, todos da Constituição Federal;", "ordem": 1398}, {"id": 1399, "artigo_id": 369, "paragrafo_id": 911, "numero_romano": "III", "numero_int": 3, "texto": "III - Receita-Base da União: a receita da União com a contribuição prevista no art. 195, V, e com o imposto previsto no art. 153, VIII, ambos da Constituição Federal, apurada como proporção do PIB;", "ordem": 1399}, {"id": 1400, "artigo_id": 369, "paragrafo_id": 911, "numero_romano": "IV", "numero_int": 4, "texto": "IV - Receita-Base dos Entes Subnacionais: a receita dos Estados, do Distrito Federal e dos Municípios com o imposto previsto no art. 156-A da Constituição Federal, deduzida da parcela a que se refere a alínea \"b\" do inciso II do caput, apurada como proporção do PIB;", "ordem": 1400}, {"id": 1401, "artigo_id": 369, "paragrafo_id": 911, "numero_romano": "V", "numero_int": 5, "texto": "V - Receita-Base Total: a soma da Receita-Base da União com a Receita-Base dos Entes Subnacionais, sendo essa última:", "ordem": 1401}, {"id": 1402, "artigo_id": 369, "paragrafo_id": 914, "numero_romano": "I", "numero_int": 1, "texto": "I - definidas de forma a que a Receita-Base seja igual ao respectivo Teto de Referência;", "ordem": 1402}, {"id": 1403, "artigo_id": 369, "paragrafo_id": 914, "numero_romano": "II", "numero_int": 2, "texto": "II - no caso do § 5º, proporcionais para as alíquotas de referência federal, estadual e municipal.", "ordem": 1403}, {"id": 1404, "artigo_id": 370, "paragrafo_id": 918, "numero_romano": "I", "numero_int": 1, "texto": "I - de 2029 a 2032, 80% (oitenta por cento);", "ordem": 1404}, {"id": 1405, "artigo_id": 370, "paragrafo_id": 918, "numero_romano": "II", "numero_int": 2, "texto": "II - em 2033, 90% (noventa por cento);", "ordem": 1405}, {"id": 1406, "artigo_id": 370, "paragrafo_id": 918, "numero_romano": "III", "numero_int": 3, "texto": "III - de 2034 a 2077, percentual correspondente ao aplicado em 2033, reduzido à razão de 1/45 (um quarenta e cinco avos) por ano.", "ordem": 1406}, {"id": 1407, "artigo_id": 370, "paragrafo_id": 919, "numero_romano": "I", "numero_int": 1, "texto": "I - no caso dos Estados:", "ordem": 1407}, {"id": 1408, "artigo_id": 370, "paragrafo_id": 919, "numero_romano": "II", "numero_int": 2, "texto": "II - no caso do Distrito Federal:", "ordem": 1408}, {"id": 1409, "artigo_id": 370, "paragrafo_id": 919, "numero_romano": "III", "numero_int": 3, "texto": "III - no caso dos Municípios:", "ordem": 1409}, {"id": 1410, "artigo_id": 370, "paragrafo_id": 922, "numero_romano": "I", "numero_int": 1, "texto": "I - constituirão a base de cálculo dos fundos de que trata o art. 212-A, II, da Constituição Federal, observado que:", "ordem": 1410}, {"id": 1411, "artigo_id": 370, "paragrafo_id": 922, "numero_romano": "II", "numero_int": 2, "texto": "II - constituirão as bases de cálculo de que tratam os arts. 29-A, 198, § 2º, 204, parágrafo único, 212 e 216, § 6º, da Constituição Federal, excetuados os valores distribuídos nos termos do § 2º, I, \"b\";", "ordem": 1411}, {"id": 1412, "artigo_id": 370, "paragrafo_id": 922, "numero_romano": "III", "numero_int": 3, "texto": "III - poderão ser vinculados para prestação de garantias às operações de crédito por antecipação de receita previstas no art. 165, § 8º, para pagamento de débitos com a União e para prestar-lhe garantia ou contragarantia, nos termos do art. 167, § 4º, todos da Constituição Federal.", "ordem": 1412}, {"id": 1413, "artigo_id": 371, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - o valor apurado nos termos dos arts. 149-C e 156-A, § 4º, II, e § 5º, I e IV, com base nas alíquotas de referência, após a aplicação do disposto no art. 158, IV, \"b\", todos da Constituição Federal; e", "ordem": 1413}, {"id": 1414, "artigo_id": 371, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - a respectiva receita média, apurada nos termos do art. 131, § 2º, I, II e III, deste Ato das Disposições Constitucionais Transitórias, limitada a 3 (três) vezes a média nacional por habitante da respectiva esfera federativa.", "ordem": 1414}, {"id": 1415, "artigo_id": 371, "paragrafo_id": 924, "numero_romano": "I", "numero_int": 1, "texto": "I - a soma do valor apurado nos termos do inciso I do caput com o valor recebido nos termos deste artigo; e", "ordem": 1415}, {"id": 1416, "artigo_id": 371, "paragrafo_id": 924, "numero_romano": "II", "numero_int": 2, "texto": "II - a receita média apurada na forma do inciso II do caput.", "ordem": 1416}, {"id": 1417, "artigo_id": 373, "paragrafo_id": 927, "numero_romano": "I", "numero_int": 1, "texto": "I - apresentado o pedido de homologação, o ente federativo deverá se pronunciar no prazo estabelecido na lei complementar a que se refere o caput;", "ordem": 1417}, {"id": 1418, "artigo_id": 373, "paragrafo_id": 927, "numero_romano": "II", "numero_int": 2, "texto": "II - na ausência de resposta ao pedido de homologação no prazo a que se refere o inciso I deste parágrafo, os respectivos saldos credores serão considerados homologados.", "ordem": 1418}, {"id": 1419, "artigo_id": 373, "paragrafo_id": 929, "numero_romano": "I", "numero_int": 1, "texto": "I - pelo prazo remanescente, apurado nos termos do art. 20, § 5º, da Lei Complementar nº 87, de 13 de setembro de 1996, para os créditos relativos à entrada de mercadorias destinadas ao ativo permanente;", "ordem": 1419}, {"id": 1420, "artigo_id": 373, "paragrafo_id": 929, "numero_romano": "II", "numero_int": 2, "texto": "II - em 240 (duzentos e quarenta) parcelas mensais, iguais e sucessivas, nos demais casos.", "ordem": 1420}, {"id": 1421, "artigo_id": 373, "paragrafo_id": 932, "numero_romano": "I", "numero_int": 1, "texto": "I - as regras gerais de implementação do parcelamento previsto no § 3º;", "ordem": 1421}, {"id": 1422, "artigo_id": 373, "paragrafo_id": 932, "numero_romano": "II", "numero_int": 2, "texto": "II - a forma pela qual os titulares dos créditos de que trata este artigo poderão transferi-los a terceiros;", "ordem": 1422}, {"id": 1423, "artigo_id": 373, "paragrafo_id": 932, "numero_romano": "III", "numero_int": 3, "texto": "III - a forma pela qual o crédito de que trata este artigo poderá ser ressarcido ao contribuinte pelo Comitê Gestor do Imposto sobre Bens e Serviços, caso não seja possível compensar o valor da parcela nos termos do § 3º.", "ordem": 1423}, {"id": 1424, "artigo_id": 375, "paragrafo_id": null, "numero_romano": "I", "numero_int": 1, "texto": "I - a alíquota ou o percentual de contribuição não poderão ser superiores e a base de incidência não poderá ser mais ampla que os das respectivas contribuições vigentes em 30 de abril de 2023;", "ordem": 1424}, {"id": 1425, "artigo_id": 375, "paragrafo_id": null, "numero_romano": "II", "numero_int": 2, "texto": "II - a instituição de contribuição nos termos deste artigo implicará a extinção da contribuição correspondente, vinculada ao imposto de que trata o art. 155, II, da Constituição Federal, vigente em 30 de abril de 2023;", "ordem": 1425}, {"id": 1426, "artigo_id": 375, "paragrafo_id": null, "numero_romano": "III", "numero_int": 3, "texto": "III - a destinação de sua receita deverá ser a mesma das contribuições vigentes em 30 de abril de 2023;", "ordem": 1426}, {"id": 1427, "artigo_id": 375, "paragrafo_id": null, "numero_romano": "IV", "numero_int": 4, "texto": "IV - a contribuição instituída nos termos do caput será extinta em 31 de dezembro de 2043.", "ordem": 1427}]
  const ALINEAS = [{"id": 1, "inciso_id": 47, "letra": "a", "texto": "a) a proteção às participações individuais em obras coletivas e à reprodução da imagem e voz humanas, inclusive nas atividades desportivas;", "ordem": 1}, {"id": 2, "inciso_id": 47, "letra": "b", "texto": "b) o direito de fiscalização do aproveitamento econômico das obras que criarem ou de que participarem aos criadores, aos intérpretes e às respectivas representações sindicais e associativas;", "ordem": 2}, {"id": 3, "inciso_id": 53, "letra": "a", "texto": "a) o direito de petição aos Poderes Públicos em defesa de direitos ou contra ilegalidade ou abuso de poder;", "ordem": 3}, {"id": 4, "inciso_id": 53, "letra": "b", "texto": "b) a obtenção de certidões em repartições públicas, para defesa de direitos e esclarecimento de situações de interesse pessoal;", "ordem": 4}, {"id": 5, "inciso_id": 57, "letra": "a", "texto": "a) a plenitude de defesa;", "ordem": 5}, {"id": 6, "inciso_id": 57, "letra": "b", "texto": "b) o sigilo das votações;", "ordem": 6}, {"id": 7, "inciso_id": 57, "letra": "c", "texto": "c) a soberania dos veredictos;", "ordem": 7}, {"id": 8, "inciso_id": 57, "letra": "d", "texto": "d) a competência para o julgamento dos crimes dolosos contra a vida;", "ordem": 8}, {"id": 9, "inciso_id": 65, "letra": "a", "texto": "a) privação ou restrição da liberdade;", "ordem": 9}, {"id": 10, "inciso_id": 65, "letra": "b", "texto": "b) perda de bens;", "ordem": 10}, {"id": 11, "inciso_id": 65, "letra": "c", "texto": "c) multa;", "ordem": 11}, {"id": 12, "inciso_id": 65, "letra": "d", "texto": "d) prestação social alternativa;", "ordem": 12}, {"id": 13, "inciso_id": 65, "letra": "e", "texto": "e) suspensão ou interdição de direitos;", "ordem": 13}, {"id": 14, "inciso_id": 66, "letra": "a", "texto": "a) de morte, salvo em caso de guerra declarada, nos termos do art. 84, XIX;", "ordem": 14}, {"id": 15, "inciso_id": 66, "letra": "b", "texto": "b) de caráter perpétuo;", "ordem": 15}, {"id": 16, "inciso_id": 66, "letra": "c", "texto": "c) de trabalhos forçados;", "ordem": 16}, {"id": 17, "inciso_id": 66, "letra": "d", "texto": "d) de banimento;", "ordem": 17}, {"id": 18, "inciso_id": 66, "letra": "e", "texto": "e) cruéis;", "ordem": 18}, {"id": 19, "inciso_id": 89, "letra": "a", "texto": "a) partido político com representação no Congresso Nacional;", "ordem": 19}, {"id": 20, "inciso_id": 89, "letra": "b", "texto": "b) organização sindical, entidade de classe ou associação legalmente constituída e em funcionamento há pelo menos um ano, em defesa dos interesses de seus membros ou associados;", "ordem": 20}, {"id": 21, "inciso_id": 91, "letra": "a", "texto": "a) para assegurar o conhecimento de informações relativas à pessoa do impetrante, constantes de registros ou bancos de dados de entidades governamentais ou de caráter público;", "ordem": 21}, {"id": 22, "inciso_id": 91, "letra": "b", "texto": "b) para a retificação de dados, quando não se prefira fazê-lo por processo sigiloso, judicial ou administrativo;", "ordem": 22}, {"id": 23, "inciso_id": 95, "letra": "a", "texto": "a) o registro civil de nascimento;", "ordem": 23}, {"id": 24, "inciso_id": 95, "letra": "b", "texto": "b) a certidão de óbito;", "ordem": 24}, {"id": 25, "inciso_id": 127, "letra": "a", "texto": "a) (Revogada).", "ordem": 25}, {"id": 26, "inciso_id": 127, "letra": "b", "texto": "b) (Revogada).", "ordem": 26}, {"id": 27, "inciso_id": 141, "letra": "a", "texto": "a) os nascidos na República Federativa do Brasil, ainda que de pais estrangeiros, desde que estes não estejam a serviço de seu país;", "ordem": 27}, {"id": 28, "inciso_id": 141, "letra": "b", "texto": "b) os nascidos no estrangeiro, de pai brasileiro ou mãe brasileira, desde que qualquer deles esteja a serviço da República Federativa do Brasil;", "ordem": 28}, {"id": 29, "inciso_id": 141, "letra": "c", "texto": "c) os nascidos no estrangeiro de pai brasileiro ou de mãe brasileira, desde que sejam registrados em repartição brasileira competente ou venham a residir na República Federativa do Brasil e optem, em qualquer tempo, depois de atingida a maioridade, pela nacionalidade brasileira;", "ordem": 29}, {"id": 30, "inciso_id": 142, "letra": "a", "texto": "a) os que, na forma da lei, adquiram a nacionalidade brasileira, exigidas aos originários de países de língua portuguesa apenas residência por um ano ininterrupto e idoneidade moral;", "ordem": 30}, {"id": 31, "inciso_id": 142, "letra": "b", "texto": "b) os estrangeiros de qualquer nacionalidade, residentes na República Federativa do Brasil há mais de quinze anos ininterruptos e sem condenação penal, desde que requeiram a nacionalidade brasileira.", "ordem": 31}, {"id": 32, "inciso_id": 151, "letra": "a", "texto": "a) revogada;", "ordem": 32}, {"id": 33, "inciso_id": 151, "letra": "b", "texto": "b) revogada.", "ordem": 33}, {"id": 34, "inciso_id": 156, "letra": "a", "texto": "a) os analfabetos;", "ordem": 34}, {"id": 35, "inciso_id": 156, "letra": "b", "texto": "b) os maiores de setenta anos;", "ordem": 35}, {"id": 36, "inciso_id": 156, "letra": "c", "texto": "c) os maiores de dezesseis e menores de dezoito anos.", "ordem": 36}, {"id": 37, "inciso_id": 162, "letra": "a", "texto": "a) trinta e cinco anos para Presidente e Vice-Presidente da República e Senador;", "ordem": 37}, {"id": 38, "inciso_id": 162, "letra": "b", "texto": "b) trinta anos para Governador e Vice-Governador de Estado e do Distrito Federal;", "ordem": 38}, {"id": 39, "inciso_id": 162, "letra": "c", "texto": "c) vinte e um anos para Deputado Federal, Deputado Estadual ou Distrital, Prefeito, Vice-Prefeito e juiz de paz;", "ordem": 39}, {"id": 40, "inciso_id": 162, "letra": "d", "texto": "d) dezoito anos para Vereador.", "ordem": 40}, {"id": 41, "inciso_id": 200, "letra": "a", "texto": "a) os serviços de radiodifusão sonora, e de sons e imagens;", "ordem": 41}, {"id": 42, "inciso_id": 200, "letra": "b", "texto": "b) os serviços e instalações de energia elétrica e o aproveitamento energético dos cursos de água, em articulação com os Estados onde se situam os potenciais hidroenergéticos;", "ordem": 42}, {"id": 43, "inciso_id": 200, "letra": "c", "texto": "c) a navegação aérea, aeroespacial e a infra-estrutura aeroportuária;", "ordem": 43}, {"id": 44, "inciso_id": 200, "letra": "d", "texto": "d) os serviços de transporte ferroviário e aquaviário entre portos brasileiros e fronteiras nacionais, ou que transponham os limites de Estado ou Território;", "ordem": 44}, {"id": 45, "inciso_id": 200, "letra": "e", "texto": "e) os serviços de transporte rodoviário interestadual e internacional de passageiros;", "ordem": 45}, {"id": 46, "inciso_id": 200, "letra": "f", "texto": "f) os portos marítimos, fluviais e lacustres;", "ordem": 46}, {"id": 47, "inciso_id": 211, "letra": "a", "texto": "a) toda atividade nuclear em território nacional somente será admitida para fins pacíficos e mediante aprovação do Congresso Nacional;", "ordem": 47}, {"id": 48, "inciso_id": 211, "letra": "b", "texto": "b) sob regime de permissão, são autorizadas a comercialização e a utilização de radioisótopos para pesquisa e uso agrícolas e industriais;", "ordem": 48}, {"id": 49, "inciso_id": 211, "letra": "c", "texto": "c) sob regime de permissão, são autorizadas a produção, a comercialização e a utilização de radioisótopos para pesquisa e uso médicos;", "ordem": 49}, {"id": 50, "inciso_id": 211, "letra": "d", "texto": "d) a responsabilidade civil por danos nucleares independe da existência de culpa;", "ordem": 50}, {"id": 51, "inciso_id": 280, "letra": "a", "texto": "a) 9 (nove) Vereadores, nos Municípios de até 15.000 (quinze mil) habitantes;", "ordem": 51}, {"id": 52, "inciso_id": 280, "letra": "b", "texto": "b) 11 (onze) Vereadores, nos Municípios de mais de 15.000 (quinze mil) habitantes e de até 30.000 (trinta mil) habitantes;", "ordem": 52}, {"id": 53, "inciso_id": 280, "letra": "c", "texto": "c) 13 (treze) Vereadores, nos Municípios com mais de 30.000 (trinta mil) habitantes e de até 50.000 (cinquenta mil) habitantes;", "ordem": 53}, {"id": 54, "inciso_id": 280, "letra": "d", "texto": "d) 15 (quinze) Vereadores, nos Municípios de mais de 50.000 (cinquenta mil) habitantes e de até 80.000 (oitenta mil) habitantes;", "ordem": 54}, {"id": 55, "inciso_id": 280, "letra": "e", "texto": "e) 17 (dezessete) Vereadores, nos Municípios de mais de 80.000 (oitenta mil) habitantes e de até 120.000 (cento e vinte mil) habitantes;", "ordem": 55}, {"id": 56, "inciso_id": 280, "letra": "f", "texto": "f) 19 (dezenove) Vereadores, nos Municípios de mais de 120.000 (cento e vinte mil) habitantes e de até 160.000 (cento sessenta mil) habitantes;", "ordem": 56}, {"id": 57, "inciso_id": 280, "letra": "g", "texto": "g) 21 (vinte e um) Vereadores, nos Municípios de mais de 160.000 (cento e sessenta mil) habitantes e de até 300.000 (trezentos mil) habitantes;", "ordem": 57}, {"id": 58, "inciso_id": 280, "letra": "h", "texto": "h) 23 (vinte e três) Vereadores, nos Municípios de mais de 300.000 (trezentos mil) habitantes e de até 450.000 (quatrocentos e cinquenta mil) habitantes;", "ordem": 58}, {"id": 59, "inciso_id": 280, "letra": "i", "texto": "i) 25 (vinte e cinco) Vereadores, nos Municípios de mais de 450.000 (quatrocentos e cinquenta mil) habitantes e de até 600.000 (seiscentos mil) habitantes;", "ordem": 59}, {"id": 60, "inciso_id": 280, "letra": "j", "texto": "j) 27 (vinte e sete) Vereadores, nos Municípios de mais de 600.000 (seiscentos mil) habitantes e de até 750.000 (setecentos cinquenta mil) habitantes;", "ordem": 60}, {"id": 61, "inciso_id": 280, "letra": "k", "texto": "k) 29 (vinte e nove) Vereadores, nos Municípios de mais de 750.000 (setecentos e cinquenta mil) habitantes e de até 900.000 (novecentos mil) habitantes;", "ordem": 61}, {"id": 62, "inciso_id": 280, "letra": "l", "texto": "l) 31 (trinta e um) Vereadores, nos Municípios de mais de 900.000 (novecentos mil) habitantes e de até 1.050.000 (um milhão e cinquenta mil) habitantes;", "ordem": 62}, {"id": 63, "inciso_id": 280, "letra": "m", "texto": "m) 33 (trinta e três) Vereadores, nos Municípios de mais de 1.050.000 (um milhão e cinquenta mil) habitantes e de até 1.200.000 (um milhão e duzentos mil) habitantes;", "ordem": 63}, {"id": 64, "inciso_id": 280, "letra": "n", "texto": "n) 35 (trinta e cinco) Vereadores, nos Municípios de mais de 1.200.000 (um milhão e duzentos mil) habitantes e de até 1.350.000 (um milhão e trezentos e cinquenta mil) habitantes;", "ordem": 64}, {"id": 65, "inciso_id": 280, "letra": "o", "texto": "o) 37 (trinta e sete) Vereadores, nos Municípios de 1.350.000 (um milhão e trezentos e cinquenta mil) habitantes e de até 1.500.000 (um milhão e quinhentos mil) habitantes;", "ordem": 65}, {"id": 66, "inciso_id": 280, "letra": "p", "texto": "p) 39 (trinta e nove) Vereadores, nos Municípios de mais de 1.500.000 (um milhão e quinhentos mil) habitantes e de até 1.800.000 (um milhão e oitocentos mil) habitantes;", "ordem": 66}, {"id": 67, "inciso_id": 280, "letra": "q", "texto": "q) 41 (quarenta e um) Vereadores, nos Municípios de mais de 1.800.000 (um milhão e oitocentos mil) habitantes e de até 2.400.000 (dois milhões e quatrocentos mil) habitantes;", "ordem": 67}, {"id": 68, "inciso_id": 280, "letra": "r", "texto": "r) 43 (quarenta e três) Vereadores, nos Municípios de mais de 2.400.000 (dois milhões e quatrocentos mil) habitantes e de até 3.000.000 (três milhões) de habitantes;", "ordem": 68}, {"id": 69, "inciso_id": 280, "letra": "s", "texto": "s) 45 (quarenta e cinco) Vereadores, nos Municípios de mais de 3.000.000 (três milhões) de habitantes e de até 4.000.000 (quatro milhões) de habitantes;", "ordem": 69}, {"id": 70, "inciso_id": 280, "letra": "t", "texto": "t) 47 (quarenta e sete) Vereadores, nos Municípios de mais de 4.000.000 (quatro milhões) de habitantes e de até 5.000.000 (cinco milhões) de habitantes;", "ordem": 70}, {"id": 71, "inciso_id": 280, "letra": "u", "texto": "u) 49 (quarenta e nove) Vereadores, nos Municípios de mais de 5.000.000 (cinco milhões) de habitantes e de até 6.000.000 (seis milhões) de habitantes;", "ordem": 71}, {"id": 72, "inciso_id": 280, "letra": "v", "texto": "v) 51 (cinquenta e um) Vereadores, nos Municípios de mais de 6.000.000 (seis milhões) de habitantes e de até 7.000.000 (sete milhões) de habitantes;", "ordem": 72}, {"id": 73, "inciso_id": 280, "letra": "w", "texto": "w) 53 (cinquenta e três) Vereadores, nos Municípios de mais de 7.000.000 (sete milhões) de habitantes e de até 8.000.000 (oito milhões) de habitantes; e", "ordem": 73}, {"id": 74, "inciso_id": 280, "letra": "x", "texto": "x) 55 (cinquenta e cinco) Vereadores, nos Municípios de mais de 8.000.000 (oito milhões) de habitantes;", "ordem": 74}, {"id": 75, "inciso_id": 282, "letra": "a", "texto": "a) em Municípios de até dez mil habitantes, o subsídio máximo dos Vereadores corresponderá a vinte por cento do subsídio dos Deputados Estaduais;", "ordem": 75}, {"id": 76, "inciso_id": 282, "letra": "b", "texto": "b) em Municípios de dez mil e um a cinqüenta mil habitantes, o subsídio máximo dos Vereadores corresponderá a trinta por cento do subsídio dos Deputados Estaduais;", "ordem": 76}, {"id": 77, "inciso_id": 282, "letra": "c", "texto": "c) em Municípios de cinqüenta mil e um a cem mil habitantes, o subsídio máximo dos Vereadores corresponderá a quarenta por cento do subsídio dos Deputados Estaduais;", "ordem": 77}, {"id": 78, "inciso_id": 282, "letra": "d", "texto": "d) em Municípios de cem mil e um a trezentos mil habitantes, o subsídio máximo dos Vereadores corresponderá a cinqüenta por cento do subsídio dos Deputados Estaduais;", "ordem": 78}, {"id": 79, "inciso_id": 282, "letra": "e", "texto": "e) em Municípios de trezentos mil e um a quinhentos mil habitantes, o subsídio máximo dos Vereadores corresponderá a sessenta por cento do subsídio dos Deputados Estaduais;", "ordem": 79}, {"id": 80, "inciso_id": 282, "letra": "f", "texto": "f) em Municípios de mais de quinhentos mil habitantes, o subsídio máximo dos Vereadores corresponderá a setenta e cinco por cento do subsídio dos Deputados Estaduais;", "ordem": 80}, {"id": 81, "inciso_id": 313, "letra": "a", "texto": "a) suspender o pagamento da dívida fundada por mais de dois anos consecutivos, salvo motivo de força maior;", "ordem": 81}, {"id": 82, "inciso_id": 313, "letra": "b", "texto": "b) deixar de entregar aos Municípios receitas tributárias fixadas nesta Constituição, dentro dos prazos estabelecidos em lei;", "ordem": 82}, {"id": 83, "inciso_id": 315, "letra": "a", "texto": "a) forma republicana, sistema representativo e regime democrático;", "ordem": 83}, {"id": 84, "inciso_id": 315, "letra": "b", "texto": "b) direitos da pessoa humana;", "ordem": 84}, {"id": 85, "inciso_id": 315, "letra": "c", "texto": "c) autonomia municipal;", "ordem": 85}, {"id": 86, "inciso_id": 315, "letra": "d", "texto": "d) prestação de contas da administração pública, direta e indireta.", "ordem": 86}, {"id": 87, "inciso_id": 315, "letra": "e", "texto": "e) aplicação do mínimo exigido da receita resultante de impostos estaduais, compreendida a proveniente de transferências, na manutenção e desenvolvimento do ensino e nas ações e serviços públicos de saúde.", "ordem": 87}, {"id": 88, "inciso_id": 337, "letra": "a", "texto": "a) a de dois cargos de professor;", "ordem": 88}, {"id": 89, "inciso_id": 337, "letra": "b", "texto": "b) a de um cargo de professor com outro de qualquer natureza;", "ordem": 89}, {"id": 90, "inciso_id": 337, "letra": "c", "texto": "c) a de dois cargos ou empregos privativos de profissionais de saúde, com profissões regulamentadas;", "ordem": 90}, {"id": 91, "inciso_id": 419, "letra": "a", "texto": "a) Magistrados, nos casos estabelecidos nesta Constituição;", "ordem": 91}, {"id": 92, "inciso_id": 419, "letra": "b", "texto": "b) Ministros do Tribunal de Contas da União indicados pelo Presidente da República;", "ordem": 92}, {"id": 93, "inciso_id": 419, "letra": "c", "texto": "c) Governador de Território;", "ordem": 93}, {"id": 94, "inciso_id": 419, "letra": "d", "texto": "d) Presidente e diretores do banco central;", "ordem": 94}, {"id": 95, "inciso_id": 419, "letra": "e", "texto": "e) Procurador-Geral da República;", "ordem": 95}, {"id": 96, "inciso_id": 419, "letra": "f", "texto": "f) titulares de outros cargos que a lei determinar;", "ordem": 96}, {"id": 97, "inciso_id": 432, "letra": "a", "texto": "a) firmar ou manter contrato com pessoa jurídica de direito público, autarquia, empresa pública, sociedade de economia mista ou empresa concessionária de serviço público, salvo quando o contrato obedecer a cláusulas uniformes;", "ordem": 97}, {"id": 98, "inciso_id": 432, "letra": "b", "texto": "b) aceitar ou exercer cargo, função ou emprego remunerado, inclusive os de que sejam demissíveis \"ad nutum\", nas entidades constantes da alínea anterior;", "ordem": 98}, {"id": 99, "inciso_id": 433, "letra": "a", "texto": "a) ser proprietários, controladores ou diretores de empresa que goze de favor decorrente de contrato com pessoa jurídica de direito público, ou nela exercer função remunerada;", "ordem": 99}, {"id": 100, "inciso_id": 433, "letra": "b", "texto": "b) ocupar cargo ou função de que sejam demissíveis \"ad nutum\", nas entidades referidas no inciso I, \"a\";", "ordem": 100}, {"id": 101, "inciso_id": 433, "letra": "c", "texto": "c) patrocinar causa em que seja interessada qualquer das entidades a que se refere o inciso I, \"a\";", "ordem": 101}, {"id": 102, "inciso_id": 433, "letra": "d", "texto": "d) ser titulares de mais de um cargo ou mandato público eletivo.", "ordem": 102}, {"id": 103, "inciso_id": 469, "letra": "a", "texto": "a) criação de cargos, funções ou empregos públicos na administração direta e autárquica ou aumento de sua remuneração;", "ordem": 103}, {"id": 104, "inciso_id": 469, "letra": "b", "texto": "b) organização administrativa e judiciária, matéria tributária e orçamentária, serviços públicos e pessoal da administração dos Territórios;", "ordem": 104}, {"id": 105, "inciso_id": 469, "letra": "c", "texto": "c) servidores públicos da União e Territórios, seu regime jurídico, provimento de cargos, estabilidade e aposentadoria;", "ordem": 105}, {"id": 106, "inciso_id": 469, "letra": "d", "texto": "d) organização do Ministério Público e da Defensoria Pública da União, bem como normas gerais para a organização do Ministério Público e da Defensoria Pública dos Estados, do Distrito Federal e dos Territórios;", "ordem": 106}, {"id": 107, "inciso_id": 469, "letra": "e", "texto": "e) criação e extinção de Ministérios e órgãos da administração pública, observado o disposto no art. 84, VI;", "ordem": 107}, {"id": 108, "inciso_id": 469, "letra": "f", "texto": "f) militares das Forças Armadas, seu regime jurídico, provimento de cargos, promoções, estabilidade, remuneração, reforma e transferência para a reserva.", "ordem": 108}, {"id": 109, "inciso_id": 470, "letra": "a", "texto": "a) nacionalidade, cidadania, direitos políticos, partidos políticos e direito eleitoral;", "ordem": 109}, {"id": 110, "inciso_id": 470, "letra": "b", "texto": "b) direito penal, processual penal e processual civil;", "ordem": 110}, {"id": 111, "inciso_id": 470, "letra": "c", "texto": "c) organização do Poder Judiciário e do Ministério Público, a carreira e a garantia de seus membros;", "ordem": 111}, {"id": 112, "inciso_id": 470, "letra": "d", "texto": "d) planos plurianuais, diretrizes orçamentárias, orçamento e créditos adicionais e suplementares, ressalvado o previsto no art. 167, § 3º;", "ordem": 112}, {"id": 113, "inciso_id": 505, "letra": "a", "texto": "a) organização e funcionamento da administração federal, quando não implicar aumento de despesa nem criação ou extinção de órgãos públicos;", "ordem": 113}, {"id": 114, "inciso_id": 505, "letra": "b", "texto": "b) extinção de funções ou cargos públicos, quando vagos;", "ordem": 114}, {"id": 115, "inciso_id": 570, "letra": "a", "texto": "a) é obrigatória a promoção do juiz que figure por três vezes consecutivas ou cinco alternadas em lista de merecimento;", "ordem": 115}, {"id": 116, "inciso_id": 570, "letra": "b", "texto": "b) a promoção por merecimento pressupõe dois anos de exercício na respectiva entrância e integrar o juiz a primeira quinta parte da lista de antigüidade desta, salvo se não houver com tais requisitos quem aceite o lugar vago;", "ordem": 116}, {"id": 117, "inciso_id": 570, "letra": "c", "texto": "c) aferição do merecimento conforme o desempenho e pelos critérios objetivos de produtividade e presteza no exercício da jurisdição e pela freqüência e aproveitamento em cursos oficiais ou reconhecidos de aperfeiçoamento;", "ordem": 117}, {"id": 118, "inciso_id": 570, "letra": "d", "texto": "d) na apuração de antigüidade, o tribunal somente poderá recusar o juiz mais antigo pelo voto fundamentado de dois terços de seus membros, conforme procedimento próprio, e assegurada ampla defesa, repetindo-se a votação até fixar-se a indicação;", "ordem": 118}, {"id": 119, "inciso_id": 570, "letra": "e", "texto": "e) não será promovido o juiz que, injustificadamente, retiver autos em seu poder além do prazo legal, não podendo devolvê-los ao cartório sem o devido despacho ou decisão;", "ordem": 119}, {"id": 120, "inciso_id": 581, "letra": "a", "texto": "a) eleger seus órgãos diretivos e elaborar seus regimentos internos, com observância das normas de processo e das garantias processuais das partes, dispondo sobre a competência e o funcionamento dos respectivos órgãos jurisdicionais e administrativos;", "ordem": 120}, {"id": 121, "inciso_id": 581, "letra": "b", "texto": "b) organizar suas secretarias e serviços auxiliares e os dos juízos que lhes forem vinculados, velando pelo exercício da atividade correicional respectiva;", "ordem": 121}, {"id": 122, "inciso_id": 581, "letra": "c", "texto": "c) prover, na forma prevista nesta Constituição, os cargos de juiz de carreira da respectiva jurisdição;", "ordem": 122}, {"id": 123, "inciso_id": 581, "letra": "d", "texto": "d) propor a criação de novas varas judiciárias;", "ordem": 123}, {"id": 124, "inciso_id": 581, "letra": "e", "texto": "e) prover, por concurso público de provas, ou de provas e títulos, obedecido o disposto no art. 169, parágrafo único, os cargos necessários à administração da Justiça, exceto os de confiança assim definidos em lei;", "ordem": 124}, {"id": 125, "inciso_id": 581, "letra": "f", "texto": "f) conceder licença, férias e outros afastamentos a seus membros e aos juízes e servidores que lhes forem imediatamente vinculados;", "ordem": 125}, {"id": 126, "inciso_id": 582, "letra": "a", "texto": "a) a alteração do número de membros dos tribunais inferiores;", "ordem": 126}, {"id": 127, "inciso_id": 582, "letra": "b", "texto": "b) a criação e a extinção de cargos e a remuneração dos seus serviços auxiliares e dos juízos que lhes forem vinculados, bem como a fixação do subsídio de seus membros e dos juízes, inclusive dos tribunais inferiores, onde houver;", "ordem": 127}, {"id": 128, "inciso_id": 582, "letra": "c", "texto": "c) a criação ou extinção dos tribunais inferiores;", "ordem": 128}, {"id": 129, "inciso_id": 582, "letra": "d", "texto": "d) a alteração da organização e da divisão judiciárias;", "ordem": 129}, {"id": 130, "inciso_id": 615, "letra": "a", "texto": "a) a ação direta de inconstitucionalidade de lei ou ato normativo federal ou estadual e a ação declaratória de constitucionalidade de lei ou ato normativo federal;", "ordem": 130}, {"id": 131, "inciso_id": 615, "letra": "b", "texto": "b) nas infrações penais comuns, o Presidente da República, o Vice-Presidente, os membros do Congresso Nacional, seus próprios Ministros e o Procurador-Geral da República;", "ordem": 131}, {"id": 132, "inciso_id": 615, "letra": "c", "texto": "c) nas infrações penais comuns e nos crimes de responsabilidade, os Ministros de Estado e os Comandantes da Marinha, do Exército e da Aeronáutica, ressalvado o disposto no art. 52, I, os membros dos Tribunais Superiores, os do Tribunal de Contas da União e os chefes de missão diplomática de caráter permanente;", "ordem": 132}, {"id": 133, "inciso_id": 615, "letra": "d", "texto": "d) o habeas corpus , sendo paciente qualquer das pessoas referidas nas alíneas anteriores; o mandado de segurança e o habeas data contra atos do Presidente da República, das Mesas da Câmara dos Deputados e do Senado Federal, do Tribunal de Contas da União, do Procurador-Geral da República e do próprio Supremo Tribunal Federal;", "ordem": 133}, {"id": 134, "inciso_id": 615, "letra": "e", "texto": "e) o litígio entre Estado estrangeiro ou organismo internacional e a União, o Estado, o Distrito Federal ou o Território;", "ordem": 134}, {"id": 135, "inciso_id": 615, "letra": "f", "texto": "f) as causas e os conflitos entre a União e os Estados, a União e o Distrito Federal, ou entre uns e outros, inclusive as respectivas entidades da administração indireta;", "ordem": 135}, {"id": 136, "inciso_id": 615, "letra": "g", "texto": "g) a extradição solicitada por Estado estrangeiro;", "ordem": 136}, {"id": 137, "inciso_id": 615, "letra": "i", "texto": "i) o habeas corpus , quando o coator for Tribunal Superior ou quando o coator ou o paciente for autoridade ou funcionário cujos atos estejam sujeitos diretamente à jurisdição do Supremo Tribunal Federal, ou se trate de crime sujeito à mesma jurisdição em uma única instância;", "ordem": 137}, {"id": 138, "inciso_id": 615, "letra": "j", "texto": "j) a revisão criminal e a ação rescisória de seus julgados;", "ordem": 138}, {"id": 139, "inciso_id": 615, "letra": "l", "texto": "l) a reclamação para a preservação de sua competência e garantia da autoridade de suas decisões;", "ordem": 139}, {"id": 140, "inciso_id": 615, "letra": "m", "texto": "m) a execução de sentença nas causas de sua competência originária, facultada a delegação de atribuições para a prática de atos processuais;", "ordem": 140}, {"id": 141, "inciso_id": 615, "letra": "n", "texto": "n) a ação em que todos os membros da magistratura sejam direta ou indiretamente interessados, e aquela em que mais da metade dos membros do tribunal de origem estejam impedidos ou sejam direta ou indiretamente interessados;", "ordem": 141}, {"id": 142, "inciso_id": 615, "letra": "o", "texto": "o) os conflitos de competência entre o Superior Tribunal de Justiça e quaisquer tribunais, entre Tribunais Superiores, ou entre estes e qualquer outro tribunal;", "ordem": 142}, {"id": 143, "inciso_id": 615, "letra": "p", "texto": "p) o pedido de medida cautelar das ações diretas de inconstitucionalidade;", "ordem": 143}, {"id": 144, "inciso_id": 615, "letra": "q", "texto": "q) o mandado de injunção, quando a elaboração da norma regulamentadora for atribuição do Presidente da República, do Congresso Nacional, da Câmara dos Deputados, do Senado Federal, das Mesas de uma dessas Casas Legislativas, do Tribunal de Contas da União, de um dos Tribunais Superiores, ou do próprio Supremo Tribunal Federal;", "ordem": 144}, {"id": 145, "inciso_id": 615, "letra": "r", "texto": "r) as ações contra o Conselho Nacional de Justiça e contra o Conselho Nacional do Ministério Público;", "ordem": 145}, {"id": 146, "inciso_id": 616, "letra": "a", "texto": "a) o habeas corpus , o mandado de segurança, o habeas data e o mandado de injunção decididos em única instância pelos Tribunais Superiores, se denegatória a decisão;", "ordem": 146}, {"id": 147, "inciso_id": 616, "letra": "b", "texto": "b) o crime político;", "ordem": 147}, {"id": 148, "inciso_id": 617, "letra": "a", "texto": "a) contrariar dispositivo desta Constituição;", "ordem": 148}, {"id": 149, "inciso_id": 617, "letra": "b", "texto": "b) declarar a inconstitucionalidade de tratado ou lei federal;", "ordem": 149}, {"id": 150, "inciso_id": 617, "letra": "c", "texto": "c) julgar válida lei ou ato de governo local contestado em face desta Constituição.", "ordem": 150}, {"id": 151, "inciso_id": 617, "letra": "d", "texto": "d) julgar válida lei local contestada em face de lei federal.", "ordem": 151}, {"id": 152, "inciso_id": 648, "letra": "a", "texto": "a) nos crimes comuns, os Governadores dos Estados e do Distrito Federal, e, nestes e nos de responsabilidade, os desembargadores dos Tribunais de Justiça dos Estados e do Distrito Federal, os membros dos Tribunais de Contas dos Estados e do Distrito Federal, os dos Tribunais Regionais Federais, dos Tribunais Regionais Eleitorais e do Trabalho, os membros dos Conselhos ou Tribunais de Contas dos Municípios e os do Ministério Público da União que oficiem perante tribunais;", "ordem": 152}, {"id": 153, "inciso_id": 648, "letra": "b", "texto": "b) os mandados de segurança e os habeas data contra ato de Ministro de Estado, dos Comandantes da Marinha, do Exército e da Aeronáutica ou do próprio Tribunal;", "ordem": 153}, {"id": 154, "inciso_id": 648, "letra": "c", "texto": "c) os habeas corpus, quando o coator ou paciente for qualquer das pessoas mencionadas na alínea a, ou quando o coator for tribunal sujeito à sua jurisdição, Ministro de Estado ou Comandante da Marinha, do Exército ou da Aeronáutica, ressalvada a competência da Justiça Eleitoral;", "ordem": 154}, {"id": 155, "inciso_id": 648, "letra": "d", "texto": "d) os conflitos de competência entre quaisquer tribunais, ressalvado o disposto no art. 102, I, \"o\", bem como entre tribunal e juízes a ele não vinculados e entre juízes vinculados a tribunais diversos;", "ordem": 155}, {"id": 156, "inciso_id": 648, "letra": "e", "texto": "e) as revisões criminais e as ações rescisórias de seus julgados;", "ordem": 156}, {"id": 157, "inciso_id": 648, "letra": "f", "texto": "f) a reclamação para a preservação de sua competência e garantia da autoridade de suas decisões;", "ordem": 157}, {"id": 158, "inciso_id": 648, "letra": "g", "texto": "g) os conflitos de atribuições entre autoridades administrativas e judiciárias da União, ou entre autoridades judiciárias de um Estado e administrativas de outro ou do Distrito Federal, ou entre as deste e da União;", "ordem": 158}, {"id": 159, "inciso_id": 648, "letra": "h", "texto": "h) o mandado de injunção, quando a elaboração da norma regulamentadora for atribuição de órgão, entidade ou autoridade federal, da administração direta ou indireta, excetuados os casos de competência do Supremo Tribunal Federal e dos órgãos da Justiça Militar, da Justiça Eleitoral, da Justiça do Trabalho e da Justiça Federal;", "ordem": 159}, {"id": 160, "inciso_id": 648, "letra": "i", "texto": "i) a homologação de sentenças estrangeiras e a concessão de exequatur às cartas rogatórias;", "ordem": 160}, {"id": 161, "inciso_id": 648, "letra": "j", "texto": "j) os conflitos entre entes federativos, ou entre estes e o Comitê Gestor do Imposto sobre Bens e Serviços, relacionados aos tributos previstos nos arts. 156-A e 195, V;", "ordem": 161}, {"id": 162, "inciso_id": 649, "letra": "a", "texto": "a) os habeas corpus decididos em única ou última instância pelos Tribunais Regionais Federais ou pelos tribunais dos Estados, do Distrito Federal e Territórios, quando a decisão for denegatória;", "ordem": 162}, {"id": 163, "inciso_id": 649, "letra": "b", "texto": "b) os mandados de segurança decididos em única instância pelos Tribunais Regionais Federais ou pelos tribunais dos Estados, do Distrito Federal e Territórios, quando denegatória a decisão;", "ordem": 163}, {"id": 164, "inciso_id": 649, "letra": "c", "texto": "c) as causas em que forem partes Estado estrangeiro ou organismo internacional, de um lado, e, do outro, Município ou pessoa residente ou domiciliada no País;", "ordem": 164}, {"id": 165, "inciso_id": 650, "letra": "a", "texto": "a) contrariar tratado ou lei federal, ou negar-lhes vigência;", "ordem": 165}, {"id": 166, "inciso_id": 650, "letra": "b", "texto": "b) julgar válido ato de governo local contestado em face de lei federal;", "ordem": 166}, {"id": 167, "inciso_id": 650, "letra": "c", "texto": "c) der a lei federal interpretação divergente da que lhe haja atribuído outro tribunal.", "ordem": 167}, {"id": 168, "inciso_id": 663, "letra": "a", "texto": "a) os juízes federais da área de sua jurisdição, incluídos os da Justiça Militar e da Justiça do Trabalho, nos crimes comuns e de responsabilidade, e os membros do Ministério Público da União, ressalvada a competência da Justiça Eleitoral;", "ordem": 168}, {"id": 169, "inciso_id": 663, "letra": "b", "texto": "b) as revisões criminais e as ações rescisórias de julgados seus ou dos juízes federais da região;", "ordem": 169}, {"id": 170, "inciso_id": 663, "letra": "c", "texto": "c) os mandados de segurança e os habeas data contra ato do próprio Tribunal ou de juiz federal;", "ordem": 170}, {"id": 171, "inciso_id": 663, "letra": "d", "texto": "d) os habeas corpus, quando a autoridade coatora for juiz federal;", "ordem": 171}, {"id": 172, "inciso_id": 663, "letra": "e", "texto": "e) os conflitos de competência entre juízes federais vinculados ao Tribunal;", "ordem": 172}, {"id": 173, "inciso_id": 683, "letra": "a", "texto": "a) três juízes dentre os Ministros do Supremo Tribunal Federal;", "ordem": 173}, {"id": 174, "inciso_id": 683, "letra": "b", "texto": "b) dois juízes dentre os Ministros do Superior Tribunal de Justiça;", "ordem": 174}, {"id": 175, "inciso_id": 685, "letra": "a", "texto": "a) de dois juízes dentre os desembargadores do Tribunal de Justiça;", "ordem": 175}, {"id": 176, "inciso_id": 685, "letra": "b", "texto": "b) de dois juízes, dentre juízes de direito, escolhidos pelo Tribunal de Justiça;", "ordem": 176}, {"id": 177, "inciso_id": 697, "letra": "a", "texto": "a) o Ministério Público Federal;", "ordem": 177}, {"id": 178, "inciso_id": 697, "letra": "b", "texto": "b) o Ministério Público do Trabalho;", "ordem": 178}, {"id": 179, "inciso_id": 697, "letra": "c", "texto": "c) o Ministério Público Militar;", "ordem": 179}, {"id": 180, "inciso_id": 697, "letra": "d", "texto": "d) o Ministério Público do Distrito Federal e Territórios;", "ordem": 180}, {"id": 181, "inciso_id": 699, "letra": "a", "texto": "a) vitaliciedade, após dois anos de exercício, não podendo perder o cargo senão por sentença judicial transitada em julgado;", "ordem": 181}, {"id": 182, "inciso_id": 699, "letra": "b", "texto": "b) inamovibilidade, salvo por motivo de interesse público, mediante decisão do órgão colegiado competente do Ministério Público, pelo voto da maioria absoluta de seus membros, assegurada ampla defesa;", "ordem": 182}, {"id": 183, "inciso_id": 699, "letra": "c", "texto": "c) irredutibilidade de subsídio, fixado na forma do art. 39, § 4º, e ressalvado o disposto nos arts. 37, X e XI, 150, II, 153, III, 153, § 2º, I;", "ordem": 183}, {"id": 184, "inciso_id": 700, "letra": "a", "texto": "a) receber, a qualquer título e sob qualquer pretexto, honorários, percentagens ou custas processuais;", "ordem": 184}, {"id": 185, "inciso_id": 700, "letra": "b", "texto": "b) exercer a advocacia;", "ordem": 185}, {"id": 186, "inciso_id": 700, "letra": "c", "texto": "c) participar de sociedade comercial, na forma da lei;", "ordem": 186}, {"id": 187, "inciso_id": 700, "letra": "d", "texto": "d) exercer, ainda que em disponibilidade, qualquer outra função pública, salvo uma de magistério;", "ordem": 187}, {"id": 188, "inciso_id": 700, "letra": "e", "texto": "e) exercer atividade político-partidária;", "ordem": 188}, {"id": 189, "inciso_id": 700, "letra": "f", "texto": "f) receber, a qualquer título ou pretexto, auxílios ou contribuições de pessoas físicas, entidades públicas ou privadas, ressalvadas as exceções previstas em lei.", "ordem": 189}, {"id": 190, "inciso_id": 711, "letra": "a", "texto": "a) reunião, ainda que exercida no seio das associações;", "ordem": 190}, {"id": 191, "inciso_id": 711, "letra": "b", "texto": "b) sigilo de correspondência;", "ordem": 191}, {"id": 192, "inciso_id": 711, "letra": "c", "texto": "c) sigilo de comunicação telegráfica e telefônica;", "ordem": 192}, {"id": 193, "inciso_id": 752, "letra": "a", "texto": "a) definição de tributos e de suas espécies, bem como, em relação aos impostos discriminados nesta Constituição, a dos respectivos fatos geradores, bases de cálculo e contribuintes;", "ordem": 193}, {"id": 194, "inciso_id": 752, "letra": "b", "texto": "b) obrigação, lançamento, crédito, prescrição e decadência tributários;", "ordem": 194}, {"id": 195, "inciso_id": 752, "letra": "c", "texto": "c) adequado tratamento tributário ao ato cooperativo praticado pelas sociedades cooperativas, inclusive em relação aos tributos previstos nos arts. 156-A e 195, V;", "ordem": 195}, {"id": 196, "inciso_id": 752, "letra": "d", "texto": "d) definição de tratamento diferenciado e favorecido para as microempresas e para as empresas de pequeno porte, inclusive regimes especiais ou simplificados no caso dos impostos previstos nos arts. 155, II, e 156-A, das contribuições sociais previstas no art. 195, I e V, e § 12 e da contribuição a que se refere o art. 239.", "ordem": 196}, {"id": 197, "inciso_id": 763, "letra": "a", "texto": "a) ad valorem , tendo por base o faturamento, a receita bruta ou o valor da operação e, no caso de importação, o valor aduaneiro;", "ordem": 197}, {"id": 198, "inciso_id": 763, "letra": "b", "texto": "b) específica, tendo por base a unidade de medida adotada.", "ordem": 198}, {"id": 199, "inciso_id": 770, "letra": "a", "texto": "a) em relação a fatos geradores ocorridos antes do início da vigência da lei que os houver instituído ou aumentado;", "ordem": 199}, {"id": 200, "inciso_id": 770, "letra": "b", "texto": "b) no mesmo exercício financeiro em que haja sido publicada a lei que os instituiu ou aumentou;", "ordem": 200}, {"id": 201, "inciso_id": 770, "letra": "c", "texto": "c) antes de decorridos noventa dias da data em que haja sido publicada a lei que os instituiu ou aumentou, observado o disposto na alínea b;", "ordem": 201}, {"id": 202, "inciso_id": 773, "letra": "a", "texto": "a) patrimônio, renda ou serviços, uns dos outros;", "ordem": 202}, {"id": 203, "inciso_id": 773, "letra": "b", "texto": "b) entidades religiosas e templos de qualquer culto, inclusive suas organizações assistenciais e beneficentes;", "ordem": 203}, {"id": 204, "inciso_id": 773, "letra": "c", "texto": "c) patrimônio, renda ou serviços dos partidos políticos, inclusive suas fundações, das entidades sindicais dos trabalhadores, das instituições de educação e de assistência social, sem fins lucrativos, atendidos os requisitos da lei;", "ordem": 204}, {"id": 205, "inciso_id": 773, "letra": "d", "texto": "d) livros, jornais, periódicos e o papel destinado a sua impressão.", "ordem": 205}, {"id": 206, "inciso_id": 773, "letra": "e", "texto": "e) fonogramas e videofonogramas musicais produzidos no Brasil contendo obras musicais ou literomusicais de autores brasileiros e/ou obras em geral interpretadas por artistas brasileiros bem como os suportes materiais ou arquivos digitais que os contenham, salvo na etapa de replicação industrial de mídias ópticas de leitura a laser.", "ordem": 206}, {"id": 207, "inciso_id": 809, "letra": "a", "texto": "a) se o doador tiver domicilio ou residência no exterior;", "ordem": 207}, {"id": 208, "inciso_id": 809, "letra": "b", "texto": "b) se o de cujus possuía bens, era residente ou domiciliado ou teve o seu inventário processado no exterior;", "ordem": 208}, {"id": 209, "inciso_id": 815, "letra": "a", "texto": "a) não implicará crédito para compensação com o montante devido nas operações ou prestações seguintes;", "ordem": 209}, {"id": 210, "inciso_id": 815, "letra": "b", "texto": "b) acarretará a anulação do crédito relativo às operações anteriores;", "ordem": 210}, {"id": 211, "inciso_id": 818, "letra": "a", "texto": "a) estabelecer alíquotas mínimas nas operações internas, mediante resolução de iniciativa de um terço e aprovada pela maioria absoluta de seus membros;", "ordem": 211}, {"id": 212, "inciso_id": 818, "letra": "b", "texto": "b) fixar alíquotas máximas nas mesmas operações para resolver conflito específico que envolva interesse de Estados, mediante resolução de iniciativa da maioria absoluta e aprovada por dois terços de seus membros;", "ordem": 212}, {"id": 213, "inciso_id": 820, "letra": "a", "texto": "a) (revogada);", "ordem": 213}, {"id": 214, "inciso_id": 820, "letra": "b", "texto": "b) (revogada);", "ordem": 214}, {"id": 215, "inciso_id": 821, "letra": "a", "texto": "a) ao destinatário, quando este for contribuinte do imposto;", "ordem": 215}, {"id": 216, "inciso_id": 821, "letra": "b", "texto": "b) ao remetente, quando o destinatário não for contribuinte do imposto;", "ordem": 216}, {"id": 217, "inciso_id": 822, "letra": "a", "texto": "a) sobre a entrada de bem ou mercadoria importados do exterior por pessoa física ou jurídica, ainda que não seja contribuinte habitual do imposto, qualquer que seja a sua finalidade, assim como sobre o serviço prestado no exterior, cabendo o imposto ao Estado onde estiver situado o domicílio ou o estabelecimento do destinatário da mercadoria, bem ou serviço;", "ordem": 217}, {"id": 218, "inciso_id": 822, "letra": "b", "texto": "b) sobre o valor total da operação, quando mercadorias forem fornecidas com serviços não compreendidos na competência tributária dos Municípios;", "ordem": 218}, {"id": 219, "inciso_id": 823, "letra": "a", "texto": "a) sobre operações que destinem mercadorias para o exterior, nem sobre serviços prestados a destinatários no exterior, assegurada a manutenção e o aproveitamento do montante do imposto cobrado nas operações e prestações anteriores;", "ordem": 219}, {"id": 220, "inciso_id": 823, "letra": "b", "texto": "b) sobre operações que destinem a outros Estados petróleo, inclusive lubrificantes, combustíveis líquidos e gasosos dele derivados, e energia elétrica;", "ordem": 220}, {"id": 221, "inciso_id": 823, "letra": "c", "texto": "c) sobre o ouro, nas hipóteses definidas no art. 153, § 5º;", "ordem": 221}, {"id": 222, "inciso_id": 823, "letra": "d", "texto": "d) nas prestações de serviço de comunicação nas modalidades de radiodifusão sonora e de sons e imagens de recepção livre e gratuita;", "ordem": 222}, {"id": 223, "inciso_id": 825, "letra": "a", "texto": "a) definir seus contribuintes;", "ordem": 223}, {"id": 224, "inciso_id": 825, "letra": "b", "texto": "b) dispor sobre substituição tributária;", "ordem": 224}, {"id": 225, "inciso_id": 825, "letra": "c", "texto": "c) disciplinar o regime de compensação do imposto;", "ordem": 225}, {"id": 226, "inciso_id": 825, "letra": "d", "texto": "d) fixar, para efeito de sua cobrança e definição do estabelecimento responsável, o local das operações relativas à circulação de mercadorias e das prestações de serviços;", "ordem": 226}, {"id": 227, "inciso_id": 825, "letra": "e", "texto": "e) excluir da incidência do imposto, nas exportações para o exterior, serviços e outros produtos além dos mencionados no inciso X, \"a\"", "ordem": 227}, {"id": 228, "inciso_id": 825, "letra": "f", "texto": "f) prever casos de manutenção de crédito, relativamente à remessa para outro Estado e exportação para o exterior, de serviços e de mercadorias;", "ordem": 228}, {"id": 229, "inciso_id": 825, "letra": "g", "texto": "g) regular a forma como, mediante deliberação dos Estados e do Distrito Federal, isenções, incentivos e benefícios fiscais serão concedidos e revogados.", "ordem": 229}, {"id": 230, "inciso_id": 825, "letra": "h", "texto": "h) definir os combustíveis e lubrificantes sobre os quais o imposto incidirá uma única vez, qualquer que seja a sua finalidade, hipótese em que não se aplicará o disposto no inciso X, b ;", "ordem": 230}, {"id": 231, "inciso_id": 825, "letra": "i", "texto": "i) fixar a base de cálculo, de modo que o montante do imposto a integre, também na importação do exterior de bem, mercadoria ou serviço.", "ordem": 231}, {"id": 232, "inciso_id": 829, "letra": "a", "texto": "a) serão uniformes em todo o território nacional, podendo ser diferenciadas por produto;", "ordem": 232}, {"id": 233, "inciso_id": 829, "letra": "b", "texto": "b) poderão ser específicas, por unidade de medida adotada, ou ad valorem , incidindo sobre o valor da operação ou sobre o preço que o produto ou seu similar alcançaria em uma venda em condições de livre concorrência;", "ordem": 233}, {"id": 234, "inciso_id": 829, "letra": "c", "texto": "c) poderão ser reduzidas e restabelecidas, não se lhes aplicando o disposto no art. 150, III, b .", "ordem": 234}, {"id": 235, "inciso_id": 832, "letra": "a", "texto": "a) aeronaves agrícolas e de operador certificado para prestar serviços aéreos a terceiros;", "ordem": 235}, {"id": 236, "inciso_id": 832, "letra": "b", "texto": "b) embarcações de pessoa jurídica que detenha outorga para prestar serviços de transporte aquaviário ou de pessoa física ou jurídica que pratique pesca industrial, artesanal, científica ou de subsistência;", "ordem": 236}, {"id": 237, "inciso_id": 832, "letra": "c", "texto": "c) plataformas suscetíveis de se locomoverem na água por meios próprios, inclusive aquelas cuja finalidade principal seja a exploração de atividades econômicas em águas territoriais e na zona econômica exclusiva e embarcações que tenham essa mesma finalidade principal;", "ordem": 237}, {"id": 238, "inciso_id": 832, "letra": "d", "texto": "d) tratores e máquinas agrícolas.", "ordem": 238}, {"id": 239, "inciso_id": 832, "letra": "e", "texto": "e) veículos terrestres de passageiros, caminhonetes e mistos com 20 (vinte) anos ou mais de fabricação, excetuados os micro-ônibus, ônibus, reboques e semirreboques.", "ordem": 239}, {"id": 240, "inciso_id": 859, "letra": "a", "texto": "a) a sua forma de cálculo;", "ordem": 240}, {"id": 241, "inciso_id": 859, "letra": "b", "texto": "b) o tratamento em relação às operações em que o imposto não seja recolhido tempestivamente;", "ordem": 241}, {"id": 242, "inciso_id": 859, "letra": "c", "texto": "c) as regras de distribuição aplicáveis aos regimes favorecidos, específicos e diferenciados de tributação previstos nesta Constituição;", "ordem": 242}, {"id": 243, "inciso_id": 860, "letra": "a", "texto": "a) o adquirente possa efetuar o recolhimento do imposto incidente nas suas aquisições de bens ou serviços; ou", "ordem": 243}, {"id": 244, "inciso_id": 860, "letra": "b", "texto": "b) o recolhimento do imposto ocorra na liquidação financeira da operação;", "ordem": 244}, {"id": 245, "inciso_id": 863, "letra": "a", "texto": "a) crédito integral e imediato do imposto;", "ordem": 245}, {"id": 246, "inciso_id": 863, "letra": "b", "texto": "b) diferimento; ou", "ordem": 246}, {"id": 247, "inciso_id": 863, "letra": "c", "texto": "c) redução em 100% (cem por cento) das alíquotas do imposto;", "ordem": 247}, {"id": 248, "inciso_id": 868, "letra": "a", "texto": "a) serão as alíquotas uniformes em todo o território nacional, específicas por unidade de medida e diferenciadas por produto, admitida a não aplicação do disposto no § 1º, V a VII;", "ordem": 248}, {"id": 249, "inciso_id": 868, "letra": "b", "texto": "b) será vedada a apropriação de créditos em relação às aquisições dos produtos de que trata este inciso destinados a distribuição, comercialização ou revenda;", "ordem": 249}, {"id": 250, "inciso_id": 868, "letra": "c", "texto": "c) será concedido crédito nas aquisições dos produtos de que trata este inciso por sujeito passivo do imposto, observado o disposto na alínea \"b\" e no § 1º, VIII;", "ordem": 250}, {"id": 251, "inciso_id": 869, "letra": "a", "texto": "a) alterações nas alíquotas, nas regras de creditamento e na base de cálculo, admitida, em relação aos adquirentes dos bens e serviços de que trata este inciso, a não aplicação do disposto no § 1º, VIII;", "ordem": 251}, {"id": 252, "inciso_id": 869, "letra": "b", "texto": "b) hipóteses em que o imposto incidirá sobre a receita ou o faturamento, com alíquota uniforme em todo o território nacional, admitida a não aplicação do disposto no § 1º, V a VII, e, em relação aos adquirentes dos bens e serviços de que trata este inciso, também do disposto no § 1º, VIII;", "ordem": 252}, {"id": 253, "inciso_id": 870, "letra": "a", "texto": "a) as hipóteses em que o imposto não incidirá sobre as operações realizadas entre a sociedade cooperativa e seus associados, entre estes e aquela e pelas sociedades cooperativas entre si quando associadas para a consecução dos objetivos sociais;", "ordem": 253}, {"id": 254, "inciso_id": 870, "letra": "b", "texto": "b) o regime de aproveitamento do crédito das etapas anteriores;", "ordem": 254}, {"id": 255, "inciso_id": 889, "letra": "a", "texto": "a) 14 (quatorze) representantes, com base nos votos de cada Município, com valor igual para todos; e", "ordem": 255}, {"id": 256, "inciso_id": 889, "letra": "b", "texto": "b) 13 (treze) representantes, com base nos votos de cada Município ponderados pelas respectivas populações.", "ordem": 256}, {"id": 257, "inciso_id": 890, "letra": "a", "texto": "a) da maioria absoluta de seus representantes; e", "ordem": 257}, {"id": 258, "inciso_id": 890, "letra": "b", "texto": "b) de representantes dos Estados e do Distrito Federal que correspondam a mais de 50% (cinquenta por cento) da população do País; e", "ordem": 258}, {"id": 259, "inciso_id": 897, "letra": "a", "texto": "a) do produto da arrecadação do imposto do Estado sobre operações relativas à circulação de mercadorias e sobre prestações de serviços de transporte interestadual e intermunicipal e de comunicação; Vigência", "ordem": 259}, {"id": 260, "inciso_id": 897, "letra": "b", "texto": "b) do produto da arrecadação do imposto previsto no art. 156-A distribuída aos Estados.", "ordem": 260}, {"id": 261, "inciso_id": 904, "letra": "a", "texto": "a) vinte e um inteiros e cinco décimos por cento ao Fundo de Participação dos Estados e do Distrito Federal; (Regulamento)", "ordem": 261}, {"id": 262, "inciso_id": 904, "letra": "b", "texto": "b) vinte e dois inteiros e cinco décimos por cento ao Fundo de Participação dos Municípios; (Regulamento)", "ordem": 262}, {"id": 263, "inciso_id": 904, "letra": "c", "texto": "c) três por cento, para aplicação em programas de financiamento ao setor produtivo das Regiões Norte, Nordeste e Centro-Oeste, através de suas instituições financeiras de caráter regional, de acordo com os planos regionais de desenvolvimento, ficando assegurada ao semi-árido do Nordeste a metade dos recursos destinados à Região, na forma que a lei estabelecer; (Regulamento)", "ordem": 263}, {"id": 264, "inciso_id": 904, "letra": "d", "texto": "d) um por cento ao Fundo de Participação dos Municípios, que será entregue no primeiro decêndio do mês de dezembro de cada ano;", "ordem": 264}, {"id": 265, "inciso_id": 904, "letra": "e", "texto": "e) 1% (um por cento) ao Fundo de Participação dos Municípios, que será entregue no primeiro decêndio do mês de julho de cada ano;", "ordem": 265}, {"id": 266, "inciso_id": 904, "letra": "f", "texto": "f) 1% (um por cento) ao Fundo de Participação dos Municípios, que será entregue no primeiro decêndio do mês de setembro de cada ano; Produção de efeitos", "ordem": 266}, {"id": 267, "inciso_id": 924, "letra": "a", "texto": "a) indicadores de sua apuração;", "ordem": 267}, {"id": 268, "inciso_id": 924, "letra": "b", "texto": "b) níveis de compatibilidade dos resultados fiscais com a trajetória da dívida;", "ordem": 268}, {"id": 269, "inciso_id": 924, "letra": "c", "texto": "c) trajetória de convergência do montante da dívida com os limites definidos em legislação;", "ordem": 269}, {"id": 270, "inciso_id": 924, "letra": "d", "texto": "d) medidas de ajuste, suspensões e vedações;", "ordem": 270}, {"id": 271, "inciso_id": 924, "letra": "e", "texto": "e) planejamento de alienação de ativos com vistas à redução do montante da dívida.", "ordem": 271}, {"id": 272, "inciso_id": 941, "letra": "a", "texto": "a) dotações para pessoal e seus encargos;", "ordem": 272}, {"id": 273, "inciso_id": 941, "letra": "b", "texto": "b) serviço da dívida;", "ordem": 273}, {"id": 274, "inciso_id": 941, "letra": "c", "texto": "c) transferências tributárias constitucionais para Estados, Municípios e Distrito Federal; ou", "ordem": 274}, {"id": 275, "inciso_id": 942, "letra": "a", "texto": "a) com a correção de erros ou omissões; ou", "ordem": 275}, {"id": 276, "inciso_id": 942, "letra": "b", "texto": "b) com os dispositivos do texto do projeto de lei.", "ordem": 276}, {"id": 277, "inciso_id": 973, "letra": "a", "texto": "a) as reposições de cargos de chefia e de direção que não acarretem aumento de despesa;", "ordem": 277}, {"id": 278, "inciso_id": 973, "letra": "b", "texto": "b) as reposições decorrentes de vacâncias de cargos efetivos ou vitalícios;", "ordem": 278}, {"id": 279, "inciso_id": 973, "letra": "c", "texto": "c) as contratações temporárias de que trata o inciso IX do caput do art. 37 desta Constituição; e", "ordem": 279}, {"id": 280, "inciso_id": 973, "letra": "d", "texto": "d) as reposições de temporários para prestação de serviço militar e de alunos de órgãos de formação de militares;", "ordem": 280}, {"id": 281, "inciso_id": 1022, "letra": "a", "texto": "a) diferenciada por produto ou uso;", "ordem": 281}, {"id": 282, "inciso_id": 1023, "letra": "a", "texto": "a) ao pagamento de subsídios a preços ou transporte de álcool combustível, gás natural e seus derivados e derivados de petróleo;", "ordem": 282}, {"id": 283, "inciso_id": 1023, "letra": "b", "texto": "b) ao financiamento de projetos ambientais relacionados com a indústria do petróleo e do gás;", "ordem": 283}, {"id": 284, "inciso_id": 1023, "letra": "c", "texto": "c) ao financiamento de programas de infra-estrutura de transportes.", "ordem": 284}, {"id": 285, "inciso_id": 1023, "letra": "d", "texto": "d) ao pagamento de subsídios a tarifas de transporte público coletivo de passageiros.", "ordem": 285}, {"id": 286, "inciso_id": 1048, "letra": "a", "texto": "a) a folha de salários e demais rendimentos do trabalho pagos ou creditados, a qualquer título, à pessoa física que lhe preste serviço, mesmo sem vínculo empregatício;", "ordem": 286}, {"id": 287, "inciso_id": 1048, "letra": "b", "texto": "b) a receita ou o faturamento; Vigência", "ordem": 287}, {"id": 288, "inciso_id": 1048, "letra": "c", "texto": "c) o lucro;", "ordem": 288}, {"id": 289, "inciso_id": 1110, "letra": "a", "texto": "a) das parcelas dos Estados no imposto de que trata o art. 156-A;", "ordem": 289}, {"id": 290, "inciso_id": 1110, "letra": "b", "texto": "b) da parcela do Distrito Federal no imposto de que trata o art. 156-A, relativa ao exercício de sua competência estadual, nos termos do art. 156-A, § 2º; e", "ordem": 290}, {"id": 291, "inciso_id": 1110, "letra": "c", "texto": "c) dos recursos a que se referem os incisos I, II e III do caput do art. 155, o inciso II do caput do art. 157, os incisos II, III e IV do caput do art. 158 e as alíneas \"a\" e \"b\" do inciso I e o inciso II do caput do art. 159 desta Constituição;", "ordem": 291}, {"id": 292, "inciso_id": 1113, "letra": "a", "texto": "a) 10 (dez) pontos percentuais no âmbito de cada Estado e do Distrito Federal, sempre que o valor anual por aluno (VAAF), nos termos do inciso III do caput deste artigo, não alcançar o mínimo definido nacionalmente;", "ordem": 292}, {"id": 293, "inciso_id": 1113, "letra": "b", "texto": "b) no mínimo, 10,5 (dez inteiros e cinco décimos) pontos percentuais em cada rede pública de ensino municipal, estadual ou distrital, sempre que o valor anual total por aluno (VAAT), referido no inciso VI do caput deste artigo, não alcançar o mínimo definido nacionalmente;", "ordem": 293}, {"id": 294, "inciso_id": 1113, "letra": "c", "texto": "c) 2,5 (dois inteiros e cinco décimos) pontos percentuais nas redes públicas que, cumpridas condicionalidades de melhoria de gestão previstas em lei, alcançarem evolução de indicadores a serem definidos, de atendimento e melhoria da aprendizagem com redução das desigualdades, nos termos do sistema nacional de avaliação da educação básica;", "ordem": 294}, {"id": 295, "inciso_id": 1118, "letra": "a", "texto": "a) a organização dos fundos referidos no inciso I do caput deste artigo e a distribuição proporcional de seus recursos, as diferenças e as ponderações quanto ao valor anual por aluno entre etapas, modalidades, duração da jornada e tipos de estabelecimento de ensino, observados as respectivas especificidades e os insumos necessários para a garantia de sua qualidade;", "ordem": 295}, {"id": 296, "inciso_id": 1118, "letra": "b", "texto": "b) a forma de cálculo do VAAF decorrente do inciso III do caput deste artigo e do VAAT referido no inciso VI do caput deste artigo;", "ordem": 296}, {"id": 297, "inciso_id": 1118, "letra": "c", "texto": "c) a forma de cálculo para distribuição prevista na alínea \"c\" do inciso V do caput deste artigo;", "ordem": 297}, {"id": 298, "inciso_id": 1118, "letra": "d", "texto": "d) a transparência, o monitoramento, a fiscalização e o controle interno, externo e social dos fundos referidos no inciso I do caput deste artigo, assegurada a criação, a autonomia, a manutenção e a consolidação de conselhos de acompanhamento e controle social, admitida sua integração aos conselhos de educação;", "ordem": 298}, {"id": 299, "inciso_id": 1118, "letra": "e", "texto": "e) o conteúdo e a periodicidade da avaliação, por parte do órgão responsável, dos efeitos redistributivos, da melhoria dos indicadores educacionais e da ampliação do atendimento;", "ordem": 299}, {"id": 300, "inciso_id": 1197, "letra": "a", "texto": "a) cinco dentre os magistrados com mais de trinta e cinco anos de idade, em exercício na área do novo Estado ou do Estado originário;", "ordem": 300}, {"id": 301, "inciso_id": 1197, "letra": "b", "texto": "b) dois dentre promotores, nas mesmas condições, e advogados de comprovada idoneidade e saber jurídico, com dez anos, no mínimo, de exercício profissional, obedecido o procedimento fixado na Constituição;", "ordem": 301}, {"id": 302, "inciso_id": 1201, "letra": "a", "texto": "a) no sexto ano de instalação, o Estado assumirá vinte por cento dos encargos financeiros para fazer face ao pagamento dos servidores públicos, ficando ainda o restante sob a responsabilidade da União;", "ordem": 302}, {"id": 303, "inciso_id": 1201, "letra": "b", "texto": "b) no sétimo ano, os encargos do Estado serão acrescidos de trinta por cento e, no oitavo, dos restantes cinqüenta por cento;", "ordem": 303}, {"id": 304, "inciso_id": 1205, "letra": "a", "texto": "a) do empregado eleito para cargo de direção de comissões internas de prevenção de acidentes, desde o registro de sua candidatura até um ano após o final de seu mandato;", "ordem": 304}, {"id": 305, "inciso_id": 1205, "letra": "b", "texto": "b) da empregada gestante, desde a confirmação da gravidez até cinco meses após o parto.", "ordem": 305}, {"id": 306, "inciso_id": 1300, "letra": "a", "texto": "a) câmaras e prestadoras de serviços de compensação e de liquidação de que trata o parágrafo único do art. 2º da Lei nº 10.214, de 27 de março de 2001 ;", "ordem": 306}, {"id": 307, "inciso_id": 1300, "letra": "b", "texto": "b) companhias securitizadoras de que trata a Lei nº 9.514, de 20 de novembro de 1997 ;", "ordem": 307}, {"id": 308, "inciso_id": 1300, "letra": "c", "texto": "c) sociedades anônimas que tenham por objeto exclusivo a aquisição de créditos oriundos de operações praticadas no mercado financeiro;", "ordem": 308}, {"id": 309, "inciso_id": 1301, "letra": "a", "texto": "a) operações de compra e venda de ações, realizadas em recintos ou sistemas de negociação de bolsas de valores e no mercado de balcão organizado;", "ordem": 309}, {"id": 310, "inciso_id": 1301, "letra": "b", "texto": "b) contratos referenciados em ações ou índices de ações, em suas diversas modalidades, negociados em bolsas de valores, de mercadorias e de futuros;", "ordem": 310}, {"id": 311, "inciso_id": 1314, "letra": "a", "texto": "a) de, no mínimo, 1,5% (um inteiro e cinco décimos por cento), para os Estados das regiões Norte, Nordeste e Centro-Oeste, além do Distrito Federal, ou cujo estoque de precatórios pendentes das suas administrações direta e indireta corresponder a até 35% (trinta e cinco por cento) do total da receita corrente líquida;", "ordem": 311}, {"id": 312, "inciso_id": 1314, "letra": "b", "texto": "b) de, no mínimo, 2% (dois por cento), para os Estados das regiões Sul e Sudeste, cujo estoque de precatórios pendentes das suas administrações direta e indireta corresponder a mais de 35% (trinta e cinco por cento) da receita corrente líquida;", "ordem": 312}, {"id": 313, "inciso_id": 1315, "letra": "a", "texto": "a) de, no mínimo, 1% (um por cento), para Municípios das regiões Norte, Nordeste e Centro-Oeste, ou cujo estoque de precatórios pendentes das suas administrações direta e indireta corresponder a até 35% (trinta e cinco por cento) da receita corrente líquida;", "ordem": 313}, {"id": 314, "inciso_id": 1315, "letra": "b", "texto": "b) de, no mínimo, 1,5% (um inteiro e cinco décimos por cento), para Municípios das regiões Sul e Sudeste, cujo estoque de precatórios pendentes das suas administrações direta e indireta corresponder a mais de 35 % (trinta e cinco por cento) da receita corrente líquida.", "ordem": 314}, {"id": 315, "inciso_id": 1332, "letra": "a", "texto": "a) não poderá contrair empréstimo externo ou interno;", "ordem": 315}, {"id": 316, "inciso_id": 1332, "letra": "b", "texto": "b) ficará impedida de receber transferências voluntárias;", "ordem": 316}, {"id": 317, "inciso_id": 1343, "letra": "a", "texto": "a) no caso do Distrito Federal, 100% (cem por cento) desses recursos ao próprio Distrito Federal;", "ordem": 317}, {"id": 318, "inciso_id": 1343, "letra": "b", "texto": "b) no caso dos Estados, 50% (cinquenta por cento) desses recursos ao próprio Estado e 50% (cinquenta por cento) aos respectivos Municípios, conforme a circunscrição judiciária onde estão depositados os recursos, e, se houver mais de um Município na mesma circunscrição judiciária, os recursos serão rateados entre os Municípios concorrentes, proporcionalmente às respectivas populações, utilizado como referência o último levantamento censitário ou a mais recente estimativa populacional da Fundação Instituto Brasileiro de Geografia e Estatística (IBGE);", "ordem": 318}, {"id": 319, "inciso_id": 1376, "letra": "a", "texto": "a) o valor considerado para amortização da dívida será o valor atualizado dos créditos com ou sem deságio, negociado entre as partes;", "ordem": 319}, {"id": 320, "inciso_id": 1376, "letra": "b", "texto": "b) a cessão do crédito não gerará qualquer alteração na situação do devedor nem ensejará expedição de certidão negativa;", "ordem": 320}, {"id": 321, "inciso_id": 1376, "letra": "c", "texto": "c) na hipótese de crédito cedido, regulamento disporá sobre as regras às quais se submeterão os sujeitos passivos;", "ordem": 321}, {"id": 322, "inciso_id": 1376, "letra": "d", "texto": "d) os valores dos créditos de que trata este inciso, líquidos do deságio a que se refere a alínea \"a\" deste inciso, poderão ser utilizados como pagamento da dívida com a União até o limite de 10% (dez por cento) do montante da dívida, e a cessão terá de ser aceita em comum acordo entre a União e o Município cedente;", "ordem": 322}, {"id": 323, "inciso_id": 1376, "letra": "e", "texto": "e) o Município deverá fornecer todas as informações necessárias à avaliação, pela administração tributária da União, representada pela Procuradoria-Geral da Fazenda Nacional, da carteira de dívida ativa originadora dos direitos cedidos, especialmente em relação à expectativa de recebimento do fluxo futuro;", "ordem": 323}, {"id": 324, "inciso_id": 1376, "letra": "f", "texto": "f) as Fazendas Públicas municipais e a Procuradoria-Geral da Fazenda Nacional poderão implementar soluções integradas para otimizar a administração, a cobrança e a representação judicial e extrajudicial dos créditos inscritos em dívida ativa; e", "ordem": 324}, {"id": 325, "inciso_id": 1376, "letra": "g", "texto": "g) a cessão prevista neste inciso preservará a base de cálculo das vinculações constitucionais no exercício financeiro em que o contribuinte efetuar o pagamento;", "ordem": 325}, {"id": 326, "inciso_id": 1382, "letra": "a", "texto": "a) serão atendidas por meio de crédito extraordinário;", "ordem": 326}, {"id": 327, "inciso_id": 1382, "letra": "b", "texto": "b) não serão consideradas para fins de apuração da meta de resultado primário estabelecida no caput do art. 2º da Lei nº 14.194, de 20 de agosto de 2021, e do limite estabelecido para as despesas primárias, conforme disposto no inciso I do caput do art. 107 do Ato das Disposições Constitucionais Transitórias; e", "ordem": 327}, {"id": 328, "inciso_id": 1382, "letra": "c", "texto": "c) ficarão ressalvadas do disposto no inciso III do caput do art. 167 da Constituição Federal;", "ordem": 328}, {"id": 329, "inciso_id": 1384, "letra": "a", "texto": "a) à criação, à expansão ou ao aperfeiçoamento de ação governamental que acarrete aumento de despesa; e", "ordem": 329}, {"id": 330, "inciso_id": 1384, "letra": "b", "texto": "b) à renúncia de receita que possa ocorrer.", "ordem": 330}, {"id": 331, "inciso_id": 1387, "letra": "a", "texto": "a) a contribuição prevista no art. 195, V, da Constituição Federal;", "ordem": 331}, {"id": 332, "inciso_id": 1387, "letra": "b", "texto": "b) o imposto previsto no art. 153, VIII, da Constituição Federal;", "ordem": 332}, {"id": 333, "inciso_id": 1389, "letra": "a", "texto": "a) terá suas alíquotas reduzidas a zero, exceto em relação aos produtos que tenham industrialização incentivada na Zona Franca de Manaus, conforme critérios estabelecidos em lei complementar; e", "ordem": 333}, {"id": 334, "inciso_id": 1389, "letra": "b", "texto": "b) não incidirá de forma cumulativa com o imposto previsto no art. 153, VIII, da Constituição Federal.", "ordem": 334}, {"id": 335, "inciso_id": 1394, "letra": "a", "texto": "a) das contribuições previstas no art. 195, I, \"b\", e IV, e da contribuição para o Programa de Integração Social de que trata o art. 239, todos da Constituição Federal;", "ordem": 335}, {"id": 336, "inciso_id": 1394, "letra": "b", "texto": "b) do imposto previsto no art. 153, IV; e", "ordem": 336}, {"id": 337, "inciso_id": 1394, "letra": "c", "texto": "c) do imposto previsto no art. 153, V, da Constituição Federal, sobre operações de seguros;", "ordem": 337}, {"id": 338, "inciso_id": 1395, "letra": "a", "texto": "a) da receita do imposto previsto no art. 155, II, da Constituição Federal; e", "ordem": 338}, {"id": 339, "inciso_id": 1395, "letra": "b", "texto": "b) das receitas destinadas a fundos estaduais financiados por contribuições estabelecidas como condição à aplicação de diferimento, regime especial ou outro tratamento diferenciado, relativos ao imposto de que trata o art. 155, II, da Constituição Federal, em funcionamento em 30 de abril de 2023, excetuadas as receitas dos fundos mantidas na forma do art. 136 deste Ato das Disposições Constitucionais Transitórias;", "ordem": 339}, {"id": 340, "inciso_id": 1401, "letra": "a", "texto": "a) multiplicada por 10 (dez) em 2029;", "ordem": 340}, {"id": 341, "inciso_id": 1401, "letra": "b", "texto": "b) multiplicada por 5 (cinco) em 2030;", "ordem": 341}, {"id": 342, "inciso_id": 1401, "letra": "c", "texto": "c) multiplicada por 10 (dez) e dividida por 3 (três) em 2031;", "ordem": 342}, {"id": 343, "inciso_id": 1401, "letra": "d", "texto": "d) multiplicada por 10 (dez) e dividida por 4 (quatro) em 2032;", "ordem": 343}, {"id": 344, "inciso_id": 1401, "letra": "e", "texto": "e) multiplicada por 1 (um) em 2033.", "ordem": 344}, {"id": 345, "inciso_id": 1407, "letra": "a", "texto": "a) a arrecadação do imposto previsto no art. 155, II, após aplicação do disposto no art. 158, IV, \"a\", todos da Constituição Federal; e", "ordem": 345}, {"id": 346, "inciso_id": 1407, "letra": "b", "texto": "b) as receitas destinadas aos fundos estaduais de que trata o art. 130, II, \"b\", deste Ato das Disposições Constitucionais Transitórias;", "ordem": 346}, {"id": 347, "inciso_id": 1408, "letra": "a", "texto": "a) a arrecadação do imposto previsto no art. 155, II, da Constituição Federal; e", "ordem": 347}, {"id": 348, "inciso_id": 1408, "letra": "b", "texto": "b) a arrecadação do imposto previsto no art. 156, III, da Constituição Federal;", "ordem": 348}, {"id": 349, "inciso_id": 1409, "letra": "a", "texto": "a) a arrecadação do imposto previsto no art. 156, III, da Constituição Federal; e", "ordem": 349}, {"id": 350, "inciso_id": 1409, "letra": "b", "texto": "b) a parcela creditada na forma do art. 158, IV, \"a\", da Constituição Federal.", "ordem": 350}, {"id": 351, "inciso_id": 1410, "letra": "a", "texto": "a) para os Estados, o percentual de que trata o art. 212-A, II, será aplicado proporcionalmente à razão entre a soma dos valores distribuídos a cada ente nos termos do § 2º, I, \"a\", e do § 4º, e a soma dos valores distribuídos nos termos do § 2º, I e do § 4º;", "ordem": 351}, {"id": 352, "inciso_id": 1410, "letra": "b", "texto": "b) para o Distrito Federal, o percentual de que trata o art. 212-A, II, será aplicado proporcionalmente à razão entre a soma dos valores distribuídos nos termos do § 2º, II, \"a\", e do § 4º, e a soma dos valores distribuídos nos termos do § 2º, II, e do § 4º, considerada, em ambas as somas, somente a parcela estadual nos valores distribuídos nos termos do § 4º;", "ordem": 352}, {"id": 353, "inciso_id": 1410, "letra": "c", "texto": "c) para os Municípios, o percentual de que trata o art. 212-A, II, será aplicado proporcionalmente à razão entre a soma dos valores distribuídos nos termos do § 2º, III, \"b\", e a soma dos valores distribuídos nos termos do § 2º, III;", "ordem": 353}]

  console.log('Inserindo títulos...')
  await insertBatch('cf_titulos', TITULOS)

  console.log('Inserindo capítulos...')
