  console.log('\n✅ SEED CONCLUÍDO!')
  console.log(`  ${ARTIGOS.filter((a:any) => a.tipo==='CF').length} artigos CF`)
  console.log(`  ${ARTIGOS.filter((a:any) => a.tipo==='ADCT').length} artigos ADCT`)
